// Minimal slugify helper -- was previously imported from ./blog-content.
// Blog/site-pages were deleted; only the survey code still needs this.
function slugifyContent(value: string): string {
  return String(value || '')
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 120)
}

const DB_PATH = path.resolve(process.cwd(), '..', 'store', 'motion.db')

/** Generate a random 12-char alphanumeric public ID (non-sequential, URL-safe) */
export function generatePublicId(): string {
  return crypto.randomBytes(9).toString('base64url').slice(0, 12)
}

const ALLOWED_ENTITY_TABLES = ['docs', 'projects', 'tasks', 'workspaces', 'folders', 'stages', 'sheets', 'team_members', 'client_profiles', 'client_businesses'] as const

export function resolveEntityId(table: string, param: string | number): number | null {
  if (typeof param === 'number' || /^\d+$/.test(String(param))) {
    return Number(param) || null
  }
  if (!(ALLOWED_ENTITY_TABLES as readonly string[]).includes(table)) return null
  const row = getDb().prepare(`SELECT id FROM ${table} WHERE public_id = ?`).get(String(param)) as { id: number } | undefined
  return row?.id || null
}

let db: Database.Database

export function getDb(): Database.Database {
  if (!db || !db.open) {
    db = new Database(DB_PATH)
    db.pragma('journal_mode = WAL')
    db.pragma('busy_timeout = 5000')
    db.pragma('foreign_keys = ON')
    initAppTables()
    try { seedBuiltinTools() } catch { /* non-fatal */ }
  }
  return db
}

