  if (!cbColNames.includes('tiktok_handle')) d.exec("ALTER TABLE client_businesses ADD COLUMN tiktok_handle TEXT")
  if (!cbColNames.includes('facebook_page')) d.exec("ALTER TABLE client_businesses ADD COLUMN facebook_page TEXT")
  if (!cbColNames.includes('folder_id')) d.exec("ALTER TABLE client_businesses ADD COLUMN folder_id INTEGER")
  if (!cbColNames.includes('workspace_id')) d.exec("ALTER TABLE client_businesses ADD COLUMN workspace_id INTEGER")
  if (!cbColNames.includes('updated_at')) d.exec("ALTER TABLE client_businesses ADD COLUMN updated_at INTEGER DEFAULT (strftime('%s','now'))")
  if (!cbColNames.includes('avatar_url')) d.exec("ALTER TABLE client_businesses ADD COLUMN avatar_url TEXT")

  // Migrate client_businesses: remove NOT NULL + FOREIGN KEY on client_id (businesses can be standalone)
  try {
    const tableInfo = d.prepare("SELECT sql FROM sqlite_master WHERE type='table' AND name='client_businesses'").get() as { sql: string } | undefined
    if (tableInfo && tableInfo.sql.includes('NOT NULL REFERENCES')) {
      d.exec('PRAGMA foreign_keys = OFF')
      d.exec(`CREATE TABLE client_businesses_new (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        client_id INTEGER DEFAULT 0,
        name TEXT NOT NULL,
        ad_account_id TEXT,
        page_id TEXT,
        monthly_budget REAL,
        sort_order INTEGER DEFAULT 0,
        created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
        slug TEXT,
        industry TEXT,
        avatar_color TEXT DEFAULT '#7a6b55',
        status TEXT DEFAULT 'active',
        context TEXT DEFAULT '',
        brand_voice TEXT DEFAULT '',
        goals TEXT DEFAULT '',
        target_audience TEXT DEFAULT '',
        services TEXT DEFAULT '',
        offer TEXT DEFAULT '',
        offer_details TEXT DEFAULT '',
        location TEXT,
        website TEXT,
        instagram_handle TEXT,
        tiktok_handle TEXT,
        facebook_page TEXT,
        folder_id INTEGER,
        workspace_id INTEGER,
        updated_at INTEGER
      )`)
      d.exec(`INSERT INTO client_businesses_new SELECT
        id, client_id, name, ad_account_id, page_id, monthly_budget, sort_order, created_at,
        slug, industry, avatar_color, status, context, brand_voice, goals, target_audience,
        services, offer, offer_details, location, website, instagram_handle, tiktok_handle,
        facebook_page, folder_id, workspace_id, updated_at
        FROM client_businesses`)
      d.exec('DROP TABLE client_businesses')
      d.exec('ALTER TABLE client_businesses_new RENAME TO client_businesses')
      d.exec('PRAGMA foreign_keys = ON')
    }
  } catch { /* migration already done or not needed */ }

  // Backfill: migrate data from client_profiles → client_businesses
  const bizNoSlug = d.prepare('SELECT * FROM client_businesses WHERE slug IS NULL').all() as { id: number; client_id: number; name: string }[]
  if (bizNoSlug.length > 0) {
    for (const biz of bizNoSlug) {
      const slug = biz.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '')
      // Try to pull context from the linked client_profile
      const cp = biz.client_id > 0 ? d.prepare('SELECT * FROM client_profiles WHERE id = ?').get(biz.client_id) as Record<string, unknown> | undefined : undefined
      if (cp) {
        d.prepare(`UPDATE client_businesses SET
          slug = ?, industry = ?, avatar_color = ?, status = ?,
          context = ?, brand_voice = ?, goals = ?, target_audience = ?,
          services = ?, offer = ?, offer_details = ?,
          location = ?, website = ?,
          instagram_handle = ?, tiktok_handle = ?, facebook_page = ?,
          folder_id = COALESCE(folder_id, ?), workspace_id = COALESCE(workspace_id, ?)
          WHERE id = ?`).run(
          slug, cp.industry || null, cp.avatar_color || '#7a6b55', cp.status || 'active',
          cp.context || '', cp.brand_voice || '', cp.goals || '', cp.target_audience || '',
          cp.services || '', cp.offer || '', cp.offer_details || '',
          cp.location || null, cp.website || null,
          cp.instagram_handle || null, cp.tiktok_handle || null, cp.facebook_page || null,
          cp.folder_id || null, cp.workspace_id || null,
          biz.id
        )
      } else {
        d.prepare('UPDATE client_businesses SET slug = ? WHERE id = ?').run(slug, biz.id)
      }
    }
  }

  // Backfill: auto-create folders for businesses without one
  const bizNoFolder = d.prepare('SELECT * FROM client_businesses WHERE folder_id IS NULL').all() as { id: number; name: string; avatar_color: string | null; workspace_id: number | null }[]
  if (bizNoFolder.length > 0) {
    const defaultWs2 = d.prepare('SELECT id FROM workspaces ORDER BY id LIMIT 1').get() as { id: number } | undefined
    if (defaultWs2) {
      for (const biz of bizNoFolder) {
        const wsId = biz.workspace_id || defaultWs2.id
        const fr = d.prepare('INSERT INTO folders (workspace_id, name, color, public_id) VALUES (?, ?, ?, ?)').run(wsId, biz.name, biz.avatar_color || '#7a6b55', generatePublicId())
        d.prepare('UPDATE client_businesses SET folder_id = ?, workspace_id = ? WHERE id = ?').run(fr.lastInsertRowid, wsId, biz.id)
      }
    }
  }

  // Client profiles should NOT get sidebar folders (only businesses do).
  // Clean up any existing client_profile folders that were created by old migration.
  // NOTE: We keep the folder rows in case docs/projects were moved there, but we unlink
  // client_profiles from them so the sidebar filter works cleanly.

  // ─── Webhooks (Zapier/n8n/Make integration) ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS webhooks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      url TEXT NOT NULL,
      events TEXT NOT NULL DEFAULT '[]',
      secret TEXT,
      enabled INTEGER DEFAULT 1,
      last_triggered INTEGER,
      last_status INTEGER,
      failure_count INTEGER DEFAULT 0,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)

  // ─── External API Tokens (for Zapier/external access) ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS external_tokens (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      token TEXT NOT NULL UNIQUE,
      scopes TEXT NOT NULL DEFAULT '["read"]',
      last_used INTEGER,
      expires_at INTEGER,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)

  // ─── Meeting Notes / Transcriptions ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS meeting_notes (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      title TEXT NOT NULL,
      source TEXT DEFAULT 'manual',
      transcript TEXT,
      summary TEXT,
      action_items TEXT DEFAULT '[]',
      attendees TEXT DEFAULT '[]',
      client_id INTEGER,
      duration_seconds INTEGER,
      meeting_date TEXT,
      agent_processed INTEGER DEFAULT 0,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      updated_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)

  // ─── BYOK (Bring Your Own Key) ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS api_keys (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL DEFAULT 1,
      provider TEXT NOT NULL DEFAULT 'anthropic',
      api_key_encrypted TEXT NOT NULL,
      model_preference TEXT DEFAULT 'standard',
      daily_budget_cents INTEGER DEFAULT 500,
      spent_today_cents INTEGER DEFAULT 0,
      last_reset_date TEXT,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      UNIQUE(user_id, provider)
    )
  `)

  // ─── Agent Runs (execution log) ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS agent_runs (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      agent_id TEXT NOT NULL,
      task_id INTEGER,
      trigger TEXT NOT NULL DEFAULT 'manual',
      status TEXT NOT NULL DEFAULT 'running',
      input_tokens INTEGER DEFAULT 0,
      output_tokens INTEGER DEFAULT 0,
      cost_cents INTEGER DEFAULT 0,
      model TEXT,
      started_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      completed_at INTEGER,
      result TEXT,
      error TEXT
    )
  `)

  // ─── Model Routing Telemetry ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS model_routing_log (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      model TEXT NOT NULL,
      cost_cents INTEGER DEFAULT 0,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)

  // ─── Push Subscriptions (Web Push notifications) ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS push_subscriptions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL DEFAULT 1,
      endpoint TEXT NOT NULL UNIQUE,
      keys_p256dh TEXT NOT NULL,
      keys_auth TEXT NOT NULL,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)

  d.exec(`
    CREATE TABLE IF NOT EXISTS crm_push_subscriptions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      workspace_id INTEGER NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE,
      user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
      endpoint TEXT NOT NULL,
      p256dh TEXT NOT NULL,
      auth TEXT NOT NULL,
      ua TEXT,
      created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')),
      updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now')),
      UNIQUE(workspace_id, user_id, endpoint)
    )
  `)
  d.exec(`CREATE INDEX IF NOT EXISTS idx_crm_push_subscriptions_workspace_user ON crm_push_subscriptions(workspace_id, user_id)`)

  // ─── Approval Queue (for agent actions needing human sign-off) ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS approval_queue (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      agent_id TEXT NOT NULL,
      action_type TEXT NOT NULL,
      action_data TEXT NOT NULL,
      status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending', 'approved', 'denied', 'expired')),
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      resolved_at INTEGER,
      resolved_by TEXT
    )
  `)

  // ─── Dispatch Queue (agent chaining + background execution) ───
  d.exec(`
    CREATE TABLE IF NOT EXISTS dispatch_queue (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      task_id INTEGER REFERENCES tasks(id) ON DELETE CASCADE,
      agent_id TEXT NOT NULL,
      trigger_type TEXT NOT NULL DEFAULT 'manual' CHECK(trigger_type IN ('manual', 'chain', 'schedule', 'event')),
      source_agent_id TEXT,
      source_task_id INTEGER,
      priority INTEGER DEFAULT 5,
      status TEXT NOT NULL DEFAULT 'queued' CHECK(status IN ('queued', 'working', 'needs_review', 'approved', 'done', 'failed', 'cancelled')),
      input_context TEXT,
      result TEXT,
      error TEXT,
      run_type TEXT NOT NULL DEFAULT 'single' CHECK(run_type IN ('single', 'team_parent', 'team_child')),
      parent_dispatch_id INTEGER REFERENCES dispatch_queue(id) ON DELETE CASCADE,
      specialist_role TEXT,
      attempt_count INTEGER DEFAULT 0,
      max_retries INTEGER DEFAULT 2,
      next_retry_at INTEGER,
      worker_id TEXT,
      heartbeat_at INTEGER,
      chain_config TEXT,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      started_at INTEGER,
      completed_at INTEGER
    )
  `)

  // Evolve dispatch_queue table
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN result_summary TEXT') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN feedback TEXT') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN session_id TEXT') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN token_count INTEGER DEFAULT 0') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN worker_id TEXT') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN heartbeat_at INTEGER') } catch { /* already exists */ }
  try { d.exec("ALTER TABLE dispatch_queue ADD COLUMN run_type TEXT NOT NULL DEFAULT 'single'") } catch { /* already exists */ }
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN parent_dispatch_id INTEGER REFERENCES dispatch_queue(id) ON DELETE CASCADE') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN specialist_role TEXT') } catch { /* already exists */ }
  try { d.exec("UPDATE dispatch_queue SET run_type = 'single' WHERE run_type IS NULL OR run_type = ''") } catch { /* best effort */ }
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_dispatch_parent ON dispatch_queue(parent_dispatch_id)') } catch { /* already exists */ }

  // Migrate dispatch_queue CHECK constraint: old DB has 'pending' default, need 'queued'
  try {
    const hasOldDefault = d.prepare(`SELECT sql FROM sqlite_master WHERE type='table' AND name='dispatch_queue'`).get() as any
    if (hasOldDefault?.sql?.includes("'pending'")) {
      d.exec(`
        CREATE TABLE dispatch_queue_new (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          task_id INTEGER REFERENCES tasks(id) ON DELETE CASCADE,
          agent_id TEXT NOT NULL,
          trigger_type TEXT NOT NULL DEFAULT 'manual' CHECK(trigger_type IN ('manual', 'chain', 'schedule', 'event')),
          source_agent_id TEXT,
          source_task_id INTEGER,
          priority INTEGER DEFAULT 5,
          status TEXT NOT NULL DEFAULT 'queued' CHECK(status IN ('queued', 'working', 'needs_review', 'approved', 'done', 'failed', 'cancelled')),
          input_context TEXT,
          result TEXT,
          error TEXT,
          run_type TEXT NOT NULL DEFAULT 'single' CHECK(run_type IN ('single', 'team_parent', 'team_child')),
          parent_dispatch_id INTEGER REFERENCES dispatch_queue_new(id) ON DELETE CASCADE,
          specialist_role TEXT,
          attempt_count INTEGER DEFAULT 0,
          max_retries INTEGER DEFAULT 2,
          next_retry_at INTEGER,
          worker_id TEXT,
          heartbeat_at INTEGER,
          chain_config TEXT,
          created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
          started_at INTEGER,
          completed_at INTEGER,
          result_summary TEXT,
          feedback TEXT,
          session_id TEXT,
          token_count INTEGER DEFAULT 0
        );
        INSERT INTO dispatch_queue_new SELECT id, task_id, agent_id, trigger_type, source_agent_id, source_task_id, priority,
          CASE WHEN status = 'pending' THEN 'queued' WHEN status = 'running' THEN 'working' WHEN status = 'completed' THEN 'done' ELSE status END,
          input_context, result, error, 'single', NULL, NULL, attempt_count, max_retries, next_retry_at, NULL, NULL, chain_config, created_at, started_at, completed_at,
          result_summary, feedback, session_id, token_count
        FROM dispatch_queue;
        DROP TABLE dispatch_queue;
        ALTER TABLE dispatch_queue_new RENAME TO dispatch_queue;
        CREATE INDEX IF NOT EXISTS idx_dispatch_parent ON dispatch_queue(parent_dispatch_id);
      `)
    }
  } catch { /* migration already done or table empty */ }

  // Dispatch chat thread: every user/agent turn within a single dispatch row
  // (resumed via session_id). Used by the /dispatch/[id] chat UI.
  d.exec(`
    CREATE TABLE IF NOT EXISTS dispatch_messages (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      dispatch_id INTEGER NOT NULL REFERENCES dispatch_queue(id) ON DELETE CASCADE,
      role TEXT NOT NULL CHECK(role IN ('user','agent','system')),
      content TEXT NOT NULL,
      token_count INTEGER DEFAULT 0,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_dispatch_messages_dispatch ON dispatch_messages(dispatch_id, created_at)') } catch { /* already exists */ }

  // Dispatch pipeline dependencies: DAG edges between dispatches so a task's
  // subtasks can be fanned out with "B starts only after A is done" ordering.
  // Populated by the Run Pipeline endpoint; enforced by the bridge claim query.
  d.exec(`
    CREATE TABLE IF NOT EXISTS dispatch_dependencies (
      dispatch_id INTEGER NOT NULL REFERENCES dispatch_queue(id) ON DELETE CASCADE,
      depends_on_dispatch_id INTEGER NOT NULL REFERENCES dispatch_queue(id) ON DELETE CASCADE,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      PRIMARY KEY (dispatch_id, depends_on_dispatch_id)
    )
  `)
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_dispatch_deps_dispatch ON dispatch_dependencies(dispatch_id)') } catch { /* */ }
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_dispatch_deps_depends_on ON dispatch_dependencies(depends_on_dispatch_id)') } catch { /* */ }

  // Per-dispatch event stream. The bridge ships SDK message events (tool_use,
  // tool_result, text, error) in small batches while a dispatch is running so
  // the /dispatch/[id] Activity panel can render what Claude Code is actually
  // doing in near-real-time instead of just staring at "working".
  d.exec(`
    CREATE TABLE IF NOT EXISTS dispatch_events (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      dispatch_id INTEGER NOT NULL REFERENCES dispatch_queue(id) ON DELETE CASCADE,
      ts INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      kind TEXT NOT NULL,
      payload TEXT
    )
  `)
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_dispatch_events_dispatch_ts ON dispatch_events(dispatch_id, ts)') } catch { /* */ }
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_dispatch_events_dispatch_id ON dispatch_events(dispatch_id, id)') } catch { /* */ }

  // Recurring dispatch schedules. Rows here represent cron-style recurring
  // jobs the user wires up in the /dispatch/schedules UI; a Hetzner crontab
  // entry hits /api/cron/tick every minute to fire any due schedules.
  // Either task_id (link an existing task) or input_context (inline prompt)
  // must be set; validation happens in the API layer, not the DB.
  d.exec(`
    CREATE TABLE IF NOT EXISTS scheduled_dispatches (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      cron_expr TEXT NOT NULL,
      timezone TEXT NOT NULL DEFAULT 'America/Vancouver',
      agent_id TEXT NOT NULL,
      task_id INTEGER REFERENCES tasks(id) ON DELETE SET NULL,
      input_context TEXT,
      enabled INTEGER NOT NULL DEFAULT 1,
      next_run_at INTEGER,
      last_run_at INTEGER,
      last_dispatch_id INTEGER REFERENCES dispatch_queue(id) ON DELETE SET NULL,
      last_status TEXT,
      last_error TEXT,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      updated_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_scheduled_dispatches_next ON scheduled_dispatches(enabled, next_run_at)') } catch { /* */ }

  // Schedule types: cron | heartbeat | multistep
  // - cron: one dispatch, one agent
  // - heartbeat: one dispatch, bridge prepends heartbeat context (comms/git/todos)
  // - multistep: clone a routine template -> spawn parent task + subtasks -> fire pipeline
  try { d.exec("ALTER TABLE scheduled_dispatches ADD COLUMN type TEXT NOT NULL DEFAULT 'cron'") } catch { /* already exists */ }
  // NOTE: sqlite ALTER TABLE ADD COLUMN cannot attach a REFERENCES clause to an
  // existing table, so routine_id is declared as a plain INTEGER — orphaned rows
  // get pruned at query time (LEFT JOIN + null check). Fine for our scale.
  try { d.exec('ALTER TABLE scheduled_dispatches ADD COLUMN routine_id INTEGER') } catch { /* already exists */ }

  // Routine templates — saved multi-step workflows. A schedule with type='multistep'
  // points at one of these; when the schedule fires, the tick handler clones the
  // template into a fresh parent task + subtasks, wires blocked_by edges, and
  // enqueues a pipeline dispatch. "Run now" on the routines page skips the schedule
  // and does the same thing on demand.
  d.exec(`
    CREATE TABLE IF NOT EXISTS routines (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      description TEXT,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      updated_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)
  d.exec(`
    CREATE TABLE IF NOT EXISTS routine_steps (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      routine_id INTEGER NOT NULL REFERENCES routines(id) ON DELETE CASCADE,
      sort_order INTEGER NOT NULL DEFAULT 0,
      title TEXT NOT NULL,
      agent_id TEXT NOT NULL,
      input_context TEXT,
      blocked_by_order INTEGER
    )
  `)
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_routine_steps_routine ON routine_steps(routine_id, sort_order)') } catch { /* */ }

  // Concurrency + retry knobs for schedules. skip_if_running lets a cron tick
  // bail if the previous dispatch for this schedule is still queued/working.
  // retry_on_failure + max_retries let a failed tick re-fire on the next minute
  // instead of skipping to the next cadence; failure_count is the consecutive
  // failure counter used to cap retries.
  try { d.exec('ALTER TABLE scheduled_dispatches ADD COLUMN skip_if_running INTEGER NOT NULL DEFAULT 0') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE scheduled_dispatches ADD COLUMN retry_on_failure INTEGER NOT NULL DEFAULT 0') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE scheduled_dispatches ADD COLUMN max_retries INTEGER NOT NULL DEFAULT 0') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE scheduled_dispatches ADD COLUMN failure_count INTEGER NOT NULL DEFAULT 0') } catch { /* already exists */ }

  // Tag dispatches with the schedule that spawned them so the history view and
  // concurrency guard can query cleanly (previously relied on pattern-matching
  // the task_activities metadata, which didn't catch inline-context schedules
  // that don't carry a task_id).
  try { d.exec('ALTER TABLE dispatch_queue ADD COLUMN source_schedule_id INTEGER') } catch { /* already exists */ }
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_dispatch_queue_source_schedule ON dispatch_queue(source_schedule_id, created_at DESC)') } catch { /* */ }

  // Tool Registry — typed function manifest for agent dispatch. Each row is
  // one callable tool: motion-internal tools map to a switch in invokeMotionTool,
  // webhook tools POST args to a url, bridge-forward tools are exposed to the
  // Mac bridge so Claude Code sub-agents can call them. input_schema is a
  // JSON Schema object describing the args the tool accepts.
  d.exec(`
    CREATE TABLE IF NOT EXISTS tools (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL UNIQUE,
      description TEXT,
      handler_type TEXT NOT NULL DEFAULT 'motion-internal'
        CHECK(handler_type IN ('motion-internal','webhook','bridge-forward')),
      endpoint TEXT,
      input_schema TEXT NOT NULL DEFAULT '{}',
      enabled INTEGER NOT NULL DEFAULT 1,
      builtin INTEGER NOT NULL DEFAULT 0,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      updated_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_tools_enabled ON tools(enabled)') } catch { /* */ }

  // Per-tool invocation log — one row per tool call. Used by the UI to show
  // recent activity and debug failures. Bounded by a periodic prune (not yet
  // wired).
  d.exec(`
    CREATE TABLE IF NOT EXISTS tool_invocations (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      tool_id INTEGER NOT NULL REFERENCES tools(id) ON DELETE CASCADE,
      tool_name TEXT NOT NULL,
      caller TEXT,
      dispatch_id INTEGER,
      args_json TEXT,
      result_json TEXT,
      status TEXT NOT NULL CHECK(status IN ('ok','error')),
      error TEXT,
      duration_ms INTEGER,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s','now'))
    )
  `)
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_tool_invocations_tool ON tool_invocations(tool_id, created_at DESC)') } catch { /* */ }

  // Phase 3: bridge-forward tools route a tool call to a Mac-side shell command
  // via an enqueued dispatch. We track the forward dispatch id on the invocation
  // row so the UI can link "this call was forwarded to dispatch #42".
  try { d.exec('ALTER TABLE tool_invocations ADD COLUMN forward_dispatch_id INTEGER') } catch { /* already exists */ }

  // External schedules — live mirror of non-Motion recurring work, pushed by
  // the Mac bridge on boot and refreshed periodically. Hetzner crontab is
  // still read live via execSync (no push needed from the same host), but Mac
  // launchd plists live on the laptop and need a round-trip. Primary key is
  // (source, raw) so re-syncing is idempotent.
  d.exec(`
    CREATE TABLE IF NOT EXISTS external_schedules (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      source TEXT NOT NULL CHECK(source IN ('mac-launchd','hetzner-crontab')),
      label TEXT NOT NULL,
      schedule_hint TEXT,
      program TEXT,
      raw TEXT NOT NULL,
      location TEXT,
      last_seen_at INTEGER NOT NULL DEFAULT (strftime('%s','now')),
      UNIQUE(source, raw)
    )
  `)
  try { d.exec('CREATE INDEX IF NOT EXISTS idx_external_schedules_source ON external_schedules(source)') } catch { /* */ }

  // Doc sub-pages and type
  try { d.exec('ALTER TABLE docs ADD COLUMN parent_doc_id INTEGER REFERENCES docs(id) ON DELETE CASCADE') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE docs ADD COLUMN doc_type TEXT') } catch { /* already exists */ }

  // Doc color, icon, sharing, publishing
  try { d.exec('ALTER TABLE docs ADD COLUMN color TEXT') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE docs ADD COLUMN icon TEXT') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE docs ADD COLUMN published INTEGER DEFAULT 0') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE docs ADD COLUMN publish_slug TEXT') } catch { /* already exists */ }
  try { d.exec('CREATE UNIQUE INDEX IF NOT EXISTS idx_docs_publish_slug ON docs(publish_slug)') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE docs ADD COLUMN share_mode TEXT DEFAULT \'private\'') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE docs ADD COLUMN sort_order INTEGER DEFAULT 0') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE docs ADD COLUMN business_id INTEGER') } catch { /* already exists */ }
  try { d.exec('ALTER TABLE docs ADD COLUMN client_id INTEGER') } catch { /* already exists */ }

  // Workspace: is_private flag, description
  try { d.exec('ALTER TABLE workspaces ADD COLUMN is_private INTEGER DEFAULT 0') } catch { /* already exists */ }
