  // ─── Messaging: FTS5 Full-Text Search ───
  try {
    d.exec(`
      CREATE VIRTUAL TABLE IF NOT EXISTS msg_messages_fts USING fts5(
        content,
        content=msg_messages,
        content_rowid=id
      )
    `)
    // Triggers to keep FTS in sync
    d.exec(`
      CREATE TRIGGER IF NOT EXISTS msg_fts_insert AFTER INSERT ON msg_messages BEGIN
        INSERT INTO msg_messages_fts(rowid, content) VALUES (new.id, new.content);
      END
    `)
    d.exec(`
      CREATE TRIGGER IF NOT EXISTS msg_fts_update AFTER UPDATE OF content ON msg_messages BEGIN
        INSERT INTO msg_messages_fts(msg_messages_fts, rowid, content) VALUES('delete', old.id, old.content);
        INSERT INTO msg_messages_fts(rowid, content) VALUES (new.id, new.content);
      END
    `)
    d.exec(`
      CREATE TRIGGER IF NOT EXISTS msg_fts_delete AFTER DELETE ON msg_messages BEGIN
        INSERT INTO msg_messages_fts(msg_messages_fts, rowid, content) VALUES('delete', old.id, old.content);
      END
    `)
    // Backfill FTS from existing messages (only if empty)
    const ftsCount = (d.prepare('SELECT COUNT(*) as c FROM msg_messages_fts').get() as { c: number }).c
    if (ftsCount === 0) {
      const msgCount = (d.prepare('SELECT COUNT(*) as c FROM msg_messages').get() as { c: number }).c
      if (msgCount > 0) {
        d.exec('INSERT INTO msg_messages_fts(rowid, content) SELECT id, content FROM msg_messages')
      }
    }
  } catch { /* FTS5 may not be available */ }

