  d.exec(`CREATE INDEX IF NOT EXISTS idx_crm_opp_activity_opportunity ON crm_opportunity_activity(opportunity_id, created_at DESC, id DESC)`)
  d.exec(`CREATE INDEX IF NOT EXISTS idx_crm_opp_activity_workspace ON crm_opportunity_activity(workspace_id, created_at DESC)`)

  // Saved filter views. Opportunity list has its own saved-view surface (name +
