const DEFAULT_STATUSES: { name: string; color: string }[] = [
  { name: 'Todo', color: '#4285f4' },
  { name: 'In Progress', color: '#ffa726' },
  { name: 'Done', color: '#7a6b55' },
  { name: 'Blocked', color: '#ef5350' },
]

export function seedDefaultStatuses(workspaceId: number): void {
  const existing = getDb().prepare('SELECT COUNT(*) as cnt FROM workspace_statuses WHERE workspace_id = ?').get(workspaceId) as { cnt: number }
  if (existing.cnt > 0) return
  const stmt = getDb().prepare('INSERT INTO workspace_statuses (workspace_id, name, color, sort_order) VALUES (?, ?, ?, ?)')
  DEFAULT_STATUSES.forEach((s, i) => stmt.run(workspaceId, s.name, s.color, i))
}

