export function getProjects(workspaceId: number, folderId?: number, includeArchived?: boolean): Project[] {
  const archiveFilter = includeArchived ? '' : ' AND (archived = 0 OR archived IS NULL)'
  const deletedFilter = ' AND deleted_at IS NULL'
  if (folderId !== undefined) {
    return getDb().prepare(`SELECT * FROM projects WHERE workspace_id = ? AND folder_id = ?${archiveFilter}${deletedFilter} ORDER BY sort_order, name`).all(workspaceId, folderId) as Project[]
  }
  return getDb().prepare(`SELECT * FROM projects WHERE workspace_id = ?${archiveFilter}${deletedFilter} ORDER BY sort_order, name`).all(workspaceId) as Project[]
}

