/**
 * Returns the workspace's "Outreach" project, creating it lazily if missing.
 * Used by CRM task creation paths to surface person-linked tasks in the same
 * projects/tasks view the rest of the app uses, rather than leaving them
 * floating with no project. Match is case-insensitive so a user-renamed
 * project (e.g. "outreach") is still found.
 */
export function ensureOutreachProject(workspaceId: number): Project {
  const existing = getDb().prepare(
    `SELECT * FROM projects
     WHERE workspace_id = ?
       AND LOWER(name) = 'outreach'
       AND (archived = 0 OR archived IS NULL)
       AND deleted_at IS NULL
     ORDER BY id ASC LIMIT 1`
  ).get(workspaceId) as Project | undefined
  if (existing) return existing
  return createProject(workspaceId, 'Outreach', undefined, '#D97757')
}

