export function getTasks(opts?: { projectId?: number; stageId?: number; workspaceId?: number; status?: string }): Task[] {
  const clauses: string[] = []
  const vals: unknown[] = []
  if (opts?.projectId) { clauses.push('project_id = ?'); vals.push(opts.projectId) }
  if (opts?.stageId) { clauses.push('stage_id = ?'); vals.push(opts.stageId) }
  if (opts?.workspaceId) { clauses.push('workspace_id = ?'); vals.push(opts.workspaceId) }
  if (opts?.status) { clauses.push('status = ?'); vals.push(opts.status) }
  clauses.push('deleted_at IS NULL')
  const where = `WHERE ${clauses.join(' AND ')}`
  return getDb().prepare(`SELECT * FROM tasks ${where} ORDER BY sort_order, created_at DESC`).all(...vals) as Task[]
}

