export function createTask(data: { title: string; projectId?: number; stageId?: number; workspaceId?: number; folderId?: number; assignee?: string; priority?: string; status?: string; due_date?: string; description?: string; duration_minutes?: number; parentTaskId?: number; effort_level?: string; businessId?: number; crmContactId?: number | null }): Task {
  const now = Math.floor(Date.now() / 1000)
  const result = getDb().prepare(
    'INSERT INTO tasks (title, project_id, stage_id, workspace_id, folder_id, assignee, priority, status, due_date, description, duration_minutes, parent_task_id, effort_level, business_id, crm_contact_id, public_id, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
  ).run(
    data.title,
    data.projectId || null,
    data.stageId || null,
    data.workspaceId || null,
    data.folderId || null,
    data.assignee || null,
    data.priority || DEFAULT_TASK_VALUES.priority,
    data.status || DEFAULT_TASK_VALUES.status,
    data.due_date || null,
    data.description || null,
    data.duration_minutes || DEFAULT_TASK_VALUES.duration_minutes,
    data.parentTaskId || null,
    data.effort_level || null,
    data.businessId || null,
    data.crmContactId || null,
    generatePublicId(),
    now, now
  )
  const newTask = getDb().prepare('SELECT * FROM tasks WHERE id = ?').get(result.lastInsertRowid) as Task
  import('./vault').then(({ syncTask }) => syncTask(newTask)).catch(() => {})
  return newTask
}

/** Tasks linked to a contact — surfaced on the contact detail page. */
export function getTasksForContact(contactId: number, workspaceId: number): Task[] {
  return getDb().prepare(
    `SELECT * FROM tasks
     WHERE crm_contact_id = ? AND (workspace_id = ? OR workspace_id IS NULL)
       AND (deleted_at IS NULL)
     ORDER BY
       CASE status WHEN 'done' THEN 1 WHEN 'cancelled' THEN 1 WHEN 'archived' THEN 1 ELSE 0 END,
       COALESCE(due_date, '9999-12-31') ASC,
       id DESC`
  ).all(contactId, workspaceId) as Task[]
}

/**
 * Transitions a task's status. When a task flips to 'done' the first time, fire
 * the task_completed workflow trigger bound to the CRM contact the task is
 * attached to. Also toggles completed_at for reporting.
 */
export function setTaskStatus(taskId: number, status: Task['status'], workspaceId: number): Task | null {
  const existing = getDb().prepare('SELECT * FROM tasks WHERE id = ?').get(taskId) as Task | undefined
  if (!existing) return null
  if (existing.workspace_id !== null && existing.workspace_id !== workspaceId) return null
  const now = Math.floor(Date.now() / 1000)
  const completedAt = status === 'done'
    ? (existing.completed_at ?? now)
    : (status === 'backlog' || status === 'todo' || status === 'in_progress' ? null : existing.completed_at)
  getDb().prepare('UPDATE tasks SET status = ?, completed_at = ?, updated_at = ? WHERE id = ?')
    .run(status, completedAt, now, taskId)
  const wasIncomplete = existing.status !== 'done' && existing.status !== 'cancelled' && existing.status !== 'archived'
  const isDone = status === 'done'
  if (wasIncomplete && isDone && existing.crm_contact_id) {
    try {
      queueCrmWorkflowRunsForTrigger({
        workspaceId,
        contactId: existing.crm_contact_id,
        triggerType: 'task_completed',
        triggerValue: existing.task_type || '',
      })
      createCrmContactActivity({
        contactId: existing.crm_contact_id,
        workspaceId,
        type: 'task',
        body: `Task completed: ${existing.title}`,
      })
    } catch { /* keep status update resilient even if trigger queue fails */ }
  }
  return getDb().prepare('SELECT * FROM tasks WHERE id = ?').get(taskId) as Task
}

function clearTaskSchedulingMetadata(taskId: number): void {
  const d = getDb()
  d.prepare('UPDATE tasks SET scheduled_start = NULL, scheduled_end = NULL, schedule_id = NULL, overdue_from = NULL WHERE id = ?').run(taskId)
  d.prepare('DELETE FROM task_chunks WHERE task_id = ?').run(taskId)
}

export function clearStaleTaskSchedulingMetadata(): number {
  const d = getDb()
  const STALE_SCHEDULE_GRACE_SECONDS = 5 * 60

  // Clear scheduling data for deleted/terminal tasks, but never touch task-level locked rows.
  const staleTaskIds = d.prepare(
    `SELECT id FROM tasks
     WHERE (
            deleted_at IS NOT NULL
         OR status IN ('done', 'cancelled', 'archived')
           )
       AND locked_at IS NULL
       AND (
            scheduled_start IS NOT NULL
         OR scheduled_end IS NOT NULL
         OR schedule_id IS NOT NULL
         OR overdue_from IS NOT NULL
         OR EXISTS (SELECT 1 FROM task_chunks tc WHERE tc.task_id = tasks.id)
           )`
  ).all() as { id: number }[]

  // Clear stale locked chunks on auto_schedule tasks that have no task-level lock.
  // These are chunks from old drag operations that weren't cleared properly.
  d.prepare(
    `DELETE FROM task_chunks
     WHERE locked = 1
       AND task_id IN (
         SELECT id FROM tasks
         WHERE auto_schedule = 1
           AND locked_at IS NULL
           AND deleted_at IS NULL
           AND status NOT IN ('done', 'cancelled', 'archived')
       )`
  ).run()

  // Clear only clearly stale ghost slots. Manual future placements should survive.
  // We only wipe unlocked, unchunked, unassigned non-auto tasks whose saved slot is already past.
  const ghostTaskRows = d.prepare(
    `SELECT t.id, t.title, t.scheduled_start FROM tasks t
     WHERE t.auto_schedule = 0
       AND t.locked_at IS NULL
       AND t.deleted_at IS NULL
       AND t.status NOT IN ('done', 'cancelled', 'archived')
       AND COALESCE(t.assignee, '') = ''
       AND (t.scheduled_start IS NOT NULL OR t.scheduled_end IS NOT NULL)
       AND NOT EXISTS (
         SELECT 1 FROM task_chunks tc WHERE tc.task_id = t.id
       )
       AND (
         COALESCE(strftime('%s', t.scheduled_end), strftime('%s', t.scheduled_start)) IS NOT NULL
         AND COALESCE(strftime('%s', t.scheduled_end), strftime('%s', t.scheduled_start)) <= (strftime('%s', 'now') - ?)
       )
       AND t.updated_at <= (strftime('%s', 'now') - ?)`
  ).all(STALE_SCHEDULE_GRACE_SECONDS, STALE_SCHEDULE_GRACE_SECONDS) as { id: number; title: string; scheduled_start: string }[]

  if (ghostTaskRows.length > 0) {
    console.log(`[Scheduler] Ghost slot cleanup — ${ghostTaskRows.length} task(s) have auto_schedule=0 + no locked_at + scheduled position. Clearing:`)
    for (const g of ghostTaskRows) {
      console.log(`  → id=${g.id} "${g.title}" was at ${g.scheduled_start}`)
    }
  }

  const ghostTaskIds = ghostTaskRows.map(r => ({ id: r.id }))
  const allIds = Array.from(new Set([...staleTaskIds, ...ghostTaskIds].map(task => task.id)))
  if (allIds.length === 0) return 0

  // Batch clear in chunks of 500 to stay within SQLite variable limits
  for (let i = 0; i < allIds.length; i += 500) {
    const batch = allIds.slice(i, i + 500)
    const placeholders = batch.map(() => '?').join(',')
    d.prepare(
      `UPDATE tasks SET scheduled_start = NULL, scheduled_end = NULL, schedule_id = NULL, overdue_from = NULL WHERE id IN (${placeholders})`
    ).run(...batch)
    d.prepare(
      `DELETE FROM task_chunks WHERE task_id IN (${placeholders})`
    ).run(...batch)
  }

  // Fix stale overdue_from: if a task is scheduled in the future, overdue_from must not be
  // earlier than scheduled_start (would cause permanent OVERDUE badge on future tasks)
  const staleOverdueFixed = d.prepare(
    `UPDATE tasks
     SET overdue_from = scheduled_start
     WHERE auto_schedule = 1
       AND deleted_at IS NULL
       AND status NOT IN ('done', 'cancelled', 'archived')
       AND scheduled_start IS NOT NULL
       AND scheduled_start > strftime('%Y-%m-%dT%H:%M:%fZ', 'now')
       AND overdue_from IS NOT NULL
       AND overdue_from < scheduled_start`
  ).run()
  if (staleOverdueFixed.changes > 0) {
    console.log(`[Scheduler] Fixed ${staleOverdueFixed.changes} stale overdue_from values on future-scheduled tasks`)
  }

  return allIds.length
}

export function updateTask(id: number, data: Record<string, unknown>): Task | null {
  const existingTask = getTask(id)
  const { sets, vals } = safeBuildSets(data, ALLOWED_TASK_COLUMNS)
  if (sets.length === 0) return getTask(id)
  sets.push("updated_at = strftime('%s','now')")
  vals.push(id)
  getDb().prepare(`UPDATE tasks SET ${sets.join(', ')} WHERE id = ?`).run(...vals)

  const status = data.status
  // Clear scheduling metadata when completing/archiving, OR when turning off auto_schedule
  // WITHOUT simultaneously setting a new explicit position (drag-to-pin sets both together).
  const turningOffAutoSchedule = data.auto_schedule === 0 && existingTask?.auto_schedule === 1
  const settingExplicitPosition = data.scheduled_start != null || data.scheduled_end != null
  const shouldClearScheduling = status === 'done' || status === 'cancelled' || status === 'archived'
    || (turningOffAutoSchedule && !settingExplicitPosition)
  if (shouldClearScheduling) {
    clearTaskSchedulingMetadata(id)
  }

  // Auto-create next recurring instance when task is completed
  if (status === 'done') {
    const updated = getTask(id)
    if (updated?.recurrence_rule) {
      try {
        const { createNextRecurrenceInstance } = require('./recurrence')
        createNextRecurrenceInstance(updated)
      } catch {
        // recurrence module not available, skip
      }
    }
  }

  // Fire webhook on terminal status changes
  if (status === 'done' || status === 'cancelled') {
    import('./webhook').then(({ fireWebhook }) => {
      fireWebhook('task.' + status, { taskId: id, ...data }).catch(() => {})
    }).catch(() => {})
  }

  // Fire task_completed CRM workflow trigger on transition into 'done'
  // for CRM-linked tasks. Mirrors setTaskStatus so workflows fire no matter
  // which path completed the task.
  const wasIncomplete = existingTask
    && existingTask.status !== 'done'
    && existingTask.status !== 'cancelled'
    && existingTask.status !== 'archived'
  if (status === 'done' && wasIncomplete && existingTask?.crm_contact_id && existingTask?.workspace_id) {
    try {
      queueCrmWorkflowRunsForTrigger({
        workspaceId: existingTask.workspace_id,
        contactId: existingTask.crm_contact_id,
        triggerType: 'task_completed',
        triggerValue: existingTask.task_type || '',
      })
      createCrmContactActivity({
        contactId: existingTask.crm_contact_id,
        workspaceId: existingTask.workspace_id,
        type: 'task',
        body: `Task completed: ${existingTask.title}`,
      })
    } catch { /* keep status update resilient even if trigger queue fails */ }
  }

  const updatedTask = getTask(id)
  if (updatedTask) import('./vault').then(({ syncTask }) => syncTask(updatedTask)).catch(() => {})
  return updatedTask
}

export function syncDependencies(taskId: number, oldBlockedBy: number[], newBlockedBy: number[]): void {
  const removed = oldBlockedBy.filter(id => !newBlockedBy.includes(id))
  const added = newBlockedBy.filter(id => !oldBlockedBy.includes(id))
  const d = getDb()

  // For removed blockers: remove taskId from their blocking field
  for (const blockerId of removed) {
    const blocker = d.prepare('SELECT blocking FROM tasks WHERE id = ?').get(blockerId) as any
    if (blocker) {
      const currentBlocking = blocker.blocking ? blocker.blocking.split(',').map(Number).filter(Boolean) : []
      const updated = currentBlocking.filter((id: number) => id !== taskId)
      d.prepare('UPDATE tasks SET blocking = ? WHERE id = ?').run(
        updated.length > 0 ? updated.join(',') : null,
        blockerId
      )
    }
  }

  // For added blockers: add taskId to their blocking field
  for (const blockerId of added) {
    const blocker = d.prepare('SELECT blocking FROM tasks WHERE id = ?').get(blockerId) as any
    if (blocker) {
      const currentBlocking = blocker.blocking ? blocker.blocking.split(',').map(Number).filter(Boolean) : []
      if (!currentBlocking.includes(taskId)) {
        currentBlocking.push(taskId)
      }
      d.prepare('UPDATE tasks SET blocking = ? WHERE id = ?').run(
        currentBlocking.join(','),
        blockerId
      )
    }
  }
}

/** Remove a task ID from comma-separated blocked_by/blocking fields without corrupting other IDs */
function removeDependencyReferences(d: Database.Database, taskId: number): void {
  const idStr = String(taskId)
  for (const field of ['blocked_by', 'blocking'] as const) {
    const rows = d.prepare(
      `SELECT id, ${field} FROM tasks WHERE ${field} IS NOT NULL AND ${field} != ''`
    ).all() as { id: number; [key: string]: unknown }[]
    const update = d.prepare(`UPDATE tasks SET ${field} = ? WHERE id = ?`)
    for (const row of rows) {
      const val = String(row[field])
      const ids = val.split(',').map(s => s.trim()).filter(s => s !== '' && s !== idStr)
      update.run(ids.length > 0 ? ids.join(',') : null, row.id)
    }
  }
}

export function deleteTask(id: number): void {
  const d = getDb()
  const now = new Date().toISOString()
  // Soft-delete: mark as deleted instead of removing
  // Recursively soft-delete subtasks
  const subtaskIds = d.prepare('SELECT id FROM tasks WHERE parent_task_id = ? AND deleted_at IS NULL').all(id) as { id: number }[]
  for (const sub of subtaskIds) {
    deleteTask(sub.id)
  }
  // Clean up dependency references in other tasks
  removeDependencyReferences(d, id)
  d.prepare('UPDATE tasks SET deleted_at = ?, scheduled_start = NULL, scheduled_end = NULL, schedule_id = NULL, overdue_from = NULL WHERE id = ?').run(now, id)
  d.prepare('DELETE FROM task_chunks WHERE task_id = ?').run(id)
}

export function hardDeleteTask(id: number): void {
  import('./vault').then(({ removeVaultFile }) => removeVaultFile('task', id)).catch(() => {})
  const d = getDb()
  const subtaskIds = d.prepare('SELECT id FROM tasks WHERE parent_task_id = ?').all(id) as { id: number }[]
  for (const sub of subtaskIds) { hardDeleteTask(sub.id) }
  d.prepare('DELETE FROM task_chunks WHERE task_id = ?').run(id)
  d.prepare('DELETE FROM task_activities WHERE task_id = ?').run(id)
  d.prepare('DELETE FROM status_updates WHERE task_id = ?').run(id)
  d.prepare('DELETE FROM attachments WHERE task_id = ?').run(id)
  removeDependencyReferences(d, id)
  d.prepare('DELETE FROM tasks WHERE id = ?').run(id)
}

export function restoreTask(id: number): void {
  const d = getDb()
  d.prepare('UPDATE tasks SET deleted_at = NULL WHERE id = ?').run(id)
  // Restore subtasks too
  d.prepare('UPDATE tasks SET deleted_at = NULL WHERE parent_task_id = ? AND deleted_at IS NOT NULL').run(id)
}

export function purgeOldDeleted(): void {
  const d = getDb()
  const cutoff = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString()
  // Permanently delete items trashed more than 30 days ago
  const oldTasks = d.prepare('SELECT id FROM tasks WHERE deleted_at IS NOT NULL AND deleted_at < ?').all(cutoff) as { id: number }[]
  for (const t of oldTasks) { hardDeleteTask(t.id) }
  const oldProjects = d.prepare('SELECT id FROM projects WHERE deleted_at IS NOT NULL AND deleted_at < ?').all(cutoff) as { id: number }[]
  for (const p of oldProjects) { hardDeleteProject(p.id) }
  const oldStages = d.prepare('SELECT id FROM stages WHERE deleted_at IS NOT NULL AND deleted_at < ?').all(cutoff) as { id: number }[]
  for (const s of oldStages) { hardDeleteStage(s.id) }
}

export function purgeAllTaskData(): void {
  const d = getDb()
  d.prepare('DELETE FROM task_activities').run()
  d.prepare('DELETE FROM task_chunks').run()
  d.prepare('DELETE FROM tasks').run()
}

// ─── Docs ───

export function getDocs(opts?: { workspaceId?: number; folderId?: number; projectId?: number; search?: string; limit?: number }): Doc[] {
  const clauses: string[] = []
  const vals: unknown[] = []
  if (opts?.workspaceId) { clauses.push('workspace_id = ?'); vals.push(opts.workspaceId) }
  if (opts?.folderId) { clauses.push('folder_id = ?'); vals.push(opts.folderId) }
  if (opts?.projectId) { clauses.push('project_id = ?'); vals.push(opts.projectId) }
  if (opts?.search) { clauses.push('title LIKE ?'); vals.push(`%${opts.search}%`) }
  const where = clauses.length > 0 ? `WHERE ${clauses.join(' AND ')}` : ''
  if (opts?.limit) {
    vals.push(opts.limit)
    return getDb().prepare(`SELECT * FROM docs ${where} ORDER BY updated_at DESC LIMIT ?`).all(...vals) as Doc[]
  }
  return getDb().prepare(`SELECT * FROM docs ${where} ORDER BY updated_at DESC`).all(...vals) as Doc[]
}

export function getDoc(id: number): Doc | null {
  return getDb().prepare('SELECT * FROM docs WHERE id = ?').get(id) as Doc | null
}

export function getDocByPublicId(publicId: string): Doc | null {
  return getDb().prepare('SELECT * FROM docs WHERE public_id = ?').get(publicId) as Doc | null
}

export function getDocBreadcrumb(docId: number): { label: string; type: string; id?: number }[] {
  const d = getDb()
  const doc = d.prepare('SELECT * FROM docs WHERE id = ?').get(docId) as Doc | null
  if (!doc) return []

  const crumbs: { label: string; type: string; id?: number }[] = []

  // Walk up folder hierarchy
  if (doc.folder_id) {
    const folderChain: Folder[] = []
    let folderId: number | null = doc.folder_id
    while (folderId) {
      const folder = d.prepare('SELECT * FROM folders WHERE id = ?').get(folderId) as Folder | null
      if (!folder) break
      folderChain.unshift(folder)
      folderId = folder.parent_id
    }

    // Get workspace from the top folder
    if (folderChain.length > 0) {
      const ws = d.prepare('SELECT * FROM workspaces WHERE id = ?').get(folderChain[0].workspace_id) as Workspace | null
      if (ws) crumbs.push({ label: ws.name, type: 'workspace', id: ws.id })
    }

    for (const f of folderChain) {
      crumbs.push({ label: f.name, type: 'folder', id: f.id })
    }
  } else if (doc.workspace_id) {
    const ws = d.prepare('SELECT * FROM workspaces WHERE id = ?').get(doc.workspace_id) as Workspace | null
    if (ws) crumbs.push({ label: ws.name, type: 'workspace', id: ws.id })
  }

  crumbs.push({ label: doc.title, type: 'doc', id: doc.id })
  return crumbs
}

export function createDoc(data: { title?: string; workspaceId?: number; folderId?: number; projectId?: number; parentDocId?: number; docType?: string; businessId?: number; clientId?: number }): Doc {
  const result = getDb().prepare(
    'INSERT INTO docs (title, workspace_id, folder_id, project_id, parent_doc_id, doc_type, public_id, business_id, client_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)'
  ).run(data.title || 'Untitled Doc', data.workspaceId || null, data.folderId || null, data.projectId || null, data.parentDocId || null, data.docType || null, generatePublicId(), data.businessId || null, data.clientId || null)
  const newDoc = getDb().prepare('SELECT * FROM docs WHERE id = ?').get(result.lastInsertRowid) as Doc
  import('./vault').then(({ syncDoc }) => syncDoc(newDoc)).catch(() => {})
  return newDoc
}

export function updateDoc(id: number, data: { title?: string; content?: string; folder_id?: number | null; project_id?: number | null; parent_doc_id?: number | null; doc_type?: string | null; color?: string | null; icon?: string | null; share_mode?: string; sort_order?: number; workspace_id?: number | null; business_id?: number | null; client_id?: number | null }, source?: string): Doc | null {
  // Save version snapshot before updating content
  if (data.content !== undefined) {
    const current = getDoc(id)
    if (current && current.content) {
      getDb().prepare(
        'INSERT INTO doc_versions (doc_id, title, content, source) VALUES (?, ?, ?, ?)'
      ).run(id, current.title, current.content, source || 'user')
    }
  }
  const sets: string[] = []
  const vals: unknown[] = []
  if (data.title !== undefined) { sets.push('title = ?'); vals.push(data.title) }
  if (data.content !== undefined) { sets.push('content = ?'); vals.push(data.content) }
  if (data.folder_id !== undefined) { sets.push('folder_id = ?'); vals.push(data.folder_id) }
  if (data.project_id !== undefined) { sets.push('project_id = ?'); vals.push(data.project_id) }
  if (data.parent_doc_id !== undefined) { sets.push('parent_doc_id = ?'); vals.push(data.parent_doc_id) }
  if (data.doc_type !== undefined) { sets.push('doc_type = ?'); vals.push(data.doc_type) }
  if (data.color !== undefined) { sets.push('color = ?'); vals.push(data.color) }
  if (data.icon !== undefined) { sets.push('icon = ?'); vals.push(data.icon) }
  if (data.share_mode !== undefined) { sets.push('share_mode = ?'); vals.push(data.share_mode) }
  if (data.sort_order !== undefined) { sets.push('sort_order = ?'); vals.push(data.sort_order) }
  if (data.workspace_id !== undefined) { sets.push('workspace_id = ?'); vals.push(data.workspace_id) }
  if (data.business_id !== undefined) { sets.push('business_id = ?'); vals.push(data.business_id) }
  if (data.client_id !== undefined) { sets.push('client_id = ?'); vals.push(data.client_id) }
  if (sets.length === 0) return getDoc(id)
  sets.push("updated_at = strftime('%s','now')")
  vals.push(id)
  getDb().prepare(`UPDATE docs SET ${sets.join(', ')} WHERE id = ?`).run(...vals)
  const updatedDoc = getDoc(id)
  if (updatedDoc) import('./vault').then(({ syncDoc }) => syncDoc(updatedDoc)).catch(() => {})
  return updatedDoc
}

