const MEDIA_HANDLING_SECTION = `

## Media & File Handling
- Images: sent as base64 to your vision - you can see and analyze them
- Voice messages: automatically transcribed as [Voice message transcription] - treat as normal text
- Videos: you get a thumbnail frame (visual) + audio transcription - you can see and hear them
- PDFs and text files: contents are extracted and included inline - you can read them fully
- Links/URLs: use your fetch_webpage tool to read any URL. Use read_doc tool for internal docs (by ID)
- Web search: use web_search tool, then fetch_webpage to read full pages`

export function createAgent(data: { id: string; name: string; role?: string; system_prompt?: string; soul_md?: string; memory_md?: string; avatar_color?: string; can_delegate_to?: string; model_preference?: string; allowed_tools?: string; max_turns?: number; learnings_md?: string; task_types?: string; schedule_id?: number; max_daily_minutes?: number }): Agent {
  // Auto-append media handling to all new agents
  let soulMd = data.soul_md || null
  if (soulMd && !soulMd.includes('## Media Handling')) {
    soulMd = soulMd.trimEnd() + MEDIA_HANDLING_SECTION
  } else if (!soulMd) {
    soulMd = `# ${data.name}\n\nYou are ${data.name}, an AI agent at CTRL.${MEDIA_HANDLING_SECTION}`
  }
  getDb().prepare(
    'INSERT INTO agents (id, name, role, system_prompt, soul_md, memory_md, avatar_color, can_delegate_to, model_preference, allowed_tools, max_turns, learnings_md, task_types, schedule_id, max_daily_minutes) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
  ).run(data.id, data.name, data.role || '', data.system_prompt || null, soulMd, data.memory_md || null, data.avatar_color || null, data.can_delegate_to || null, data.model_preference || 'auto', data.allowed_tools || '["*"]', data.max_turns || 50, data.learnings_md || null, data.task_types || null, data.schedule_id || null, data.max_daily_minutes || 480)
  return getDb().prepare('SELECT * FROM agents WHERE id = ?').get(data.id) as Agent
}

