// ─── Per-user notification center ───

export type UserNotificationKind =
  | 'new_lead'
  | 'inbound_reply'
  | 'mention'
  | 'assignment'
  | 'appointment_booked'
  | 'appointment_cancelled'
  | 'appointment_rescheduled'
  | 'appointment_conflict'
  | 'ai_handoff'
  | 'task_assigned'
  | 'review_received'
  | 'opportunity_won'
  | 'opportunity_lost'
  | 'opportunity_abandoned'
  | 'affiliate_conversion'

export const USER_NOTIFICATION_KINDS: UserNotificationKind[] = [
  'new_lead',
  'inbound_reply',
  'mention',
  'assignment',
  'appointment_booked',
  'appointment_cancelled',
  'appointment_rescheduled',
  'appointment_conflict',
  'ai_handoff',
  'task_assigned',
  'review_received',
  'opportunity_won',
  'opportunity_lost',
  'opportunity_abandoned',
  'affiliate_conversion',
]

export interface UserNotification {
  id: number
  user_id: number
  workspace_id: number
  kind: UserNotificationKind
  title: string
  body: string | null
  href: string | null
  entity: string | null
  entity_id: number | null
  is_read: number
  read_at: string | null
  created_at: string
}

export interface UserNotificationPrefRow {
  in_app: number
  email: number
  push: number
}

// Per-kind default when a user has no row yet: in-app on, email/push off.
// Keep in sync with the table DEFAULTs.
const DEFAULT_PREF: UserNotificationPrefRow = { in_app: 1, email: 0, push: 0 }

export function createUserNotification(opts: {
  user_id: number
  workspace_id: number
  kind: UserNotificationKind
  title: string
  body?: string | null
  href?: string | null
  entity?: string | null
  entity_id?: number | null
}): UserNotification {
  const nowIso = new Date().toISOString()
  const result = getDb().prepare(`
    INSERT INTO user_notifications
      (user_id, workspace_id, kind, title, body, href, entity, entity_id, created_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    opts.user_id,
    opts.workspace_id,
    opts.kind,
    opts.title,
    opts.body ?? null,
    opts.href ?? null,
    opts.entity ?? null,
    opts.entity_id ?? null,
    nowIso,
  )
  return getDb()
    .prepare('SELECT * FROM user_notifications WHERE id = ?')
    .get(Number(result.lastInsertRowid)) as UserNotification
}

export function listUserNotifications(
  userId: number,
  opts: { limit?: number; onlyUnread?: boolean } = {},
): UserNotification[] {
  const limit = Math.min(Math.max(opts.limit ?? 50, 1), 200)
  if (opts.onlyUnread) {
    return getDb().prepare(
      `SELECT * FROM user_notifications
       WHERE user_id = ? AND is_read = 0
       ORDER BY created_at DESC, id DESC
       LIMIT ?`
    ).all(userId, limit) as UserNotification[]
  }
  return getDb().prepare(
    `SELECT * FROM user_notifications
     WHERE user_id = ?
     ORDER BY created_at DESC, id DESC
     LIMIT ?`
  ).all(userId, limit) as UserNotification[]
}

/**
 * Mark some (by ids) or all of a user's unread notifications as read.
 * Passing null / undefined / empty for ids marks EVERY unread row for this user.
 */
export function markNotificationsRead(userId: number, ids?: number[] | null): number {
  const nowIso = new Date().toISOString()
  if (!ids || ids.length === 0) {
    const info = getDb().prepare(
      `UPDATE user_notifications
         SET is_read = 1, read_at = ?
       WHERE user_id = ? AND is_read = 0`
    ).run(nowIso, userId)
    return info.changes
  }
  const clean = ids.filter((n) => Number.isInteger(n) && n > 0)
  if (clean.length === 0) return 0
  const placeholders = clean.map(() => '?').join(',')
  const info = getDb().prepare(
    `UPDATE user_notifications
       SET is_read = 1, read_at = ?
     WHERE user_id = ? AND id IN (${placeholders}) AND is_read = 0`
  ).run(nowIso, userId, ...clean)
  return info.changes
}

export function getUnreadNotificationCount(userId: number): number {
  const row = getDb().prepare(
    'SELECT COUNT(*) AS count FROM user_notifications WHERE user_id = ? AND is_read = 0'
  ).get(userId) as { count: number } | undefined
  return row?.count ?? 0
}

/**
 * Returns a map of { [kind]: { in_app, email, push } } covering every
 * known kind, filling unseeded kinds with the defaults.
 */
export function getUserNotificationPrefs(
  userId: number,
): Record<UserNotificationKind, UserNotificationPrefRow> {
  const rows = getDb().prepare(
    'SELECT kind, in_app, email, push FROM user_notification_prefs WHERE user_id = ?'
  ).all(userId) as Array<{ kind: string; in_app: number; email: number; push: number }>
  const map = new Map(rows.map((r) => [r.kind, { in_app: r.in_app, email: r.email, push: r.push }]))
  const out = {} as Record<UserNotificationKind, UserNotificationPrefRow>
  for (const kind of USER_NOTIFICATION_KINDS) {
    out[kind] = map.get(kind) ?? { ...DEFAULT_PREF }
  }
  return out
}

export function updateUserNotificationPref(
  userId: number,
  kind: UserNotificationKind,
  patch: Partial<{ in_app: boolean | number; email: boolean | number; push: boolean | number }>,
): UserNotificationPrefRow {
  const existing = getDb().prepare(
    'SELECT in_app, email, push FROM user_notification_prefs WHERE user_id = ? AND kind = ?'
  ).get(userId, kind) as UserNotificationPrefRow | undefined
  const base: UserNotificationPrefRow = existing ?? { ...DEFAULT_PREF }
  const toInt = (v: unknown, fallback: number): number => {
    if (v === undefined) return fallback
    return v ? 1 : 0
  }
  const next: UserNotificationPrefRow = {
    in_app: toInt(patch.in_app, base.in_app),
    email: toInt(patch.email, base.email),
    push: toInt(patch.push, base.push),
  }
  if (existing) {
    getDb().prepare(
      `UPDATE user_notification_prefs SET in_app = ?, email = ?, push = ?
       WHERE user_id = ? AND kind = ?`
    ).run(next.in_app, next.email, next.push, userId, kind)
  } else {
    getDb().prepare(
      `INSERT INTO user_notification_prefs (user_id, kind, in_app, email, push)
       VALUES (?, ?, ?, ?, ?)`
    ).run(userId, kind, next.in_app, next.email, next.push)
  }
  return next
}

