// ─── Sidebar Tree ───

export function buildSidebarTree(workspaceId: number): TreeNode[] {
  const workspace = getWorkspaceById(workspaceId)
  if (!workspace) return []

  // Only exclude folders that belong to client_profiles (individual people) from sidebar
  // Business folders (Animo, Client A brand, etc.) should show in the sidebar
  const clientProfileFolderIds = new Set(
    (getDb().prepare('SELECT folder_id FROM client_profiles WHERE folder_id IS NOT NULL').all() as { folder_id: number }[]).map(r => r.folder_id)
  )
  const allFolders = getFolders(workspaceId).filter(f => !clientProfileFolderIds.has(f.id))
  const allProjects = getProjects(workspaceId)
  const allDocs = getDocs({ workspaceId })
  const allSheets = getDb().prepare('SELECT * FROM sheets WHERE workspace_id = ? ORDER BY sort_order, updated_at DESC').all(workspaceId) as { id: number; public_id: string; name: string; workspace_id: number; folder_id: number | null; color: string | null; sort_order: number; created_at: number; updated_at: number }[]

  function buildSheetNode(s: { id: number; public_id: string; name: string; folder_id: number | null; color: string | null; sort_order: number; created_at: number; updated_at: number }, parentColor?: string): TreeNode {
    return {
      id: `database-${s.id}`,
      public_id: s.public_id,
      type: 'database' as const,
      name: s.name,
      color: s.color || parentColor || '#6b7280',
      itemCount: 0,
      children: [],
      data: s as any,
    }
  }

  function buildProjectNode(p: Project): TreeNode {
    const taskCount = (getDb().prepare('SELECT COUNT(*) as c FROM tasks WHERE project_id = ?').get(p.id) as { c: number }).c
    const projDocs = allDocs.filter(d => d.project_id === p.id && !d.parent_doc_id)

    // Compute project health: green (on track), yellow (tasks at risk), red (tasks overdue)
    let health: 'green' | 'yellow' | 'red' | null = null
    if (taskCount > 0) {
      const now = Math.floor(Date.now() / 1000)
      const nowDate = new Date().toISOString().split('T')[0]
      const threeDaysFromNow = new Date(Date.now() + 3 * 86400000).toISOString().split('T')[0]
      const overdue = (getDb().prepare("SELECT COUNT(*) as c FROM tasks WHERE project_id = ? AND status NOT IN ('done','cancelled','archived') AND due_date IS NOT NULL AND due_date < ?").get(p.id, nowDate) as { c: number }).c
      const atRisk = (getDb().prepare("SELECT COUNT(*) as c FROM tasks WHERE project_id = ? AND status NOT IN ('done','cancelled','archived') AND due_date IS NOT NULL AND due_date >= ? AND due_date <= ?").get(p.id, nowDate, threeDaysFromNow) as { c: number }).c
      if (overdue > 0) health = 'red'
      else if (atRisk > 0) health = 'yellow'
      else health = 'green'
    }

    return {
      id: `project-${p.id}`,
      public_id: p.public_id,
      type: 'project' as const,
      name: p.name,
      color: p.color,
      itemCount: taskCount,
      children: projDocs.map(d => ({
        id: `doc-${d.id}`,
        public_id: d.public_id,
        type: 'doc' as const,
        name: d.title,
        color: d.color || p.color,
        itemCount: 0,
        children: [],
        data: d,
      })),
      data: { ...p, health } as any,
    }
  }

  function sortBySortOrder(nodes: TreeNode[]): TreeNode[] {
    return nodes.sort((a, b) => {
      const aOrder = (a.data as { sort_order?: number }).sort_order ?? 0
      const bOrder = (b.data as { sort_order?: number }).sort_order ?? 0
      if (aOrder !== bOrder) return aOrder - bOrder
      return a.name.localeCompare(b.name)
    })
  }

  function buildDocNode(d: Doc, parentColor?: string): TreeNode {
    const fallbackColor = parentColor || '#6b7280'
    const childDocs = allDocs.filter(cd => cd.parent_doc_id === d.id)
    return {
      id: `doc-${d.id}`,
      public_id: d.public_id,
      type: 'doc' as const,
      name: d.title,
      color: d.color || fallbackColor,
      itemCount: childDocs.length,
      children: childDocs.map(cd => ({
        id: `doc-${cd.id}`,
        public_id: cd.public_id,
        type: 'doc' as const,
        name: cd.title,
        color: cd.color || fallbackColor,
        itemCount: 0,
        children: [],
        data: cd,
      })),
      data: d,
    }
  }

  function buildFolderNode(folder: Folder): TreeNode {
    const children: TreeNode[] = []

    // Sub-folders
    const subFolders = allFolders.filter(f => f.parent_id === folder.id)
    for (const f of subFolders) children.push(buildFolderNode(f))

    // Projects in this folder
    const folderProjects = allProjects.filter(p => p.folder_id === folder.id)
    for (const p of folderProjects) children.push(buildProjectNode(p))

    // Docs directly in this folder (not in a project)
    const folderDocs = allDocs.filter(d => d.folder_id === folder.id && !d.project_id && !d.parent_doc_id)
    for (const d of folderDocs) children.push(buildDocNode(d, folder.color))

    // Sheets in this folder
    const folderSheets = allSheets.filter(s => s.folder_id === folder.id)
    for (const s of folderSheets) children.push(buildSheetNode(s, folder.color))

    return {
      id: `folder-${folder.id}`,
      public_id: folder.public_id,
      type: 'folder',
      name: folder.name,
      color: folder.color,
      itemCount: children.length,
      children: sortBySortOrder(children),
      data: folder,
    }
  }

  // Build top-level: all items without a parent folder, sorted together
  const tree: TreeNode[] = []

  const topFolders = allFolders.filter(f => !f.parent_id)
  for (const folder of topFolders) tree.push(buildFolderNode(folder))

  const orphanProjects = allProjects.filter(p => !p.folder_id)
  for (const p of orphanProjects) tree.push(buildProjectNode(p))

  const orphanDocs = allDocs.filter(d => !d.folder_id && !d.project_id && !d.parent_doc_id)
  for (const d of orphanDocs) tree.push(buildDocNode(d))

  const orphanSheets = allSheets.filter(s => !s.folder_id)
  for (const s of orphanSheets) tree.push(buildSheetNode(s))

  return sortBySortOrder(tree)
}

// ─── All Tasks (enriched) ───

export interface EnrichedTask extends Task {
  workspace_name: string | null
  project_name: string | null
  project_color: string | null
  project_start_date?: string | null
  project_due_date?: string | null
  stage_name: string | null
  stage_color: string | null
  folder_name: string | null
  contact_name: string | null
  contact_public_id: string | null
}

function getEnrichedTasks(whereClause: string, params: unknown[] = []): EnrichedTask[] {
  return getDb().prepare(`
    SELECT t.*,
      w.name as workspace_name,
      p.name as project_name, p.color as project_color,
      p.start_date as project_start_date, p.deadline as project_due_date,
      s.name as stage_name, s.color as stage_color,
      f.name as folder_name, f.color as folder_color,
      cc.name as contact_name, cc.public_id as contact_public_id
    FROM tasks t
    LEFT JOIN workspaces w ON t.workspace_id = w.id
    LEFT JOIN projects p ON t.project_id = p.id
    LEFT JOIN stages s ON t.stage_id = s.id
    LEFT JOIN folders f ON t.folder_id = f.id
    LEFT JOIN crm_contacts cc ON t.crm_contact_id = cc.id
    ${whereClause}
    ORDER BY t.sort_order, t.created_at DESC
  `).all(...params) as EnrichedTask[]
}

export function getAllTasksEnriched(workspaceId?: number | number[]): EnrichedTask[] {
  const scope = buildWorkspaceScopeClause('t.workspace_id', workspaceId)
  return getEnrichedTasks(
    `WHERE ${scope.clause} AND t.parent_task_id IS NULL AND t.deleted_at IS NULL`,
    scope.params,
  )
}

export function getProjectTasksEnriched(projectId: number): EnrichedTask[] {
  return getEnrichedTasks(
    'WHERE t.project_id = ? AND t.parent_task_id IS NULL AND t.deleted_at IS NULL',
    [projectId],
  )
}

export function getTasksForScheduling(workspaceId?: number | number[]): EnrichedTask[] {
  const scope = buildWorkspaceScopeClause('t.workspace_id', workspaceId)
  return getEnrichedTasks(
    `WHERE ${scope.clause}
       AND t.parent_task_id IS NULL
       AND t.deleted_at IS NULL
       AND t.status NOT IN ('done', 'cancelled', 'archived')
       AND (
         (t.auto_schedule = 1 AND t.assignee IS NOT NULL)
         OR (t.scheduled_start IS NOT NULL AND t.scheduled_end IS NOT NULL)
       )`,
    scope.params,
  )
}

export function getUnassignedAutoScheduleTasks(workspaceId?: number | number[]): Array<Pick<Task, 'id' | 'title'>> {
  const scope = buildWorkspaceScopeClause('workspace_id', workspaceId)
  return getDb().prepare(
    `SELECT id, title FROM tasks
     WHERE ${scope.clause}
       AND parent_task_id IS NULL
       AND deleted_at IS NULL
       AND status NOT IN ('done', 'cancelled', 'archived')
       AND auto_schedule = 1
       AND assignee IS NULL
     ORDER BY updated_at DESC`
  ).all(...scope.params) as Array<Pick<Task, 'id' | 'title'>>
}

export function getProjectTemplateUsage(workspaceId?: number | number[]): Array<{ template_id: number; id: number; name: string }> {
  const scope = buildWorkspaceScopeClause('workspace_id', workspaceId)
  return getDb().prepare(
    `SELECT template_id, id, name FROM projects
     WHERE ${scope.clause}
       AND deleted_at IS NULL
       AND template_id IS NOT NULL
       AND (archived = 0 OR archived IS NULL)
     ORDER BY name`
  ).all(...scope.params) as Array<{ template_id: number; id: number; name: string }>
}

export function getAllProjects(workspaceId?: number | number[]): Project[] {
  if (Array.isArray(workspaceId)) {
    if (workspaceId.length === 0) return []
    const ph = workspaceId.map(() => '?').join(',')
    return getDb().prepare(`SELECT * FROM projects WHERE workspace_id IN (${ph}) AND deleted_at IS NULL ORDER BY sort_order, name`).all(...workspaceId) as Project[]
  }
  if (workspaceId) {
    return getDb().prepare('SELECT * FROM projects WHERE workspace_id = ? AND deleted_at IS NULL ORDER BY sort_order, name').all(workspaceId) as Project[]
  }
  return getDb().prepare('SELECT * FROM projects WHERE deleted_at IS NULL ORDER BY sort_order, name').all() as Project[]
}

export function getAllStages(workspaceId?: number | number[]): Stage[] {
  if (Array.isArray(workspaceId)) {
    if (workspaceId.length === 0) return []
    const ph = workspaceId.map(() => '?').join(',')
    return getDb().prepare(`SELECT s.* FROM stages s JOIN projects p ON s.project_id = p.id WHERE p.workspace_id IN (${ph}) AND s.deleted_at IS NULL ORDER BY s.sort_order, s.name`).all(...workspaceId) as Stage[]
  }
  if (workspaceId) {
    return getDb().prepare('SELECT s.* FROM stages s JOIN projects p ON s.project_id = p.id WHERE p.workspace_id = ? AND s.deleted_at IS NULL ORDER BY s.sort_order, s.name').all(workspaceId) as Stage[]
  }
  return getDb().prepare('SELECT * FROM stages WHERE deleted_at IS NULL ORDER BY sort_order, name').all() as Stage[]
}

export function getAllFolders(workspaceId?: number | number[]): Folder[] {
  if (Array.isArray(workspaceId)) {
    if (workspaceId.length === 0) return []
    const ph = workspaceId.map(() => '?').join(',')
    return getDb().prepare(`SELECT * FROM folders WHERE workspace_id IN (${ph}) ORDER BY sort_order, name`).all(...workspaceId) as Folder[]
  }
  if (workspaceId) {
    return getDb().prepare('SELECT * FROM folders WHERE workspace_id = ? ORDER BY sort_order, name').all(workspaceId) as Folder[]
  }
  return getDb().prepare('SELECT * FROM folders ORDER BY sort_order, name').all() as Folder[]
}

