// ─── Project Delete (cascade) ───

export function deleteProject(id: number): void {
  const d = getDb()
  const now = new Date().toISOString()
  const txn = d.transaction(() => {
    // Soft-delete: mark project, stages, and tasks as deleted
    const taskIds = d.prepare('SELECT id FROM tasks WHERE project_id = ? AND deleted_at IS NULL').all(id) as { id: number }[]
    for (const t of taskIds) {
      d.prepare('DELETE FROM task_chunks WHERE task_id = ?').run(t.id)
    }
    d.prepare('UPDATE tasks SET deleted_at = ?, scheduled_start = NULL, scheduled_end = NULL, schedule_id = NULL, overdue_from = NULL WHERE project_id = ? AND deleted_at IS NULL').run(now, id)
    d.prepare('UPDATE stages SET deleted_at = ? WHERE project_id = ? AND deleted_at IS NULL').run(now, id)
    d.prepare('UPDATE projects SET deleted_at = ? WHERE id = ?').run(now, id)
  })
  txn()
}

export function hardDeleteProject(id: number): void {
  const d = getDb()
  const txn = d.transaction(() => {
    const taskIds = d.prepare('SELECT id FROM tasks WHERE project_id = ?').all(id) as { id: number }[]
    for (const t of taskIds) { hardDeleteTask(t.id) }
    d.prepare('DELETE FROM stages WHERE project_id = ?').run(id)
    d.prepare('DELETE FROM docs WHERE project_id = ?').run(id)
    d.prepare('DELETE FROM projects WHERE id = ?').run(id)
  })
  txn()
}

export function restoreProject(id: number): void {
  const d = getDb()
  const txn = d.transaction(() => {
    // Get the deleted_at timestamp of the project to match its children
    const proj = d.prepare('SELECT deleted_at FROM projects WHERE id = ?').get(id) as { deleted_at: string } | undefined
    if (!proj?.deleted_at) return
    d.prepare('UPDATE projects SET deleted_at = NULL WHERE id = ?').run(id)
    d.prepare('UPDATE stages SET deleted_at = NULL WHERE project_id = ? AND deleted_at = ?').run(id, proj.deleted_at)
    d.prepare('UPDATE tasks SET deleted_at = NULL WHERE project_id = ? AND deleted_at = ?').run(id, proj.deleted_at)
  })
  txn()
}

// ─── Stage Delete + Reassign + Reorder ───

export function deleteStage(id: number): void {
  const d = getDb()
  const now = new Date().toISOString()
  const txn = d.transaction(() => {
    const taskIds = d.prepare('SELECT id FROM tasks WHERE stage_id = ? AND deleted_at IS NULL').all(id) as { id: number }[]
    for (const t of taskIds) {
      d.prepare('DELETE FROM task_chunks WHERE task_id = ?').run(t.id)
    }
    d.prepare('UPDATE tasks SET deleted_at = ?, scheduled_start = NULL, scheduled_end = NULL, schedule_id = NULL, overdue_from = NULL WHERE stage_id = ? AND deleted_at IS NULL').run(now, id)
    d.prepare('UPDATE stages SET deleted_at = ? WHERE id = ?').run(now, id)
  })
  txn()
}

export function hardDeleteStage(id: number): void {
  const d = getDb()
  const txn = d.transaction(() => {
    const taskIds = d.prepare('SELECT id FROM tasks WHERE stage_id = ?').all(id) as { id: number }[]
    for (const t of taskIds) { hardDeleteTask(t.id) }
    d.prepare('DELETE FROM stages WHERE id = ?').run(id)
  })
  txn()
}

export function restoreStage(id: number): void {
  const d = getDb()
  const txn = d.transaction(() => {
    const stage = d.prepare('SELECT deleted_at FROM stages WHERE id = ?').get(id) as { deleted_at: string } | undefined
    if (!stage?.deleted_at) return
    d.prepare('UPDATE stages SET deleted_at = NULL WHERE id = ?').run(id)
    d.prepare('UPDATE tasks SET deleted_at = NULL WHERE stage_id = ? AND deleted_at = ?').run(id, stage.deleted_at)
  })
  txn()
}

export function getRecentlyDeleted(): { tasks: Task[]; projects: Project[]; stages: Stage[] } {
  const d = getDb()
  const cutoff = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString()
  return {
    tasks: d.prepare('SELECT * FROM tasks WHERE deleted_at IS NOT NULL AND deleted_at > ? AND parent_task_id IS NULL ORDER BY deleted_at DESC').all(cutoff) as Task[],
    projects: d.prepare('SELECT * FROM projects WHERE deleted_at IS NOT NULL AND deleted_at > ? ORDER BY deleted_at DESC').all(cutoff) as Project[],
    stages: d.prepare('SELECT * FROM stages WHERE deleted_at IS NOT NULL AND deleted_at > ? ORDER BY deleted_at DESC').all(cutoff) as Stage[],
  }
}

export function reassignStageTasks(fromId: number, toId: number | null): void {
  getDb().prepare('UPDATE tasks SET stage_id = ? WHERE stage_id = ?').run(toId, fromId)
}

export function reorderStages(projectId: number, stageIds: number[]): void {
  const d = getDb()
  const stmt = d.prepare('UPDATE stages SET sort_order = ? WHERE id = ? AND project_id = ?')
  const txn = d.transaction(() => {
    stageIds.forEach((id, i) => stmt.run(i, id, projectId))
  })
  txn()
}

// ─── Stage Auto-Progression ───

export function checkStageCompletion(projectId: number, stageId: number): { advanced: boolean; newStageId?: number; newStageName?: string } {
  const d = getDb()
  // Get all non-cancelled/non-archived tasks in this stage
  const stageTasks = d.prepare(
    "SELECT id, status FROM tasks WHERE project_id = ? AND stage_id = ? AND status != 'cancelled' AND status != 'archived'"
  ).all(projectId, stageId) as any[]

  // Check if all are done
  const allDone = stageTasks.length > 0 && stageTasks.every((t: any) => t.status === 'done')
  if (!allDone) return { advanced: false }

  // Get all stages ordered by sort_order
  const stages = d.prepare(
    'SELECT id, name, sort_order, is_active FROM stages WHERE project_id = ? ORDER BY sort_order ASC'
  ).all(projectId) as any[]

  const currentIndex = stages.findIndex((s: any) => s.id === stageId)
  if (currentIndex === -1 || currentIndex === stages.length - 1) return { advanced: false }

  const nextStage = stages[currentIndex + 1]

  // Deactivate current stage, activate next
  d.prepare('UPDATE stages SET is_active = 0 WHERE id = ?').run(stageId)
  d.prepare('UPDATE stages SET is_active = 1 WHERE id = ?').run(nextStage.id)

  // Promote backlog tasks in new active stage to todo
  d.prepare(
    "UPDATE tasks SET status = 'todo' WHERE project_id = ? AND stage_id = ? AND status = 'backlog'"
  ).run(projectId, nextStage.id)

  return { advanced: true, newStageId: nextStage.id, newStageName: nextStage.name }
}

// ─── Project Templates ───

export function getTemplates(): ProjectTemplate[] {
  return getDb().prepare('SELECT * FROM project_templates ORDER BY is_builtin DESC, name').all() as ProjectTemplate[]
}

export function getTemplate(id: number): ProjectTemplate | null {
  return getDb().prepare('SELECT * FROM project_templates WHERE id = ?').get(id) as ProjectTemplate | null
}

export function createTemplate(data: { name: string; description?: string; stages: string; default_tasks: string; workspace_id?: number; is_builtin?: number; roles?: string; text_variables?: string }): ProjectTemplate {
  const result = getDb().prepare(
    'INSERT INTO project_templates (name, description, stages, default_tasks, workspace_id, is_builtin, template_version, roles, text_variables) VALUES (?, ?, ?, ?, ?, ?, 1, ?, ?)'
  ).run(data.name, data.description || null, data.stages, data.default_tasks, data.workspace_id || null, data.is_builtin || 0, data.roles || '[]', data.text_variables || '[]')
  return getDb().prepare('SELECT * FROM project_templates WHERE id = ?').get(result.lastInsertRowid) as ProjectTemplate
}

export function createTemplateFromProject(projectId: number, name: string, description?: string): ProjectTemplate {
  const stages = getStages(projectId)
  const tasks = getTasks({ projectId })
  const stageData = stages.map(s => ({ name: s.name, color: s.color, sort_order: s.sort_order }))
  const taskData = tasks.map(t => ({
    title: t.title,
    description: t.description,
    priority: t.priority,
    stage_index: stages.findIndex(s => s.id === t.stage_id),
    duration_minutes: t.duration_minutes,
  }))
  return createTemplate({ name, description, stages: JSON.stringify(stageData), default_tasks: JSON.stringify(taskData) })
}

export function updateTemplate(id: number, data: { name?: string; description?: string; stages?: string; default_tasks?: string; roles?: string; text_variables?: string }): ProjectTemplate | null {
  const d = getDb()
  const sets: string[] = []
  const vals: unknown[] = []
  if (data.name !== undefined) { sets.push('name = ?'); vals.push(data.name) }
  if (data.description !== undefined) { sets.push('description = ?'); vals.push(data.description) }
  if (data.stages !== undefined) { sets.push('stages = ?'); vals.push(data.stages) }
  if (data.default_tasks !== undefined) { sets.push('default_tasks = ?'); vals.push(data.default_tasks) }
  if (data.roles !== undefined) { sets.push('roles = ?'); vals.push(data.roles) }
  if (data.text_variables !== undefined) { sets.push('text_variables = ?'); vals.push(data.text_variables) }
  if (sets.length === 0) return getTemplate(id)
  // Auto-increment template_version on any edit to stages or default_tasks
  if (data.stages !== undefined || data.default_tasks !== undefined) {
    sets.push('template_version = template_version + 1')
  }
  vals.push(id)
  d.prepare(`UPDATE project_templates SET ${sets.join(', ')} WHERE id = ?`).run(...vals)
  return getTemplate(id)
}

export function deleteTemplate(id: number): void {
  getDb().prepare('DELETE FROM project_templates WHERE id = ?').run(id)
}

export function createProjectFromTemplate(
  workspaceId: number,
  templateId: number,
  name: string,
  options?: {
    folderId?: number
    color?: string
    startDate?: string
    deadline?: string
    roleAssignments?: Record<string, string>
    textVariables?: Record<string, string>
  }
): Project | null {
  const template = getTemplate(templateId)
  if (!template) return null
  const d = getDb()
  const opts = options || {}

  // Wrap entire creation in a transaction - if anything fails, nothing is committed
  const runInTransaction = d.transaction(() => {
    return _createProjectFromTemplateInner(d, template, workspaceId, name, opts)
  })

  try {
    return runInTransaction()
  } catch (err) {
    console.error('createProjectFromTemplate failed (rolled back):', err)
    return null
  }
}

function _createProjectFromTemplateInner(
  d: ReturnType<typeof getDb>,
  template: ProjectTemplate,
  workspaceId: number,
  name: string,
  opts: {
    folderId?: number
    color?: string
    startDate?: string
    deadline?: string
    roleAssignments?: Record<string, string>
    textVariables?: Record<string, string>
  }
): Project {

  function replaceVars(text: string, vars: Record<string, string>): string {
    if (!text || !vars) return text
    return text.replace(/\{\{(\w+)\}\}/g, (_, key) => vars[key] ?? `{{${key}}}`)
  }

  const stages = JSON.parse(template.stages) as { name: string; color: string; sort_order: number }[]
  const tasks = JSON.parse(template.default_tasks) as {
    id?: string | number
    title: string
    description?: string
    priority?: string
    stage_index: number
    duration_minutes?: number
    role?: string
    offset_days?: number
    start_offset_days?: number  // Legacy field name from AI generator
    offset_unit?: 'days' | 'weekdays' | 'weeks'
    deadline_offset_days?: number
    deadline_offset_unit?: 'days' | 'weekdays' | 'weeks'
    blocked_by_ids?: (string | number)[]
    auto_schedule?: number
    hard_deadline?: number
    min_chunk_minutes?: number
    checklist?: string[]
    labels?: string[]
  }[]

  const project = createProject(workspaceId, name, opts.folderId, opts.color)
  // Store which template + version this project was created from
  d.prepare("UPDATE projects SET template_id = ?, template_version = ?, updated_at = strftime('%s','now') WHERE id = ?").run(template.id, template.template_version, project.id)

  // Set project dates if provided
  if (opts.startDate || opts.deadline) {
    const projectUpdates: Record<string, string> = {}
    if (opts.startDate) projectUpdates.start_date = opts.startDate
    if (opts.deadline) projectUpdates.deadline = opts.deadline
    updateProject(project.id, projectUpdates)
  }

  // Delete default stages created by createProject's caller
  d.prepare('DELETE FROM stages WHERE project_id = ?').run(project.id)

  const stageIdMap: Record<number, number> = {}
  stages.forEach((s, i) => {
    const stageName = opts.textVariables ? replaceVars(s.name, opts.textVariables) : s.name
    const stage = createStage(project.id, stageName, s.color)
    updateStage(stage.id, { sort_order: s.sort_order })
    stageIdMap[i] = stage.id
  })

  // Stage activation: first stage (lowest sort_order) is active, rest inactive
  const sortedStages = [...stages].sort((a, b) => a.sort_order - b.sort_order)
  stages.forEach((s, i) => {
    const isFirst = s.sort_order === sortedStages[0].sort_order
    updateStage(stageIdMap[i], { is_active: isFirst ? 1 : 0 })
  })

  // First pass: create all tasks, build template ID -> real ID map
  const templateToRealId: Record<string, number> = {}
  const createdTaskIds: number[] = []

  for (const t of tasks) {
    const title = opts.textVariables ? replaceVars(t.title, opts.textVariables) : t.title
    const description = t.description && opts.textVariables ? replaceVars(t.description, opts.textVariables) : t.description

    // Determine assignee: direct member reference (member:xxx) or role mapping
    let assignee: string | undefined
    if (t.role?.startsWith('member:')) {
      assignee = t.role.slice(7) // "member:operator" -> "operator"
    } else if (t.role && opts.roleAssignments) {
      assignee = opts.roleAssignments[t.role]
    }

    // Calculate dates from offsets (supports days, weekdays, weeks)
    let startDate: string | undefined
    let dueDate: string | undefined
    if (opts.startDate) {
      const addOffset = (base: Date, amount: number, unit: string = 'days'): string => {
        const result = new Date(base)
        if (unit === 'weeks') {
          result.setDate(result.getDate() + amount * 7)
        } else if (unit === 'weekdays') {
          let added = 0
          const dir = amount >= 0 ? 1 : -1
          const target = Math.abs(amount)
          while (added < target) {
            result.setDate(result.getDate() + dir)
            const dow = result.getDay()
            if (dow !== 0 && dow !== 6) added++
          }
        } else {
          result.setDate(result.getDate() + amount)
        }
        // Format as YYYY-MM-DD using local date parts (avoids UTC conversion issues)
        const y = result.getFullYear()
        const m = String(result.getMonth() + 1).padStart(2, '0')
        const d = String(result.getDate()).padStart(2, '0')
        return `${y}-${m}-${d}`
      }
      // Use T12:00:00 to avoid UTC midnight timezone issues (bare YYYY-MM-DD parses as UTC)
      const safeBase = opts.startDate + 'T12:00:00'
      const startOffsetDays = t.offset_days ?? t.start_offset_days  // Handle legacy field name
      if (startOffsetDays !== undefined) {
        startDate = addOffset(new Date(safeBase), startOffsetDays, t.offset_unit || 'days')
      }
      if (t.deadline_offset_days !== undefined) {
        dueDate = addOffset(new Date(safeBase), t.deadline_offset_days, t.deadline_offset_unit || 'days')
      }
    }

    const newTask = createTask({
      title: String(title || 'Untitled'),
      description: description ? String(description) : undefined,
      priority: typeof t.priority === 'string' ? t.priority : 'medium',
      projectId: project.id,
      workspaceId,
      stageId: t.stage_index >= 0 ? stageIdMap[t.stage_index] : undefined,
      duration_minutes: Number(t.duration_minutes) || 30,
      assignee: assignee ? String(assignee) : undefined,
    })

    // Update additional fields via updateTask - sanitize all values for SQLite
    const extraFields: Record<string, unknown> = {}
    if (startDate) extraFields.start_date = String(startDate)
    if (dueDate) extraFields.due_date = String(dueDate)
    extraFields.auto_schedule = (!t.auto_schedule || t.auto_schedule === 0) ? 0 : 1
    extraFields.hard_deadline = (t.hard_deadline && t.hard_deadline !== 0) ? 1 : 0
    if (t.min_chunk_minutes !== undefined) extraFields.min_chunk_minutes = Number(t.min_chunk_minutes) || 0
    if (t.labels && Array.isArray(t.labels) && t.labels.length > 0) extraFields.labels = t.labels.join(',')
    else if (t.labels && typeof t.labels === 'string') extraFields.labels = String(t.labels)
    if ((t as any).status && typeof (t as any).status === 'string' && (t as any).status !== 'todo') extraFields.status = (t as any).status
    if (Object.keys(extraFields).length > 0) {
      updateTask(newTask.id, extraFields)
    }

    // Track template ID mapping
    if (t.id !== undefined) {
      templateToRealId[String(t.id)] = newTask.id
    }
    createdTaskIds.push(newTask.id)

    // Create subtasks from checklist
    if (t.checklist && t.checklist.length > 0) {
      for (const item of t.checklist) {
        const subtitleText = opts.textVariables ? replaceVars(item, opts.textVariables) : item
        createTask({
          title: subtitleText,
          projectId: project.id,
          workspaceId,
          stageId: t.stage_index >= 0 ? stageIdMap[t.stage_index] : undefined,
          parentTaskId: newTask.id,
        })
      }
    }
  }

  // Second pass: wire up task dependencies
  for (let i = 0; i < tasks.length; i++) {
    const t = tasks[i]
    if (!t.blocked_by_ids || t.blocked_by_ids.length === 0) continue
    if (t.id === undefined) continue

    const realTaskId = templateToRealId[String(t.id)]
    if (!realTaskId) continue

    const realBlockerIds: number[] = []
    for (const blockerId of t.blocked_by_ids) {
      const realBlocker = templateToRealId[String(blockerId)]
      if (realBlocker) realBlockerIds.push(realBlocker)
    }

    if (realBlockerIds.length > 0) {
      // Set blocked_by on the dependent task
      updateTask(realTaskId, { blocked_by: realBlockerIds.join(',') })

      // Set/append blocking on each blocker task
      for (const blockerId of realBlockerIds) {
        const blockerTask = d.prepare('SELECT blocking FROM tasks WHERE id = ?').get(blockerId) as { blocking?: string } | undefined
        const existing = blockerTask?.blocking ? blockerTask.blocking.split(',').map(Number) : []
        if (!existing.includes(realTaskId)) {
          existing.push(realTaskId)
          updateTask(blockerId, { blocking: existing.join(',') })
        }
      }
    }
  }

  return d.prepare('SELECT * FROM projects WHERE id = ?').get(project.id) as Project
}

/** Apply a project template's stages and tasks to an existing project (replaces current stages/tasks) */
export function applyTemplateToProject(
  projectId: number,
  templateId: number,
  options?: {
    roleAssignments?: Record<string, string>
    textVariables?: Record<string, string>
  }
): boolean {
  const template = getTemplate(templateId)
  if (!template) return false
  const d = getDb()

  const project = d.prepare('SELECT * FROM projects WHERE id = ?').get(projectId) as Project | undefined
  if (!project) return false
  const opts = options || {}

  function replaceVars(text: string, vars: Record<string, string>): string {
    if (!text || !vars) return text
    return text.replace(/\{\{(\w+)\}\}/g, (_, key) => vars[key] ?? `{{${key}}}`)
  }

  // Build text variables with built-in {{pn}} (project name)
  const textVars = { pn: project.name, ...(opts.textVariables || {}) }

  const stages = JSON.parse(template.stages) as { name: string; color: string; sort_order: number }[]
  const tasks = JSON.parse(template.default_tasks) as {
    id?: string | number
    title: string
    description?: string
    status?: string
    priority?: string
    stage_index: number
    duration_minutes?: number
    role?: string
    auto_schedule?: number
    hard_deadline?: number
    min_chunk_minutes?: number
    checklist?: string[]
    labels?: string[]
    blocked_by_ids?: (string | number)[]
  }[]

  // Delete existing stages and tasks for this project
  d.prepare('DELETE FROM tasks WHERE project_id = ?').run(projectId)
  d.prepare('DELETE FROM stages WHERE project_id = ?').run(projectId)

  // Link template
  d.prepare("UPDATE projects SET template_id = ?, template_version = ?, updated_at = strftime('%s','now') WHERE id = ?").run(templateId, template.template_version, projectId)

  // Create stages
  const stageIdMap: Record<number, number> = {}
  stages.forEach((s, i) => {
    const stage = createStage(projectId, s.name, s.color)
    updateStage(stage.id, { sort_order: s.sort_order })
    stageIdMap[i] = stage.id
  })

  const sortedStages = [...stages].sort((a, b) => a.sort_order - b.sort_order)
  stages.forEach((s, i) => {
    const isFirst = s.sort_order === sortedStages[0].sort_order
    updateStage(stageIdMap[i], { is_active: isFirst ? 1 : 0 })
  })

  // Create tasks
  const templateToRealId: Record<string, number> = {}
  for (const t of tasks) {
    const title = replaceVars(t.title, textVars)
    const description = t.description ? replaceVars(t.description, textVars) : t.description
    const assignee = t.role && opts.roleAssignments ? opts.roleAssignments[t.role] : undefined

    const newTask = createTask({
      title,
      description,
      priority: t.priority,
      projectId,
      workspaceId: project.workspace_id,
      stageId: t.stage_index >= 0 ? stageIdMap[t.stage_index] : undefined,
      duration_minutes: t.duration_minutes,
      assignee,
    })

    const extraFields: Record<string, unknown> = {}
    if (t.status && t.status !== 'todo') extraFields.status = t.status
    if (t.auto_schedule !== undefined) extraFields.auto_schedule = t.auto_schedule ? 1 : 0
    else extraFields.auto_schedule = 1
    if (t.hard_deadline !== undefined) extraFields.hard_deadline = t.hard_deadline ? 1 : 0
    if (t.min_chunk_minutes !== undefined) extraFields.min_chunk_minutes = Number(t.min_chunk_minutes) || 0
    if (t.labels && Array.isArray(t.labels) && t.labels.length > 0) extraFields.labels = t.labels.join(',')
    else if (t.labels && typeof t.labels === 'string') extraFields.labels = t.labels
    if (Object.keys(extraFields).length > 0) updateTask(newTask.id, extraFields)

    if (t.id !== undefined) templateToRealId[String(t.id)] = newTask.id

    if (t.checklist && t.checklist.length > 0) {
      for (const item of t.checklist) {
        const subtitleText = replaceVars(item, textVars)
        createTask({ title: subtitleText, projectId, workspaceId: project.workspace_id, stageId: t.stage_index >= 0 ? stageIdMap[t.stage_index] : undefined, parentTaskId: newTask.id })
      }
    }
  }

  // Wire up dependencies
  for (const t of tasks) {
    if (!t.blocked_by_ids?.length || t.id === undefined) continue
    const realTaskId = templateToRealId[String(t.id)]
    if (!realTaskId) continue
    const realBlockerIds = t.blocked_by_ids.map(id => templateToRealId[String(id)]).filter(Boolean)
    if (realBlockerIds.length > 0) {
      updateTask(realTaskId, { blocked_by: realBlockerIds.join(',') })
      for (const blockerId of realBlockerIds) {
        const blockerTask = d.prepare('SELECT blocking FROM tasks WHERE id = ?').get(blockerId) as { blocking?: string } | undefined
        const existing = blockerTask?.blocking ? blockerTask.blocking.split(',').map(Number) : []
        if (!existing.includes(realTaskId)) {
          existing.push(realTaskId)
          updateTask(blockerId, { blocking: existing.join(',') })
        }
      }
    }
  }

  return true
}

export function createProjectWithStagesAndTasks(data: {
  workspaceId: number
  name: string
  description?: string
  color?: string
  folderId?: number
  stages: { name: string; color: string }[]
  tasks: { title: string; description?: string; priority?: string; stage_index: number; duration_minutes?: number }[]
}): Project {
  const project = createProject(data.workspaceId, data.name, data.folderId, data.color)
  if (data.description) updateProject(project.id, { description: data.description })

  const d = getDb()
  // Delete default stages
  d.prepare('DELETE FROM stages WHERE project_id = ?').run(project.id)

  const stageIdMap: Record<number, number> = {}
  data.stages.forEach((s, i) => {
    const stage = createStage(project.id, s.name, s.color)
    stageIdMap[i] = stage.id
  })

  for (const t of data.tasks) {
    createTask({
      title: t.title,
      description: t.description,
      priority: t.priority,
      projectId: project.id,
      workspaceId: data.workspaceId,
      stageId: t.stage_index >= 0 ? stageIdMap[t.stage_index] : undefined,
      duration_minutes: t.duration_minutes,
    })
  }

  return project
}

// ─── Task Templates ───

export function getTaskTemplates(workspaceId?: number): TaskTemplate[] {
  if (workspaceId) {
    return getDb().prepare('SELECT * FROM task_templates WHERE workspace_id = ? OR workspace_id IS NULL ORDER BY name').all(workspaceId) as TaskTemplate[]
  }
  return getDb().prepare('SELECT * FROM task_templates ORDER BY name').all() as TaskTemplate[]
}

export function getTaskTemplate(id: number): TaskTemplate | null {
  return getDb().prepare('SELECT * FROM task_templates WHERE id = ?').get(id) as TaskTemplate | null
}

export function createTaskTemplate(data: {
  name: string
  description?: string
  default_title?: string
  default_priority?: string
  default_duration_minutes?: number
  default_status?: string
  subtasks?: string
  workspace_id?: number
}): TaskTemplate {
  const result = getDb().prepare(
    'INSERT INTO task_templates (name, description, default_title, default_priority, default_duration_minutes, default_status, subtasks, workspace_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?)'
  ).run(
    data.name,
    data.description || null,
    data.default_title || null,
    data.default_priority || DEFAULT_TASK_VALUES.priority,
    data.default_duration_minutes || DEFAULT_TASK_VALUES.duration_minutes,
    data.default_status || DEFAULT_TASK_VALUES.status,
    data.subtasks || null,
    data.workspace_id || null
  )
  return getDb().prepare('SELECT * FROM task_templates WHERE id = ?').get(result.lastInsertRowid) as TaskTemplate
}

export function deleteTaskTemplate(id: number): void {
  getDb().prepare('DELETE FROM task_templates WHERE id = ?').run(id)
}

export function createTaskFromTemplate(templateId: number, opts?: { project_id?: number; workspace_id?: number; stage_id?: number }): Task[] {
  const template = getTaskTemplate(templateId)
  if (!template) return []

  const mainTask = createTask({
    title: template.default_title || template.name,
    priority: template.default_priority || DEFAULT_TASK_VALUES.priority,
    status: (template.default_status || DEFAULT_TASK_VALUES.status) as 'todo',
    duration_minutes: template.default_duration_minutes || DEFAULT_TASK_VALUES.duration_minutes,
    description: template.description || undefined,
    projectId: opts?.project_id || undefined,
    workspaceId: opts?.workspace_id || (template.workspace_id ?? undefined),
    stageId: opts?.stage_id || undefined,
  })

  const created: Task[] = [mainTask]

  if (template.subtasks) {
    const subtasks = JSON.parse(template.subtasks) as { title: string; duration_minutes?: number; priority?: string }[]
    for (const sub of subtasks) {
      const subTask = createTask({
        title: sub.title,
        priority: sub.priority || template.default_priority || DEFAULT_TASK_VALUES.priority,
        duration_minutes: sub.duration_minutes || DEFAULT_TASK_VALUES.duration_minutes,
        projectId: opts?.project_id || undefined,
        workspaceId: opts?.workspace_id || (template.workspace_id ?? undefined),
        stageId: opts?.stage_id || undefined,
        parentTaskId: mainTask.id,
      })
      created.push(subTask)
    }
  }

  return created
}

