// ─── Knowledge Entries ───

export interface KnowledgeEntry {
  id: number
  type: 'text' | 'url'
  title: string
  content: string | null
  url: string | null
  workspace_id: number | null
  private: number
  created_at: number
}

export function getKnowledgeEntries(workspaceId?: number): KnowledgeEntry[] {
  if (workspaceId) {
    return getDb().prepare('SELECT * FROM knowledge_entries WHERE workspace_id = ? ORDER BY created_at DESC').all(workspaceId) as KnowledgeEntry[]
  }
  return getDb().prepare('SELECT * FROM knowledge_entries ORDER BY created_at DESC').all() as KnowledgeEntry[]
}

export function getKnowledgeEntry(id: number): KnowledgeEntry | null {
  return getDb().prepare('SELECT * FROM knowledge_entries WHERE id = ?').get(id) as KnowledgeEntry | null
}

export function createKnowledgeEntry(data: { type?: string; title: string; content?: string; url?: string; workspace_id?: number; private?: boolean }): KnowledgeEntry {
  const result = getDb().prepare(
    'INSERT INTO knowledge_entries (type, title, content, url, workspace_id, private) VALUES (?, ?, ?, ?, ?, ?)'
  ).run(
    data.type || 'text',
    data.title,
    data.content || null,
    data.url || null,
    data.workspace_id || null,
    data.private ? 1 : 0
  )
  return getDb().prepare('SELECT * FROM knowledge_entries WHERE id = ?').get(result.lastInsertRowid) as KnowledgeEntry
}

export function updateKnowledgeEntry(id: number, data: { type?: string; title?: string; content?: string; url?: string; workspace_id?: number; private?: boolean }): KnowledgeEntry | null {
  const sets: string[] = []
  const vals: unknown[] = []
  if (data.type !== undefined) { sets.push('type = ?'); vals.push(data.type) }
  if (data.title !== undefined) { sets.push('title = ?'); vals.push(data.title) }
  if (data.content !== undefined) { sets.push('content = ?'); vals.push(data.content) }
  if (data.url !== undefined) { sets.push('url = ?'); vals.push(data.url) }
  if (data.workspace_id !== undefined) { sets.push('workspace_id = ?'); vals.push(data.workspace_id) }
  if (data.private !== undefined) { sets.push('private = ?'); vals.push(data.private ? 1 : 0) }
  if (sets.length === 0) return getKnowledgeEntry(id)
  vals.push(id)
  getDb().prepare(`UPDATE knowledge_entries SET ${sets.join(', ')} WHERE id = ?`).run(...vals)
  return getKnowledgeEntry(id)
}

export function deleteKnowledgeEntry(id: number): void {
  getDb().prepare('DELETE FROM knowledge_entries WHERE id = ?').run(id)
}

// ─── Agenda Snapshots ───

export interface AgendaSnapshot {
  id: number
  date: string
  data: string
  created_at: number
}

export function saveAgendaSnapshot(date: string, data: string): void {
  getDb().prepare(`
    INSERT INTO agenda_snapshots (date, data, created_at)
    VALUES (?, ?, unixepoch())
    ON CONFLICT(date) DO UPDATE SET data = excluded.data, created_at = excluded.created_at
  `).run(date, data)
}

export function getAgendaSnapshot(date: string): AgendaSnapshot | null {
  return getDb().prepare('SELECT * FROM agenda_snapshots WHERE date = ?').get(date) as AgendaSnapshot | null
}

export function getAgendaSnapshotDates(): string[] {
  const rows = getDb().prepare('SELECT date FROM agenda_snapshots ORDER BY date DESC').all() as { date: string }[]
  return rows.map(r => r.date)
}

// ─── Status Updates ───

export interface StatusUpdate {
  id: number
  task_id: number | null
  project_id: number | null
  content: string
  author: string
  created_at: number
}

export function createStatusUpdate(data: { taskId?: number; projectId?: number; content: string; author?: string }): StatusUpdate {
  const d = getDb()
  d.prepare(
    'INSERT INTO status_updates (task_id, project_id, content, author, created_at) VALUES (?, ?, ?, ?, ?)'
  ).run(data.taskId ?? null, data.projectId ?? null, data.content, data.author ?? 'Operator', Math.floor(Date.now() / 1000))
  return d.prepare('SELECT * FROM status_updates WHERE id = last_insert_rowid()').get() as StatusUpdate
}

export function getStatusUpdates(opts?: { taskId?: number; projectId?: number }): StatusUpdate[] {
  const d = getDb()
  if (opts?.taskId) {
    return d.prepare('SELECT * FROM status_updates WHERE task_id = ? ORDER BY created_at DESC').all(opts.taskId) as StatusUpdate[]
  }
  if (opts?.projectId) {
    return d.prepare('SELECT * FROM status_updates WHERE project_id = ? ORDER BY created_at DESC').all(opts.projectId) as StatusUpdate[]
  }
  return d.prepare('SELECT * FROM status_updates ORDER BY created_at DESC LIMIT 100').all() as StatusUpdate[]
}

export function deleteStatusUpdate(id: number): void {
  getDb().prepare('DELETE FROM status_updates WHERE id = ?').run(id)
}

// ─── Booking Links ───

export interface BookingLink {
  id: number
  name: string
  slug: string
  durations: string
  custom_hours: string | null
  daily_limit: number
  start_delay_days: number
  one_time: number
  buffer_before: number
  buffer_after: number
  active: number
  created_at: number
  questions: string | null
}

export function getBookingLinks(): BookingLink[] {
  return getDb().prepare('SELECT * FROM booking_links ORDER BY created_at DESC').all() as BookingLink[]
}

export function getBookingLinkBySlug(slug: string): BookingLink | null {
  return getDb().prepare('SELECT * FROM booking_links WHERE slug = ?').get(slug) as BookingLink | null
}

export function getBookingLinkById(id: number): BookingLink | null {
  return getDb().prepare('SELECT * FROM booking_links WHERE id = ?').get(id) as BookingLink | null
}

export function createBookingLink(data: {
  name: string
  slug: string
  durations?: number[]
  custom_hours?: Record<string, { start: string; end: string }[]> | null
  daily_limit?: number
  start_delay_days?: number
  one_time?: boolean
  buffer_before?: number
  buffer_after?: number
}): BookingLink {
  const d = getDb()
  d.prepare(
    `INSERT INTO booking_links (name, slug, durations, custom_hours, daily_limit, start_delay_days, one_time, buffer_before, buffer_after)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
  ).run(
    data.name,
    data.slug,
    JSON.stringify(data.durations ?? [30]),
    data.custom_hours ? JSON.stringify(data.custom_hours) : null,
    data.daily_limit ?? 0,
    data.start_delay_days ?? 0,
    data.one_time ? 1 : 0,
    data.buffer_before ?? 0,
    data.buffer_after ?? 0,
  )
  return d.prepare('SELECT * FROM booking_links WHERE id = last_insert_rowid()').get() as BookingLink
}

export function updateBookingLink(id: number, data: Record<string, unknown>): BookingLink | null {
  const d = getDb()
  const sets: string[] = []
  const vals: unknown[] = []
  for (const [k, v] of Object.entries(data)) {
    if (!(ALLOWED_BOOKING_LINK_COLUMNS as readonly string[]).includes(k)) continue
    if (['durations', 'custom_hours'].includes(k)) {
      sets.push(`${k} = ?`)
      vals.push(v != null ? JSON.stringify(v) : null)
    } else if (k === 'one_time') {
      sets.push(`${k} = ?`)
      vals.push(v ? 1 : 0)
    } else {
      sets.push(`${k} = ?`)
      vals.push(v)
    }
  }
  if (sets.length === 0) return getBookingLinkById(id)
  vals.push(id)
  d.prepare(`UPDATE booking_links SET ${sets.join(', ')} WHERE id = ?`).run(...vals)
  return d.prepare('SELECT * FROM booking_links WHERE id = ?').get(id) as BookingLink | null
}

export function deleteBookingLink(id: number): void {
  getDb().prepare('DELETE FROM booking_links WHERE id = ?').run(id)
}

