// Auto-archive tasks untouched for 6 months
export function autoArchiveStale(): number {
  const d = getDb()
  const sixMonthsAgo = Math.floor(Date.now() / 1000) - 6 * 30 * 86400
  const archivedTaskIds = d.prepare(
    "SELECT id FROM tasks WHERE status NOT IN ('done','cancelled','archived') AND updated_at < ?"
  ).all(sixMonthsAgo) as { id: number }[]

  const result = d.prepare(
    "UPDATE tasks SET status = 'archived', scheduled_start = NULL, scheduled_end = NULL, schedule_id = NULL, overdue_from = NULL, updated_at = strftime('%s','now') WHERE status NOT IN ('done','cancelled','archived') AND updated_at < ?"
  ).run(sixMonthsAgo)

  for (const task of archivedTaskIds) {
    d.prepare('DELETE FROM task_chunks WHERE task_id = ?').run(task.id)
  }

  return result.changes
}

