// Convert team members to assignee options for dropdowns
// For human members, also check users table for avatar_url (Google profile photo)
export function getAssigneeOptions(): { id: string; name: string; role: string; type: 'human' | 'agent'; avatar: string; color: string }[] {
  const members = getTeamMembers()
  const d = getDb()
  // Get user avatar_urls keyed by name (for human members)
  const users = d.prepare('SELECT name, avatar_url FROM users WHERE avatar_url IS NOT NULL').all() as { name: string; avatar_url: string }[]
  const userAvatarMap = new Map(users.map(u => [u.name, u.avatar_url]))

  return members.map(m => {
    // Priority: team_members.avatar (uploaded) > users.avatar_url (Google photo) > initial letter
    let avatar = m.avatar || ''
    if (!avatar || avatar.length <= 2) {
      // No uploaded avatar -- check users table for Google profile photo
      const userAvatar = userAvatarMap.get(m.name)
      if (userAvatar) avatar = userAvatar
    }
    if (!avatar) avatar = m.name.charAt(0).toUpperCase()

    return {
      id: m.public_id || m.name.split(' ')[0].toLowerCase(),
      name: m.name,
      role: m.role,
      type: m.type,
      avatar,
      color: m.color,
    }
  })
}

