export function createClientBusiness(data: Record<string, unknown>): ClientBusiness {
  const name = data.name as string
  const slug = (data.slug as string) || name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '')
  const clientId = (data.client_id as number) || 0
  const wsId = (data.workspace_id as number) || (getDb().prepare('SELECT id FROM workspaces ORDER BY id LIMIT 1').get() as { id: number } | undefined)?.id || null

  const folderId = (data.folder_id as number | null) || null

  const result = getDb().prepare(`INSERT INTO client_businesses (
    client_id, name, slug, industry, avatar_color, status,
    context, brand_voice, goals, target_audience, services, offer, offer_details,
    ad_account_id, page_id, monthly_budget,
    location, website, instagram_handle, tiktok_handle, facebook_page,
    folder_id, workspace_id, public_id
  ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`).run(
    clientId, name, slug,
    data.industry || null, data.avatar_color || '#7a6b55', data.status || 'active',
    data.context || '', data.brand_voice || '', data.goals || '', data.target_audience || '',
    data.services || '', data.offer || '', data.offer_details || '',
    data.ad_account_id || null, data.page_id || null, data.monthly_budget || null,
    data.location || null, data.website || null,
    data.instagram_handle || null, data.tiktok_handle || null, data.facebook_page || null,
    folderId, wsId, generatePublicId()
  )
  return getDb().prepare('SELECT * FROM client_businesses WHERE id = ?').get(result.lastInsertRowid) as ClientBusiness
}

