  const { sets, vals } = safeBuildSets(data, ALLOWED_CLIENT_BUSINESS_COLUMNS)
  sets.push("updated_at = strftime('%s','now')")
  if (sets.length === 0) return getDb().prepare('SELECT * FROM client_businesses WHERE id = ?').get(id) as ClientBusiness | null
  vals.push(id)
  getDb().prepare(`UPDATE client_businesses SET ${sets.join(', ')} WHERE id = ?`).run(...vals)
