export function getDispatchById(id: number): (DispatchItem & { task_title?: string; task_description?: string; project_name?: string }) | null {
  return getDb().prepare(`
    SELECT dq.*, t.title as task_title, t.description as task_description, p.name as project_name
    FROM dispatch_queue dq
    LEFT JOIN tasks t ON dq.task_id = t.id
    LEFT JOIN projects p ON t.project_id = p.id
    WHERE dq.id = ?
  `).get(id) as (DispatchItem & { task_title?: string; task_description?: string; project_name?: string }) | null
}

export function getChildDispatches(parentDispatchId: number): (DispatchItem & { task_title?: string; project_name?: string })[] {
  return getDb().prepare(`
    SELECT dq.*, t.title as task_title, p.name as project_name
    FROM dispatch_queue dq
    LEFT JOIN tasks t ON dq.task_id = t.id
    LEFT JOIN projects p ON t.project_id = p.id
    WHERE dq.parent_dispatch_id = ?
    ORDER BY dq.created_at ASC
  `).all(parentDispatchId) as (DispatchItem & { task_title?: string; project_name?: string })[]
}

export function getDispatchesForDashboard(): (DispatchItem & {
  task_title?: string
  project_name?: string
  child_total?: number
  child_done?: number
  child_failed?: number
  child_working?: number
  child_queued?: number
  pending_dep_count?: number
  pending_dep_agent?: string | null
  pending_dep_title?: string | null
})[] {
  return getDb().prepare(`
    SELECT dq.*, t.title as task_title, p.name as project_name,
      (SELECT COUNT(*) FROM dispatch_queue c WHERE c.parent_dispatch_id = dq.id) AS child_total,
      (SELECT COUNT(*) FROM dispatch_queue c WHERE c.parent_dispatch_id = dq.id AND c.status = 'done') AS child_done,
      (SELECT COUNT(*) FROM dispatch_queue c WHERE c.parent_dispatch_id = dq.id AND c.status = 'failed') AS child_failed,
      (SELECT COUNT(*) FROM dispatch_queue c WHERE c.parent_dispatch_id = dq.id AND c.status = 'working') AS child_working,
      (SELECT COUNT(*) FROM dispatch_queue c WHERE c.parent_dispatch_id = dq.id AND c.status = 'queued') AS child_queued,
      (SELECT COUNT(*)
        FROM dispatch_dependencies dd
        JOIN dispatch_queue dep ON dep.id = dd.depends_on_dispatch_id
        WHERE dd.dispatch_id = dq.id
          AND dep.status NOT IN ('done', 'approved', 'needs_review')
      ) AS pending_dep_count,
      (SELECT dep.agent_id
        FROM dispatch_dependencies dd
        JOIN dispatch_queue dep ON dep.id = dd.depends_on_dispatch_id
        WHERE dd.dispatch_id = dq.id
          AND dep.status NOT IN ('done', 'approved', 'needs_review')
        ORDER BY dep.created_at ASC
        LIMIT 1
      ) AS pending_dep_agent,
      (SELECT dt.title
        FROM dispatch_dependencies dd
        JOIN dispatch_queue dep ON dep.id = dd.depends_on_dispatch_id
        LEFT JOIN tasks dt ON dt.id = dep.task_id
        WHERE dd.dispatch_id = dq.id
          AND dep.status NOT IN ('done', 'approved', 'needs_review')
        ORDER BY dep.created_at ASC
        LIMIT 1
      ) AS pending_dep_title
    FROM dispatch_queue dq
    LEFT JOIN tasks t ON dq.task_id = t.id
    LEFT JOIN projects p ON t.project_id = p.id
    WHERE dq.status != 'cancelled'
      AND COALESCE(dq.run_type, 'single') != 'team_child'
    ORDER BY dq.created_at DESC
    LIMIT 100
  `).all() as (DispatchItem & {
    task_title?: string
    project_name?: string
    child_total?: number
    child_done?: number
    child_failed?: number
    child_working?: number
    child_queued?: number
    pending_dep_count?: number
    pending_dep_agent?: string | null
    pending_dep_title?: string | null
  })[]
}

export function addDispatchActivity(taskId: number, type: string, content: string): TaskActivity {
  return createTaskActivity(taskId, type, content, 'claude')
}

export function getDispatchActivities(dispatchId: number): TaskActivity[] {
  const dispatch = getDb().prepare('SELECT task_id FROM dispatch_queue WHERE id = ?').get(dispatchId) as { task_id: number | null } | undefined
  if (!dispatch?.task_id) return []
  return getDb().prepare(`
    SELECT * FROM task_activities
    WHERE task_id = ? AND activity_type IN ('dispatch_queued', 'dispatch_started', 'dispatch_progress', 'dispatch_completed', 'dispatch_approved', 'dispatch_rejected', 'dispatch_failed')
    ORDER BY created_at DESC
  `).all(dispatch.task_id) as TaskActivity[]
}

// --- Memory Browser ---

export interface MemoryRow {
  id: number
  content: string
  sector: string
  source: string
  source_contact: string | null
  source_channel: string | null
  salience: number
  created_at: number
  accessed_at: number
  client_slug: string | null
}

export function browseMemories(opts: {
  query?: string
  sector?: string
  source?: string
  clientSlug?: string
  offset?: number
  limit?: number
}): { rows: MemoryRow[]; total: number } {
  const d = getDb()
  const limit = opts.limit || 50
  const offset = opts.offset || 0
  const conditions: string[] = []
  const params: unknown[] = []

  if (opts.sector) {
    conditions.push('m.sector = ?')
    params.push(opts.sector)
  }
  if (opts.source) {
    conditions.push('m.source = ?')
    params.push(opts.source)
  }
  if (opts.clientSlug) {
    conditions.push('m.client_slug = ?')
    params.push(opts.clientSlug)
  }

  let where = conditions.length > 0 ? 'WHERE ' + conditions.join(' AND ') : ''

  if (opts.query && opts.query.trim()) {
    // Use FTS5 search
    const ftsQuery = opts.query.trim().split(/\s+/).map(w => `"${w}"*`).join(' ')
    try {
      const ftsWhere = where ? where + ' AND ' : 'WHERE '
      const countSql = `SELECT COUNT(*) as c FROM memories m INNER JOIN memories_fts f ON m.id = f.rowid ${ftsWhere}memories_fts MATCH ?`
      params.push(ftsQuery)
      const total = (d.prepare(countSql).get(...params) as { c: number }).c

      const sql = `SELECT m.id, m.content, m.sector, m.source, m.source_contact, m.source_channel, m.salience, m.created_at, m.accessed_at, m.client_slug
        FROM memories m INNER JOIN memories_fts f ON m.id = f.rowid
        ${ftsWhere}memories_fts MATCH ?
        ORDER BY m.created_at DESC LIMIT ? OFFSET ?`
      const rows = d.prepare(sql).all(...params, limit, offset) as MemoryRow[]
      return { rows, total }
    } catch {
      // FTS query failed, fall back to LIKE
      const likeWhere = where ? where + ' AND ' : 'WHERE '
      // Remove the ftsQuery param we already pushed
      params.pop()
      conditions.push('m.content LIKE ?')
      params.push(`%${opts.query.trim()}%`)
      where = 'WHERE ' + conditions.join(' AND ')
    }
  }

  const countSql = `SELECT COUNT(*) as c FROM memories m ${where}`
  const total = (d.prepare(countSql).get(...params) as { c: number }).c

  const sql = `SELECT m.id, m.content, m.sector, m.source, m.source_contact, m.source_channel, m.salience, m.created_at, m.accessed_at, m.client_slug
    FROM memories m ${where}
    ORDER BY m.created_at DESC LIMIT ? OFFSET ?`
  const rows = d.prepare(sql).all(...params, limit, offset) as MemoryRow[]
  return { rows, total }
}

export function getMemorySourceStats(): Array<{ source: string; channel: string | null; count: number }> {
  const d = getDb()
  try {
    return d.prepare(`SELECT source, source_channel as channel, COUNT(*) as count FROM memories GROUP BY source, source_channel ORDER BY count DESC`).all() as Array<{ source: string; channel: string | null; count: number }>
  } catch {
    return []
  }
}

export function getMemorySectorStats(): { semantic: number; episodic: number; total: number } {
  const d = getDb()
  try {
    const rows = d.prepare('SELECT sector, COUNT(*) as c FROM memories GROUP BY sector').all() as Array<{ sector: string; c: number }>
    const semantic = rows.find(r => r.sector === 'semantic')?.c || 0
    const episodic = rows.find(r => r.sector === 'episodic')?.c || 0
    return { semantic, episodic, total: semantic + episodic }
  } catch {
    return { semantic: 0, episodic: 0, total: 0 }
  }
}

