// ─── User Ad Accounts (Meta/Facebook) ───

export interface UserAdAccount {
  id: number
  user_id: number
  account_id: string
  account_name: string
  client_slug: string | null
  currency: string
  business_name: string | null
  enabled: number
  created_at: number
}

export function getUserAdAccounts(userId: number): UserAdAccount[] {
  return getDb().prepare('SELECT * FROM user_ad_accounts WHERE user_id = ? ORDER BY account_name').all(userId) as UserAdAccount[]
}

export function saveUserAdAccounts(userId: number, accounts: Array<{ account_id: string; account_name: string; client_slug?: string; currency?: string; business_name?: string }>) {
  const d = getDb()
  const upsert = d.prepare(
    `INSERT INTO user_ad_accounts (user_id, account_id, account_name, client_slug, currency, business_name)
     VALUES (?, ?, ?, ?, ?, ?)
     ON CONFLICT(user_id, account_id) DO UPDATE SET
       account_name = excluded.account_name,
       client_slug = COALESCE(excluded.client_slug, user_ad_accounts.client_slug),
       currency = excluded.currency,
       business_name = excluded.business_name`
  )
  const tx = d.transaction(() => {
    // Remove accounts not in the new list
    const ids = accounts.map(a => a.account_id)
    if (ids.length > 0) {
      d.prepare(`DELETE FROM user_ad_accounts WHERE user_id = ? AND account_id NOT IN (${ids.map(() => '?').join(',')})`).run(userId, ...ids)
    } else {
      d.prepare('DELETE FROM user_ad_accounts WHERE user_id = ?').run(userId)
    }
    // Upsert selected accounts
    for (const acc of accounts) {
      upsert.run(userId, acc.account_id, acc.account_name, acc.client_slug || null, acc.currency || 'CAD', acc.business_name || null)
    }
  })
  tx()
}

/** Resolve an ad account by name, client_slug, or account_id. Case-insensitive partial match on name/slug. */
export function resolveAdAccountId(userId: number, query: string): UserAdAccount | null {
  const d = getDb()
  // Try exact account_id match (with and without act_ prefix)
  const rawId = query.replace(/^act_/, '')
  const byId = d.prepare('SELECT * FROM user_ad_accounts WHERE user_id = ? AND (account_id = ? OR account_id = ?)').get(userId, rawId, `act_${rawId}`) as UserAdAccount | undefined
  if (byId) return byId
  // Try exact client_slug match (case-insensitive)
  const bySlug = d.prepare('SELECT * FROM user_ad_accounts WHERE user_id = ? AND LOWER(client_slug) = LOWER(?)').get(userId, query) as UserAdAccount | undefined
  if (bySlug) return bySlug
  // Try partial account_name match (case-insensitive)
  const byName = d.prepare('SELECT * FROM user_ad_accounts WHERE user_id = ? AND LOWER(account_name) LIKE LOWER(?)').get(userId, `%${query}%`) as UserAdAccount | undefined
  if (byName) return byName
  // Try partial business_name match
  const byBiz = d.prepare('SELECT * FROM user_ad_accounts WHERE user_id = ? AND LOWER(business_name) LIKE LOWER(?)').get(userId, `%${query}%`) as UserAdAccount | undefined
  if (byBiz) return byBiz
  return null
}

