export interface UserPage {
  id: number
  user_id: number
  page_id: string
  page_name: string
  page_access_token: string
  instagram_account_id: string | null
  category: string | null
  picture_url: string | null
  fan_count: number
  enabled: number
  created_at: number
}

export function getUserPages(userId: number): UserPage[] {
  return getDb().prepare('SELECT * FROM user_pages WHERE user_id = ? ORDER BY page_name').all(userId) as UserPage[]
}

export function saveUserPages(userId: number, pages: Array<{ page_id: string; page_name: string; page_access_token: string; instagram_account_id?: string | null; category?: string; picture_url?: string; fan_count?: number }>) {
  const d = getDb()
  const upsert = d.prepare(
    `INSERT INTO user_pages (user_id, page_id, page_name, page_access_token, instagram_account_id, category, picture_url, fan_count)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?)
     ON CONFLICT(user_id, page_id) DO UPDATE SET
       page_name = excluded.page_name,
       page_access_token = excluded.page_access_token,
       instagram_account_id = excluded.instagram_account_id,
       category = excluded.category,
       picture_url = excluded.picture_url,
       fan_count = excluded.fan_count`
  )
  const tx = d.transaction(() => {
    const ids = pages.map(p => p.page_id)
    if (ids.length > 0) {
      d.prepare(`DELETE FROM user_pages WHERE user_id = ? AND page_id NOT IN (${ids.map(() => '?').join(',')})`).run(userId, ...ids)
    } else {
      d.prepare('DELETE FROM user_pages WHERE user_id = ?').run(userId)
    }
    for (const page of pages) {
      upsert.run(userId, page.page_id, page.page_name, page.page_access_token, page.instagram_account_id || null, page.category || null, page.picture_url || null, page.fan_count || 0)
    }
  })
  tx()
}

