// ─── Messaging ───

export interface MsgChannel {
  id: number; workspace_id: number | null; name: string; slug: string; description: string | null; topic: string | null
  type: 'public' | 'private' | 'dm'; created_by: number | null; is_default: number
  archived: number; created_at: number; updated_at: number
}

export interface MsgMessage {
  id: number; channel_id: number; thread_parent_id: number | null
  sender_user_id: number | null; sender_agent_id: string | null
  content: string; message_type: string; edited_at: number | null
  deleted_at: number | null; created_at: number; scheduled_at: number | null
  metadata: string | null
}

export interface MsgAttachment {
  id: number; message_id: number; filename: string; filepath: string
  mimetype: string; size: number; duration_seconds: number | null; thumbnail: string | null; created_at: number
}

export function getMsgChannels(userId?: number, workspaceId?: number): MsgChannel[] {
  const d = getDb()
  if (userId && workspaceId) {
    return d.prepare(`
      SELECT c.* FROM msg_channels c
      JOIN msg_channel_members m ON m.channel_id = c.id AND m.user_id = ?
      WHERE c.archived = 0 AND (c.workspace_id = ? OR c.workspace_id IS NULL) AND c.type != 'dm'
      ORDER BY c.is_default DESC, c.sort_order ASC, c.name
    `).all(userId, workspaceId) as MsgChannel[]
  }
  if (userId) {
    return d.prepare(`
      SELECT c.* FROM msg_channels c
      JOIN msg_channel_members m ON m.channel_id = c.id AND m.user_id = ?
      WHERE c.archived = 0
      ORDER BY c.is_default DESC, c.sort_order ASC, c.name
    `).all(userId) as MsgChannel[]
  }
  if (workspaceId) {
    return d.prepare("SELECT * FROM msg_channels WHERE archived = 0 AND (workspace_id = ? OR workspace_id IS NULL) AND type != 'dm' ORDER BY is_default DESC, sort_order ASC, name").all(workspaceId) as MsgChannel[]
  }
  return d.prepare("SELECT * FROM msg_channels WHERE archived = 0 AND type != 'dm' ORDER BY is_default DESC, sort_order ASC, name").all() as MsgChannel[]
}

export function getMsgDmChannels(userId: number): (MsgChannel & { other_user_name?: string })[] {
  const d = getDb()
  const channels = d.prepare(`
    SELECT c.* FROM msg_channels c
    JOIN msg_channel_members m ON m.channel_id = c.id AND m.user_id = ?
    WHERE c.type = 'dm' AND c.archived = 0
    ORDER BY c.name
  `).all(userId) as MsgChannel[]

  const agentNames: Record<number, string> = { 100: 'Jimmy', 101: 'Gary', 102: 'Ricky', 103: 'Sofia', 105: 'Jimmyclaw' }
  const teamMembers = getTeamMembers()

  return channels.map(ch => {
    const members = d.prepare('SELECT user_id FROM msg_channel_members WHERE channel_id = ?').all(ch.id) as { user_id: number }[]
    const otherId = members.find(m => m.user_id !== userId)?.user_id
    let otherName: string | undefined
    if (otherId) {
      otherName = agentNames[otherId] || teamMembers.find(m => m.id === otherId)?.name || `User ${otherId}`
    }
    return { ...ch, other_user_name: otherName }
  })
}

export function getMsgChannel(id: number): MsgChannel | null {
  return getDb().prepare('SELECT * FROM msg_channels WHERE id = ?').get(id) as MsgChannel | null
}

export function getMsgChannelBySlug(slug: string): MsgChannel | null {
  return getDb().prepare('SELECT * FROM msg_channels WHERE slug = ?').get(slug) as MsgChannel | null
}

export function createMsgChannel(data: { name: string; slug: string; type: string; workspace_id?: number; description?: string; created_by?: number }): MsgChannel {
  // Block channel creation in private workspaces
  if (data.workspace_id && isPrivateWorkspace(data.workspace_id)) {
    throw new Error('PRIVATE_WORKSPACE_RESTRICTED')
  }
  const d = getDb()
  const result = d.prepare(
    'INSERT INTO msg_channels (name, slug, type, workspace_id, description, created_by) VALUES (?, ?, ?, ?, ?, ?)'
  ).run(data.name, data.slug, data.type, data.workspace_id || null, data.description || null, data.created_by || null)
  return d.prepare('SELECT * FROM msg_channels WHERE id = ?').get(result.lastInsertRowid) as MsgChannel
}

export function updateMsgChannel(id: number, data: { name?: string; description?: string; topic?: string; archived?: number; type?: string }): void {
  const sets: string[] = []; const vals: unknown[] = []
  if (data.name !== undefined) { sets.push('name = ?'); vals.push(data.name) }
  if (data.description !== undefined) { sets.push('description = ?'); vals.push(data.description) }
  if (data.topic !== undefined) { sets.push('topic = ?'); vals.push(data.topic) }
  if (data.archived !== undefined) { sets.push('archived = ?'); vals.push(data.archived) }
  if (data.type !== undefined && ['public', 'private'].includes(data.type)) { sets.push('type = ?'); vals.push(data.type) }
  if (sets.length === 0) return
  sets.push("updated_at = strftime('%s','now')")
  vals.push(id)
  getDb().prepare(`UPDATE msg_channels SET ${sets.join(', ')} WHERE id = ?`).run(...vals)
}

