export function getMsgMessages(channelId: number, limit = 50, beforeId?: number): MsgMessage[] {
  const d = getDb()
  const now = Math.floor(Date.now() / 1000)
  if (beforeId) {
    return d.prepare('SELECT * FROM msg_messages WHERE channel_id = ? AND thread_parent_id IS NULL AND deleted_at IS NULL AND (scheduled_at IS NULL OR scheduled_at <= ?) AND id < ? ORDER BY created_at DESC LIMIT ?').all(channelId, now, beforeId, limit) as MsgMessage[]
  }
  return d.prepare('SELECT * FROM msg_messages WHERE channel_id = ? AND thread_parent_id IS NULL AND deleted_at IS NULL AND (scheduled_at IS NULL OR scheduled_at <= ?) ORDER BY created_at DESC LIMIT ?').all(channelId, now, limit) as MsgMessage[]
}

