export function createMsgMessage(data: { channel_id: number; content: string; sender_user_id?: number; sender_agent_id?: string; thread_parent_id?: number; message_type?: string; metadata?: string }): MsgMessage {
  const d = getDb()
  const result = d.prepare(
    'INSERT INTO msg_messages (channel_id, content, sender_user_id, sender_agent_id, thread_parent_id, message_type, metadata) VALUES (?, ?, ?, ?, ?, ?, ?)'
  ).run(data.channel_id, data.content, data.sender_user_id || null, data.sender_agent_id || null, data.thread_parent_id || null, data.message_type || 'text', data.metadata || null)
  d.prepare("UPDATE msg_channels SET updated_at = strftime('%s','now') WHERE id = ?").run(data.channel_id)
  return d.prepare('SELECT * FROM msg_messages WHERE id = ?').get(result.lastInsertRowid) as MsgMessage
}

