export function getReminders(userId: number, onlyDue = false): { id: number; user_id: number; message_id: number; channel_id: number; remind_at: number; dismissed: number; created_at: number }[] {
  if (onlyDue) {
    return getDb().prepare("SELECT * FROM msg_reminders WHERE user_id = ? AND dismissed = 0 AND remind_at <= strftime('%s','now') ORDER BY remind_at ASC").all(userId) as any[]
  }
  return getDb().prepare('SELECT * FROM msg_reminders WHERE user_id = ? AND dismissed = 0 ORDER BY remind_at ASC').all(userId) as any[]
}

