// ─── User Threads ───

export function getUserThreads(userId: number, limit: number = 30): MsgMessage[] {
  // Get threads where user is the OP or has replied
  return getDb().prepare(`
    SELECT DISTINCT p.* FROM msg_messages p
    WHERE p.deleted_at IS NULL AND p.thread_parent_id IS NULL
    AND (
      p.sender_user_id = ?
      OR p.id IN (
        SELECT DISTINCT thread_parent_id FROM msg_messages
        WHERE sender_user_id = ? AND thread_parent_id IS NOT NULL AND deleted_at IS NULL
      )
    )
    AND (SELECT COUNT(*) FROM msg_messages WHERE thread_parent_id = p.id AND deleted_at IS NULL) > 0
    ORDER BY (
      SELECT MAX(created_at) FROM msg_messages WHERE thread_parent_id = p.id AND deleted_at IS NULL
    ) DESC
    LIMIT ?
  `).all(userId, userId, limit) as MsgMessage[]
}

// ─── Activity Feed ───

export function getUserActivity(userId: number, limit: number = 50): { type: string; message_id: number; channel_id: number; actor_user_id: number | null; actor_agent_id: string | null; detail: string | null; created_at: number }[] {
  const d = getDb()
  const results: any[] = []

  // Mentions
  const mentions = d.prepare(`
    SELECT mm.message_id, mm.channel_id, m.sender_user_id as actor_user_id, m.sender_agent_id as actor_agent_id, m.created_at, mm.mention_type
    FROM msg_mentions mm
    JOIN msg_messages m ON m.id = mm.message_id
    WHERE mm.user_id = ? AND m.deleted_at IS NULL
    ORDER BY m.created_at DESC LIMIT ?
  `).all(userId, limit) as any[]
  for (const m of mentions) {
    results.push({ type: 'mention', message_id: m.message_id, channel_id: m.channel_id, actor_user_id: m.actor_user_id, actor_agent_id: m.actor_agent_id, detail: m.mention_type, created_at: m.created_at })
  }

  // Thread replies to user's messages
  const threadReplies = d.prepare(`
    SELECT r.id as message_id, r.channel_id, r.sender_user_id as actor_user_id, r.sender_agent_id as actor_agent_id, r.created_at
    FROM msg_messages r
    JOIN msg_messages p ON r.thread_parent_id = p.id
    WHERE p.sender_user_id = ? AND r.sender_user_id != ? AND r.deleted_at IS NULL
    ORDER BY r.created_at DESC LIMIT ?
  `).all(userId, userId, limit) as any[]
  for (const r of threadReplies) {
    results.push({ type: 'thread_reply', message_id: r.message_id, channel_id: r.channel_id, actor_user_id: r.actor_user_id, actor_agent_id: r.actor_agent_id, detail: null, created_at: r.created_at })
  }

  // Reactions to user's messages
  const reactions = d.prepare(`
    SELECT r.message_id, m.channel_id, r.user_id as actor_user_id, NULL as actor_agent_id, r.created_at, r.emoji
    FROM msg_reactions r
    JOIN msg_messages m ON m.id = r.message_id
    WHERE m.sender_user_id = ? AND r.user_id != ? AND m.deleted_at IS NULL
    ORDER BY r.created_at DESC LIMIT ?
  `).all(userId, userId, limit) as any[]
  for (const r of reactions) {
    results.push({ type: 'reaction', message_id: r.message_id, channel_id: r.channel_id, actor_user_id: r.actor_user_id, actor_agent_id: r.actor_agent_id, detail: r.emoji, created_at: r.created_at })
  }

  // Sort by created_at DESC and limit
  results.sort((a, b) => b.created_at - a.created_at)
  return results.slice(0, limit)
}

