// Portal token verification -- reusable across ads routes
export function verifyPortalToken(slug: string, token: string | null): boolean {
  const d = getDb()
  const portal = d.prepare('SELECT password_hash, magic_link_token FROM portal_access WHERE client_slug = ? AND enabled = 1').get(slug) as { password_hash: string | null; magic_link_token: string | null } | undefined
  if (!portal) return false
  if (!portal.password_hash) return true // no password set, slug access is enough
  if (!token) return false
  // Check magic link token
  if (portal.magic_link_token && token === portal.magic_link_token) return true
  // Check password
  if (portal.password_hash.includes(':')) {
    const [salt, hash] = portal.password_hash.split(':')
    const attempt = crypto.scryptSync(token, salt, 64).toString('hex')
    return hash.length === attempt.length && crypto.timingSafeEqual(Buffer.from(hash), Buffer.from(attempt))
  }
  return false
}

// Get allowed ad account IDs for a portal's client -- reusable across ads routes
export function getPortalAdAccountIds(slug: string): string[] {
  const d = getDb()
  const clientRow = d.prepare('SELECT id FROM client_profiles WHERE slug = ?').get(slug) as { id: number } | undefined
  if (!clientRow) return []
  const businesses = d.prepare('SELECT ad_account_id FROM client_businesses WHERE client_id = ? AND ad_account_id IS NOT NULL').all(clientRow.id) as { ad_account_id: string }[]
  return businesses.map(b => b.ad_account_id)
}

