export function getCampaignAnalytics(campaignId: number): EmailStepAnalytics[] {
  const steps = getCampaignSteps(campaignId)
  return steps.map(step => {
    const counts = getDb().prepare(`
      SELECT
        COUNT(*) FILTER (WHERE status IN ('sent','opened','clicked','replied')) AS sent_count,
        COUNT(*) FILTER (WHERE status IN ('opened','clicked','replied')) AS opened_count,
        COUNT(*) FILTER (WHERE status = 'clicked') AS clicked_count,
        COUNT(*) FILTER (WHERE status = 'replied') AS replied_count
      FROM email_sends
      WHERE step_id = ?
    `).get(step.id) as {
      sent_count: number
      opened_count: number
      clicked_count: number
      replied_count: number
    }
    return { ...step, ...counts }
  })
}

