export function getQueuedEmailSends(now: number): Array<(EmailSend & { contact: CrmContact; campaign: EmailCampaign; step: EmailSequenceStep })> {
  const rows = getDb().prepare(`
    SELECT s.id
    FROM email_sends s
    WHERE s.status = 'queued' AND s.sent_at IS NULL AND s.scheduled_for <= ?
    ORDER BY s.scheduled_for ASC, s.id ASC
  `).all(now) as { id: number }[]
  return rows
    .map(row => getEmailSendWithContext(row.id))
    .filter((row): row is (EmailSend & { contact: CrmContact; campaign: EmailCampaign; step: EmailSequenceStep }) => row !== null)
}

export function hasCampaignReply(contactId: number, campaignId: number): boolean {
  const row = getDb().prepare(`
    SELECT 1
    FROM email_sends
    WHERE contact_id = ? AND campaign_id = ? AND status = 'replied'
    LIMIT 1
  `).get(contactId, campaignId)
  return !!row
}

function resolveCampaignSubjectVariant(
  campaign: Pick<EmailCampaign, 'id' | 'subject_b' | 'subject_split_pct'>,
  contactId: number,
  stepPosition: number,
): 'a' | 'b' {
  if (stepPosition !== 0) return 'a'
  const subjectB = (campaign.subject_b || '').trim()
  if (!subjectB) return 'a'
  const split = Math.max(0, Math.min(100, Math.round(campaign.subject_split_pct ?? 50)))
  if (split <= 0) return 'a'
  if (split >= 100) return 'b'
  const bucket = parseInt(crypto.createHash('sha1').update(`${campaign.id}:${contactId}`).digest('hex').slice(0, 8), 16) % 100
  return bucket < split ? 'b' : 'a'
}

export function queueCampaignSends(campaignId: number): EmailSend[] {
  const campaign = getCampaign(campaignId)
  if (!campaign) return []
  const contacts = getCampaignContacts(campaignId)
  const steps = getCampaignSteps(campaignId)
  const existing = getDb().prepare('SELECT contact_id, step_id FROM email_sends WHERE campaign_id = ?').all(campaignId) as Array<{ contact_id: number; step_id: number }>
  const existingKeys = new Set(existing.map(row => `${row.contact_id}:${row.step_id}`))
  const created: EmailSend[] = []
  const launchAt = Math.floor(Date.now() / 1000)

  for (const contact of contacts) {
    let delayHoursTotal = 0
    for (const step of steps) {
      delayHoursTotal += (step.delay_days * 24) + step.delay_hours
      const key = `${contact.id}:${step.id}`
      if (existingKeys.has(key)) continue
      created.push(createEmailSend({
        contact_id: contact.id,
        campaign_id: campaignId,
        step_id: step.id,
        scheduled_for: launchAt + (delayHoursTotal * 3600),
        subject_variant: resolveCampaignSubjectVariant(campaign, contact.id, step.position),
      }))
    }
  }

  return created
}

