/**
 * Resolve the workspace id for an EmailSend via its campaign. Lets the mark*
 * helpers fire the email_event workflow trigger without the caller having
 * to plumb workspace context through tracking webhooks.
 */
function workspaceIdForSend(send: EmailSend): number | null {
  const row = getDb().prepare('SELECT workspace_id FROM email_campaigns WHERE id = ?').get(send.campaign_id) as { workspace_id: number } | undefined
  return row?.workspace_id ?? null
}

/** Fire the email_event trigger for a send. No-op when workspace is unknown. */
function fireEmailEventTrigger(send: EmailSend, eventValue: 'opened' | 'clicked' | 'replied' | 'bounced' | 'unsubscribed'): void {
  const workspaceId = workspaceIdForSend(send)
  if (!workspaceId) return
  try {
    queueCrmWorkflowRunsForTrigger({
      workspaceId,
      contactId: send.contact_id,
      triggerType: 'email_event',
      triggerValue: eventValue,
    })
  } catch { /* don't let trigger queue failures break the send update */ }
}

export function markSendOpened(id: number): EmailSend | null {
  const existing = getEmailSend(id)
  if (!existing) return null
  if (existing.opened_at) return existing
  const now = Math.floor(Date.now() / 1000)
  const nextStatus: EmailSend['status'] = existing.status === 'sent' ? 'opened' : existing.status
  const updated = updateEmailSend(id, { opened_at: now, status: nextStatus })
  if (updated) fireEmailEventTrigger(updated, 'opened')
  return updated
}

export function markSendClicked(id: number): EmailSend | null {
  const existing = getEmailSend(id)
  if (!existing) return null
  const now = Math.floor(Date.now() / 1000)
  const wasAlreadyClicked = existing.status === 'clicked' || existing.status === 'replied'
  const updated = updateEmailSend(id, {
    opened_at: existing.opened_at ?? now,
    status: existing.status === 'replied' ? 'replied' : 'clicked',
  })
  // Only fire on the transition to clicked so workflows don't multi-enrol
  // a contact who clicks the same link twice.
  if (updated && !wasAlreadyClicked) fireEmailEventTrigger(updated, 'clicked')
  return updated
}

export function markSendReplied(id: number): EmailSend | null {
  const existing = getEmailSend(id)
  if (!existing) return null
  const now = Math.floor(Date.now() / 1000)
  const wasReplied = existing.status === 'replied'
  const updated = updateEmailSend(id, {
    status: 'replied',
    replied_at: now,
    opened_at: existing.opened_at ?? now,
  })
  if (updated && !wasReplied) fireEmailEventTrigger(updated, 'replied')
  return updated
}

