// Catalog ids from src/lib/crm-actions.ts, plus the sentinels start/end.
// Kept inline (not imported) so this file stays DB-only and boot-safe.
const CRM_WORKFLOW_NODE_TYPES = new Set<string>([
  'start', 'end',
  // Communication
  'send_email', 'send_sms', 'send_internal_notification', 'voicemail_drop', 'manual_call_task', 'webhook',
  'send_review_request', 'send_survey',
  // Contact
  'add_tag', 'remove_tag', 'add_to_list', 'remove_from_list',
  'set_lifecycle_stage', 'update_custom_field', 'update_contact_field', 'toggle_dnd', 'add_note',
  // Ticketing
  'assign_ticket', 'set_ticket_status', 'add_ticket_tag',
  // Pipeline
  'set_pipeline_stage',
  // Opportunity
  'create_opportunity', 'update_opportunity_stage', 'assign_opportunity', 'delete_opportunity',
  // Task
  'create_task', 'update_task', 'complete_task',
  // Flow control
  'wait', 'condition', 'ab_split', 'goal_event', 'add_to_workflow', 'remove_from_workflow', 'end_workflow',
  'enroll_in_drip',
  // Calendar
  'book_appointment', 'cancel_appointment', 'send_calendar_link',
  // Data / math
  'math_on_field',
  // External
  'facebook_audience_add', 'facebook_audience_remove', 'google_analytics_event', 'facebook_pixel_event',
  // Affiliate
  'approve_affiliate', 'pay_affiliate_payout',
])

function makeWorkflowNodeId(prefix = 'node'): string {
  return `${prefix}_${crypto.randomBytes(5).toString('hex')}`
}

function defaultCrmWorkflowGraph(): CrmWorkflowGraph {
  const startId = 'start'
  const endId = 'end'
  return {
    nodes: [
      { id: startId, type: 'start', label: 'Start', config: {} },
      { id: endId, type: 'end', label: 'End', config: {} },
    ],
    edges: [
      { id: `edge_${startId}_${endId}`, source: startId, target: endId, branch: 'default' },
    ],
  }
}

function normalizeWorkflowNode(raw: unknown, _index: number): CrmWorkflowNode | null {
  if (!raw || typeof raw !== 'object') return null
  const row = raw as Record<string, unknown>
  const id = typeof row.id === 'string' && row.id.trim() ? row.id.trim() : makeWorkflowNodeId('node')
  const type = typeof row.type === 'string' ? row.type : ''
  if (!CRM_WORKFLOW_NODE_TYPES.has(type as CrmWorkflowNode['type'])) return null
  const label = typeof row.label === 'string' ? row.label.trim() : ''
  const config = row.config && typeof row.config === 'object' ? { ...(row.config as Record<string, unknown>) } : {}
  return {
    id,
    type: type as CrmWorkflowNode['type'],
    label: label || undefined,
    config,
  }
}

function normalizeCrmWorkflowGraph(raw: unknown): CrmWorkflowGraph {
  const parsed = raw && typeof raw === 'object' ? raw as Record<string, unknown> : {}
  const nodeRows = Array.isArray(parsed.nodes) ? parsed.nodes : []
  const edgeRows = Array.isArray(parsed.edges) ? parsed.edges : []
  const nodes = nodeRows.map((row, index) => normalizeWorkflowNode(row, index)).filter((row): row is CrmWorkflowNode => Boolean(row))

  let hasStart = false
  let hasEnd = false
  const dedupedNodes: CrmWorkflowNode[] = []
  const nodeIdSet = new Set<string>()
  for (const node of nodes) {
    if (nodeIdSet.has(node.id)) continue
    nodeIdSet.add(node.id)
    if (node.type === 'start') hasStart = true
    if (node.type === 'end') hasEnd = true
    dedupedNodes.push(node)
  }
  if (!hasStart) {
    dedupedNodes.unshift({ id: 'start', type: 'start', label: 'Start', config: {} })
    nodeIdSet.add('start')
  }
  if (!hasEnd) {
    const endId = nodeIdSet.has('end') ? makeWorkflowNodeId('end') : 'end'
    dedupedNodes.push({ id: endId, type: 'end', label: 'End', config: {} })
    nodeIdSet.add(endId)
  }

  const edges: CrmWorkflowEdge[] = []
  const edgeIdSet = new Set<string>()
  for (const row of edgeRows) {
    if (!row || typeof row !== 'object') continue
    const edge = row as Record<string, unknown>
    const source = typeof edge.source === 'string' ? edge.source.trim() : ''
    const target = typeof edge.target === 'string' ? edge.target.trim() : ''
    if (!source || !target) continue
    if (!nodeIdSet.has(source) || !nodeIdSet.has(target)) continue
    const id = typeof edge.id === 'string' && edge.id.trim() ? edge.id.trim() : `edge_${source}_${target}`
    if (edgeIdSet.has(id)) continue
    const branchRaw = typeof edge.branch === 'string' ? edge.branch.trim().toLowerCase() : 'default'
    const branch =
      branchRaw === 'true' || branchRaw === 'false' || branchRaw === 'a' || branchRaw === 'b'
        ? branchRaw
        : 'default'
    edgeIdSet.add(id)
    edges.push({ id, source, target, branch: branch as CrmWorkflowEdge['branch'] })
  }

  if (edges.length === 0) {
    const startNode = dedupedNodes.find((node) => node.type === 'start') || dedupedNodes[0]
    const endNode = [...dedupedNodes].reverse().find((node) => node.type === 'end') || dedupedNodes[dedupedNodes.length - 1]
    if (startNode && endNode) {
      const middleNodes = dedupedNodes.filter((node) => node.id !== startNode.id && node.id !== endNode.id)
      const linear = [startNode, ...middleNodes, endNode]
      for (let i = 0; i < linear.length - 1; i += 1) {
        const source = linear[i]
        const target = linear[i + 1]
        edges.push({ id: `edge_${source.id}_${target.id}`, source: source.id, target: target.id, branch: 'default' })
      }
    }
  }

  return {
    nodes: dedupedNodes,
    edges,
  }
}

function enrichCrmWorkflow(row: CrmWorkflow): CrmWorkflowRecord {
  return {
    ...row,
    graph: normalizeCrmWorkflowGraph(safeJsonParse<CrmWorkflowGraph>(row.graph_json, defaultCrmWorkflowGraph())),
    is_active_bool: Boolean(row.is_active),
  }
}

