function normalizeTagKey(tag: string): string {
  return tag.trim().toLowerCase()
}

export interface CrmTagUsage {
  tag: string
  contact_count: number
}

/** Tag usage across all contacts in a workspace. Derived from the comma-separated `tags` column. */
export function getCrmTagsUsage(workspaceId: number): CrmTagUsage[] {
  const rows = getDb()
    .prepare("SELECT tags FROM crm_contacts WHERE workspace_id = ? AND tags IS NOT NULL AND tags != ''")
    .all(workspaceId) as Array<{ tags: string | null }>
  const counts = new Map<string, { display: string; count: number }>()
  for (const row of rows) {
    const seen = new Set<string>()
    for (const tag of crmParseTags(row.tags)) {
      const key = normalizeTagKey(tag)
      if (!key || seen.has(key)) continue
      seen.add(key)
      const existing = counts.get(key)
      if (existing) existing.count += 1
      else counts.set(key, { display: tag.trim(), count: 1 })
    }
  }
  return Array.from(counts.values())
    .map(({ display, count }) => ({ tag: display, contact_count: count }))
    .sort((a, b) => b.contact_count - a.contact_count || a.tag.localeCompare(b.tag))
}

/** Renames a tag on every contact in the workspace that has it.
 *  Returns the number of contacts touched. Case-insensitive match. */
export function renameCrmTag(workspaceId: number, fromTag: string, toTag: string): number {
  const fromKey = normalizeTagKey(fromTag)
  const toKey = normalizeTagKey(toTag)
  if (!fromKey || !toKey || fromKey === toKey) return 0
  const rows = getDb()
    .prepare("SELECT id, tags FROM crm_contacts WHERE workspace_id = ? AND tags IS NOT NULL AND tags != ''")
    .all(workspaceId) as Array<{ id: number; tags: string | null }>
  const update = getDb().prepare('UPDATE crm_contacts SET tags = ?, updated_at = ? WHERE id = ?')
  const now = Math.floor(Date.now() / 1000)
  let touched = 0
  for (const row of rows) {
    const tags = crmParseTags(row.tags)
    if (!tags.some((t) => normalizeTagKey(t) === fromKey)) continue
    const renamed = tags
      .map((t) => (normalizeTagKey(t) === fromKey ? toTag : t))
    // Deduplicate after rename (in case target tag already exists on the contact).
    const seen = new Set<string>()
    const deduped: string[] = []
    for (const t of renamed) {
      const key = normalizeTagKey(t)
      if (seen.has(key)) continue
      seen.add(key)
      deduped.push(t)
    }
    update.run(deduped.join(', '), now, row.id)
    touched += 1
  }
  return touched
}

