  if (data.name !== undefined) { sets.push('name = ?'); params.push(data.name.trim()) }
  if (data.channel !== undefined) { sets.push('channel = ?'); params.push(data.channel) }
  if (data.subject !== undefined) { sets.push('subject = ?'); params.push(data.subject?.trim() || null) }
  if (data.body !== undefined) { sets.push('body = ?'); params.push(data.body) }
  if (data.content_kind !== undefined) { sets.push('content_kind = ?'); params.push(data.content_kind === 'blocks' ? 'blocks' : 'plain') }
