export interface CrmAiGeneration {
  id: number
  workspace_id: number
  user_id: number | null
  prompt_id: number | null
  category: string
  input_context_json: string
  output_text: string
  model: string
  tokens_in: number
  tokens_out: number
  liked: number | null
  created_at: string
  updated_at: string
}

export interface CrmAiGenerationRecord extends CrmAiGeneration {
  liked_bool: boolean | null
}

function enrichCrmAiGeneration(row: CrmAiGeneration): CrmAiGenerationRecord {
  return {
    ...row,
    liked_bool: row.liked === null ? null : Boolean(row.liked),
  }
}

export function createCrmAiGeneration(workspaceId: number, userId: number | null, data: {
  prompt_id?: number | null
  category: string
  input_context?: Record<string, unknown> | string | null
  output_text: string
  model: string
  tokens_in?: number
  tokens_out?: number
  liked?: boolean | null
}): CrmAiGenerationRecord {
  const now = crmAiNowIso()
  const inputContextJson = typeof data.input_context === 'string'
    ? data.input_context
    : JSON.stringify(data.input_context ?? {})
  const likedValue = data.liked === undefined || data.liked === null ? null : (data.liked ? 1 : 0)
  const result = getDb().prepare(`
    INSERT INTO crm_ai_generations (
      workspace_id, user_id, prompt_id, category, input_context_json, output_text,
      model, tokens_in, tokens_out, liked, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    userId ?? null,
    data.prompt_id ?? null,
    data.category.trim(),
    inputContextJson,
    data.output_text,
    data.model.trim(),
    Math.max(0, Math.floor(data.tokens_in ?? 0)),
    Math.max(0, Math.floor(data.tokens_out ?? 0)),
    likedValue,
    now,
    now,
  )
  if (data.prompt_id) {
    getDb().prepare(`
      UPDATE crm_ai_prompts
      SET usage_count = usage_count + 1, updated_at = ?
      WHERE id = ? AND workspace_id = ?
    `).run(now, data.prompt_id, workspaceId)
  }
  const row = getDb().prepare('SELECT * FROM crm_ai_generations WHERE id = ?').get(Number(result.lastInsertRowid)) as CrmAiGeneration
  return enrichCrmAiGeneration(row)
}

export function listCrmAiGenerations(workspaceId: number, opts?: { limit?: number }): CrmAiGenerationRecord[] {
  const limit = Math.min(200, Math.max(1, Math.floor(opts?.limit ?? 50)))
  const rows = getDb().prepare(`
    SELECT * FROM crm_ai_generations
    WHERE workspace_id = ?
    ORDER BY created_at DESC, id DESC
    LIMIT ?
  `).all(workspaceId, limit) as CrmAiGeneration[]
  return rows.map(enrichCrmAiGeneration)
}

