// ─── Reputation: review campaigns ─────────────────────────────────────────
export type CrmReviewCampaignTrigger =
  | 'manual'
  | 'opportunity_won'
  | 'appointment_completed'
  | 'invoice_paid'
  | 'form_submitted'

export type CrmReviewCampaignChannel = 'sms' | 'email' | 'both'

export interface CrmReviewCampaign {
  id: number
  workspace_id: number
  name: string
  trigger_event: CrmReviewCampaignTrigger
  channel: CrmReviewCampaignChannel
  message_template_sms: string | null
  message_template_email: string | null
  subject_template: string | null
  preview_text: string | null
  send_delay_hours: number
  follow_up_after_days: number | null
  max_follow_ups: number
  active: number
  created_by_user_id: number | null
  created_at: number
  updated_at: number
}

// The UI imports `CrmReviewRequestCampaign` by its legacy name. Alias so the
// campaigns page and any older callers keep compiling without a sweep.
export type CrmReviewRequestCampaign = CrmReviewCampaign

export function listCrmReviewCampaigns(workspaceId: number): CrmReviewCampaign[] {
  return getDb().prepare(`
    SELECT * FROM crm_review_campaigns
    WHERE workspace_id = ?
    ORDER BY active DESC, id ASC
  `).all(workspaceId) as CrmReviewCampaign[]
}

export function getCrmReviewCampaign(id: number, workspaceId: number): CrmReviewCampaign | null {
  const row = getDb().prepare(
    'SELECT * FROM crm_review_campaigns WHERE id = ? AND workspace_id = ?'
  ).get(id, workspaceId) as CrmReviewCampaign | undefined
  return row || null
}

export function createCrmReviewCampaign(data: {
  workspaceId: number
  name: string
  trigger_event: CrmReviewCampaignTrigger
  channel: CrmReviewCampaignChannel
  message_template_sms?: string | null
  message_template_email?: string | null
  subject_template?: string | null
  preview_text?: string | null
  send_delay_hours?: number
  follow_up_after_days?: number | null
  max_follow_ups?: number
  active?: boolean
  createdByUserId?: number | null
}): CrmReviewCampaign {
  const result = getDb().prepare(`
    INSERT INTO crm_review_campaigns
      (workspace_id, name, trigger_event, channel, message_template_sms, message_template_email,
       subject_template, preview_text, send_delay_hours, follow_up_after_days, max_follow_ups,
       active, created_by_user_id)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    data.workspaceId,
    data.name,
    data.trigger_event,
    data.channel,
    data.message_template_sms ?? null,
    data.message_template_email ?? null,
    data.subject_template ?? null,
    data.preview_text ?? null,
    Math.max(0, Math.floor(data.send_delay_hours ?? 0)),
    data.follow_up_after_days == null ? null : Math.max(1, Math.floor(data.follow_up_after_days)),
    Math.max(0, Math.min(5, Math.floor(data.max_follow_ups ?? 0))),
    data.active === false ? 0 : 1,
    data.createdByUserId ?? null,
  )
  const campaign = getCrmReviewCampaign(Number(result.lastInsertRowid), data.workspaceId)
  if (!campaign) throw new Error('Failed to create review campaign')
  return campaign
}

export function updateCrmReviewCampaign(
  id: number,
  workspaceId: number,
  patch: {
    name?: string
    trigger_event?: CrmReviewCampaignTrigger
    channel?: CrmReviewCampaignChannel
    message_template_sms?: string | null
    message_template_email?: string | null
    subject_template?: string | null
    preview_text?: string | null
    send_delay_hours?: number
    follow_up_after_days?: number | null
    max_follow_ups?: number
    active?: 0 | 1
  },
): CrmReviewCampaign | null {
  const existing = getCrmReviewCampaign(id, workspaceId)
  if (!existing) return null
  const fields: string[] = []
  const args: Array<string | number | null> = []
  if (patch.name != null) { fields.push('name = ?'); args.push(patch.name) }
  if (patch.trigger_event != null) { fields.push('trigger_event = ?'); args.push(patch.trigger_event) }
  if (patch.channel != null) { fields.push('channel = ?'); args.push(patch.channel) }
  if (patch.message_template_sms !== undefined) { fields.push('message_template_sms = ?'); args.push(patch.message_template_sms) }
  if (patch.message_template_email !== undefined) { fields.push('message_template_email = ?'); args.push(patch.message_template_email) }
  if (patch.subject_template !== undefined) { fields.push('subject_template = ?'); args.push(patch.subject_template) }
  if (patch.preview_text !== undefined) { fields.push('preview_text = ?'); args.push(patch.preview_text) }
  if (patch.send_delay_hours != null) { fields.push('send_delay_hours = ?'); args.push(patch.send_delay_hours) }
  if (patch.follow_up_after_days !== undefined) { fields.push('follow_up_after_days = ?'); args.push(patch.follow_up_after_days) }
  if (patch.max_follow_ups != null) { fields.push('max_follow_ups = ?'); args.push(patch.max_follow_ups) }
  if (patch.active !== undefined) { fields.push('active = ?'); args.push(patch.active) }
  if (fields.length === 0) return existing
  fields.push(`updated_at = strftime('%s','now')`)
  args.push(id, workspaceId)
  getDb().prepare(
    `UPDATE crm_review_campaigns SET ${fields.join(', ')} WHERE id = ? AND workspace_id = ?`
  ).run(...args)
  return getCrmReviewCampaign(id, workspaceId)
}

export function deleteCrmReviewCampaign(id: number, workspaceId: number): boolean {
  const result = getDb().prepare(
    'DELETE FROM crm_review_campaigns WHERE id = ? AND workspace_id = ?'
  ).run(id, workspaceId)
  return result.changes > 0
}

// ─── Reputation: embeddable review widgets ────────────────────────────────
export type CrmReviewWidgetTheme = 'light' | 'dark' | 'auto'
export type CrmReviewWidgetLayout = 'grid' | 'carousel' | 'list' | 'badge'

export interface CrmReviewWidgetRecord {
  id: number
  workspace_id: number
  public_id: string
  name: string
  min_rating: number
  max_reviews: number
  sources: number[]
  theme: CrmReviewWidgetTheme
  layout: CrmReviewWidgetLayout
  active: number
  created_at: number
  updated_at: number
}

interface CrmReviewWidgetRow {
  id: number
  workspace_id: number
  public_id: string
  name: string
  min_rating: number
  max_reviews: number
  sources: string
  theme: CrmReviewWidgetTheme
  layout: CrmReviewWidgetLayout
  active: number
  created_at: number
  updated_at: number
}

function mapReviewWidgetRow(row: CrmReviewWidgetRow): CrmReviewWidgetRecord {
  let sources: number[] = []
  try {
    const parsed = JSON.parse(row.sources || '[]') as unknown
    if (Array.isArray(parsed)) {
      sources = parsed.map((n) => Number(n)).filter((n) => Number.isFinite(n))
    }
  } catch { sources = [] }
  return {
    id: row.id,
    workspace_id: row.workspace_id,
    public_id: row.public_id,
    name: row.name,
    min_rating: row.min_rating,
    max_reviews: row.max_reviews,
    sources,
    theme: row.theme,
    layout: row.layout,
    active: row.active,
    created_at: row.created_at,
    updated_at: row.updated_at,
  }
}

export function listCrmReviewWidgets(workspaceId: number): CrmReviewWidgetRecord[] {
  const rows = getDb().prepare(`
    SELECT * FROM crm_review_widgets
    WHERE workspace_id = ?
    ORDER BY active DESC, id ASC
  `).all(workspaceId) as CrmReviewWidgetRow[]
  return rows.map(mapReviewWidgetRow)
}

export function getCrmReviewWidget(id: number, workspaceId: number): CrmReviewWidgetRecord | null {
  const row = getDb().prepare(
    'SELECT * FROM crm_review_widgets WHERE id = ? AND workspace_id = ?'
  ).get(id, workspaceId) as CrmReviewWidgetRow | undefined
  return row ? mapReviewWidgetRow(row) : null
}

export function getCrmReviewWidgetByPublicId(publicId: string): CrmReviewWidgetRecord | null {
  const row = getDb().prepare(
    'SELECT * FROM crm_review_widgets WHERE public_id = ?'
  ).get(publicId) as CrmReviewWidgetRow | undefined
  return row ? mapReviewWidgetRow(row) : null
}

export function createCrmReviewWidget(data: {
  workspaceId: number
  name: string
  min_rating?: number
  max_reviews?: number
  sources?: number[]
  theme?: CrmReviewWidgetTheme
  layout?: CrmReviewWidgetLayout
  active?: boolean
}): CrmReviewWidgetRecord {
  const publicId = generatePublicId()
  const sources = Array.isArray(data.sources)
    ? data.sources.map((n) => Number(n)).filter((n) => Number.isFinite(n))
    : []
  const result = getDb().prepare(`
    INSERT INTO crm_review_widgets
      (workspace_id, public_id, name, min_rating, max_reviews, sources, theme, layout, active)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    data.workspaceId,
    publicId,
    data.name,
    Math.max(1, Math.min(5, Math.floor(data.min_rating ?? 4))),
    Math.max(1, Math.min(50, Math.floor(data.max_reviews ?? 10))),
    JSON.stringify(sources),
    data.theme ?? 'auto',
    data.layout ?? 'grid',
    data.active === false ? 0 : 1,
  )
  const widget = getCrmReviewWidget(Number(result.lastInsertRowid), data.workspaceId)
  if (!widget) throw new Error('Failed to create review widget')
  return widget
}

export function updateCrmReviewWidget(
  id: number,
  workspaceId: number,
  patch: {
    name?: string
    min_rating?: number
    max_reviews?: number
    sources?: number[]
    theme?: CrmReviewWidgetTheme
    layout?: CrmReviewWidgetLayout
    active?: boolean
  },
): CrmReviewWidgetRecord | null {
  const existing = getCrmReviewWidget(id, workspaceId)
  if (!existing) return null
  const fields: string[] = []
  const args: Array<string | number | null> = []
  if (patch.name != null) { fields.push('name = ?'); args.push(patch.name) }
  if (patch.min_rating != null) { fields.push('min_rating = ?'); args.push(Math.max(1, Math.min(5, Math.floor(patch.min_rating)))) }
  if (patch.max_reviews != null) { fields.push('max_reviews = ?'); args.push(Math.max(1, Math.min(50, Math.floor(patch.max_reviews)))) }
  if (patch.sources !== undefined) {
    const clean = Array.isArray(patch.sources)
      ? patch.sources.map((n) => Number(n)).filter((n) => Number.isFinite(n))
      : []
    fields.push('sources = ?')
    args.push(JSON.stringify(clean))
  }
  if (patch.theme != null) { fields.push('theme = ?'); args.push(patch.theme) }
  if (patch.layout != null) { fields.push('layout = ?'); args.push(patch.layout) }
  if (patch.active !== undefined) { fields.push('active = ?'); args.push(patch.active ? 1 : 0) }
  if (fields.length === 0) return existing
  fields.push(`updated_at = strftime('%s','now')`)
  args.push(id, workspaceId)
  getDb().prepare(
    `UPDATE crm_review_widgets SET ${fields.join(', ')} WHERE id = ? AND workspace_id = ?`
  ).run(...args)
  return getCrmReviewWidget(id, workspaceId)
}

export function deleteCrmReviewWidget(id: number, workspaceId: number): boolean {
  const result = getDb().prepare(
    'DELETE FROM crm_review_widgets WHERE id = ? AND workspace_id = ?'
  ).run(id, workspaceId)
  return result.changes > 0
}

