export function listCrmSocialPosts(
  workspaceId: number,
  filters?: {
    status?: CrmSocialPostStatus
    channel?: CrmSocialChannel
    from?: number | null
    to?: number | null
    limit?: number
  },
): CrmSocialPostRecord[] {
  const clauses: string[] = ['p.workspace_id = ?']
  const args: unknown[] = [workspaceId]
  if (filters?.status) { clauses.push('p.status = ?'); args.push(filters.status) }
  if (filters?.from != null) { clauses.push('COALESCE(p.scheduled_at, p.published_at, p.created_at) >= ?'); args.push(filters.from) }
  if (filters?.to != null) { clauses.push('COALESCE(p.scheduled_at, p.published_at, p.created_at) <= ?'); args.push(filters.to) }
  let sql = `SELECT p.* FROM crm_social_posts p WHERE ${clauses.join(' AND ')}`
  if (filters?.channel) {
    sql = `
      SELECT DISTINCT p.* FROM crm_social_posts p
      INNER JOIN crm_social_post_channels pc ON pc.post_id = p.id
      WHERE ${clauses.join(' AND ')} AND pc.channel = ?
    `
    args.push(filters.channel)
  }
  sql += ` ORDER BY COALESCE(p.scheduled_at, p.published_at, p.created_at) DESC, p.id DESC`
  const limit = filters?.limit && filters.limit > 0 ? Math.min(filters.limit, 500) : 200
  sql += ` LIMIT ${limit}`
  const rows = getDb().prepare(sql).all(...args) as CrmSocialPostRow[]
  return rows.map((row) => mapSocialPostRow(row, loadSocialPostChannels(row.id)))
}

export function getCrmSocialPost(id: number, workspaceId: number): CrmSocialPostRecord | null {
  const row = getDb().prepare(
    `SELECT * FROM crm_social_posts WHERE id = ? AND workspace_id = ?`
  ).get(id, workspaceId) as CrmSocialPostRow | undefined
  if (!row) return null
  return mapSocialPostRow(row, loadSocialPostChannels(row.id))
}

function insertSocialPostChannels(postId: number, workspaceId: number, accountIds: number[]): void {
  if (accountIds.length === 0) return
  const db = getDb()
  const lookup = db.prepare(`SELECT id, channel, display_name FROM crm_social_accounts WHERE id = ? AND workspace_id = ?`)
  const insert = db.prepare(
    `INSERT INTO crm_social_post_channels (post_id, account_id, channel, account_name) VALUES (?, ?, ?, ?)`
  )
  for (const accountId of accountIds) {
    const account = lookup.get(accountId, workspaceId) as { id: number; channel: string; display_name: string } | undefined
    if (!account) continue
    insert.run(postId, account.id, account.channel, account.display_name)
  }
}

export function createCrmSocialPost(
  workspaceId: number,
  data: {
    body: string
    media?: string[]
    link_url?: string | null
    scheduled_at?: number | null
    status?: CrmSocialPostStatus
    account_ids: number[]
    created_by_user_id?: number | null
  },
): CrmSocialPostRecord {
  const media = Array.isArray(data.media) ? data.media.filter((v): v is string => typeof v === 'string') : []
  const status: CrmSocialPostStatus = data.status
    ?? (data.scheduled_at && data.scheduled_at > 0 ? 'scheduled' : 'draft')
  const info = getDb().prepare(
    `INSERT INTO crm_social_posts
       (workspace_id, body, link_url, media_json, scheduled_at, status, created_by_user_id)
     VALUES (?, ?, ?, ?, ?, ?, ?)`
  ).run(
    workspaceId,
    data.body ?? '',
    data.link_url ?? null,
    JSON.stringify(media),
    data.scheduled_at ?? null,
    status,
    data.created_by_user_id ?? null,
  )
  const postId = Number(info.lastInsertRowid)
  insertSocialPostChannels(postId, workspaceId, data.account_ids)
  const created = getCrmSocialPost(postId, workspaceId)
  if (!created) throw new Error('Failed to create social post')
  return created
}

export function updateCrmSocialPost(
  id: number,
  workspaceId: number,
  patch: {
    body?: string
    media?: string[]
    link_url?: string | null
    scheduled_at?: number | null
    status?: CrmSocialPostStatus
    account_ids?: number[]
  },
): CrmSocialPostRecord | null {
  const existing = getCrmSocialPost(id, workspaceId)
  if (!existing) return null
  const fields: string[] = []
  const args: unknown[] = []
  if (patch.body !== undefined) { fields.push('body = ?'); args.push(patch.body) }
  if (patch.link_url !== undefined) { fields.push('link_url = ?'); args.push(patch.link_url) }
  if (patch.media !== undefined) {
    const media = Array.isArray(patch.media) ? patch.media.filter((v): v is string => typeof v === 'string') : []
    fields.push('media_json = ?')
    args.push(JSON.stringify(media))
  }
  if (patch.scheduled_at !== undefined) { fields.push('scheduled_at = ?'); args.push(patch.scheduled_at) }
  if (patch.status !== undefined) {
    fields.push('status = ?')
    args.push(patch.status)
    if (patch.status === 'published') { fields.push('published_at = strftime(\'%s\',\'now\')') }
  }
  if (fields.length > 0) {
    fields.push('updated_at = strftime(\'%s\',\'now\')')
    args.push(id, workspaceId)
    getDb().prepare(
      `UPDATE crm_social_posts SET ${fields.join(', ')} WHERE id = ? AND workspace_id = ?`
    ).run(...args)
  }
  if (patch.account_ids !== undefined) {
    getDb().prepare(`DELETE FROM crm_social_post_channels WHERE post_id = ?`).run(id)
    insertSocialPostChannels(id, workspaceId, patch.account_ids)
  }
  return getCrmSocialPost(id, workspaceId)
}

export function deleteCrmSocialPost(id: number, workspaceId: number): boolean {
  const result = getDb().prepare(
    `DELETE FROM crm_social_posts WHERE id = ? AND workspace_id = ?`
  ).run(id, workspaceId)
  return result.changes > 0
}

export function getScheduledSocialPostsDue(now: number = Math.floor(Date.now() / 1000), limit = 20): CrmSocialPostRecord[] {
  const rows = getDb().prepare(
    `SELECT * FROM crm_social_posts
      WHERE status = 'scheduled' AND scheduled_at IS NOT NULL AND scheduled_at <= ?
      ORDER BY scheduled_at ASC, id ASC LIMIT ?`
  ).all(now, Math.max(1, Math.min(limit, 200))) as CrmSocialPostRow[]
  return rows.map((row) => mapSocialPostRow(row, loadSocialPostChannels(row.id)))
}

export function markCrmSocialPostPublishing(id: number): number {
  const result = getDb().prepare(
    `UPDATE crm_social_posts
        SET status = 'publishing', updated_at = strftime('%s','now')
      WHERE id = ? AND status = 'scheduled'`
  ).run(id)
  return result.changes
}

