function affiliateNowIso(): string {
  return new Date().toISOString()
}

function normalizeAffiliateEmail(email: string): string {
  return email.trim().toLowerCase()
}

function slugifyAffiliateValue(value: string): string {
  const slug = value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48)
  return slug || 'affiliate'
}

function generateAffiliateLoginToken(): string {
  return `aff_${crypto.randomBytes(18).toString('base64url')}`
}

function generateAffiliateShortCode(): string {
  const raw = crypto.randomBytes(6).toString('base64url').replace(/[^a-zA-Z0-9]/g, '').toLowerCase()
  return (raw || crypto.randomBytes(4).toString('hex')).slice(0, 8)
}

function normalizeAffiliateTimestamp(value: unknown): string {
  if (typeof value === 'number' && Number.isFinite(value)) {
    const millis = value > 9_999_999_999 ? value : value * 1000
    return new Date(millis).toISOString()
  }
  if (typeof value === 'string' && value.trim()) {
    const trimmed = value.trim()
    const asNumber = Number(trimmed)
    if (Number.isFinite(asNumber) && /^\d+(\.\d+)?$/.test(trimmed)) {
      const millis = asNumber > 9_999_999_999 ? asNumber : asNumber * 1000
      return new Date(millis).toISOString()
    }
    const parsed = new Date(trimmed)
    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString()
  }
  return affiliateNowIso()
}

function hashAffiliateIp(ip: string | null | undefined): string | null {
  const normalized = String(ip || '').trim()
  if (!normalized) return null
  return crypto.createHash('sha256').update(normalized).digest('hex')
}

function currentMonthRange(reference = new Date()): { start: string; end: string } {
  const start = new Date(Date.UTC(reference.getUTCFullYear(), reference.getUTCMonth(), 1))
  const end = new Date(Date.UTC(reference.getUTCFullYear(), reference.getUTCMonth() + 1, 1))
  return { start: start.toISOString(), end: end.toISOString() }
}

function previousMonthRange(reference = new Date()): { start: string; end: string } {
  const end = new Date(Date.UTC(reference.getUTCFullYear(), reference.getUTCMonth(), 1))
  const start = new Date(Date.UTC(end.getUTCFullYear(), end.getUTCMonth() - 1, 1))
  return { start: start.toISOString(), end: end.toISOString() }
}

function resolveAffiliateCommissionCents(affiliate: Pick<CrmAffiliate, 'commission_rate_pct' | 'commission_flat_cents'>, orderValueCents: number): number {
  const rate = Number.isFinite(affiliate.commission_rate_pct) ? affiliate.commission_rate_pct : 0
  const flat = Number.isFinite(affiliate.commission_flat_cents) ? affiliate.commission_flat_cents : 0
  const computed = Math.round((Math.max(0, orderValueCents) * Math.max(0, rate)) / 100)
  return Math.max(0, computed + Math.max(0, flat))
}

function ensureUniqueAffiliateSlug(workspaceId: number, candidate: string, ignoreId?: number): string {
  const base = slugifyAffiliateValue(candidate)
  let slug = base
  let attempt = 1
  while (true) {
    const row = ignoreId
      ? getDb().prepare('SELECT id FROM crm_affiliates WHERE workspace_id = ? AND slug = ? AND id != ? LIMIT 1').get(workspaceId, slug, ignoreId)
      : getDb().prepare('SELECT id FROM crm_affiliates WHERE workspace_id = ? AND slug = ? LIMIT 1').get(workspaceId, slug)
    if (!row) return slug
    attempt += 1
    slug = `${base}-${attempt}`
  }
}

function ensureUniqueAffiliateShortCode(candidate?: string | null, ignoreId?: number): string {
  const preferred = String(candidate || '').trim().toLowerCase().replace(/[^a-z0-9]/g, '').slice(0, 10)
  let shortCode = preferred || generateAffiliateShortCode()
  while (true) {
    const row = ignoreId
      ? getDb().prepare('SELECT id FROM crm_affiliate_links WHERE short_code = ? AND id != ? LIMIT 1').get(shortCode, ignoreId)
      : getDb().prepare('SELECT id FROM crm_affiliate_links WHERE short_code = ? LIMIT 1').get(shortCode)
    if (!row) return shortCode
    shortCode = generateAffiliateShortCode()
  }
}

function enrichCrmAffiliate(row: CrmAffiliate): CrmAffiliateRecord {
  const month = currentMonthRange()
  const counts = getDb().prepare(`
    SELECT
      (SELECT COUNT(*) FROM crm_affiliate_links WHERE affiliate_id = ?) AS link_count,
      (SELECT COALESCE(SUM(clicks), 0) FROM crm_affiliate_links WHERE affiliate_id = ?) AS clicks_total,
      (SELECT COALESCE(SUM(signups), 0) FROM crm_affiliate_links WHERE affiliate_id = ?) AS signups_total,
      (SELECT COALESCE(SUM(conversions), 0) FROM crm_affiliate_links WHERE affiliate_id = ?) AS conversions_total,
      (SELECT COALESCE(SUM(revenue_cents), 0) FROM crm_affiliate_links WHERE affiliate_id = ?) AS revenue_cents_total,
      (SELECT COUNT(*) FROM crm_affiliate_referrals WHERE affiliate_id = ? AND status = 'pending') AS pending_referrals,
      (SELECT COALESCE(SUM(commission_cents), 0) FROM crm_affiliate_referrals WHERE affiliate_id = ? AND status = 'approved') AS approved_commissions_cents,
      (SELECT COALESCE(SUM(commission_cents), 0) FROM crm_affiliate_referrals WHERE affiliate_id = ? AND status = 'paid') AS paid_commissions_cents,
      (SELECT COALESCE(SUM(commission_cents), 0) FROM crm_affiliate_referrals WHERE affiliate_id = ? AND converted_at >= ? AND converted_at < ? AND status IN ('approved', 'paid')) AS earnings_this_month_cents,
      (SELECT name FROM crm_contacts WHERE id = ?) AS contact_name
  `).get(
    row.id,
    row.id,
    row.id,
    row.id,
    row.id,
    row.id,
    row.id,
    row.id,
    row.id,
    month.start,
    month.end,
    row.contact_id,
  ) as {
    link_count: number
    clicks_total: number
    signups_total: number
    conversions_total: number
    revenue_cents_total: number
    pending_referrals: number
    approved_commissions_cents: number
    paid_commissions_cents: number
    earnings_this_month_cents: number
    contact_name: string | null
  }
  return {
    ...row,
    contact_name: counts.contact_name,
    link_count: counts.link_count,
    clicks_total: counts.clicks_total,
    signups_total: counts.signups_total,
    conversions_total: counts.conversions_total,
    revenue_cents_total: counts.revenue_cents_total,
    pending_referrals: counts.pending_referrals,
    approved_commissions_cents: counts.approved_commissions_cents,
    paid_commissions_cents: counts.paid_commissions_cents,
    earnings_this_month_cents: counts.earnings_this_month_cents,
    active_bool: row.status === 'active',
  }
}

function enrichCrmAffiliateLink(row: CrmAffiliateLink): CrmAffiliateLinkRecord {
  const extra = getDb().prepare(`
    SELECT a.name AS affiliate_name, a.slug AS affiliate_slug,
           (SELECT visited_at FROM crm_affiliate_clicks WHERE link_id = ? ORDER BY visited_at DESC, id DESC LIMIT 1) AS latest_click_at
    FROM crm_affiliates a
    WHERE a.id = ?
  `).get(row.id, row.affiliate_id) as { affiliate_name: string; affiliate_slug: string; latest_click_at: string | null } | undefined
  return {
    ...row,
    affiliate_name: extra?.affiliate_name || 'Unknown affiliate',
    affiliate_slug: extra?.affiliate_slug || '',
    latest_click_at: extra?.latest_click_at || null,
  }
}

function enrichCrmAffiliateReferral(row: CrmAffiliateReferral): CrmAffiliateReferralRecord {
  const extra = getDb().prepare(`
    SELECT a.name AS affiliate_name, a.contact_id AS affiliate_contact_id,
           l.name AS link_name, l.short_code AS short_code,
           c.name AS contact_name, c.email AS contact_email
    FROM crm_affiliates a
    LEFT JOIN crm_affiliate_links l ON l.id = ?
    LEFT JOIN crm_contacts c ON c.id = ?
    WHERE a.id = ?
  `).get(row.link_id, row.contact_id, row.affiliate_id) as {
    affiliate_name: string
    affiliate_contact_id: number | null
    link_name: string | null
    short_code: string | null
    contact_name: string | null
    contact_email: string | null
  } | undefined
  return {
    ...row,
    affiliate_name: extra?.affiliate_name || 'Unknown affiliate',
    affiliate_contact_id: extra?.affiliate_contact_id ?? null,
    link_name: extra?.link_name || null,
    short_code: extra?.short_code || null,
    contact_name: extra?.contact_name || 'Unknown contact',
    contact_email: extra?.contact_email || null,
  }
}

function enrichCrmAffiliatePayout(row: CrmAffiliatePayout): CrmAffiliatePayoutRecord {
  const extra = getDb().prepare(`
    SELECT a.name AS affiliate_name,
           (SELECT COUNT(*) FROM crm_affiliate_referrals WHERE payout_id = ?) AS referral_count
    FROM crm_affiliates a
    WHERE a.id = ?
  `).get(row.id, row.affiliate_id) as { affiliate_name: string; referral_count: number } | undefined
  return {
    ...row,
    affiliate_name: extra?.affiliate_name || 'Unknown affiliate',
    referral_count: extra?.referral_count || 0,
  }
}

function enrichCrmAffiliateClick(row: CrmAffiliateClick): CrmAffiliateClickRecord {
  const extra = getDb().prepare('SELECT name AS link_name, short_code FROM crm_affiliate_links WHERE id = ?').get(row.link_id) as { link_name: string; short_code: string } | undefined
  return {
    ...row,
    link_name: extra?.link_name || 'Affiliate link',
    short_code: extra?.short_code || '',
  }
}

export function listCrmAffiliates(workspaceId: number, opts: { status?: CrmAffiliateStatus | 'all'; search?: string | null } = {}): CrmAffiliateRecord[] {
  const clauses = ['workspace_id = ?']
  const params: Array<string | number> = [workspaceId]
  if (opts.status && opts.status !== 'all') {
    clauses.push('status = ?')
    params.push(opts.status)
  }
  if (opts.search && opts.search.trim()) {
    const q = `%${opts.search.trim().toLowerCase()}%`
    clauses.push('(LOWER(name) LIKE ? OR LOWER(email) LIKE ? OR LOWER(slug) LIKE ?)')
    params.push(q, q, q)
  }
  const rows = getDb().prepare(`
    SELECT *
    FROM crm_affiliates
    WHERE ${clauses.join(' AND ')}
    ORDER BY CASE status WHEN 'active' THEN 0 WHEN 'paused' THEN 1 ELSE 2 END ASC, created_at DESC, id DESC
  `).all(...params) as CrmAffiliate[]
  return rows.map(enrichCrmAffiliate)
}

export function getCrmAffiliateById(id: number, workspaceId: number): CrmAffiliateRecord | null {
  const row = getDb().prepare('SELECT * FROM crm_affiliates WHERE id = ?').get(id) as CrmAffiliate | undefined
  if (!row || row.workspace_id !== workspaceId) return null
  return enrichCrmAffiliate(row)
}

export function getCrmAffiliateByContactId(contactId: number, workspaceId: number): CrmAffiliateRecord | null {
  const row = getDb().prepare('SELECT * FROM crm_affiliates WHERE contact_id = ? AND workspace_id = ? LIMIT 1').get(contactId, workspaceId) as CrmAffiliate | undefined
  return row ? enrichCrmAffiliate(row) : null
}

export function getCrmAffiliateByLoginToken(loginToken: string): CrmAffiliateRecord | null {
  const row = getDb().prepare('SELECT * FROM crm_affiliates WHERE login_token = ? LIMIT 1').get(loginToken) as CrmAffiliate | undefined
  if (!row || row.status === 'terminated') return null
  return enrichCrmAffiliate(row)
}

export function createCrmAffiliate(workspaceId: number, data: {
  name: string
  email: string
  contact_id?: number | null
  slug?: string | null
  commission_rate_pct?: number | null
  commission_flat_cents?: number | null
  payout_method?: CrmAffiliatePayoutMethod
  paypal_email?: string | null
  status?: CrmAffiliateStatus
  joined_at?: string | null
  approved_at?: string | null
}): CrmAffiliateRecord {
  const nowIso = affiliateNowIso()
  const normalizedEmail = normalizeAffiliateEmail(data.email)
  const linkedContact = data.contact_id ? getCrmContactById(data.contact_id, workspaceId) : getCrmContactByEmail(workspaceId, normalizedEmail)
  const status = data.status || 'active'
  const approvedAt = data.approved_at === null
    ? null
    : data.approved_at || (status === 'active' ? nowIso : null)
  const result = getDb().prepare(`
    INSERT INTO crm_affiliates (
      workspace_id, name, email, contact_id, slug, commission_rate_pct, commission_flat_cents,
      payout_method, paypal_email, status, joined_at, approved_at, login_token, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    data.name.trim(),
    normalizedEmail,
    linkedContact?.id ?? null,
    ensureUniqueAffiliateSlug(workspaceId, data.slug || data.name),
    data.commission_rate_pct ?? 0,
    data.commission_flat_cents ?? 0,
    data.payout_method || 'manual',
    data.paypal_email ? normalizeAffiliateEmail(data.paypal_email) : null,
    status,
    data.joined_at || nowIso,
    approvedAt,
    generateAffiliateLoginToken(),
    nowIso,
    nowIso,
  )
  const affiliate = getCrmAffiliateById(Number(result.lastInsertRowid), workspaceId) as CrmAffiliateRecord
  if (affiliate.contact_id && affiliate.status === 'active') {
    queueCrmWorkflowRunsForTrigger({
      workspaceId,
      contactId: affiliate.contact_id,
      triggerType: 'affiliate_joined',
    })
  }
  return affiliate
}

export function updateCrmAffiliate(id: number, workspaceId: number, data: Partial<{
  name: string
  email: string
  contact_id: number | null
  slug: string | null
  commission_rate_pct: number | null
  commission_flat_cents: number | null
  payout_method: CrmAffiliatePayoutMethod
  paypal_email: string | null
  status: CrmAffiliateStatus
  joined_at: string | null
  approved_at: string | null
}>): CrmAffiliateRecord | null {
  const existing = getCrmAffiliateById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number | null> = []
  let shouldQueueJoined = false

  if (data.name !== undefined) { sets.push('name = ?'); params.push(data.name.trim()) }
  if (data.email !== undefined) { sets.push('email = ?'); params.push(normalizeAffiliateEmail(data.email)) }
  if (data.contact_id !== undefined) {
    const linked = data.contact_id ? getCrmContactById(data.contact_id, workspaceId) : null
    sets.push('contact_id = ?')
    params.push(linked?.id ?? null)
  }
  if (data.slug !== undefined) { sets.push('slug = ?'); params.push(ensureUniqueAffiliateSlug(workspaceId, data.slug || existing.name, id)) }
  if (data.commission_rate_pct !== undefined) { sets.push('commission_rate_pct = ?'); params.push(data.commission_rate_pct ?? 0) }
  if (data.commission_flat_cents !== undefined) { sets.push('commission_flat_cents = ?'); params.push(data.commission_flat_cents ?? 0) }
  if (data.payout_method !== undefined) { sets.push('payout_method = ?'); params.push(data.payout_method) }
  if (data.paypal_email !== undefined) { sets.push('paypal_email = ?'); params.push(data.paypal_email ? normalizeAffiliateEmail(data.paypal_email) : null) }
  if (data.joined_at !== undefined) { sets.push('joined_at = ?'); params.push(data.joined_at ?? affiliateNowIso()) }
  if (data.approved_at !== undefined) { sets.push('approved_at = ?'); params.push(data.approved_at) }
  if (data.status !== undefined) {
    sets.push('status = ?')
    params.push(data.status)
    shouldQueueJoined = data.status === 'active' && existing.status !== 'active'
    if (data.status === 'active' && !existing.approved_at && data.approved_at === undefined) {
      sets.push('approved_at = ?')
      params.push(affiliateNowIso())
    }
  }

  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(affiliateNowIso())
  params.push(id)
  getDb().prepare(`UPDATE crm_affiliates SET ${sets.join(', ')} WHERE id = ?`).run(...params)
  const affiliate = getCrmAffiliateById(id, workspaceId)
  if (affiliate && shouldQueueJoined && affiliate.contact_id) {
    queueCrmWorkflowRunsForTrigger({
      workspaceId,
      contactId: affiliate.contact_id,
      triggerType: 'affiliate_joined',
    })
  }
  return affiliate
}

export function regenerateCrmAffiliateLoginToken(id: number, workspaceId: number): CrmAffiliateRecord | null {
  const affiliate = getCrmAffiliateById(id, workspaceId)
  if (!affiliate) return null
  getDb().prepare('UPDATE crm_affiliates SET login_token = ?, updated_at = ? WHERE id = ?').run(generateAffiliateLoginToken(), affiliateNowIso(), id)
  return getCrmAffiliateById(id, workspaceId)
}

