export function updateCrmAffiliateLink(id: number, workspaceId: number, data: Partial<{
  name: string
  target_url: string
  short_code: string | null
}>): CrmAffiliateLinkRecord | null {
  const existing = getCrmAffiliateLinkById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number> = []
  if (data.name !== undefined) { sets.push('name = ?'); params.push(data.name.trim()) }
  if (data.target_url !== undefined) { sets.push('target_url = ?'); params.push(data.target_url.trim()) }
  if (data.short_code !== undefined) { sets.push('short_code = ?'); params.push(ensureUniqueAffiliateShortCode(data.short_code, id)) }
  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(affiliateNowIso())
  params.push(id)
  getDb().prepare(`UPDATE crm_affiliate_links SET ${sets.join(', ')} WHERE id = ?`).run(...params)
  return getCrmAffiliateLinkById(id, workspaceId)
}

export function listCrmAffiliateClicks(workspaceId: number, opts: { affiliateId?: number | null; limit?: number } = {}): CrmAffiliateClickRecord[] {
  const limit = Math.min(Math.max(opts.limit ?? 50, 1), 500)
  const clauses = ['c.workspace_id = ?']
  const params: Array<number | string> = [workspaceId]
  if (opts.affiliateId) {
    clauses.push('l.affiliate_id = ?')
    params.push(opts.affiliateId)
  }
  const rows = getDb().prepare(`
    SELECT c.*
    FROM crm_affiliate_clicks c
    JOIN crm_affiliate_links l ON l.id = c.link_id
    WHERE ${clauses.join(' AND ')}
    ORDER BY c.visited_at DESC, c.id DESC
    LIMIT ?
  `).all(...params, limit) as CrmAffiliateClick[]
  return rows.map(enrichCrmAffiliateClick)
}

