export function updateCrmAffiliateReferral(id: number, workspaceId: number, data: Partial<{
  status: CrmAffiliateReferralStatus
  commission_cents: number | null
  payout_id: number | null
  converted_at: string | null
  order_value_cents: number | null
}>): CrmAffiliateReferralRecord | null {
  const existing = getCrmAffiliateReferralById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number | null> = []
  if (data.status !== undefined) { sets.push('status = ?'); params.push(data.status) }
  if (data.commission_cents !== undefined) { sets.push('commission_cents = ?'); params.push(data.commission_cents ?? 0) }
  if (data.payout_id !== undefined) { sets.push('payout_id = ?'); params.push(data.payout_id) }
  if (data.converted_at !== undefined) { sets.push('converted_at = ?'); params.push(data.converted_at) }
  if (data.order_value_cents !== undefined) { sets.push('order_value_cents = ?'); params.push(data.order_value_cents ?? 0) }
  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(affiliateNowIso())
  params.push(id)
  getDb().prepare(`UPDATE crm_affiliate_referrals SET ${sets.join(', ')} WHERE id = ?`).run(...params)
  return getCrmAffiliateReferralById(id, workspaceId)
}

