export interface CrmWebchatWidget {
  id: number
  workspace_id: number
  public_id: string
  name: string
  greeting: string
  away_message: string
  primary_color: string
  position: string
  avatar_url: string | null
  welcome_text: string | null
  offline_capture_enabled: number
  offline_notify_email: string | null
  is_active: number
  created_at: number
  updated_at: number
}

export function getCrmWebchatWidgets(workspaceId: number): CrmWebchatWidget[] {
  return getDb()
    .prepare('SELECT * FROM crm_webchat_widgets WHERE workspace_id = ? ORDER BY updated_at DESC, id DESC')
    .all(workspaceId) as CrmWebchatWidget[]
}

export function getCrmWebchatWidgetById(id: number, workspaceId: number): CrmWebchatWidget | null {
  const row = getDb().prepare('SELECT * FROM crm_webchat_widgets WHERE id = ?').get(id) as CrmWebchatWidget | undefined
  if (!row || row.workspace_id !== workspaceId) return null
  return row
}

export function getCrmWebchatWidgetByPublicId(publicId: string): CrmWebchatWidget | null {
  const row = getDb().prepare('SELECT * FROM crm_webchat_widgets WHERE public_id = ?').get(publicId) as CrmWebchatWidget | undefined
  return row || null
}

export function createCrmWebchatWidget(workspaceId: number, data: { name: string; greeting?: string; away_message?: string; primary_color?: string }): CrmWebchatWidget {
  const now = Math.floor(Date.now() / 1000)
  const result = getDb().prepare(`
    INSERT INTO crm_webchat_widgets (workspace_id, public_id, name, greeting, away_message, primary_color, is_active, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, 1, ?, ?)
  `).run(
    workspaceId,
    generatePublicId(),
    data.name.trim(),
    (data.greeting?.trim() || 'Hi there — how can we help?'),
    (data.away_message?.trim() || "Thanks, we'll reply shortly!"),
    (data.primary_color?.trim() || '#f1ede5'),
    now,
    now,
  )
  return getCrmWebchatWidgetById(Number(result.lastInsertRowid), workspaceId) as CrmWebchatWidget
}

export function updateCrmWebchatWidget(id: number, workspaceId: number, data: Partial<{
  name: string
  greeting: string
  away_message: string
  primary_color: string
  position: string
  avatar_url: string | null
  welcome_text: string | null
  offline_capture_enabled: boolean
  offline_notify_email: string | null
  is_active: boolean
}>): CrmWebchatWidget | null {
  const existing = getCrmWebchatWidgetById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number | null> = []
  if (data.name !== undefined) { sets.push('name = ?'); params.push(data.name.trim()) }
  if (data.greeting !== undefined) { sets.push('greeting = ?'); params.push(data.greeting.trim()) }
  if (data.away_message !== undefined) { sets.push('away_message = ?'); params.push(data.away_message.trim()) }
  if (data.primary_color !== undefined) { sets.push('primary_color = ?'); params.push(data.primary_color.trim()) }
  if (data.position !== undefined) {
    const v = data.position === 'bottom-left' ? 'bottom-left' : 'bottom-right'
    sets.push('position = ?'); params.push(v)
  }
  if (data.avatar_url !== undefined) { sets.push('avatar_url = ?'); params.push(data.avatar_url ? data.avatar_url.trim() : null) }
  if (data.welcome_text !== undefined) { sets.push('welcome_text = ?'); params.push(data.welcome_text ? data.welcome_text.trim() : null) }
  if (data.offline_capture_enabled !== undefined) { sets.push('offline_capture_enabled = ?'); params.push(data.offline_capture_enabled ? 1 : 0) }
  if (data.offline_notify_email !== undefined) { sets.push('offline_notify_email = ?'); params.push(data.offline_notify_email ? data.offline_notify_email.trim() : null) }
  if (data.is_active !== undefined) { sets.push('is_active = ?'); params.push(data.is_active ? 1 : 0) }
  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(Math.floor(Date.now() / 1000))
  params.push(id)
  getDb().prepare(`UPDATE crm_webchat_widgets SET ${sets.join(', ')} WHERE id = ?`).run(...params)
  return getCrmWebchatWidgetById(id, workspaceId)
}

export function deleteCrmWebchatWidget(id: number, workspaceId: number): boolean {
  const existing = getCrmWebchatWidgetById(id, workspaceId)
  if (!existing) return false
  return getDb().prepare('DELETE FROM crm_webchat_widgets WHERE id = ?').run(id).changes > 0
}

// ─── Chat messages ────────────────────────────────────────────────────────

export interface CrmChatAttachment {
  url: string
  filename: string
  size_bytes: number
  mime_type?: string
}

export interface CrmChatMessage {
  id: number
  widget_id: number
  contact_id: number
  workspace_id: number
  direction: 'inbound' | 'outbound'
  body: string
  is_read: number
  read_at: number | null
  attachments_json: string | null
  session_token: string | null
  sent_at: number
}

export function getChatMessagesByContact(contactId: number): CrmChatMessage[] {
  return getDb()
    .prepare('SELECT * FROM crm_chat_messages WHERE contact_id = ? ORDER BY sent_at ASC, id ASC')
    .all(contactId) as CrmChatMessage[]
}

export function getChatMessagesBySession(sessionToken: string, limit = 100): CrmChatMessage[] {
  return getDb()
    .prepare('SELECT * FROM crm_chat_messages WHERE session_token = ? ORDER BY sent_at ASC, id ASC LIMIT ?')
    .all(sessionToken, limit) as CrmChatMessage[]
}

/** Paginated "since" helper for widget polling — ordered ascending by id. */
export function getChatMessagesBySessionSinceId(sessionToken: string, sinceId: number, limit = 100): CrmChatMessage[] {
  return getDb()
    .prepare('SELECT * FROM crm_chat_messages WHERE session_token = ? AND id > ? ORDER BY id ASC LIMIT ?')
    .all(sessionToken, sinceId, limit) as CrmChatMessage[]
}

export function recordChatMessage(data: {
  widgetId: number
  contactId: number
  workspaceId: number
  direction: 'inbound' | 'outbound'
  body: string
  sessionToken?: string | null
  attachments?: CrmChatAttachment[] | null
}): CrmChatMessage {
  const attachmentsJson = data.attachments && data.attachments.length > 0 ? JSON.stringify(data.attachments) : null
  const result = getDb().prepare(`
    INSERT INTO crm_chat_messages (widget_id, contact_id, workspace_id, direction, body, is_read, session_token, attachments_json)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    data.widgetId,
    data.contactId,
    data.workspaceId,
    data.direction,
    data.body,
    data.direction === 'outbound' ? 1 : 0, // outbound auto-read by teammate
    data.sessionToken || null,
    attachmentsJson,
  )
  return getDb().prepare('SELECT * FROM crm_chat_messages WHERE id = ?').get(result.lastInsertRowid) as CrmChatMessage
}

export function markChatMessagesRead(contactId: number): number {
  const now = Math.floor(Date.now() / 1000)
  const r = getDb().prepare(
    `UPDATE crm_chat_messages SET is_read = 1, read_at = COALESCE(read_at, ?) WHERE contact_id = ? AND direction = 'inbound' AND is_read = 0`,
  ).run(now, contactId)
  return r.changes
}

/**
 * Mark outbound (teammate) chat messages on a session as seen by the visitor
 * up to the given message id. Powers the "read receipt" ticks on the agent
 * side so they know whether a visitor has seen their reply.
 */
export function markOutboundChatMessagesSeen(sessionToken: string, upToMessageId: number): number {
  const now = Math.floor(Date.now() / 1000)
  const r = getDb().prepare(
    `UPDATE crm_chat_messages
     SET read_at = COALESCE(read_at, ?)
     WHERE session_token = ?
       AND direction = 'outbound'
       AND id <= ?
       AND read_at IS NULL`,
  ).run(now, sessionToken, upToMessageId)
  return r.changes
}

/** Transfer the owner of a conversation (contact) to another workspace user. */
export function transferConversationOwner(
  contactId: number,
  workspaceId: number,
  toUserId: number,
): boolean {
  const r = getDb().prepare(
    `UPDATE crm_contacts SET owner_id = ?, updated_at = ? WHERE id = ? AND workspace_id = ?`,
  ).run(toUserId, Math.floor(Date.now() / 1000), contactId, workspaceId)
  return r.changes > 0
}

// ─── Presence (derived from users.last_seen_at) ───────────────────────────

/**
 * Touch a user's last-seen timestamp. Called from auth session validation
 * so every authenticated request keeps the user "online" for the next ~5 min.
 */
export function touchUserLastSeen(userId: number): void {
  try {
    getDb().prepare('UPDATE users SET last_seen_at = ? WHERE id = ?')
      .run(Math.floor(Date.now() / 1000), userId)
  } catch {
    // column missing mid-migration — swallow rather than break auth
  }
}

export interface WorkspacePresenceSnapshot {
  agent_online: boolean
  agent_status: 'online' | 'away' | 'offline'
  agent_name: string | null
  agent_avatar: string | null
  last_seen_at: number | null
}

/**
 * Summarize the "is any agent around?" status for a workspace. Powers the
 * green/yellow/grey dot on the embedded widget.
 *
 *   < 5 min → online
 *   < 30 min → away
 *   else     → offline
 *
 * We pick the most recently active teammate as the face of the chat so the
 * avatar + name shown to the visitor always reflects someone who could plausibly
 * reply in the next minute.
 */
export function getWorkspacePresence(workspaceId: number): WorkspacePresenceSnapshot {
  const now = Math.floor(Date.now() / 1000)
  let row: { id: number; name: string; avatar_url: string | null; last_seen_at: number | null } | undefined
  try {
    row = getDb().prepare(`
      SELECT u.id, u.name, u.avatar_url, u.last_seen_at
      FROM users u
      JOIN user_workspace_members m ON m.user_id = u.id
      WHERE m.workspace_id = ? AND u.last_seen_at IS NOT NULL
      ORDER BY u.last_seen_at DESC
      LIMIT 1
    `).get(workspaceId) as { id: number; name: string; avatar_url: string | null; last_seen_at: number | null } | undefined
  } catch {
    row = undefined
  }
  if (!row || !row.last_seen_at) {
    return { agent_online: false, agent_status: 'offline', agent_name: null, agent_avatar: null, last_seen_at: null }
  }
  const ageSec = now - row.last_seen_at
  let status: 'online' | 'away' | 'offline' = 'offline'
  if (ageSec < 5 * 60) status = 'online'
  else if (ageSec < 30 * 60) status = 'away'
  return {
    agent_online: status === 'online',
    agent_status: status,
    agent_name: row.name,
    agent_avatar: row.avatar_url,
    last_seen_at: row.last_seen_at,
  }
}

// ─── Message reactions ────────────────────────────────────────────────────

export interface CrmMessageReaction {
  id: number
  message_id: number
  session_id: string | null
  user_id: number | null
  emoji: string
  created_at: number
}

/** Fetch all reactions for a given set of message ids. Used to hydrate thread views. */
export function getReactionsForMessages(messageIds: number[]): CrmMessageReaction[] {
  if (messageIds.length === 0) return []
  const placeholders = messageIds.map(() => '?').join(',')
  return getDb()
    .prepare(`SELECT * FROM crm_message_reactions WHERE message_id IN (${placeholders}) ORDER BY id ASC`)
    .all(...messageIds) as CrmMessageReaction[]
}

/** Toggle a reaction — if the (msg, session, emoji) triple exists we delete it, otherwise insert. */
export function toggleReactionBySession(messageId: number, sessionId: string, emoji: string): CrmMessageReaction | null {
  const db = getDb()
  const existing = db.prepare(
    `SELECT * FROM crm_message_reactions WHERE message_id = ? AND session_id = ? AND emoji = ? LIMIT 1`,
  ).get(messageId, sessionId, emoji) as CrmMessageReaction | undefined
  if (existing) {
    db.prepare('DELETE FROM crm_message_reactions WHERE id = ?').run(existing.id)
    return null
  }
  const res = db.prepare(
    `INSERT INTO crm_message_reactions (message_id, session_id, user_id, emoji) VALUES (?, ?, NULL, ?)`,
  ).run(messageId, sessionId, emoji)
  return db.prepare('SELECT * FROM crm_message_reactions WHERE id = ?').get(res.lastInsertRowid) as CrmMessageReaction
}

/** Teammate reaction — same toggle semantics, keyed by user_id. */
export function toggleReactionByUser(messageId: number, userId: number, emoji: string): CrmMessageReaction | null {
  const db = getDb()
  const existing = db.prepare(
    `SELECT * FROM crm_message_reactions WHERE message_id = ? AND user_id = ? AND emoji = ? LIMIT 1`,
  ).get(messageId, userId, emoji) as CrmMessageReaction | undefined
  if (existing) {
    db.prepare('DELETE FROM crm_message_reactions WHERE id = ?').run(existing.id)
    return null
  }
  const res = db.prepare(
    `INSERT INTO crm_message_reactions (message_id, session_id, user_id, emoji) VALUES (?, NULL, ?, ?)`,
  ).run(messageId, userId, emoji)
  return db.prepare('SELECT * FROM crm_message_reactions WHERE id = ?').get(res.lastInsertRowid) as CrmMessageReaction
}

