export interface CrmSavedReply {
  id: number
  workspace_id: number
  user_id: number | null
  shortcut: string
  body_template: string
  created_by_user_id: number | null
  created_at: number
  updated_at: number
}

/** Saved replies visible to a user — workspace-wide + that user's personal ones. */
export function getSavedRepliesForUser(workspaceId: number, userId: number): CrmSavedReply[] {
  return getDb().prepare(
    `SELECT * FROM crm_saved_replies
     WHERE workspace_id = ? AND (user_id IS NULL OR user_id = ?)
     ORDER BY user_id IS NULL DESC, shortcut COLLATE NOCASE ASC, id ASC`,
  ).all(workspaceId, userId) as CrmSavedReply[]
}

export function getSavedReplyById(id: number, workspaceId: number): CrmSavedReply | null {
  const row = getDb().prepare('SELECT * FROM crm_saved_replies WHERE id = ?').get(id) as CrmSavedReply | undefined
  if (!row || row.workspace_id !== workspaceId) return null
  return row
}

export function createSavedReply(data: {
  workspaceId: number
  userId: number | null
  createdByUserId: number
  shortcut: string
  bodyTemplate: string
}): CrmSavedReply {
  const now = Math.floor(Date.now() / 1000)
  const result = getDb().prepare(
    `INSERT INTO crm_saved_replies (workspace_id, user_id, shortcut, body_template, created_by_user_id, created_at, updated_at)
     VALUES (?, ?, ?, ?, ?, ?, ?)`,
  ).run(
    data.workspaceId,
    data.userId,
    data.shortcut.trim().replace(/^\//, ''),
    data.bodyTemplate,
    data.createdByUserId,
    now,
    now,
  )
  return getDb().prepare('SELECT * FROM crm_saved_replies WHERE id = ?').get(result.lastInsertRowid) as CrmSavedReply
}

export function updateSavedReply(
  id: number,
  workspaceId: number,
  data: Partial<{ shortcut: string; bodyTemplate: string; userId: number | null }>,
): CrmSavedReply | null {
  const existing = getSavedReplyById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number | null> = []
  if (data.shortcut !== undefined) { sets.push('shortcut = ?'); params.push(data.shortcut.trim().replace(/^\//, '')) }
  if (data.bodyTemplate !== undefined) { sets.push('body_template = ?'); params.push(data.bodyTemplate) }
  if (data.userId !== undefined) { sets.push('user_id = ?'); params.push(data.userId) }
  if (sets.length === 0) return existing
  sets.push('updated_at = ?')
  params.push(Math.floor(Date.now() / 1000))
  params.push(id)
  getDb().prepare(`UPDATE crm_saved_replies SET ${sets.join(', ')} WHERE id = ?`).run(...params)
  return getSavedReplyById(id, workspaceId)
}

export function deleteSavedReply(id: number, workspaceId: number): boolean {
  const existing = getSavedReplyById(id, workspaceId)
  if (!existing) return false
  return getDb().prepare('DELETE FROM crm_saved_replies WHERE id = ?').run(id).changes > 0
}

// ─── Forms ────────────────────────────────────────────────────────────────

export type CrmFormFieldType =
  | 'text' | 'email' | 'phone' | 'textarea' | 'select' | 'checkbox' | 'number'
  | 'file' | 'signature' | 'rating' | 'multiselect' | 'hidden'

/**
 * Per-type advanced config. Kept as a discriminated bag so adding a new field
 * type can drop in its own shape without perturbing the others.
 *
 *   file:         { maxSizeMB, allowedExtensions, multiple }
 *   rating:       { max, style, labels? }
 *   multiselect:  { options, minSelections?, maxSelections? }
 *   hidden:       handled via field.default_value (supports `{{param:foo}}`
 *                 template substitution against URL params at render time).
 */
export interface CrmFormFieldFileConfig {
  maxSizeMB: number
  allowedExtensions: string[]
  multiple: boolean
}
export interface CrmFormFieldRatingConfig {
  max: number
  style: 'stars' | 'numbers'
  labels?: { low: string; high: string } | null
}
export interface CrmFormFieldMultiselectConfig {
  options: string[]
  minSelections?: number | null
  maxSelections?: number | null
}
export type CrmFormFieldConfig = {
  file?: CrmFormFieldFileConfig
  rating?: CrmFormFieldRatingConfig
  multiselect?: CrmFormFieldMultiselectConfig
}

/** Visibility operators. */
export type CrmFormVisibilityOp =
  | 'eq' | 'neq' | 'contains' | 'has_value' | 'is_empty'

export interface CrmFormVisibilityRule {
  field_id: string
  operator: CrmFormVisibilityOp
  value?: string
}

export interface CrmFormField {
  key: string
  label: string
  type: CrmFormFieldType
  required: boolean
  placeholder?: string
  helper?: string
  options?: string[]
  /** Maps submitted value to a first-class contact field when present. */
  maps_to?: 'first_name' | 'last_name' | 'name' | 'email' | 'phone' | 'company' | null
  /** Advanced per-type config. null/undefined for simple types. */
  config?: CrmFormFieldConfig | null
  /** Show-only-if rules; all must match for the field to render. */
  visibility_rules?: CrmFormVisibilityRule[] | null
  /** Default value for hidden/prefill. Supports `{{param:utm_source}}`. */
  default_value?: string | null
}

/** A page in a multi-step survey. field_ids references CrmFormField.key. */
export interface CrmFormPage {
  id: string
  title: string
  field_ids: string[]
}

export type CrmFormBranchingOp = 'eq' | 'neq' | 'contains' | 'gte' | 'lte'

export interface CrmFormBranchingRule {
  id: string
  if: { field_id: string; op: CrmFormBranchingOp; value: string }
  then: { go_to_page_id: string } | { skip_to_end: true; message?: string }
}

export type CrmFormAbVariant = 'A' | 'B'

export type CrmFormKind = 'standard' | 'order'

export interface CrmForm {
  id: number
  workspace_id: number
  public_id: string
  name: string
  description: string | null
  fields_json: string
  success_message: string
  redirect_url: string | null
  is_active: number
  submission_count: number
  pages_json: string | null
  branching_rules_json: string | null
  ab_variant: CrmFormAbVariant | null
  ab_parent_form_id: number | null
  ab_view_count: number
  form_kind: CrmFormKind
  created_at: number
  updated_at: number
}

export interface CrmFormRecord extends CrmForm {
  fields: CrmFormField[]
  pages: CrmFormPage[] | null
  branching_rules: CrmFormBranchingRule[]
}

function enrichCrmForm(row: CrmForm): CrmFormRecord {
  const pagesRaw = row.pages_json ? safeJsonParse<CrmFormPage[] | null>(row.pages_json, null) : null
  const pages = Array.isArray(pagesRaw) && pagesRaw.length > 0 ? pagesRaw : null
  return {
    ...row,
    form_kind: row.form_kind === 'order' ? 'order' : 'standard',
    fields: safeJsonParse<CrmFormField[]>(row.fields_json, []),
    pages,
    branching_rules: row.branching_rules_json
      ? safeJsonParse<CrmFormBranchingRule[]>(row.branching_rules_json, [])
      : [],
  }
}

export function getCrmForms(workspaceId: number): CrmFormRecord[] {
  const rows = getDb()
    .prepare('SELECT * FROM crm_forms WHERE workspace_id = ? ORDER BY updated_at DESC, id DESC')
    .all(workspaceId) as CrmForm[]
  return rows.map(enrichCrmForm)
}

export function getCrmFormById(id: number, workspaceId: number): CrmFormRecord | null {
  const row = getDb().prepare('SELECT * FROM crm_forms WHERE id = ?').get(id) as CrmForm | undefined
  if (!row || row.workspace_id !== workspaceId) return null
  return enrichCrmForm(row)
}

export function getCrmFormByPublicId(publicId: string): CrmFormRecord | null {
  const row = getDb().prepare('SELECT * FROM crm_forms WHERE public_id = ?').get(publicId) as CrmForm | undefined
  return row ? enrichCrmForm(row) : null
}

const DEFAULT_FORM_FIELDS: CrmFormField[] = [
  { key: 'first_name', label: 'First name', type: 'text', required: true, maps_to: 'first_name' },
  { key: 'last_name',  label: 'Last name',  type: 'text', required: false, maps_to: 'last_name' },
  { key: 'email',      label: 'Email',      type: 'email', required: true, maps_to: 'email' },
  { key: 'phone',      label: 'Phone',      type: 'phone', required: false, maps_to: 'phone' },
]

export function createCrmForm(workspaceId: number, data: {
  name: string
  description?: string | null
  fields?: CrmFormField[]
  success_message?: string
  redirect_url?: string | null
  pages?: CrmFormPage[] | null
  branching_rules?: CrmFormBranchingRule[]
  ab_variant?: CrmFormAbVariant | null
  ab_parent_form_id?: number | null
  form_kind?: CrmFormKind
}): CrmFormRecord {
  const now = Math.floor(Date.now() / 1000)
  const fields = data.fields && data.fields.length > 0 ? data.fields : DEFAULT_FORM_FIELDS
  const result = getDb().prepare(`
    INSERT INTO crm_forms (
      workspace_id, public_id, name, description, fields_json,
      success_message, redirect_url, is_active,
      pages_json, branching_rules_json, ab_variant, ab_parent_form_id, ab_view_count,
      form_kind,
      created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, 1, ?, ?, ?, ?, 0, ?, ?, ?)
  `).run(
    workspaceId,
    generatePublicId(),
    data.name.trim(),
    data.description?.trim() || null,
    JSON.stringify(fields),
    data.success_message?.trim() || "Thanks! We'll be in touch soon.",
    data.redirect_url?.trim() || null,
    data.pages && data.pages.length > 0 ? JSON.stringify(data.pages) : null,
    data.branching_rules && data.branching_rules.length > 0 ? JSON.stringify(data.branching_rules) : null,
    data.ab_variant || null,
    data.ab_parent_form_id || null,
    data.form_kind === 'order' ? 'order' : 'standard',
    now,
    now,
  )
  return getCrmFormById(Number(result.lastInsertRowid), workspaceId) as CrmFormRecord
}

export function updateCrmForm(id: number, workspaceId: number, data: Partial<{
  name: string
  description: string | null
  fields: CrmFormField[]
  success_message: string
  redirect_url: string | null
  is_active: boolean
  pages: CrmFormPage[] | null
  branching_rules: CrmFormBranchingRule[]
  form_kind: CrmFormKind
}>): CrmFormRecord | null {
  const existing = getCrmFormById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number | null> = []
  if (data.name !== undefined) { sets.push('name = ?'); params.push(data.name.trim()) }
  if ('description' in data) { sets.push('description = ?'); params.push(data.description?.trim() || null) }
  if (data.fields !== undefined) { sets.push('fields_json = ?'); params.push(JSON.stringify(data.fields)) }
  if (data.success_message !== undefined) { sets.push('success_message = ?'); params.push(data.success_message.trim()) }
  if ('redirect_url' in data) { sets.push('redirect_url = ?'); params.push(data.redirect_url?.trim() || null) }
  if (data.is_active !== undefined) { sets.push('is_active = ?'); params.push(data.is_active ? 1 : 0) }
  if ('pages' in data) {
    sets.push('pages_json = ?')
    params.push(data.pages && data.pages.length > 0 ? JSON.stringify(data.pages) : null)
  }
  if ('branching_rules' in data) {
    sets.push('branching_rules_json = ?')
    params.push(data.branching_rules && data.branching_rules.length > 0 ? JSON.stringify(data.branching_rules) : null)
  }
  if (data.form_kind !== undefined) {
    sets.push('form_kind = ?')
    params.push(data.form_kind === 'order' ? 'order' : 'standard')
  }
  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(Math.floor(Date.now() / 1000))
  params.push(id)
  getDb().prepare(`UPDATE crm_forms SET ${sets.join(', ')} WHERE id = ?`).run(...params)
  return getCrmFormById(id, workspaceId)
}

export function deleteCrmForm(id: number, workspaceId: number): boolean {
  const existing = getCrmFormById(id, workspaceId)
  if (!existing) return false
  return getDb().prepare('DELETE FROM crm_forms WHERE id = ?').run(id).changes > 0
}

// ─── Form A/B testing ─────────────────────────────────────────────────────

/**
 * Clone an A form into a B variant. The original form is tagged ab_variant='A'
 * if it isn't already, and the new clone points back via ab_parent_form_id.
 * The clone copies fields, pages, branching, and success message — everything
 * except the public_id, name suffix, and submission counters. Returns the
 * newly created B form.
 */
export function createCrmFormAbVariant(parentFormId: number, workspaceId: number): CrmFormRecord | null {
  const parent = getCrmFormById(parentFormId, workspaceId)
  if (!parent) return null
  // Make sure the parent is flagged as A.
  if (parent.ab_variant !== 'A') {
    getDb().prepare(`UPDATE crm_forms SET ab_variant = 'A', updated_at = ? WHERE id = ?`)
      .run(Math.floor(Date.now() / 1000), parent.id)
  }
  // Reject multiple Bs — one A has exactly one B at a time.
  const existingB = getDb().prepare(
    `SELECT id FROM crm_forms WHERE ab_parent_form_id = ? LIMIT 1`,
  ).get(parent.id) as { id: number } | undefined
  if (existingB) return getCrmFormById(existingB.id, workspaceId)

  const clone = createCrmForm(workspaceId, {
    name: `${parent.name} — B`,
    description: parent.description,
    fields: parent.fields,
    success_message: parent.success_message,
    redirect_url: parent.redirect_url,
    pages: parent.pages,
    branching_rules: parent.branching_rules,
    ab_variant: 'B',
    ab_parent_form_id: parent.id,
  })
  return clone
}

/**
 * Sticky 50/50 assignment keyed on the visitor's session_key (ctrl_cid from
 * the tracking pixel or a generated cookie id). If the visitor already has an
 * assignment row for this A/B pair, return the stored variant. Otherwise flip
 * a coin, persist, and return. Safe under unique-index races — on conflict we
 * re-read and return the winning row.
 */
export function assignCrmFormAbVariant(parentFormId: number, sessionKey: string): CrmFormAbVariant {
  const db = getDb()
  const existing = db.prepare(
    `SELECT variant FROM crm_form_ab_assignments WHERE parent_form_id = ? AND session_key = ?`,
  ).get(parentFormId, sessionKey) as { variant: CrmFormAbVariant } | undefined
  if (existing) return existing.variant
  const variant: CrmFormAbVariant = Math.random() < 0.5 ? 'A' : 'B'
  try {
    db.prepare(
      `INSERT INTO crm_form_ab_assignments (parent_form_id, session_key, variant) VALUES (?, ?, ?)`,
    ).run(parentFormId, sessionKey, variant)
    return variant
  } catch {
    const retry = db.prepare(
      `SELECT variant FROM crm_form_ab_assignments WHERE parent_form_id = ? AND session_key = ?`,
    ).get(parentFormId, sessionKey) as { variant: CrmFormAbVariant } | undefined
    return retry?.variant || variant
  }
}

/** Bumps the view counter on whichever variant actually rendered. */
export function incrementCrmFormAbViewCount(formId: number): void {
  getDb().prepare(`UPDATE crm_forms SET ab_view_count = ab_view_count + 1 WHERE id = ?`).run(formId)
}

/** Returns the B-form linked to this A (parent) form, or null when none exists. */
export function getCrmFormBVariantByParent(parentFormId: number): { id: number; public_id: string } | null {
  const row = getDb().prepare(
    `SELECT id, public_id FROM crm_forms WHERE ab_parent_form_id = ? LIMIT 1`,
  ).get(parentFormId) as { id: number; public_id: string } | undefined
  return row || null
}

export interface CrmFormAbStats {
  A: { form_id: number; views: number; submissions: number; conversion_rate: number }
  B: { form_id: number; views: number; submissions: number; conversion_rate: number } | null
}

/**
 * Returns per-variant views + submissions + conversion rate. `views` comes
 * from crm_forms.ab_view_count (bumped once per rendered page view).
 * `submissions` is a COUNT from crm_form_submissions. Conversion rate is
 * clamped to 0 when views is 0 to avoid division-by-zero flicker.
 */
export function getCrmFormAbStats(parentFormId: number, workspaceId: number): CrmFormAbStats | null {
  const parent = getCrmFormById(parentFormId, workspaceId)
  if (!parent) return null
  const db = getDb()
  const parentSubs = (db.prepare(
    `SELECT COUNT(*) AS c FROM crm_form_submissions WHERE form_id = ? AND workspace_id = ?`,
  ).get(parent.id, workspaceId) as { c: number }).c || 0
  const bRow = db.prepare(
    `SELECT * FROM crm_forms WHERE ab_parent_form_id = ? AND workspace_id = ? LIMIT 1`,
  ).get(parent.id, workspaceId) as CrmForm | undefined
  const a = {
    form_id: parent.id,
    views: parent.ab_view_count || 0,
    submissions: parentSubs,
    conversion_rate: parent.ab_view_count > 0 ? parentSubs / parent.ab_view_count : 0,
  }
  if (!bRow) return { A: a, B: null }
  const bSubs = (db.prepare(
    `SELECT COUNT(*) AS c FROM crm_form_submissions WHERE form_id = ? AND workspace_id = ?`,
  ).get(bRow.id, workspaceId) as { c: number }).c || 0
  const b = {
    form_id: bRow.id,
    views: bRow.ab_view_count || 0,
    submissions: bSubs,
    conversion_rate: bRow.ab_view_count > 0 ? bSubs / bRow.ab_view_count : 0,
  }
  return { A: a, B: b }
}

export interface CrmFormSubmission {
  id: number
  form_id: number
  workspace_id: number
  contact_id: number | null
  payload_json: string
  source_url: string | null
  user_agent: string | null
  created_at: number
}

export function getCrmFormSubmissions(formId: number, workspaceId: number, limit = 100): Array<CrmFormSubmission & { payload: Record<string, string> }> {
  const rows = getDb().prepare(`
    SELECT * FROM crm_form_submissions
    WHERE form_id = ? AND workspace_id = ?
    ORDER BY created_at DESC, id DESC
    LIMIT ?
  `).all(formId, workspaceId, limit) as CrmFormSubmission[]
  return rows.map((row) => ({ ...row, payload: safeJsonParse<Record<string, string>>(row.payload_json, {}) }))
}

// ─── Calendars + appointments ─────────────────────────────────────────────

/** Weekly hours: 0 = Sunday … 6 = Saturday. Each day is an array of open
 *  windows given as minutes-since-midnight pairs [start, end). */
export interface CrmCalendarWeeklyHours {
  [dayOfWeek: string]: Array<[number, number]>
}

export type BookingMode = 'single' | 'round_robin' | 'collective' | 'group'
export type RoundRobinStrategy = 'fair' | 'sequential' | 'random'
export type CrmCalendarReminderChannels = 'sms' | 'email' | 'both'

export interface CrmCalendar {
  id: number
  workspace_id: number
  public_id: string
  name: string
  description: string | null
  duration_minutes: number
  buffer_minutes: number
  weekly_hours_json: string
  timezone: string
  owner_id: number | null
  is_active: number
  slug: string | null
  reminder_sms_hours_before: number
  reminder_email_hours_before: number
  /** One-click reminder toggles. Drive the two fixed windows (24h, 1h). */
  reminder_24h_enabled: number
  reminder_1h_enabled: number
  /** Which channel(s) get sent when either window is on. */
  reminder_channels: CrmCalendarReminderChannels
  /** Optional template overrides. When null the default body is used. */
  reminder_sms_template_id: number | null
  reminder_email_template_id: number | null
  /** JSON array of user ids the booking page rotates bookings across. */
  round_robin_user_ids_json: string | null
  last_round_robin_user_id: number | null
  /** single | round_robin | collective — controls how availability + host assignment works. */
  booking_mode: BookingMode
  /** JSON array of user ids for round_robin / collective modes. */
  host_user_ids_json: string | null
  round_robin_strategy: RoundRobinStrategy
  round_robin_cursor: number
  /** Max attendees per slot when booking_mode = 'group'. Ignored otherwise. */
  capacity: number
  created_at: number
  updated_at: number
}

/**
 * If round-robin is configured, pick the next user in the rotation and
 * persist it as last_round_robin_user_id. Returns null when rotation is off
 * or the list is empty. Self-contained so the public booking endpoint can
 * call it without understanding the rotation mechanics.
 */
export function pickRoundRobinAssignee(calendarId: number): number | null {
  const row = getDb().prepare(
    'SELECT round_robin_user_ids_json, last_round_robin_user_id FROM crm_calendars WHERE id = ?',
  ).get(calendarId) as { round_robin_user_ids_json: string | null; last_round_robin_user_id: number | null } | undefined
  if (!row?.round_robin_user_ids_json) return null
  let ids: unknown
  try { ids = JSON.parse(row.round_robin_user_ids_json) } catch { return null }
  if (!Array.isArray(ids) || ids.length === 0) return null
  const userIds = (ids as unknown[])
    .map((v) => (typeof v === 'number' ? v : Number(v)))
    .filter((n) => Number.isFinite(n) && n > 0) as number[]
  if (userIds.length === 0) return null

  // Pick the user after the last assignee (wrap around); default to the first.
  let nextIndex = 0
  if (row.last_round_robin_user_id) {
    const lastIdx = userIds.indexOf(row.last_round_robin_user_id)
    nextIndex = lastIdx >= 0 ? (lastIdx + 1) % userIds.length : 0
  }
  const pick = userIds[nextIndex]
  getDb().prepare('UPDATE crm_calendars SET last_round_robin_user_id = ?, updated_at = ? WHERE id = ?')
    .run(pick, Math.floor(Date.now() / 1000), calendarId)
  return pick
}

export interface CrmAppointmentReminder {
  id: number
  appointment_id: number
  workspace_id: number
  contact_id: number
  kind: 'sms' | 'email'
  due_at: number
  status: 'pending' | 'sent' | 'skipped' | 'failed'
  last_error: string | null
  sent_at: number | null
  offset_minutes: number | null
  created_at: number
}

/**
 * After an appointment is booked, schedule reminders based on the calendar's
 * one-click toggles (24h / 1h × sms / email / both). Legacy `hours_before`
 * columns are still honored when the new toggles are all off — keeps any
 * existing workflow-authored setups working while new booking pages use the
 * simple checkboxes. Idempotent: pending duplicates are skipped.
 */
export function scheduleAppointmentReminders(appointmentId: number): void {
  const row = getDb().prepare(`
    SELECT a.id as appointment_id, a.workspace_id, a.contact_id, a.starts_at,
           c.reminder_sms_hours_before AS sms_h, c.reminder_email_hours_before AS email_h,
           c.reminder_24h_enabled AS r24, c.reminder_1h_enabled AS r1,
           c.reminder_channels AS channels
    FROM crm_appointments a JOIN crm_calendars c ON c.id = a.calendar_id
    WHERE a.id = ?
  `).get(appointmentId) as {
    appointment_id: number; workspace_id: number; contact_id: number; starts_at: number;
    sms_h: number; email_h: number; r24: number; r1: number; channels: string;
  } | undefined
  if (!row || !row.contact_id) return

  // Only schedule for still-pending rows — don't resurrect rows that were
  // previously sent or explicitly skipped (reschedule path marks them
  // skipped before calling us again).
  const existing = getDb()
    .prepare(`SELECT kind, offset_minutes FROM crm_appointment_reminders WHERE appointment_id = ? AND status = 'pending'`)
    .all(appointmentId) as Array<{ kind: string; offset_minutes: number | null }>
  const hasPending = (kind: 'sms' | 'email', offset: number): boolean =>
    existing.some((r) => r.kind === kind && r.offset_minutes === offset)

  const insert = getDb().prepare(`
    INSERT INTO crm_appointment_reminders (appointment_id, workspace_id, contact_id, kind, due_at, offset_minutes)
    VALUES (?, ?, ?, ?, ?, ?)
  `)

  const wantSms = row.channels === 'sms' || row.channels === 'both'
  const wantEmail = row.channels === 'email' || row.channels === 'both'
  const offsets: number[] = []
  if (row.r24) offsets.push(1440)
  if (row.r1) offsets.push(60)
  let scheduled = 0
  for (const off of offsets) {
    const dueAt = row.starts_at - off * 60
    if (wantSms && !hasPending('sms', off)) {
      insert.run(row.appointment_id, row.workspace_id, row.contact_id, 'sms', dueAt, off)
      scheduled += 1
    }
    if (wantEmail && !hasPending('email', off)) {
      insert.run(row.appointment_id, row.workspace_id, row.contact_id, 'email', dueAt, off)
      scheduled += 1
    }
  }

  // If nothing was scheduled by the new toggles, honor the legacy
  // hours-before columns so existing clients aren't silently dropped.
  if (scheduled === 0) {
    if (row.sms_h > 0 && !hasPending('sms', row.sms_h * 60)) {
      const dueAt = row.starts_at - row.sms_h * 3600
      insert.run(row.appointment_id, row.workspace_id, row.contact_id, 'sms', dueAt, row.sms_h * 60)
    }
    if (row.email_h > 0 && !hasPending('email', row.email_h * 60)) {
      const dueAt = row.starts_at - row.email_h * 3600
      insert.run(row.appointment_id, row.workspace_id, row.contact_id, 'email', dueAt, row.email_h * 60)
    }
  }
}

/**
 * Cancel all still-pending reminders for an appointment (reschedule and
 * cancellation both call this). Marks status = 'skipped' with an explicit
 * reason so the booking detail can render it as "canceled" without losing
 * the audit trail.
 */
export function cancelPendingAppointmentReminders(appointmentId: number, reason = 'canceled'): number {
  const result = getDb().prepare(
    `UPDATE crm_appointment_reminders SET status = 'skipped', last_error = ? WHERE appointment_id = ? AND status = 'pending'`,
  ).run(reason, appointmentId)
  return Number(result.changes || 0)
}

/** All reminders (any status) for a single appointment, oldest-due first. */
export function getRemindersForAppointment(appointmentId: number): CrmAppointmentReminder[] {
  return getDb()
    .prepare('SELECT * FROM crm_appointment_reminders WHERE appointment_id = ? ORDER BY due_at ASC, id ASC')
    .all(appointmentId) as CrmAppointmentReminder[]
}

/** Reminders whose due_at has passed and are still pending. */
export function getDueAppointmentReminders(limit = 50): CrmAppointmentReminder[] {
  const now = Math.floor(Date.now() / 1000)
  return getDb().prepare(`
    SELECT * FROM crm_appointment_reminders
    WHERE status = 'pending' AND due_at <= ?
    ORDER BY due_at ASC
    LIMIT ?
  `).all(now, limit) as CrmAppointmentReminder[]
}

export function markAppointmentReminderResult(id: number, status: 'sent' | 'skipped' | 'failed', lastError?: string | null): void {
  const now = Math.floor(Date.now() / 1000)
  getDb().prepare(`UPDATE crm_appointment_reminders SET status = ?, last_error = ?, sent_at = ? WHERE id = ?`)
    .run(status, lastError ?? null, status === 'sent' ? now : null, id)
}

export interface CrmCalendarRecord extends CrmCalendar {
  weekly_hours: CrmCalendarWeeklyHours
  round_robin_user_ids: number[]
  /** Parsed from host_user_ids_json — the roster for round_robin + collective modes. */
  host_user_ids: number[]
}

function parseIdArray(json: string | null): number[] {
  if (!json) return []
  try {
    const parsed = JSON.parse(json) as unknown
    if (!Array.isArray(parsed)) return []
    return (parsed as unknown[])
      .map((v) => (typeof v === 'number' ? v : Number(v)))
      .filter((n) => Number.isFinite(n) && n > 0) as number[]
  } catch { return [] }
}

function enrichCrmCalendar(row: CrmCalendar): CrmCalendarRecord {
  return {
    ...row,
    // Normalize older rows where the new columns might still be null.
    booking_mode: (row.booking_mode || 'single') as BookingMode,
    round_robin_strategy: (row.round_robin_strategy || 'fair') as RoundRobinStrategy,
    round_robin_cursor: row.round_robin_cursor ?? 0,
    capacity: typeof row.capacity === 'number' && row.capacity > 0 ? row.capacity : 1,
    weekly_hours: safeJsonParse<CrmCalendarWeeklyHours>(row.weekly_hours_json, {}),
    round_robin_user_ids: parseIdArray(row.round_robin_user_ids_json),
    host_user_ids: parseIdArray(row.host_user_ids_json),
  }
}

const DEFAULT_WEEKLY_HOURS: CrmCalendarWeeklyHours = {
  '1': [[9 * 60, 17 * 60]],  // Mon
  '2': [[9 * 60, 17 * 60]],  // Tue
  '3': [[9 * 60, 17 * 60]],  // Wed
  '4': [[9 * 60, 17 * 60]],  // Thu
  '5': [[9 * 60, 17 * 60]],  // Fri
}

export function getCrmCalendars(workspaceId: number): CrmCalendarRecord[] {
  const rows = getDb()
    .prepare('SELECT * FROM crm_calendars WHERE workspace_id = ? ORDER BY updated_at DESC, id DESC')
    .all(workspaceId) as CrmCalendar[]
  return rows.map(enrichCrmCalendar)
}

export function getCrmCalendarById(id: number, workspaceId: number): CrmCalendarRecord | null {
  const row = getDb().prepare('SELECT * FROM crm_calendars WHERE id = ?').get(id) as CrmCalendar | undefined
  if (!row || row.workspace_id !== workspaceId) return null
  return enrichCrmCalendar(row)
}

export function getCrmCalendarByPublicId(publicId: string): CrmCalendarRecord | null {
  const row = getDb().prepare('SELECT * FROM crm_calendars WHERE public_id = ?').get(publicId) as CrmCalendar | undefined
  return row ? enrichCrmCalendar(row) : null
}

export function createCrmCalendar(workspaceId: number, data: {
  name: string
  description?: string | null
  duration_minutes?: number
  buffer_minutes?: number
  timezone?: string
  weekly_hours?: CrmCalendarWeeklyHours
}): CrmCalendarRecord {
  const now = Math.floor(Date.now() / 1000)

  // Seed the new booking page with the workspace-level reminder defaults so
  // operators who turn reminders on once at the workspace don't have to
  // remember to tick the box on every new calendar.
  const defaults = getDb().prepare(
    'SELECT default_reminder_24h AS r24, default_reminder_1h AS r1 FROM workspaces WHERE id = ?'
  ).get(workspaceId) as { r24: number; r1: number } | undefined
  const r24 = defaults?.r24 ? 1 : 0
  const r1 = defaults?.r1 ? 1 : 0

  const result = getDb().prepare(`
    INSERT INTO crm_calendars (workspace_id, public_id, name, description, duration_minutes, buffer_minutes, weekly_hours_json, timezone, is_active, reminder_24h_enabled, reminder_1h_enabled, reminder_channels, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?, 'both', ?, ?)
  `).run(
    workspaceId,
    generatePublicId(),
    data.name.trim(),
    data.description?.trim() || null,
    data.duration_minutes ?? 30,
    data.buffer_minutes ?? 0,
    JSON.stringify(data.weekly_hours || DEFAULT_WEEKLY_HOURS),
    data.timezone || 'America/Vancouver',
    r24,
    r1,
    now,
    now,
  )
  return getCrmCalendarById(Number(result.lastInsertRowid), workspaceId) as CrmCalendarRecord
}

export function updateCrmCalendar(id: number, workspaceId: number, data: Partial<{
  name: string
  description: string | null
  duration_minutes: number
  buffer_minutes: number
  weekly_hours: CrmCalendarWeeklyHours
  timezone: string
  is_active: boolean
  reminder_sms_hours_before: number
  reminder_email_hours_before: number
  reminder_24h_enabled: boolean
  reminder_1h_enabled: boolean
  reminder_channels: CrmCalendarReminderChannels
  reminder_sms_template_id: number | null
  reminder_email_template_id: number | null
  round_robin_user_ids: number[] | null
  booking_mode: BookingMode
  host_user_ids: number[] | null
  round_robin_strategy: RoundRobinStrategy
  capacity: number
}>): CrmCalendarRecord | null {
  const existing = getCrmCalendarById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number | null> = []
  if (data.name !== undefined) { sets.push('name = ?'); params.push(data.name.trim()) }
  if ('description' in data) { sets.push('description = ?'); params.push(data.description?.trim() || null) }
  if (data.duration_minutes !== undefined) { sets.push('duration_minutes = ?'); params.push(data.duration_minutes) }
  if (data.buffer_minutes !== undefined) { sets.push('buffer_minutes = ?'); params.push(data.buffer_minutes) }
  if (data.weekly_hours !== undefined) { sets.push('weekly_hours_json = ?'); params.push(JSON.stringify(data.weekly_hours)) }
  if (data.timezone !== undefined) { sets.push('timezone = ?'); params.push(data.timezone) }
  if (data.is_active !== undefined) { sets.push('is_active = ?'); params.push(data.is_active ? 1 : 0) }
  if (data.reminder_sms_hours_before !== undefined) { sets.push('reminder_sms_hours_before = ?'); params.push(Math.max(0, Math.min(336, data.reminder_sms_hours_before))) }
  if (data.reminder_email_hours_before !== undefined) { sets.push('reminder_email_hours_before = ?'); params.push(Math.max(0, Math.min(336, data.reminder_email_hours_before))) }
  if (data.reminder_24h_enabled !== undefined) { sets.push('reminder_24h_enabled = ?'); params.push(data.reminder_24h_enabled ? 1 : 0) }
  if (data.reminder_1h_enabled !== undefined) { sets.push('reminder_1h_enabled = ?'); params.push(data.reminder_1h_enabled ? 1 : 0) }
  if (data.reminder_channels !== undefined) { sets.push('reminder_channels = ?'); params.push(data.reminder_channels) }
  if ('reminder_sms_template_id' in data) {
    sets.push('reminder_sms_template_id = ?')
    params.push(typeof data.reminder_sms_template_id === 'number' ? data.reminder_sms_template_id : null)
  }
  if ('reminder_email_template_id' in data) {
    sets.push('reminder_email_template_id = ?')
    params.push(typeof data.reminder_email_template_id === 'number' ? data.reminder_email_template_id : null)
  }
  if ('round_robin_user_ids' in data) {
    const serialized = Array.isArray(data.round_robin_user_ids) && data.round_robin_user_ids.length > 0
      ? JSON.stringify(data.round_robin_user_ids.filter((n) => Number.isFinite(n) && n > 0))
      : null
    sets.push('round_robin_user_ids_json = ?')
    params.push(serialized)
    // Changing the roster resets the rotation pointer so the first new
    // booking goes to the first person in the fresh list.
    sets.push('last_round_robin_user_id = NULL')
  }
  if (data.booking_mode !== undefined) {
    const mode: BookingMode =
      data.booking_mode === 'round_robin' || data.booking_mode === 'collective' || data.booking_mode === 'group'
        ? data.booking_mode
        : 'single'
    sets.push('booking_mode = ?')
    params.push(mode)
  }
  if (data.capacity !== undefined) {
    const cap = Math.max(1, Math.min(1000, Math.floor(data.capacity)))
    sets.push('capacity = ?')
    params.push(cap)
  }
  if ('host_user_ids' in data) {
    const serialized = Array.isArray(data.host_user_ids) && data.host_user_ids.length > 0
      ? JSON.stringify(data.host_user_ids.filter((n) => Number.isFinite(n) && n > 0))
      : null
    sets.push('host_user_ids_json = ?')
    params.push(serialized)
    // Reset the sequential cursor when the roster changes so we don't land
    // out of bounds on a shorter list.
    sets.push('round_robin_cursor = 0')
  }
  if (data.round_robin_strategy !== undefined) {
    const strat: RoundRobinStrategy = data.round_robin_strategy === 'sequential' || data.round_robin_strategy === 'random'
      ? data.round_robin_strategy
      : 'fair'
    sets.push('round_robin_strategy = ?')
    params.push(strat)
  }
  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(Math.floor(Date.now() / 1000))
  params.push(id)
  getDb().prepare(`UPDATE crm_calendars SET ${sets.join(', ')} WHERE id = ?`).run(...params)
  return getCrmCalendarById(id, workspaceId)
}

export function deleteCrmCalendar(id: number, workspaceId: number): boolean {
  const existing = getCrmCalendarById(id, workspaceId)
  if (!existing) return false
  return getDb().prepare('DELETE FROM crm_calendars WHERE id = ?').run(id).changes > 0
}

export interface CrmAppointment {
  id: number
  calendar_id: number
  workspace_id: number
  contact_id: number | null
  starts_at: number
  ends_at: number
  status: 'confirmed' | 'cancelled' | 'showed' | 'no_show' | 'rescheduled' | 'conflict_detected'
  notes: string | null
  /** Host who owns this slot. For collective bookings this is the first host;
   *  co-hosts live in crm_booking_attendees. Legacy rows may be null. */
  assigned_user_id: number | null
  /** Unix seconds when the in-app "starting soon" host notification fired.
   *  Null until the scheduler dispatches it. Keeps the tick idempotent. */
  reminder_sent_at: number | null
  /** Unguessable token powering the /a/[token] self-service page so contacts
   *  can cancel or reschedule without an account. Auto-generated on insert. */
  manage_token: string | null
  created_at: number
  updated_at: number
}

export interface CrmBookingAttendee {
  id: number
  booking_id: number
  user_id: number
  status: 'invited' | 'accepted' | 'declined'
  created_at: number
}

export function getCrmAppointments(workspaceId: number, options: { calendarId?: number; from?: number; to?: number; limit?: number } = {}): CrmAppointment[] {
  const clauses = ['workspace_id = ?']
  const params: Array<number> = [workspaceId]
  if (options.calendarId) { clauses.push('calendar_id = ?'); params.push(options.calendarId) }
  if (options.from) { clauses.push('starts_at >= ?'); params.push(options.from) }
  if (options.to) { clauses.push('starts_at <= ?'); params.push(options.to) }
  params.push(options.limit ?? 100)
  return getDb().prepare(
    `SELECT * FROM crm_appointments WHERE ${clauses.join(' AND ')} ORDER BY starts_at ASC LIMIT ?`
  ).all(...params) as CrmAppointment[]
}

export function getCrmAppointmentById(id: number, workspaceId: number): CrmAppointment | null {
  const row = getDb().prepare('SELECT * FROM crm_appointments WHERE id = ?').get(id) as CrmAppointment | undefined
  if (!row || row.workspace_id !== workspaceId) return null
  return row
}

/**
 * Soonest upcoming booking for a contact that can still be cancelled. Workflow
 * actions use this to target "their next appointment" without asking the
 * operator to know the id — confirmed/pending states only, optionally scoped
 * to a single calendar.
 */
export function getNextUpcomingCrmAppointmentForContact(
  workspaceId: number,
  contactId: number,
  calendarId?: number | null,
): CrmAppointment | null {
  const now = Math.floor(Date.now() / 1000)
  const clauses = [
    'workspace_id = ?',
    'contact_id = ?',
    'starts_at >= ?',
    "status IN ('confirmed', 'rescheduled')",
  ]
  const params: Array<number> = [workspaceId, contactId, now]
  if (calendarId) { clauses.push('calendar_id = ?'); params.push(calendarId) }
  const row = getDb().prepare(
    `SELECT * FROM crm_appointments WHERE ${clauses.join(' AND ')} ORDER BY starts_at ASC LIMIT 1`
  ).get(...params) as CrmAppointment | undefined
  return row || null
}

export function createCrmAppointment(data: {
  calendar_id: number
  workspace_id: number
  contact_id: number | null
  starts_at: number
  ends_at: number
  notes?: string | null
  assigned_user_id?: number | null
}): CrmAppointment {
  const manageToken = crypto.randomBytes(18).toString('base64url')
  const result = getDb().prepare(`
    INSERT INTO crm_appointments (calendar_id, workspace_id, contact_id, starts_at, ends_at, notes, assigned_user_id, manage_token)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    data.calendar_id,
    data.workspace_id,
    data.contact_id,
    data.starts_at,
    data.ends_at,
    data.notes || null,
    data.assigned_user_id ?? null,
    manageToken,
  )
  const appointmentId = Number(result.lastInsertRowid)
  // Auto-schedule reminder rows if the calendar has reminder offsets set.
  // No-op when both offsets are zero, which is the default.
  try { scheduleAppointmentReminders(appointmentId) } catch { /* keep booking resilient */ }
  return getDb().prepare('SELECT * FROM crm_appointments WHERE id = ?').get(appointmentId) as CrmAppointment
}

/**
 * Token-scoped appointment lookup for the public self-service page. Returns
 * null when the token is empty or no row matches — callers render a 404 on
 * null without leaking workspace info.
 */
export function getCrmAppointmentByManageToken(token: string): CrmAppointment | null {
  if (!token) return null
  const row = getDb().prepare('SELECT * FROM crm_appointments WHERE manage_token = ?').get(token) as CrmAppointment | undefined
  return row || null
}

/** Record co-hosts for a collective booking. Primary host lives on the booking's
 *  assigned_user_id. Safe to call with an empty list. */
export function addCrmBookingAttendees(bookingId: number, userIds: number[]): void {
  const unique = Array.from(new Set(userIds.filter((n) => Number.isFinite(n) && n > 0)))
  if (unique.length === 0) return
  const insert = getDb().prepare(
    'INSERT INTO crm_booking_attendees (booking_id, user_id) VALUES (?, ?)'
  )
  for (const uid of unique) {
    try { insert.run(bookingId, uid) } catch { /* swallow — attendee failures never break a booking */ }
  }
}

export function getCrmBookingAttendees(bookingId: number): CrmBookingAttendee[] {
  return getDb().prepare(
    'SELECT * FROM crm_booking_attendees WHERE booking_id = ? ORDER BY id ASC'
  ).all(bookingId) as CrmBookingAttendee[]
}

export function updateCrmAppointmentStatus(id: number, workspaceId: number, status: CrmAppointment['status']): CrmAppointment | null {
  const existing = getCrmAppointmentById(id, workspaceId)
  if (!existing) return null
  getDb().prepare('UPDATE crm_appointments SET status = ?, updated_at = ? WHERE id = ?')
    .run(status, Math.floor(Date.now() / 1000), id)
  // If the booking is abandoned or rescheduled, pending reminders are now
  // stale — cancel them so the worker doesn't still blast a 24h SMS for a
  // meeting that is no longer happening.
  if (status === 'cancelled' || status === 'rescheduled' || status === 'conflict_detected') {
    const reason = status === 'rescheduled'
      ? 'rescheduled'
      : status === 'conflict_detected'
        ? 'conflict_detected'
        : 'canceled'
    try { cancelPendingAppointmentReminders(id, reason) } catch { /* non-critical */ }
  }
  return getCrmAppointmentById(id, workspaceId)
}

/**
 * Move an existing booking to a new start time. Re-schedules its reminders
 * from scratch so the 24h / 1h windows line up with the new slot.
 */
export function rescheduleCrmAppointment(id: number, workspaceId: number, newStartsAt: number): CrmAppointment | null {
  const existing = getCrmAppointmentById(id, workspaceId)
  if (!existing) return null
  const duration = existing.ends_at - existing.starts_at
  getDb().prepare('UPDATE crm_appointments SET starts_at = ?, ends_at = ?, status = ?, updated_at = ? WHERE id = ?')
    .run(newStartsAt, newStartsAt + Math.max(duration, 60), 'confirmed', Math.floor(Date.now() / 1000), id)
  try {
    cancelPendingAppointmentReminders(id, 'rescheduled')
    scheduleAppointmentReminders(id)
  } catch { /* keep reschedule resilient */ }
  return getCrmAppointmentById(id, workspaceId)
}

/** Host-scoped busy blocks covering the given window. Used by multi-host
 *  booking pages so we can compute each host's union / intersection of free
 *  time. For a given user, "busy" means:
 *    - any confirmed appointment in this workspace where assigned_user_id = user
 *    - every busy event from the workspace's synced Google calendars
 *  Synced events aren't wired per-user in this schema, so they block every
 *  host — this matches how single-host booking pages already treat conflicts. */
export function getHostBusyBlocks(
  workspaceId: number,
  userIds: number[],
  fromSec: number,
  toSec: number,
): Map<number, Array<{ starts_at: number; ends_at: number }>> {
  const out = new Map<number, Array<{ starts_at: number; ends_at: number }>>()
  if (userIds.length === 0) return out

  // Per-user appointments across every booking page in the workspace.
  const placeholders = userIds.map(() => '?').join(',')
  const appointmentRows = getDb().prepare(`
    SELECT assigned_user_id, starts_at, ends_at
    FROM crm_appointments
    WHERE workspace_id = ?
      AND status IN ('confirmed','showed','rescheduled')
      AND assigned_user_id IN (${placeholders})
      AND starts_at < ? AND ends_at > ?
  `).all(workspaceId, ...userIds, toSec, fromSec) as Array<{ assigned_user_id: number; starts_at: number; ends_at: number }>

  // Collective bookings also make co-hosts busy.
  const attendeeRows = getDb().prepare(`
    SELECT ba.user_id, a.starts_at, a.ends_at
    FROM crm_booking_attendees ba
    JOIN crm_appointments a ON a.id = ba.booking_id
    WHERE a.workspace_id = ?
      AND a.status IN ('confirmed','showed','rescheduled')
      AND ba.user_id IN (${placeholders})
      AND a.starts_at < ? AND a.ends_at > ?
  `).all(workspaceId, ...userIds, toSec, fromSec) as Array<{ user_id: number; starts_at: number; ends_at: number }>

  // Global synced busy — applies to every host for now.
  const fromIso = new Date(fromSec * 1000).toISOString()
  const toIso = new Date(toSec * 1000).toISOString()
  const syncedRows = getDb().prepare(`
    SELECT e.start_time, e.end_time
    FROM calendar_events e
    JOIN google_calendars g ON g.id = e.calendar_id
    WHERE g.use_for_conflicts = 1
      AND e.all_day = 0
      AND (e.status IS NULL OR e.status != 'cancelled')
      AND e.start_time < ? AND e.end_time > ?
  `).all(toIso, fromIso) as Array<{ start_time: string; end_time: string }>
  const syncedBlocks: Array<{ starts_at: number; ends_at: number }> = []
  for (const row of syncedRows) {
    const s = Math.floor(new Date(row.start_time).getTime() / 1000)
    const e = Math.floor(new Date(row.end_time).getTime() / 1000)
    if (Number.isFinite(s) && Number.isFinite(e) && e > s) {
      syncedBlocks.push({ starts_at: s, ends_at: e })
    }
  }

  for (const uid of userIds) {
    const blocks = syncedBlocks.slice()
    for (const row of appointmentRows) if (row.assigned_user_id === uid) blocks.push({ starts_at: row.starts_at, ends_at: row.ends_at })
    for (const row of attendeeRows) if (row.user_id === uid) blocks.push({ starts_at: row.starts_at, ends_at: row.ends_at })
    out.set(uid, blocks)
  }
  return out
}

/** How many bookings did each host close for this calendar in the window?
 *  Powers the fair round-robin strategy. */
export function getHostBookingCounts(
  calendarId: number,
  userIds: number[],
  sinceSec: number,
): Map<number, number> {
  const counts = new Map<number, number>()
  for (const uid of userIds) counts.set(uid, 0)
  if (userIds.length === 0) return counts
  const placeholders = userIds.map(() => '?').join(',')
  const rows = getDb().prepare(`
    SELECT assigned_user_id, COUNT(*) AS n
    FROM crm_appointments
    WHERE calendar_id = ?
      AND assigned_user_id IN (${placeholders})
      AND starts_at >= ?
      AND status IN ('confirmed','showed','rescheduled')
    GROUP BY assigned_user_id
  `).all(calendarId, ...userIds, sinceSec) as Array<{ assigned_user_id: number; n: number }>
  for (const row of rows) counts.set(row.assigned_user_id, row.n)
  return counts
}

/** Pick the host for a round-robin booking, from the set of hosts free at the
 *  requested slot. Persists cursor + last_round_robin_user_id so the next
 *  booking picks correctly. Returns null if no host is free. */
export function pickRoundRobinHost(
  calendarId: number,
  freeHostIds: number[],
  strategy: RoundRobinStrategy,
): number | null {
  if (freeHostIds.length === 0) return null
  const row = getDb().prepare(
    'SELECT host_user_ids_json, round_robin_cursor, last_round_robin_user_id FROM crm_calendars WHERE id = ?'
  ).get(calendarId) as { host_user_ids_json: string | null; round_robin_cursor: number | null; last_round_robin_user_id: number | null } | undefined
  if (!row) return null
  const roster = parseIdArray(row.host_user_ids_json)

  let pick: number | null = null
  if (strategy === 'random') {
    pick = freeHostIds[Math.floor(Math.random() * freeHostIds.length)]
  } else if (strategy === 'sequential' && roster.length > 0) {
    const cursor = row.round_robin_cursor ?? 0
    // Walk the roster from `cursor` and take the first free host.
    for (let i = 0; i < roster.length; i += 1) {
      const candidate = roster[(cursor + i) % roster.length]
      if (freeHostIds.includes(candidate)) { pick = candidate; break }
    }
    // Increment and persist — next booking lands on the person after this pick.
    if (pick !== null) {
      const pickIdx = roster.indexOf(pick)
      const nextCursor = (pickIdx + 1) % roster.length
      getDb().prepare(
        'UPDATE crm_calendars SET round_robin_cursor = ?, last_round_robin_user_id = ?, updated_at = ? WHERE id = ?'
      ).run(nextCursor, pick, Math.floor(Date.now() / 1000), calendarId)
      return pick
    }
    return null
  } else {
    // fair: fewest bookings in the last 30 days, tiebreak lowest user id.
    const sinceSec = Math.floor(Date.now() / 1000) - 30 * 86_400
    const counts = getHostBookingCounts(calendarId, freeHostIds, sinceSec)
    pick = [...freeHostIds].sort((a, b) => {
      const ca = counts.get(a) ?? 0
      const cb = counts.get(b) ?? 0
      if (ca !== cb) return ca - cb
      return a - b
    })[0]
  }

  if (pick !== null) {
    getDb().prepare(
      'UPDATE crm_calendars SET last_round_robin_user_id = ?, updated_at = ? WHERE id = ?'
    ).run(pick, Math.floor(Date.now() / 1000), calendarId)
  }
  return pick
}

/** Check whether the given [start, end) slot conflicts with either an existing
 *  confirmed appointment on this booking page, or a busy event from any
 *  Google-synced calendar that is marked use_for_conflicts = 1. */
export function hasCalendarConflict(
  calendarId: number,
  starts_at: number,
  ends_at: number,
  excludeAppointmentId?: number,
): boolean {
  // In group mode the same slot accepts multiple contacts up to `capacity`.
  // The conflict check then becomes: is the slot AT capacity, OR does the
  // slot span a synced-busy event? Exact starts_at/ends_at match is how we
  // identify "the same class session" vs. an overlapping 1:1 booking we'd
  // still want to block on.
  //
  // `excludeAppointmentId` lets the reschedule path exclude the row we're
  // moving so its own old slot doesn't block the new slot (they don't
  // overlap in practice — the row is being updated in place — but we exclude
  // just-in-case for the no-change edge).
  const cal = getDb().prepare(
    'SELECT booking_mode, capacity FROM crm_calendars WHERE id = ?',
  ).get(calendarId) as { booking_mode: string | null; capacity: number | null } | undefined
  const mode = (cal?.booking_mode || 'single') as BookingMode

  if (mode === 'group') {
    // Any other-slot overlap (a 1:1 leftover or a different group session that
    // happens to overlap) still blocks — only identical starts_at/ends_at rows
    // are treated as seats on the same class.
    const overlap = getDb().prepare(`
      SELECT id, starts_at, ends_at FROM crm_appointments
      WHERE calendar_id = ? AND status IN ('confirmed','showed','rescheduled')
        AND starts_at < ? AND ends_at > ?
    `).all(calendarId, ends_at, starts_at) as Array<{ id: number; starts_at: number; ends_at: number }>
    const filtered = excludeAppointmentId
      ? overlap.filter((a) => a.id !== excludeAppointmentId)
      : overlap
    const sameSession = filtered.filter((a) => a.starts_at === starts_at && a.ends_at === ends_at)
    const differentSession = filtered.filter((a) => a.starts_at !== starts_at || a.ends_at !== ends_at)
    if (differentSession.length > 0) return true
    const capacity = Math.max(1, cal?.capacity ?? 1)
    if (sameSession.length >= capacity) return true
  } else {
    const params: Array<number> = [calendarId, ends_at, starts_at]
    let excludeSql = ''
    if (excludeAppointmentId) {
      excludeSql = ' AND id != ?'
      params.push(excludeAppointmentId)
    }
    const appointment = getDb().prepare(`
      SELECT id FROM crm_appointments
      WHERE calendar_id = ? AND status IN ('confirmed','showed','rescheduled')
        AND starts_at < ? AND ends_at > ?${excludeSql}
      LIMIT 1
    `).get(...params) as { id: number } | undefined
    if (appointment) return true
  }

  const startIso = new Date(starts_at * 1000).toISOString()
  const endIso = new Date(ends_at * 1000).toISOString()
  const synced = getDb().prepare(`
    SELECT e.id FROM calendar_events e
    JOIN google_calendars g ON g.id = e.calendar_id
    WHERE g.use_for_conflicts = 1
      AND e.all_day = 0
      AND (e.status IS NULL OR e.status != 'cancelled')
      AND e.start_time < ? AND e.end_time > ?
    LIMIT 1
  `).get(endIso, startIso) as { id: string } | undefined
  return Boolean(synced)
}

/** Count confirmed attendees already booked on this exact group slot. */
export function countGroupSlotAttendees(calendarId: number, starts_at: number, ends_at: number): number {
  const row = getDb().prepare(`
    SELECT COUNT(*) AS n FROM crm_appointments
    WHERE calendar_id = ? AND starts_at = ? AND ends_at = ?
      AND status IN ('confirmed','showed','rescheduled')
  `).get(calendarId, starts_at, ends_at) as { n: number } | undefined
  return row?.n ?? 0
}

export function recordCrmFormSubmission(data: {
  form_id: number
  workspace_id: number
  contact_id: number | null
  payload: Record<string, string>
  source_url?: string | null
  user_agent?: string | null
}): CrmFormSubmission {
  const result = getDb().prepare(`
    INSERT INTO crm_form_submissions (form_id, workspace_id, contact_id, payload_json, source_url, user_agent)
    VALUES (?, ?, ?, ?, ?, ?)
  `).run(
    data.form_id,
    data.workspace_id,
    data.contact_id,
    JSON.stringify(data.payload),
    data.source_url || null,
    data.user_agent || null,
  )
  // Bump the submission_count on the form
  getDb().prepare('UPDATE crm_forms SET submission_count = submission_count + 1, updated_at = ? WHERE id = ?')
    .run(Math.floor(Date.now() / 1000), data.form_id)
  const row = getDb().prepare('SELECT * FROM crm_form_submissions WHERE id = ?').get(Number(result.lastInsertRowid)) as CrmFormSubmission
  return row
}

// ─── Surveys + NPS ───────────────────────────────────────────────────────

export type CrmSurveyType = 'nps' | 'csat' | 'ces' | 'custom'
export type CrmSurveyStatus = 'draft' | 'published' | 'archived'
export type CrmSurveyResponseSource = 'direct' | 'email' | 'sms' | 'embed' | 'web'
export type CrmSurveyQuestionType =
  | 'nps'
  | 'csat_1_5'
  | 'csat_1_7'
  | 'ces_1_7'
  | 'rating_stars'
  | 'short_text'
  | 'long_text'
  | 'single'
  | 'multi'
  | 'yesno'
  | 'emoji_reaction'
  | 'matrix'

export interface CrmSurvey {
  id: number
  workspace_id: number
  public_id: string
  title: string
  slug: string
  description: string | null
  survey_type: CrmSurveyType
  intro_html: string | null
  thankyou_html: string | null
  redirect_url: string | null
  primary_color_override: string | null
  logo_url: string | null
  status: CrmSurveyStatus
  created_by_user_id: number | null
  created_at: number
  updated_at: number
}

export interface CrmSurveyQuestion {
  id: number
  survey_id: number
  sort_order: number
  question_type: CrmSurveyQuestionType
  prompt: string
  help_text: string | null
  required: number
  config_json: string
  branching_json: string
}

