function getOrCreateDirectEmailCampaign(workspaceId: number): EmailCampaignRecord {
  const existing = getDb().prepare(`
    SELECT id
    FROM email_campaigns
    WHERE workspace_id = ? AND name = ?
    ORDER BY id ASC
    LIMIT 1
  `).get(workspaceId, 'Direct sends') as { id: number } | undefined

  if (existing) {
    return getEmailCampaignById(existing.id, workspaceId) as EmailCampaignRecord
  }

  return createEmailCampaign({
    workspaceId,
    name: 'Direct sends',
    status: 'active',
  })
}

export function createDirectEmailSend(data: {
  workspaceId: number
  contactId: number
  subject: string
  bodyHtml: string
  accountId?: number | null
  messageId?: string | null
  threadId?: string | null
  sentAt?: number
}): (EmailSend & { subject: string }) | null {
  const contact = getCrmContactById(data.contactId, data.workspaceId)
  if (!contact) return null

  const campaign = getOrCreateDirectEmailCampaign(data.workspaceId)
  addCampaignContacts(campaign.id, [contact.id])

  const step = createCampaignStep({
    campaign_id: campaign.id,
    subject: data.subject,
    body_html: data.bodyHtml,
    delay_days: 0,
    delay_hours: 0,
  })

  const sentAt = data.sentAt ?? Math.floor(Date.now() / 1000)
  const created = createEmailSend({
    contact_id: contact.id,
    campaign_id: campaign.id,
    step_id: step.id,
    account_id: data.accountId ?? null,
    status: 'sent',
    scheduled_for: sentAt,
    message_id: data.messageId ?? null,
    thread_id: data.threadId ?? null,
  })

  const updated = updateEmailSend(created.id, {
    account_id: data.accountId ?? null,
    status: 'sent',
    sent_at: sentAt,
    message_id: data.messageId ?? null,
    thread_id: data.threadId ?? null,
  })

  if (!updated) return null
  return { ...updated, subject: step.subject }
}

