export function addContactsToCampaign(campaignId: number, workspaceId: number, contactIds: number[]): number {
  if (!getEmailCampaignById(campaignId, workspaceId)) return 0
  const allowed = contactIds.filter((id) => Boolean(getCrmContactById(id, workspaceId)))
  const before = getCampaignContacts(campaignId).length
  addCampaignContacts(campaignId, allowed)
  return getCampaignContacts(campaignId).length - before
}

export function enqueueContactsForCampaign(campaignId: number, workspaceId: number, contactIds: number[]): { added: number; queued: number; skipped: number } {
  const campaign = getEmailCampaignById(campaignId, workspaceId)
  if (!campaign) return { added: 0, queued: 0, skipped: contactIds.length }
  const firstStep = getCampaignSteps(campaignId)[0]
  if (!firstStep) return { added: 0, queued: 0, skipped: contactIds.length }
  const allowed = Array.from(new Set(contactIds))
    .map((id) => getCrmContactById(id, workspaceId))
    .filter((contact): contact is CrmContactRecord => Boolean(contact))
  if (!allowed.length) return { added: 0, queued: 0, skipped: contactIds.length }

  const existingPairs = new Set(
    (getDb().prepare('SELECT contact_id, step_id FROM email_sends WHERE campaign_id = ?').all(campaignId) as Array<{ contact_id: number; step_id: number }>)
      .map((row) => `${row.contact_id}:${row.step_id}`)
  )
  const added = addContactsToCampaign(campaignId, workspaceId, allowed.map((contact) => contact.id))
  let queued = 0
  for (const contact of allowed) {
    const key = `${contact.id}:${firstStep.id}`
    if (existingPairs.has(key)) continue
    createEmailSend({
      contact_id: contact.id,
      campaign_id: campaignId,
      step_id: firstStep.id,
      account_id: null,
      status: 'queued',
      scheduled_for: 0,
      subject_variant: resolveCampaignSubjectVariant(campaign, contact.id, firstStep.position),
    })
    queued += 1
  }
  return { added, queued, skipped: Math.max(contactIds.length - allowed.length, 0) }
}

