export function queueCampaignLaunch(campaignId: number, workspaceId: number): { queued: number; skipped: number } {
  if (!getEmailCampaignById(campaignId, workspaceId)) return { queued: 0, skipped: 0 }
  const before = (getDb().prepare('SELECT COUNT(*) as count FROM email_sends WHERE campaign_id = ?').get(campaignId) as { count: number }).count
  const created = queueCampaignSends(campaignId)
  updateCampaign(campaignId, { status: 'active', send_status: 'sent' })
  const after = (getDb().prepare('SELECT COUNT(*) as count FROM email_sends WHERE campaign_id = ?').get(campaignId) as { count: number }).count
  return { queued: created.length, skipped: Math.max(after - before - created.length, 0) }
}

/**
 * Tick hook: find any campaigns whose user-chosen `scheduled_at` has arrived,
 * fan out their sends via the existing pipeline (queueCampaignSends → email
 * queue worker), and flip send_status draft→scheduled→sending→sent.
 *
 * Called from the crm workflow runner on its 20s cadence alongside the other
 * processDue* workers. Keeps its own try/catch so a single bad row doesn't
 * poison the tick.
 */
export function processDueScheduledCampaigns(nowEpoch: number): { sent: number } {
  const nowIso = new Date(nowEpoch * 1000).toISOString()
  const rows = getDb().prepare(`
    SELECT id, workspace_id, name FROM email_campaigns
    WHERE send_status = 'scheduled' AND scheduled_at IS NOT NULL AND scheduled_at <= ?
    ORDER BY scheduled_at ASC, id ASC
  `).all(nowIso) as Array<{ id: number; workspace_id: number; name: string }>

  let sent = 0
  for (const row of rows) {
    try {
      // Flip to 'sending' so concurrent ticks skip it
      updateCampaign(row.id, { send_status: 'sending' })
      // Fan-out via existing pipeline
      queueCampaignSends(row.id)
      // Mark campaign itself as active so the sequence worker picks up subsequent steps
      updateCampaign(row.id, { status: 'active', send_status: 'sent' })
      sent += 1
    } catch {
      // Leave it in 'sending' — next tick won't retry (guarded by send_status filter);
      // manual intervention required to reset.
    }
  }
  return { sent }
}

export function getEmailInboxMessageById(id: number, workspaceId: number): EmailInboxMessage | null {
  const message = getInboxMessage(id)
  if (!message) return null
  const account = getEmailAccount(message.account_id, { includeSecrets: true })
  return account?.workspace_id === workspaceId ? message : null
}

export function getUnifiedInboxThreads(workspaceId: number, opts?: { unreadOnly?: boolean; direction?: 'inbound' | 'outbound' }): EmailInboxThread[] {
  const filter = opts?.unreadOnly ? 'unread' : opts?.direction === 'outbound' ? 'sent' : 'all'
  return getInboxThreads(workspaceId, filter).map((thread) => {
    const latest = getInboxMessages(workspaceId, thread.thread_id).at(-1) || null
    const contact = thread.contact_id ? getContact(thread.contact_id) : null
    return {
      ...thread,
      latest_message_id: latest?.id || 0,
      contact_name: contact?.name || null,
    }
  })
}

export function getInboxThreadMessages(workspaceId: number, threadId: string): Array<EmailInboxMessage & { contact_name: string | null }> {
  return getInboxMessages(workspaceId, threadId).map((message) => ({
    ...message,
    contact_name: message.contact_id ? getContact(message.contact_id)?.name || null : null,
  }))
}

export function createEmailInboxEntry(data: Parameters<typeof createInboxMessage>[0]): EmailInboxMessage {
  const message = createInboxMessage(data)
  if (message.direction === 'inbound' && message.contact_id) {
    const account = getEmailAccount(message.account_id, { includeSecrets: false })
    if (account) {
      queueCrmWorkflowRunsForTrigger({
        workspaceId: account.workspace_id,
        contactId: message.contact_id,
        triggerType: 'inbound_email',
      })
    }
  }
  return message
}

export function markEmailInboxRead(id: number, workspaceId: number): EmailInboxMessage | null {
  const message = getEmailInboxMessageById(id, workspaceId)
  return message ? markInboxMessageRead(id) : null
}

export function getEmailSendByThreadId(threadId: string): EmailSend | null {
  return getDb().prepare('SELECT * FROM email_sends WHERE thread_id = ? ORDER BY sent_at DESC, id DESC LIMIT 1').get(threadId) as EmailSend | null
}

export function resolveEmailSendFromReplyIdentifiers(identifiers: string[]): EmailSend | null {
  for (const identifier of identifiers) {
    const byMessageId = getEmailSendByMessageId(identifier)
    if (byMessageId) return byMessageId
    const byThreadId = getEmailSendByThreadId(identifier)
    if (byThreadId) return byThreadId
  }
  return null
}

