export interface CrmSmsMessage {
  id: number
  contact_id: number
  direction: 'inbound' | 'outbound'
  body: string
  from_phone: string | null
  to_phone: string | null
  sent_at: number
  is_read: number
  twilio_sid: string | null
}

export function getSmsMessages(contactId: number): CrmSmsMessage[] {
  return getDb().prepare('SELECT * FROM crm_sms_messages WHERE contact_id = ? ORDER BY sent_at ASC').all(contactId) as CrmSmsMessage[]
}

export function getSmsMessageByTwilioSid(twilioSid: string): CrmSmsMessage | null {
  const sid = String(twilioSid || '').trim()
  if (!sid) return null
  return getDb().prepare('SELECT * FROM crm_sms_messages WHERE twilio_sid = ? ORDER BY id DESC LIMIT 1').get(sid) as CrmSmsMessage | null
}

export function createSmsMessage(data: { contact_id: number; direction: 'inbound' | 'outbound'; body: string; from_phone?: string; to_phone?: string; twilio_sid?: string }): CrmSmsMessage {
  const d = getDb()
  const result = d.prepare(
    'INSERT INTO crm_sms_messages (contact_id, direction, body, from_phone, to_phone, twilio_sid) VALUES (?, ?, ?, ?, ?, ?)'
  ).run(data.contact_id, data.direction, data.body, data.from_phone || null, data.to_phone || null, data.twilio_sid || null)
  const message = d.prepare('SELECT * FROM crm_sms_messages WHERE id = ?').get(result.lastInsertRowid) as CrmSmsMessage
  if (message.direction === 'inbound') {
    const contact = getContact(message.contact_id)
    if (contact) {
      queueCrmWorkflowRunsForTrigger({
        workspaceId: contact.workspace_id,
        contactId: contact.id,
        triggerType: 'inbound_sms',
      })
    }
  }
  return message
}

export function markSmsMessagesRead(contactId: number): void {
  getDb().prepare("UPDATE crm_sms_messages SET is_read = 1 WHERE contact_id = ? AND direction = 'inbound' AND is_read = 0").run(contactId)
}

export interface CrmConversationThread {
  contact_id: number
  contact_name: string
  contact_email: string | null
  contact_phone: string | null
  latest_at: number
  unread_count: number
  latest_body: string | null
  latest_direction: string | null
  channels: string
  /** Current assignee — the contact's owner_id. Null = unassigned. */
  assigned_user_id: number | null
  assigned_user_name: string | null
}

export interface CrmPushSubscription {
  id: number
  workspace_id: number
  user_id: number
  endpoint: string
  p256dh: string
  auth: string
  ua: string | null
  created_at: string
  updated_at: string
}

export function getConversationThreads(workspaceId: number): CrmConversationThread[] {
  const d = getDb()
  // Email threads
  const emailRows = d.prepare(`
    SELECT c.id as contact_id, c.name as contact_name, c.email as contact_email, c.phone as contact_phone,
           MAX(e.received_at) as latest_at,
           SUM(CASE WHEN e.is_read = 0 AND e.direction = 'inbound' THEN 1 ELSE 0 END) as unread_count,
           'email' as channel
    FROM crm_contacts c
    JOIN email_inboxes e ON e.contact_id = c.id
    WHERE c.workspace_id = ?
    GROUP BY c.id
  `).all(workspaceId) as Array<{ contact_id: number; contact_name: string; contact_email: string | null; contact_phone: string | null; latest_at: number; unread_count: number; channel: string }>

  // SMS threads
  const smsRows = d.prepare(`
    SELECT c.id as contact_id, c.name as contact_name, c.email as contact_email, c.phone as contact_phone,
           MAX(s.sent_at) as latest_at,
           SUM(CASE WHEN s.is_read = 0 AND s.direction = 'inbound' THEN 1 ELSE 0 END) as unread_count,
           'sms' as channel
    FROM crm_contacts c
    JOIN crm_sms_messages s ON s.contact_id = c.id
    WHERE c.workspace_id = ?
    GROUP BY c.id
  `).all(workspaceId) as Array<{ contact_id: number; contact_name: string; contact_email: string | null; contact_phone: string | null; latest_at: number; unread_count: number; channel: string }>

  // Webchat threads
  const chatRows = d.prepare(`
    SELECT c.id as contact_id, c.name as contact_name, c.email as contact_email, c.phone as contact_phone,
           MAX(m.sent_at) as latest_at,
           SUM(CASE WHEN m.is_read = 0 AND m.direction = 'inbound' THEN 1 ELSE 0 END) as unread_count,
           'chat' as channel
    FROM crm_contacts c
    JOIN crm_chat_messages m ON m.contact_id = c.id
    WHERE c.workspace_id = ?
    GROUP BY c.id
  `).all(workspaceId) as Array<{ contact_id: number; contact_name: string; contact_email: string | null; contact_phone: string | null; latest_at: number; unread_count: number; channel: string }>

  // WhatsApp threads
  const whatsappRows = d.prepare(`
    SELECT c.id as contact_id, c.name as contact_name, c.email as contact_email, c.phone as contact_phone,
           MAX(w.sent_at) as latest_at,
           SUM(CASE WHEN w.read_at IS NULL AND w.direction = 'inbound' THEN 1 ELSE 0 END) as unread_count,
           'whatsapp' as channel
    FROM crm_contacts c
    JOIN crm_whatsapp_messages w ON w.contact_id = c.id
    WHERE c.workspace_id = ?
    GROUP BY c.id
  `).all(workspaceId) as Array<{ contact_id: number; contact_name: string; contact_email: string | null; contact_phone: string | null; latest_at: number; unread_count: number; channel: string }>

  // Instagram threads
  const instagramRows = d.prepare(`
    SELECT c.id as contact_id, c.name as contact_name, c.email as contact_email, c.phone as contact_phone,
           MAX(i.sent_at) as latest_at,
           SUM(CASE WHEN i.read_at IS NULL AND i.direction = 'inbound' THEN 1 ELSE 0 END) as unread_count,
           'instagram' as channel
    FROM crm_contacts c
    JOIN crm_instagram_messages i ON i.contact_id = c.id
    WHERE c.workspace_id = ?
    GROUP BY c.id
  `).all(workspaceId) as Array<{ contact_id: number; contact_name: string; contact_email: string | null; contact_phone: string | null; latest_at: number; unread_count: number; channel: string }>

  // Merge by contact_id
  const map = new Map<number, CrmConversationThread>()
  for (const row of [...emailRows, ...smsRows, ...chatRows, ...whatsappRows, ...instagramRows]) {
    const existing = map.get(row.contact_id)
    if (!existing) {
      map.set(row.contact_id, {
        contact_id: row.contact_id,
        contact_name: row.contact_name,
        contact_email: row.contact_email,
        contact_phone: row.contact_phone,
        latest_at: row.latest_at,
        unread_count: row.unread_count,
        latest_body: null,
        latest_direction: null,
        channels: row.channel,
        assigned_user_id: null,
        assigned_user_name: null,
      })
    } else {
      existing.unread_count += row.unread_count
      existing.channels = Array.from(new Set([...existing.channels.split(','), row.channel])).join(',')
      if (row.latest_at > existing.latest_at) existing.latest_at = row.latest_at
    }
  }

  // Batch-resolve owner metadata once so the left rail renders assignees
  // without per-thread lookups.
  const contactIds = Array.from(map.keys())
  const archivedAtByContact = new Map<number, number | null>()
  if (contactIds.length > 0) {
    const placeholders = contactIds.map(() => '?').join(',')
    const ownerRows = d.prepare(`
      SELECT c.id AS contact_id, c.owner_id, u.name AS owner_name, c.inbox_archived_at
      FROM crm_contacts c
      LEFT JOIN users u ON u.id = c.owner_id
      WHERE c.id IN (${placeholders})
    `).all(...contactIds) as Array<{ contact_id: number; owner_id: number | null; owner_name: string | null; inbox_archived_at: number | null }>
    for (const row of ownerRows) {
      const thread = map.get(row.contact_id)
      if (!thread) continue
      thread.assigned_user_id = row.owner_id
      thread.assigned_user_name = row.owner_name
      archivedAtByContact.set(row.contact_id, row.inbox_archived_at)
    }
  }

  // Get latest message body for preview — picks whichever channel had the most recent message
  const threads = Array.from(map.values()).sort((a, b) => b.latest_at - a.latest_at)
  for (const thread of threads) {
    const latestEmail = d.prepare(`SELECT body_html, direction FROM email_inboxes WHERE contact_id = ? ORDER BY received_at DESC LIMIT 1`).get(thread.contact_id) as { body_html: string | null; direction: string } | undefined
    const latestSms = d.prepare(`SELECT body, direction FROM crm_sms_messages WHERE contact_id = ? ORDER BY sent_at DESC LIMIT 1`).get(thread.contact_id) as { body: string; direction: string } | undefined
    const latestChat = d.prepare(`SELECT body, direction FROM crm_chat_messages WHERE contact_id = ? ORDER BY sent_at DESC LIMIT 1`).get(thread.contact_id) as { body: string; direction: string } | undefined
    const latestWhatsApp = d.prepare(`SELECT body, direction FROM crm_whatsapp_messages WHERE contact_id = ? ORDER BY sent_at DESC LIMIT 1`).get(thread.contact_id) as { body: string; direction: string } | undefined
    const latestInstagram = d.prepare(`SELECT body, direction FROM crm_instagram_messages WHERE contact_id = ? ORDER BY sent_at DESC LIMIT 1`).get(thread.contact_id) as { body: string; direction: string } | undefined
    const emailAt = (d.prepare(`SELECT MAX(received_at) as t FROM email_inboxes WHERE contact_id = ?`).get(thread.contact_id) as { t: number | null })?.t || 0
    const smsAt = (d.prepare(`SELECT MAX(sent_at) as t FROM crm_sms_messages WHERE contact_id = ?`).get(thread.contact_id) as { t: number | null })?.t || 0
    const chatAt = (d.prepare(`SELECT MAX(sent_at) as t FROM crm_chat_messages WHERE contact_id = ?`).get(thread.contact_id) as { t: number | null })?.t || 0
    const whatsappAt = (d.prepare(`SELECT MAX(sent_at) as t FROM crm_whatsapp_messages WHERE contact_id = ?`).get(thread.contact_id) as { t: number | null })?.t || 0
    const instagramAt = (d.prepare(`SELECT MAX(sent_at) as t FROM crm_instagram_messages WHERE contact_id = ?`).get(thread.contact_id) as { t: number | null })?.t || 0
    const maxAt = Math.max(emailAt, smsAt, chatAt, whatsappAt, instagramAt)
    if (maxAt === instagramAt && latestInstagram) {
      thread.latest_body = latestInstagram.body.slice(0, 100)
      thread.latest_direction = latestInstagram.direction
    } else if (maxAt === whatsappAt && latestWhatsApp) {
      thread.latest_body = latestWhatsApp.body.slice(0, 100)
      thread.latest_direction = latestWhatsApp.direction
    } else if (maxAt === chatAt && latestChat) {
      thread.latest_body = latestChat.body.slice(0, 100)
      thread.latest_direction = latestChat.direction
    } else if (maxAt === emailAt && latestEmail) {
      thread.latest_body = (latestEmail.body_html || '').replace(/<[^>]+>/g, '').trim().slice(0, 100)
      thread.latest_direction = latestEmail.direction
    } else if (latestSms) {
      thread.latest_body = latestSms.body.slice(0, 100)
      thread.latest_direction = latestSms.direction
    }
  }

  return threads.filter((thread) => {
    const archivedAt = archivedAtByContact.get(thread.contact_id)
    return !archivedAt || thread.latest_at > archivedAt
  })
}

export function listCrmPushSubscriptions(workspaceId: number, userId?: number): CrmPushSubscription[] {
  const args: Array<number> = [workspaceId]
  let sql = 'SELECT * FROM crm_push_subscriptions WHERE workspace_id = ?'
  if (typeof userId === 'number') {
    sql += ' AND user_id = ?'
    args.push(userId)
  }
  sql += ' ORDER BY updated_at DESC, id DESC'
  return getDb().prepare(sql).all(...args) as CrmPushSubscription[]
}

export function upsertCrmPushSubscription(data: {
  workspaceId: number
  userId: number
  endpoint: string
  p256dh: string
  auth: string
  ua?: string | null
}): CrmPushSubscription {
  const d = getDb()
  d.prepare(`
    INSERT INTO crm_push_subscriptions (workspace_id, user_id, endpoint, p256dh, auth, ua)
    VALUES (?, ?, ?, ?, ?, ?)
    ON CONFLICT(workspace_id, user_id, endpoint) DO UPDATE SET
      p256dh = excluded.p256dh,
      auth = excluded.auth,
      ua = excluded.ua,
      updated_at = (strftime('%Y-%m-%dT%H:%M:%fZ', 'now'))
  `).run(data.workspaceId, data.userId, data.endpoint, data.p256dh, data.auth, data.ua ?? null)

  return d.prepare(`
    SELECT * FROM crm_push_subscriptions
    WHERE workspace_id = ? AND user_id = ? AND endpoint = ?
    LIMIT 1
  `).get(data.workspaceId, data.userId, data.endpoint) as CrmPushSubscription
}

export function deleteCrmPushSubscription(workspaceId: number, userId: number, endpoint: string): boolean {
  const result = getDb().prepare(`
    DELETE FROM crm_push_subscriptions
    WHERE workspace_id = ? AND user_id = ? AND endpoint = ?
  `).run(workspaceId, userId, endpoint)
  return result.changes > 0
}

// ─── Tickets ─────────────────────────────────────────────────────────────────

export type CrmTicketStatus = 'open' | 'pending' | 'on_hold' | 'solved' | 'closed'
export type CrmTicketPriority = 'low' | 'normal' | 'high' | 'urgent'
export type CrmTicketChannel = 'email' | 'web' | 'manual' | 'chat'
export type CrmTicketMessageDirection = 'inbound' | 'outbound' | 'internal_note'
export type CrmTicketSlaPhase = 'first_response' | 'resolve' | 'none'
export type CrmTicketSlaState = 'none' | 'active' | 'overdue' | 'completed'

const CRM_TICKET_STATUS_VALUES: CrmTicketStatus[] = ['open', 'pending', 'on_hold', 'solved', 'closed']
const CRM_TICKET_PRIORITY_VALUES: CrmTicketPriority[] = ['low', 'normal', 'high', 'urgent']
const CRM_TICKET_CHANNEL_VALUES: CrmTicketChannel[] = ['email', 'web', 'manual', 'chat']
const CRM_TICKET_PRIORITY_ORDER: CrmTicketPriority[] = ['urgent', 'high', 'normal', 'low']

export interface CrmTicket {
  id: number
  workspace_id: number
  contact_id: number | null
  subject: string
  body: string
  status: CrmTicketStatus
  priority: CrmTicketPriority
  assignee_user_id: number | null
  channel: CrmTicketChannel
  source_message_id: string | null
  ticket_number: number
  solved_at: string | null
  sla_due_at: string | null
  first_response_at: string | null
  sla_phase: CrmTicketSlaPhase
  sla_breached_at: string | null
  created_at: string
  updated_at: string
}

export interface CrmTicketMessage {
  id: number
  workspace_id: number
  ticket_id: number
  user_id: number | null
  contact_id: number | null
  direction: CrmTicketMessageDirection
  body: string
  body_html: string | null
  created_at: string
  updated_at: string
}

export interface CrmTicketMessageRecord extends CrmTicketMessage {
  user_name: string | null
  contact_name: string | null
}

export interface CrmTicketCannedReply {
  id: number
  workspace_id: number
  title: string
  body: string
  created_at: string
  updated_at: string
}

export interface CrmTicketSlaPolicy {
  id: number
  workspace_id: number
  priority: CrmTicketPriority
  first_response_mins: number | null
  resolve_mins: number | null
  created_at: string
  updated_at: string
}

export interface CrmTicketWatcherRecord {
  user_id: number
  name: string
  email: string
}

export interface CrmTicketRecord extends CrmTicket {
  contact_name: string | null
  contact_email: string | null
  contact_phone: string | null
  assignee_name: string | null
  assignee_email: string | null
  tags_list: string[]
  message_count: number
  last_message_at: string | null
  sla_state: CrmTicketSlaState
}

export interface CrmTicketStats {
  open: number
  unassigned: number
  overdue: number
  solved_today: number
}

export interface CrmTicketSettings {
  support_email: string | null
  sla_policies: CrmTicketSlaPolicy[]
  canned_replies: CrmTicketCannedReply[]
}

export interface CrmTicketListFilters {
  status?: CrmTicketStatus
  priority?: CrmTicketPriority
  assigneeUserId?: number | null
  tag?: string | null
  search?: string | null
}

interface RawCrmTicketRow extends CrmTicket {
  contact_name: string | null
  contact_email: string | null
  contact_phone: string | null
  assignee_name: string | null
  assignee_email: string | null
  tags_blob: string | null
  message_count: number
  last_message_at: string | null
}

const CRM_TICKET_SELECT = `
  SELECT t.*,
         c.name AS contact_name,
         c.email AS contact_email,
         c.phone AS contact_phone,
         u.name AS assignee_name,
         u.email AS assignee_email,
         (
           SELECT GROUP_CONCAT(tag, '\n')
           FROM (
             SELECT tag FROM crm_ticket_tags tt
             WHERE tt.ticket_id = t.id
             ORDER BY LOWER(tag), tag
           )
         ) AS tags_blob,
         COALESCE((SELECT COUNT(*) FROM crm_ticket_messages tm WHERE tm.ticket_id = t.id), 0) AS message_count,
         (SELECT MAX(tm.created_at) FROM crm_ticket_messages tm WHERE tm.ticket_id = t.id) AS last_message_at
  FROM crm_tickets t
  LEFT JOIN crm_contacts c ON c.id = t.contact_id
  LEFT JOIN users u ON u.id = t.assignee_user_id
`

function crmTicketNowIso(): string {
  return new Date().toISOString()
}

function isClosedCrmTicketStatus(status: CrmTicketStatus): boolean {
  return status === 'solved' || status === 'closed'
}

function normalizeCrmTicketStatus(value: unknown, fallback: CrmTicketStatus = 'open'): CrmTicketStatus {
  return typeof value === 'string' && (CRM_TICKET_STATUS_VALUES as string[]).includes(value)
    ? (value as CrmTicketStatus)
    : fallback
}

function normalizeCrmTicketPriority(value: unknown, fallback: CrmTicketPriority = 'normal'): CrmTicketPriority {
  return typeof value === 'string' && (CRM_TICKET_PRIORITY_VALUES as string[]).includes(value)
    ? (value as CrmTicketPriority)
    : fallback
}

function normalizeCrmTicketChannel(value: unknown, fallback: CrmTicketChannel = 'manual'): CrmTicketChannel {
  return typeof value === 'string' && (CRM_TICKET_CHANNEL_VALUES as string[]).includes(value)
    ? (value as CrmTicketChannel)
    : fallback
}

function normalizeCrmTicketTag(tag: string): string {
  return tag.trim().toLowerCase()
}

function uniqueCrmTicketTags(tags: string[]): string[] {
  const seen = new Set<string>()
  const out: string[] = []
  for (const raw of tags) {
    const tag = normalizeCrmTicketTag(raw)
    if (!tag || seen.has(tag)) continue
    seen.add(tag)
    out.push(tag)
  }
  return out
}

function normalizeCrmTicketMinutes(value: number | null | undefined): number | null {
  if (!Number.isFinite(value ?? null)) return null
  const next = Math.max(0, Math.floor(Number(value)))
  return next > 0 ? next : null
}

function addMinutesToIso(iso: string, minutes: number): string | null {
  const baseMs = Date.parse(iso)
  if (!Number.isFinite(baseMs)) return null
  return new Date(baseMs + minutes * 60_000).toISOString()
}

function computeCrmTicketSlaState(ticket: Pick<CrmTicket, 'status' | 'sla_due_at' | 'sla_phase'>): CrmTicketSlaState {
  if (isClosedCrmTicketStatus(ticket.status)) return 'completed'
  if (!ticket.sla_due_at || ticket.sla_phase === 'none') return 'none'
  return ticket.sla_due_at <= crmTicketNowIso() ? 'overdue' : 'active'
}

function splitTicketBlob(value: string | null | undefined): string[] {
  if (!value) return []
  return value.split('\n').map((item) => item.trim()).filter(Boolean)
}

function enrichCrmTicketRow(row: RawCrmTicketRow): CrmTicketRecord {
  return {
    ...row,
    tags_list: splitTicketBlob(row.tags_blob),
    sla_state: computeCrmTicketSlaState(row),
  }
}

function getCrmTicketSlaPolicyByPriority(workspaceId: number, priority: CrmTicketPriority): CrmTicketSlaPolicy | null {
  return getDb().prepare(
    'SELECT * FROM crm_ticket_sla_policies WHERE workspace_id = ? AND priority = ? LIMIT 1'
  ).get(workspaceId, priority) as CrmTicketSlaPolicy | null
}

function computeCrmTicketSlaFields(
  workspaceId: number,
  priority: CrmTicketPriority,
  createdAt: string,
  firstResponseAt: string | null,
  status: CrmTicketStatus,
): { phase: CrmTicketSlaPhase; dueAt: string | null } {
  if (isClosedCrmTicketStatus(status)) return { phase: 'none', dueAt: null }
  const policy = getCrmTicketSlaPolicyByPriority(workspaceId, priority)
  if (!policy) return { phase: 'none', dueAt: null }
  const firstResponseMins = normalizeCrmTicketMinutes(policy.first_response_mins)
  const resolveMins = normalizeCrmTicketMinutes(policy.resolve_mins)
  if (!firstResponseAt && firstResponseMins) {
    return { phase: 'first_response', dueAt: addMinutesToIso(createdAt, firstResponseMins) }
  }
  if (resolveMins) {
    return { phase: 'resolve', dueAt: addMinutesToIso(createdAt, resolveMins) }
  }
  return { phase: 'none', dueAt: null }
}

export function getCrmTicketTags(ticketId: number, workspaceId: number): string[] {
  const ticket = getDb().prepare('SELECT id FROM crm_tickets WHERE id = ? AND workspace_id = ?').get(ticketId, workspaceId) as { id: number } | undefined
  if (!ticket) return []
  const rows = getDb().prepare(
    'SELECT tag FROM crm_ticket_tags WHERE ticket_id = ? ORDER BY LOWER(tag), tag'
  ).all(ticketId) as Array<{ tag: string }>
  return rows.map((row) => row.tag)
}

export function listCrmTicketTags(workspaceId: number): string[] {
  const rows = getDb().prepare(
    'SELECT DISTINCT tag FROM crm_ticket_tags WHERE workspace_id = ? ORDER BY LOWER(tag), tag'
  ).all(workspaceId) as Array<{ tag: string }>
  return rows.map((row) => row.tag)
}

export function listCrmTickets(workspaceId: number, filters: CrmTicketListFilters = {}): CrmTicketRecord[] {
  const clauses: string[] = ['t.workspace_id = ?']
  const args: Array<string | number> = [workspaceId]
  if (filters.status) {
    clauses.push('t.status = ?')
    args.push(filters.status)
  }
  if (filters.priority) {
    clauses.push('t.priority = ?')
    args.push(filters.priority)
  }
  if (filters.assigneeUserId === null) {
    clauses.push('t.assignee_user_id IS NULL')
  } else if (typeof filters.assigneeUserId === 'number' && filters.assigneeUserId > 0) {
    clauses.push('t.assignee_user_id = ?')
    args.push(filters.assigneeUserId)
  }
  if (filters.tag) {
    clauses.push('EXISTS (SELECT 1 FROM crm_ticket_tags tt WHERE tt.ticket_id = t.id AND tt.tag = ?)')
    args.push(normalizeCrmTicketTag(filters.tag))
  }
  const search = typeof filters.search === 'string' ? filters.search.trim() : ''
  if (search) {
    const like = `%${escapeLike(search)}%`
    clauses.push(`(
      t.subject LIKE ? ESCAPE '\\'
      OR t.body LIKE ? ESCAPE '\\'
      OR COALESCE(c.name, '') LIKE ? ESCAPE '\\'
      OR COALESCE(c.email, '') LIKE ? ESCAPE '\\'
    )`)
    args.push(like, like, like, like)
  }
  const sql = `${CRM_TICKET_SELECT}
    WHERE ${clauses.join(' AND ')}
    ORDER BY
      CASE WHEN t.status IN ('solved','closed') THEN 1 ELSE 0 END ASC,
      CASE WHEN t.status NOT IN ('solved','closed') AND t.sla_due_at IS NOT NULL AND t.sla_due_at <= ? THEN 0 ELSE 1 END ASC,
      CASE t.priority
        WHEN 'urgent' THEN 0
        WHEN 'high' THEN 1
        WHEN 'normal' THEN 2
        ELSE 3
      END ASC,
      t.updated_at DESC,
      t.id DESC`
  args.push(crmTicketNowIso())
  const rows = getDb().prepare(sql).all(...args) as RawCrmTicketRow[]
  return rows.map(enrichCrmTicketRow)
}

export function getCrmTicketById(id: number, workspaceId: number): CrmTicketRecord | null {
  const row = getDb().prepare(`${CRM_TICKET_SELECT}
    WHERE t.id = ? AND t.workspace_id = ?
    LIMIT 1`).get(id, workspaceId) as RawCrmTicketRow | undefined
  return row ? enrichCrmTicketRow(row) : null
}

export function getCrmTicketBySourceMessageId(workspaceId: number, sourceMessageId: string): CrmTicketRecord | null {
  const source = String(sourceMessageId || '').trim()
  if (!source) return null
  const row = getDb().prepare(`${CRM_TICKET_SELECT}
    WHERE t.workspace_id = ? AND t.source_message_id = ?
    LIMIT 1`).get(workspaceId, source) as RawCrmTicketRow | undefined
  return row ? enrichCrmTicketRow(row) : null
}

export function getLatestCrmTicketForContact(contactId: number, workspaceId: number, opts?: { excludeClosed?: boolean }): CrmTicketRecord | null {
  const clauses = ['t.workspace_id = ?', 't.contact_id = ?']
  const args: Array<string | number> = [workspaceId, contactId]
  if (opts?.excludeClosed) clauses.push(`t.status NOT IN ('solved','closed')`)
  const row = getDb().prepare(`${CRM_TICKET_SELECT}
    WHERE ${clauses.join(' AND ')}
    ORDER BY t.updated_at DESC, t.id DESC
    LIMIT 1`).get(...args) as RawCrmTicketRow | undefined
  return row ? enrichCrmTicketRow(row) : null
}

export function getCrmTicketMessages(ticketId: number, workspaceId: number): CrmTicketMessageRecord[] {
  const ticket = getDb().prepare('SELECT id FROM crm_tickets WHERE id = ? AND workspace_id = ?').get(ticketId, workspaceId) as { id: number } | undefined
  if (!ticket) return []
  return getDb().prepare(`
    SELECT tm.*, u.name AS user_name, c.name AS contact_name
    FROM crm_ticket_messages tm
    LEFT JOIN users u ON u.id = tm.user_id
    LEFT JOIN crm_contacts c ON c.id = tm.contact_id
    WHERE tm.ticket_id = ? AND tm.workspace_id = ?
    ORDER BY tm.created_at ASC, tm.id ASC
  `).all(ticketId, workspaceId) as CrmTicketMessageRecord[]
}

export function getCrmTicketWatchers(ticketId: number, workspaceId: number): CrmTicketWatcherRecord[] {
  const ticket = getDb().prepare('SELECT id FROM crm_tickets WHERE id = ? AND workspace_id = ?').get(ticketId, workspaceId) as { id: number } | undefined
  if (!ticket) return []
  return getDb().prepare(`
    SELECT tw.user_id, u.name, u.email
    FROM crm_ticket_watchers tw
    JOIN users u ON u.id = tw.user_id
    WHERE tw.ticket_id = ? AND tw.workspace_id = ?
    ORDER BY LOWER(u.name), LOWER(u.email), tw.user_id
  `).all(ticketId, workspaceId) as CrmTicketWatcherRecord[]
}

export function ensureCrmTicketWatcher(ticketId: number, workspaceId: number, userId: number): void {
  if (!Number.isInteger(userId) || userId <= 0) return
  getDb().prepare(
    'INSERT OR IGNORE INTO crm_ticket_watchers (workspace_id, ticket_id, user_id) VALUES (?, ?, ?)'
  ).run(workspaceId, ticketId, userId)
}

export function removeCrmTicketWatcher(ticketId: number, workspaceId: number, userId: number): boolean {
  if (!Number.isInteger(userId) || userId <= 0) return false
  return getDb().prepare(
    'DELETE FROM crm_ticket_watchers WHERE ticket_id = ? AND workspace_id = ? AND user_id = ?'
  ).run(ticketId, workspaceId, userId).changes > 0
}

export function replaceCrmTicketTags(ticketId: number, workspaceId: number, tags: string[]): string[] {
  const ticket = getDb().prepare('SELECT id FROM crm_tickets WHERE id = ? AND workspace_id = ?').get(ticketId, workspaceId) as { id: number } | undefined
  if (!ticket) return []
  const normalized = uniqueCrmTicketTags(tags)
  const db = getDb()
  const tx = db.transaction(() => {
    if (normalized.length === 0) {
      db.prepare('DELETE FROM crm_ticket_tags WHERE ticket_id = ? AND workspace_id = ?').run(ticketId, workspaceId)
      return
    }
    const placeholders = normalized.map(() => '?').join(',')
    db.prepare(`DELETE FROM crm_ticket_tags WHERE ticket_id = ? AND workspace_id = ? AND tag NOT IN (${placeholders})`).run(ticketId, workspaceId, ...normalized)
    const stmt = db.prepare('INSERT OR IGNORE INTO crm_ticket_tags (workspace_id, ticket_id, tag) VALUES (?, ?, ?)')
    for (const tag of normalized) stmt.run(workspaceId, ticketId, tag)
  })
  tx()
  return getCrmTicketTags(ticketId, workspaceId)
}

export function addCrmTicketTag(ticketId: number, workspaceId: number, tag: string): string[] {
  return replaceCrmTicketTags(ticketId, workspaceId, [...getCrmTicketTags(ticketId, workspaceId), tag])
}

export function removeCrmTicketTag(ticketId: number, workspaceId: number, tag: string): string[] {
  const target = normalizeCrmTicketTag(tag)
  return replaceCrmTicketTags(ticketId, workspaceId, getCrmTicketTags(ticketId, workspaceId).filter((item) => item !== target))
}

export function getCrmTicketStats(workspaceId: number): CrmTicketStats {
  const db = getDb()
  const nowIso = crmTicketNowIso()
  const today = nowIso.slice(0, 10)
  const open = (db.prepare(`SELECT COUNT(*) AS c FROM crm_tickets WHERE workspace_id = ? AND status NOT IN ('solved','closed')`).get(workspaceId) as { c: number }).c
  const unassigned = (db.prepare(`SELECT COUNT(*) AS c FROM crm_tickets WHERE workspace_id = ? AND status NOT IN ('solved','closed') AND assignee_user_id IS NULL`).get(workspaceId) as { c: number }).c
  const overdue = (db.prepare(`SELECT COUNT(*) AS c FROM crm_tickets WHERE workspace_id = ? AND status NOT IN ('solved','closed') AND sla_due_at IS NOT NULL AND sla_due_at <= ?`).get(workspaceId, nowIso) as { c: number }).c
  const solvedToday = (db.prepare(`SELECT COUNT(*) AS c FROM crm_tickets WHERE workspace_id = ? AND solved_at IS NOT NULL AND substr(solved_at, 1, 10) = ?`).get(workspaceId, today) as { c: number }).c
  return { open, unassigned, overdue, solved_today: solvedToday }
}

export function getCrmTicketSupportEmail(workspaceId: number): string | null {
  const row = getDb().prepare('SELECT support_email FROM workspaces WHERE id = ?').get(workspaceId) as { support_email: string | null } | undefined
  return row?.support_email ?? null
}

export function updateCrmTicketSupportEmail(workspaceId: number, supportEmail: string | null): string | null {
  const value = supportEmail && supportEmail.trim() ? supportEmail.trim().toLowerCase() : null
  getDb().prepare(`UPDATE workspaces SET support_email = ?, updated_at = strftime('%s','now') WHERE id = ?`).run(value, workspaceId)
  return getCrmTicketSupportEmail(workspaceId)
}

export function getCrmTicketCannedReplies(workspaceId: number): CrmTicketCannedReply[] {
  return getDb().prepare(
    'SELECT * FROM crm_ticket_canned_replies WHERE workspace_id = ? ORDER BY LOWER(title), id ASC'
  ).all(workspaceId) as CrmTicketCannedReply[]
}

export function getCrmTicketCannedReplyById(id: number, workspaceId: number): CrmTicketCannedReply | null {
  return getDb().prepare(
    'SELECT * FROM crm_ticket_canned_replies WHERE id = ? AND workspace_id = ? LIMIT 1'
  ).get(id, workspaceId) as CrmTicketCannedReply | null
}

export function createCrmTicketCannedReply(workspaceId: number, data: { title: string; body: string }): CrmTicketCannedReply {
  const nowIso = crmTicketNowIso()
  const result = getDb().prepare(`
    INSERT INTO crm_ticket_canned_replies (workspace_id, title, body, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?)
  `).run(workspaceId, data.title.trim(), data.body, nowIso, nowIso)
  return getDb().prepare('SELECT * FROM crm_ticket_canned_replies WHERE id = ?').get(Number(result.lastInsertRowid)) as CrmTicketCannedReply
}

export function updateCrmTicketCannedReply(id: number, workspaceId: number, data: Partial<{ title: string; body: string }>): CrmTicketCannedReply | null {
  const existing = getCrmTicketCannedReplyById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number> = []
  if (typeof data.title === 'string') { sets.push('title = ?'); params.push(data.title.trim()) }
  if (typeof data.body === 'string') { sets.push('body = ?'); params.push(data.body) }
  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(crmTicketNowIso())
  params.push(id, workspaceId)
  getDb().prepare(`UPDATE crm_ticket_canned_replies SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...params)
  return getCrmTicketCannedReplyById(id, workspaceId)
}

export function deleteCrmTicketCannedReply(id: number, workspaceId: number): boolean {
  return getDb().prepare('DELETE FROM crm_ticket_canned_replies WHERE id = ? AND workspace_id = ?').run(id, workspaceId).changes > 0
}

export function getCrmTicketSlaPolicies(workspaceId: number): CrmTicketSlaPolicy[] {
  return getDb().prepare(`
    SELECT * FROM crm_ticket_sla_policies
    WHERE workspace_id = ?
    ORDER BY CASE priority
      WHEN 'urgent' THEN 0
      WHEN 'high' THEN 1
      WHEN 'normal' THEN 2
      ELSE 3
    END ASC
  `).all(workspaceId) as CrmTicketSlaPolicy[]
}

export function replaceCrmTicketSlaPolicies(
  workspaceId: number,
  policies: Array<{ priority: CrmTicketPriority; first_response_mins?: number | null; resolve_mins?: number | null }>,
): CrmTicketSlaPolicy[] {
  const deduped = new Map<CrmTicketPriority, { priority: CrmTicketPriority; first_response_mins: number | null; resolve_mins: number | null }>()
  for (const priority of CRM_TICKET_PRIORITY_ORDER) {
    const incoming = policies.find((policy) => policy.priority === priority)
    if (!incoming) continue
    deduped.set(priority, {
      priority,
      first_response_mins: normalizeCrmTicketMinutes(incoming.first_response_mins),
      resolve_mins: normalizeCrmTicketMinutes(incoming.resolve_mins),
    })
  }
  const db = getDb()
  const tx = db.transaction(() => {
    db.prepare('DELETE FROM crm_ticket_sla_policies WHERE workspace_id = ?').run(workspaceId)
    const stmt = db.prepare(`
      INSERT INTO crm_ticket_sla_policies (workspace_id, priority, first_response_mins, resolve_mins, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?)
    `)
    for (const row of deduped.values()) {
      const nowIso = crmTicketNowIso()
      stmt.run(workspaceId, row.priority, row.first_response_mins, row.resolve_mins, nowIso, nowIso)
    }
  })
  tx()
  return getCrmTicketSlaPolicies(workspaceId)
}

export function getCrmTicketSettings(workspaceId: number): CrmTicketSettings {
  return {
    support_email: getCrmTicketSupportEmail(workspaceId),
    sla_policies: getCrmTicketSlaPolicies(workspaceId),
    canned_replies: getCrmTicketCannedReplies(workspaceId),
  }
}

function touchCrmTicket(ticketId: number, workspaceId: number, updatedAt: string): void {
  getDb().prepare('UPDATE crm_tickets SET updated_at = ? WHERE id = ? AND workspace_id = ?').run(updatedAt, ticketId, workspaceId)
}

export function createCrmTicket(workspaceId: number, data: {
  contact_id?: number | null
  subject: string
  body?: string | null
  status?: CrmTicketStatus
  priority?: CrmTicketPriority
  assignee_user_id?: number | null
  channel?: CrmTicketChannel
  source_message_id?: string | null
  tags?: string[]
  creator_user_id?: number | null
  created_at?: string
}): CrmTicketRecord {
  const nowIso = data.created_at || crmTicketNowIso()
  const status = normalizeCrmTicketStatus(data.status, 'open')
  const priority = normalizeCrmTicketPriority(data.priority, 'normal')
  const channel = normalizeCrmTicketChannel(data.channel, 'manual')
  const subject = data.subject.trim()
  if (!subject) throw new Error('Ticket subject is required')
  const body = typeof data.body === 'string' ? data.body : ''
  const assigneeUserId = typeof data.assignee_user_id === 'number' && data.assignee_user_id > 0 ? data.assignee_user_id : null
  const contactId = typeof data.contact_id === 'number' && data.contact_id > 0 ? data.contact_id : null
  const sourceMessageId = typeof data.source_message_id === 'string' && data.source_message_id.trim() ? data.source_message_id.trim() : null
  const tags = Array.isArray(data.tags) ? uniqueCrmTicketTags(data.tags) : []
  const sla = computeCrmTicketSlaFields(workspaceId, priority, nowIso, null, status)
  const solvedAt = isClosedCrmTicketStatus(status) ? nowIso : null
  const db = getDb()
  let ticketId = 0
  const tx = db.transaction(() => {
    const nextRow = db.prepare(
      'SELECT COALESCE(MAX(ticket_number), 0) + 1 AS next_number FROM crm_tickets WHERE workspace_id = ?'
    ).get(workspaceId) as { next_number: number }
    const result = db.prepare(`
      INSERT INTO crm_tickets (
        workspace_id, contact_id, subject, body, status, priority, assignee_user_id,
        channel, source_message_id, ticket_number, solved_at, sla_due_at,
        first_response_at, sla_phase, sla_breached_at, created_at, updated_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      workspaceId,
      contactId,
      subject,
      body,
      status,
      priority,
      assigneeUserId,
      channel,
      sourceMessageId,
      nextRow.next_number,
      solvedAt,
      sla.dueAt,
      null,
      sla.phase,
      null,
      nowIso,
      nowIso,
    )
    ticketId = Number(result.lastInsertRowid)
    if (tags.length > 0) {
      const tagStmt = db.prepare('INSERT OR IGNORE INTO crm_ticket_tags (workspace_id, ticket_id, tag) VALUES (?, ?, ?)')
      for (const tag of tags) tagStmt.run(workspaceId, ticketId, tag)
    }
    if (typeof data.creator_user_id === 'number' && data.creator_user_id > 0) {
      ensureCrmTicketWatcher(ticketId, workspaceId, data.creator_user_id)
    }
    if (assigneeUserId) ensureCrmTicketWatcher(ticketId, workspaceId, assigneeUserId)
  })
  tx()
  return getCrmTicketById(ticketId, workspaceId) as CrmTicketRecord
}

export function updateCrmTicket(id: number, workspaceId: number, data: Partial<{
  contact_id: number | null
  subject: string
  body: string | null
  status: CrmTicketStatus
  priority: CrmTicketPriority
  assignee_user_id: number | null
  channel: CrmTicketChannel
  source_message_id: string | null
  first_response_at: string | null
  tags: string[]
}>): CrmTicketRecord | null {
  const existing = getCrmTicketById(id, workspaceId)
  if (!existing) return null

  const nowIso = crmTicketNowIso()
  const nextStatus = data.status !== undefined ? normalizeCrmTicketStatus(data.status, existing.status) : existing.status
  const nextPriority = data.priority !== undefined ? normalizeCrmTicketPriority(data.priority, existing.priority) : existing.priority
  const nextFirstResponseAt = Object.prototype.hasOwnProperty.call(data, 'first_response_at')
    ? (typeof data.first_response_at === 'string' && data.first_response_at.trim() ? data.first_response_at : null)
    : existing.first_response_at

  let nextSolvedAt = existing.solved_at
  if (data.status !== undefined) {
    if (isClosedCrmTicketStatus(nextStatus)) nextSolvedAt = existing.solved_at || nowIso
    else if (isClosedCrmTicketStatus(existing.status) && !isClosedCrmTicketStatus(nextStatus)) nextSolvedAt = null
  }

  let nextSlaBreachedAt = existing.sla_breached_at
  if (data.status !== undefined && isClosedCrmTicketStatus(existing.status) && !isClosedCrmTicketStatus(nextStatus)) {
    nextSlaBreachedAt = null
  }
  const shouldRecomputeSla = data.status !== undefined || data.priority !== undefined || Object.prototype.hasOwnProperty.call(data, 'first_response_at')
  const nextSla = shouldRecomputeSla
    ? computeCrmTicketSlaFields(workspaceId, nextPriority, existing.created_at, nextFirstResponseAt, nextStatus)
    : { phase: existing.sla_phase, dueAt: existing.sla_due_at }

  const sets: string[] = []
  const params: Array<string | number | null> = []
  if (Object.prototype.hasOwnProperty.call(data, 'contact_id')) {
    const value = typeof data.contact_id === 'number' && data.contact_id > 0 ? data.contact_id : null
    sets.push('contact_id = ?')
    params.push(value)
  }
  if (typeof data.subject === 'string') {
    sets.push('subject = ?')
    params.push(data.subject.trim())
  }
  if (Object.prototype.hasOwnProperty.call(data, 'body')) {
    sets.push('body = ?')
    params.push(typeof data.body === 'string' ? data.body : '')
  }
  if (data.status !== undefined) {
    sets.push('status = ?')
    params.push(nextStatus)
    sets.push('solved_at = ?')
    params.push(nextSolvedAt)
    sets.push('sla_breached_at = ?')
    params.push(nextSlaBreachedAt)
  }
  if (data.priority !== undefined) {
    sets.push('priority = ?')
    params.push(nextPriority)
  }
  if (Object.prototype.hasOwnProperty.call(data, 'assignee_user_id')) {
    const value = typeof data.assignee_user_id === 'number' && data.assignee_user_id > 0 ? data.assignee_user_id : null
    sets.push('assignee_user_id = ?')
    params.push(value)
  }
  if (data.channel !== undefined) {
    sets.push('channel = ?')
    params.push(normalizeCrmTicketChannel(data.channel, existing.channel))
  }
  if (Object.prototype.hasOwnProperty.call(data, 'source_message_id')) {
    const value = typeof data.source_message_id === 'string' && data.source_message_id.trim() ? data.source_message_id.trim() : null
    sets.push('source_message_id = ?')
    params.push(value)
  }
  if (Object.prototype.hasOwnProperty.call(data, 'first_response_at')) {
    sets.push('first_response_at = ?')
    params.push(nextFirstResponseAt)
  }
  if (shouldRecomputeSla) {
    sets.push('sla_due_at = ?')
    params.push(nextSla.dueAt)
    sets.push('sla_phase = ?')
    params.push(nextSla.phase)
  }

  const tagPatch = Array.isArray(data.tags) ? uniqueCrmTicketTags(data.tags) : null
  if (!sets.length && !tagPatch) return existing

  if (sets.length) {
    sets.push('updated_at = ?')
    params.push(nowIso)
    params.push(id, workspaceId)
    getDb().prepare(`UPDATE crm_tickets SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...params)
  } else {
    touchCrmTicket(id, workspaceId, nowIso)
  }

  if (tagPatch) replaceCrmTicketTags(id, workspaceId, tagPatch)
  if (Object.prototype.hasOwnProperty.call(data, 'assignee_user_id') && typeof data.assignee_user_id === 'number' && data.assignee_user_id > 0) {
    ensureCrmTicketWatcher(id, workspaceId, data.assignee_user_id)
  }
  return getCrmTicketById(id, workspaceId)
}

export function getCrmTicketMessageById(id: number, workspaceId: number): CrmTicketMessageRecord | null {
  return getDb().prepare(`
    SELECT tm.*, u.name AS user_name, c.name AS contact_name
    FROM crm_ticket_messages tm
    LEFT JOIN users u ON u.id = tm.user_id
    LEFT JOIN crm_contacts c ON c.id = tm.contact_id
    WHERE tm.id = ? AND tm.workspace_id = ?
    LIMIT 1
  `).get(id, workspaceId) as CrmTicketMessageRecord | null
}

export function createCrmTicketMessage(workspaceId: number, data: {
  ticket_id: number
  user_id?: number | null
  contact_id?: number | null
  direction: CrmTicketMessageDirection
  body: string
  body_html?: string | null
  created_at?: string
}): CrmTicketMessageRecord | null {
  const ticket = getCrmTicketById(data.ticket_id, workspaceId)
  if (!ticket) return null
  const direction = data.direction === 'outbound' || data.direction === 'internal_note' ? data.direction : 'inbound'
  const body = data.body.trim()
  if (!body) throw new Error('Ticket message body is required')
  const createdAt = data.created_at || crmTicketNowIso()
  const result = getDb().prepare(`
    INSERT INTO crm_ticket_messages (workspace_id, ticket_id, user_id, contact_id, direction, body, body_html, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    data.ticket_id,
    data.user_id ?? null,
    data.contact_id ?? null,
    direction,
    body,
    data.body_html ?? null,
    createdAt,
    createdAt,
  )
  const messageId = Number(result.lastInsertRowid)
  if (direction === 'outbound') {
    const patch: Parameters<typeof updateCrmTicket>[2] = {}
    if (!ticket.first_response_at) patch.first_response_at = createdAt
    if (ticket.status === 'open') patch.status = 'pending'
    if (Object.keys(patch).length > 0) updateCrmTicket(ticket.id, workspaceId, patch)
    else touchCrmTicket(ticket.id, workspaceId, createdAt)
  } else {
    touchCrmTicket(ticket.id, workspaceId, createdAt)
  }
  return getCrmTicketMessageById(messageId, workspaceId)
}

export function getDueCrmTicketSlaBreaches(nowIso: string, limit = 50): Array<{
  id: number
  workspace_id: number
  contact_id: number | null
  ticket_number: number
  subject: string
  sla_due_at: string | null
}> {
  const bounded = Math.max(1, Math.min(200, Math.floor(limit)))
  return getDb().prepare(`
    SELECT id, workspace_id, contact_id, ticket_number, subject, sla_due_at
    FROM crm_tickets
    WHERE status NOT IN ('solved','closed')
      AND sla_due_at IS NOT NULL
      AND sla_breached_at IS NULL
      AND sla_due_at <= ?
    ORDER BY sla_due_at ASC, id ASC
    LIMIT ?
  `).all(nowIso, bounded) as Array<{
    id: number
    workspace_id: number
    contact_id: number | null
    ticket_number: number
    subject: string
    sla_due_at: string | null
  }>
}

export function markCrmTicketSlaBreached(ticketId: number, workspaceId: number, breachedAt = crmTicketNowIso()): CrmTicketRecord | null {
  getDb().prepare(`
    UPDATE crm_tickets
    SET sla_breached_at = ?, updated_at = ?
    WHERE id = ? AND workspace_id = ? AND sla_breached_at IS NULL
  `).run(breachedAt, breachedAt, ticketId, workspaceId)
  return getCrmTicketById(ticketId, workspaceId)
}

export function queueCrmWorkflowRunsForTicketCreated(ticket: Pick<CrmTicket, 'workspace_id' | 'contact_id' | 'assignee_user_id'>): void {
  if (!ticket.contact_id) return
  queueCrmWorkflowRunsForTrigger({
    workspaceId: ticket.workspace_id,
    contactId: ticket.contact_id,
    triggerType: 'ticket_created',
  })
  if (ticket.assignee_user_id) {
    queueCrmWorkflowRunsForTrigger({
      workspaceId: ticket.workspace_id,
      contactId: ticket.contact_id,
      triggerType: 'ticket_assigned',
      triggerValue: String(ticket.assignee_user_id),
    })
  }
}

export function queueCrmWorkflowRunsForTicketUpdated(
  beforeTicket: Pick<CrmTicket, 'workspace_id' | 'contact_id' | 'assignee_user_id' | 'status'>,
  afterTicket: Pick<CrmTicket, 'workspace_id' | 'contact_id' | 'assignee_user_id' | 'status'>,
): void {
  if (!afterTicket.contact_id) return
  if (beforeTicket.assignee_user_id !== afterTicket.assignee_user_id && afterTicket.assignee_user_id) {
    queueCrmWorkflowRunsForTrigger({
      workspaceId: afterTicket.workspace_id,
      contactId: afterTicket.contact_id,
      triggerType: 'ticket_assigned',
      triggerValue: String(afterTicket.assignee_user_id),
    })
  }
  if (beforeTicket.status !== afterTicket.status) {
    queueCrmWorkflowRunsForTrigger({
      workspaceId: afterTicket.workspace_id,
      contactId: afterTicket.contact_id,
      triggerType: 'ticket_status_changed',
      triggerValue: afterTicket.status,
    })
  }
}

export function queueCrmWorkflowRunsForTicketSlaBreached(ticket: Pick<CrmTicket, 'workspace_id' | 'contact_id'>): void {
  if (!ticket.contact_id) return
  queueCrmWorkflowRunsForTrigger({
    workspaceId: ticket.workspace_id,
    contactId: ticket.contact_id,
    triggerType: 'ticket_sla_breached',
  })
}

// ─── Workspace integrations ──────────────────────────────────────────────────

/** Known providers. Add to this as new ones are wired. */
export type WorkspaceIntegrationProvider =
  | 'google_analytics'
  | 'facebook_pixel'
  | 'twilio'
  | 'google_calendar'
  | 'stripe'
  | 'facebook_ads'

export interface WorkspaceIntegration {
  id: number
  workspace_id: number
  provider: WorkspaceIntegrationProvider | string
  is_active: number
  config: Record<string, string>
  created_at: number
  updated_at: number
}

interface WorkspaceIntegrationRow {
  id: number
  workspace_id: number
  provider: string
  is_active: number
  config_json: string
  created_at: number
  updated_at: number
}

function enrichIntegration(row: WorkspaceIntegrationRow): WorkspaceIntegration {
  let config: Record<string, string> = {}
  try { config = JSON.parse(row.config_json || '{}') } catch { config = {} }
  return {
    id: row.id,
    workspace_id: row.workspace_id,
    provider: row.provider,
    is_active: row.is_active,
    config,
    created_at: row.created_at,
    updated_at: row.updated_at,
  }
}

export function getWorkspaceIntegrations(workspaceId: number): WorkspaceIntegration[] {
  const rows = getDb().prepare(
    'SELECT * FROM workspace_integrations WHERE workspace_id = ? ORDER BY provider'
  ).all(workspaceId) as WorkspaceIntegrationRow[]
  return rows.map(enrichIntegration)
}

export function getWorkspaceIntegration(workspaceId: number, provider: string): WorkspaceIntegration | null {
  const row = getDb().prepare(
    'SELECT * FROM workspace_integrations WHERE workspace_id = ? AND provider = ?'
  ).get(workspaceId, provider) as WorkspaceIntegrationRow | undefined
  return row ? enrichIntegration(row) : null
}

export function upsertWorkspaceIntegration(
  workspaceId: number,
  provider: string,
  config: Record<string, string>,
  isActive = true,
): WorkspaceIntegration {
  const now = Math.floor(Date.now() / 1000)
  const existing = getWorkspaceIntegration(workspaceId, provider)
  if (existing) {
    getDb().prepare(
      'UPDATE workspace_integrations SET config_json = ?, is_active = ?, updated_at = ? WHERE id = ?'
    ).run(JSON.stringify(config), isActive ? 1 : 0, now, existing.id)
    return getWorkspaceIntegration(workspaceId, provider) as WorkspaceIntegration
  }
  const result = getDb().prepare(
    'INSERT INTO workspace_integrations (workspace_id, provider, config_json, is_active, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)'
  ).run(workspaceId, provider, JSON.stringify(config), isActive ? 1 : 0, now, now)
  return getWorkspaceIntegration(workspaceId, provider) as WorkspaceIntegration
}

export function deleteWorkspaceIntegration(workspaceId: number, provider: string): boolean {
  const result = getDb().prepare(
    'DELETE FROM workspace_integrations WHERE workspace_id = ? AND provider = ?'
  ).run(workspaceId, provider)
  return result.changes > 0
}

// ──────────────────────────────────────────────────────────
// Audit log helpers
// ──────────────────────────────────────────────────────────

export interface CrmAuditLogEntry {
  id: number
  workspace_id: number
  user_id: number | null
  user_name: string | null
  entity: string
  entity_id: number | null
  action: string
  summary: string
  payload_json: string | null
  created_at: number
}

/**
 * Writes a single audit-log row. Crash-safe: any failure (DB locked, bad
 * payload, missing workspace) is swallowed so an audit write cannot break
 * the originating request. The audit trail is complementary to activity
 * notes, not load-bearing.
 */
export function writeAuditLog(data: {
  workspaceId: number
  userId?: number | null
  entity: string
  entityId?: number | null
  action: string
  summary: string
  payload?: Record<string, unknown> | null
}): void {
  try {
    const payloadJson = data.payload ? JSON.stringify(data.payload) : null
    getDb().prepare(
      `INSERT INTO crm_audit_log (workspace_id, user_id, entity, entity_id, action, summary, payload_json)
       VALUES (?, ?, ?, ?, ?, ?, ?)`
    ).run(
      data.workspaceId,
      data.userId ?? null,
      data.entity,
      data.entityId ?? null,
      data.action,
      data.summary,
      payloadJson,
    )
  } catch {
    // Swallow — audit log must never break a request.
  }
}

export function listAuditLog(
  workspaceId: number,
  opts?: { entity?: string; entityId?: number; limit?: number },
): CrmAuditLogEntry[] {
  const limit = Math.min(500, Math.max(1, Math.floor(opts?.limit ?? 200)))
  const clauses: string[] = ['a.workspace_id = ?']
  const args: (string | number)[] = [workspaceId]
  if (opts?.entity) {
    clauses.push('a.entity = ?')
    args.push(opts.entity)
  }
  if (opts?.entityId && Number.isFinite(opts.entityId)) {
    clauses.push('a.entity_id = ?')
    args.push(opts.entityId)
  }
  const sql = `
    SELECT a.id, a.workspace_id, a.user_id, u.name AS user_name,
           a.entity, a.entity_id, a.action, a.summary, a.payload_json, a.created_at
    FROM crm_audit_log a
    LEFT JOIN users u ON u.id = a.user_id
    WHERE ${clauses.join(' AND ')}
    ORDER BY a.created_at DESC, a.id DESC
    LIMIT ?
  `
  args.push(limit)
  return getDb().prepare(sql).all(...args) as CrmAuditLogEntry[]
}



