function agencyNowIso(): string {
  return new Date().toISOString()
}

function normalizeAgencyTier(value: unknown): CrmAgencyMembershipTier {
  return value === 'pro' ? 'pro' : 'snapshot'
}

function agencySlugify(value: string): string {
  const slug = value
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
  return slug || 'client-workspace'
}

function agencyWorkspaceNameFromEmail(email: string, fallback?: string | null): string {
  const explicit = String(fallback || '').trim()
  if (explicit) return explicit
  const local = email.split('@')[0] || 'Client'
  return local
    .replace(/[._-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/\b\w/g, (ch) => ch.toUpperCase()) || 'Client Workspace'
}

function agencyUniqueWorkspaceSlug(base: string): string {
  const db = getDb()
  const root = agencySlugify(base)
  let slug = root
  let suffix = 2
  while (db.prepare('SELECT 1 FROM workspaces WHERE slug = ?').get(slug)) {
    slug = `${root}-${suffix}`
    suffix += 1
  }
  return slug
}

function parseAgencyTimestamp(value: string | number | null | undefined): number {
  if (typeof value === 'number' && Number.isFinite(value)) {
    return value > 10_000_000_000 ? value : value * 1000
  }
  if (typeof value === 'string' && value.trim()) {
    const parsed = Date.parse(value)
    return Number.isFinite(parsed) ? parsed : 0
  }
  return 0
}

function parseCrmAgencySnapshotPayload(value: string): CrmAgencySnapshotPayload {
  const parsed = safeJsonParse<Partial<CrmAgencySnapshotPayload>>(value, {})
  return {
    version: 1,
    source_workspace_id: typeof parsed.source_workspace_id === 'number' ? parsed.source_workspace_id : 0,
    source_workspace_name: typeof parsed.source_workspace_name === 'string' ? parsed.source_workspace_name : '',
    exported_at: typeof parsed.exported_at === 'string' ? parsed.exported_at : agencyNowIso(),
    workflows: Array.isArray(parsed.workflows) ? parsed.workflows as CrmAgencySnapshotWorkflow[] : [],
    email_templates: Array.isArray(parsed.email_templates) ? parsed.email_templates as CrmAgencySnapshotTemplate[] : [],
    sms_templates: Array.isArray(parsed.sms_templates) ? parsed.sms_templates as CrmAgencySnapshotTemplate[] : [],
    canned_replies: Array.isArray(parsed.canned_replies) ? parsed.canned_replies as CrmAgencySnapshotTemplate[] : [],
    pipelines: Array.isArray(parsed.pipelines) ? parsed.pipelines as CrmAgencySnapshotPipeline[] : [],
    drip_sequences: Array.isArray(parsed.drip_sequences) ? parsed.drip_sequences as CrmAgencySnapshotDripSequence[] : [],
  }
}

function enrichCrmAgencySnapshot(row: CrmAgencySnapshot): CrmAgencySnapshotRecord {
  const payload = parseCrmAgencySnapshotPayload(row.payload_json)
  const loadSummary = getDb().prepare(`
    SELECT
      SUM(CASE WHEN status = 'pending' THEN 1 ELSE 0 END) AS pending_count,
      MAX(updated_at) AS last_loaded_at,
      (SELECT status FROM crm_agency_snapshot_loads l2 WHERE l2.snapshot_id = ? ORDER BY updated_at DESC, id DESC LIMIT 1) AS last_status
    FROM crm_agency_snapshot_loads
    WHERE snapshot_id = ?
  `).get(row.id, row.id) as { pending_count: number | null; last_loaded_at: string | null; last_status: CrmAgencySnapshotLoad['status'] | null }
  return {
    ...row,
    payload,
    bundle_counts: {
      workflows: payload.workflows.length,
      email_templates: payload.email_templates.length,
      sms_templates: payload.sms_templates.length,
      canned_replies: payload.canned_replies.length,
      pipelines: payload.pipelines.length,
      drip_sequences: payload.drip_sequences.length,
    },
    last_load_status: loadSummary?.last_status ?? null,
    last_loaded_at: loadSummary?.last_loaded_at ?? null,
    pending_load_count: Number(loadSummary?.pending_count || 0),
  }
}

function ensureAgencySystemContact(workspaceId: number): CrmContactRecord {
  const email = `agency-${workspaceId}@internal.ctrl`
  const existing = getCrmContactByEmail(workspaceId, email)
  if (existing) return existing
  const stageId = getPipelineStages(workspaceId)[0]?.id ?? null
  const created = createCrmContact({
    workspaceId,
    name: 'Agency automation',
    email,
    tags: ['agency_system'],
    pipelineStageId: stageId,
    notes: 'System anchor contact for agency-mode workflow triggers.',
    skipWorkflowTriggers: true,
  })
  return updateCrmContact(created.id, workspaceId, {
    source: 'agency_system',
    lifecycle_stage: 'System',
    dnd_sms: true,
    dnd_email: true,
    dnd_calls: true,
  }) || created
}

function queueAgencyWorkflowTrigger(
  agencyWorkspaceId: number,
  triggerType: 'agency_client_added' | 'snapshot_loaded',
  triggerValue?: string | null,
): void {
  const contact = ensureAgencySystemContact(agencyWorkspaceId)
  queueCrmWorkflowRunsForTrigger({
    workspaceId: agencyWorkspaceId,
    contactId: contact.id,
    triggerType,
    triggerValue: triggerValue ?? '',
  })
}

export function isAgencyAdminUser(userId: number): boolean {
  const row = getDb().prepare('SELECT COALESCE(is_agency_admin, 0) AS flag FROM users WHERE id = ?').get(userId) as { flag: number } | undefined
  return Boolean(row?.flag)
}

export function getAgencyWorkspaceIdForUser(userId: number, currentWorkspaceId: number): number | null {
  if (!isAgencyAdminUser(userId)) return null
  if (!isWorkspaceMember(userId, currentWorkspaceId)) return null
  const currentIsAgency = getDb().prepare('SELECT 1 FROM crm_agency_memberships WHERE agency_workspace_id = ? LIMIT 1').get(currentWorkspaceId)
  if (currentIsAgency) return currentWorkspaceId
  const parent = getDb().prepare(
    'SELECT agency_workspace_id FROM crm_agency_memberships WHERE member_workspace_id = ? ORDER BY id ASC LIMIT 1'
  ).get(currentWorkspaceId) as { agency_workspace_id: number } | undefined
  if (parent && isWorkspaceMember(userId, parent.agency_workspace_id)) return parent.agency_workspace_id
  return currentWorkspaceId
}

export function getCrmAgencyWorkspaceContext(userId: number, currentWorkspaceId: number): CrmAgencyWorkspaceContext {
  const currentWorkspace = getWorkspaceById(currentWorkspaceId)
  const isAdmin = isAgencyAdminUser(userId)
  if (!currentWorkspace) {
    return {
      is_agency_admin: isAdmin,
      agency_workspace_id: null,
      current_workspace_id: currentWorkspaceId,
      current_workspace_name: 'Workspace',
      workspaces: [],
    }
  }
  if (!isAdmin) {
    return {
      is_agency_admin: false,
      agency_workspace_id: null,
      current_workspace_id: currentWorkspaceId,
      current_workspace_name: currentWorkspace.name,
      workspaces: [{
        id: currentWorkspace.id,
        name: currentWorkspace.name,
        public_id: currentWorkspace.public_id ?? null,
        color: currentWorkspace.color ?? null,
        role: 'agency',
        tier: 'agency',
      }],
    }
  }
  const agencyWorkspaceId = getAgencyWorkspaceIdForUser(userId, currentWorkspaceId)
  const agencyWorkspace = agencyWorkspaceId ? getWorkspaceById(agencyWorkspaceId) : currentWorkspace
  const workspaces: CrmAgencyWorkspaceContext['workspaces'] = []
  if (agencyWorkspace) {
    workspaces.push({
      id: agencyWorkspace.id,
      name: agencyWorkspace.name,
      public_id: agencyWorkspace.public_id ?? null,
      color: agencyWorkspace.color ?? null,
      role: 'agency',
      tier: 'agency',
    })
  }
  if (agencyWorkspaceId) {
    for (const client of listCrmAgencyClients(agencyWorkspaceId)) {
      workspaces.push({
        id: client.member_workspace_id,
        name: client.workspace_name,
        public_id: client.workspace_public_id,
        color: client.workspace_color,
        role: 'client',
        tier: client.tier,
      })
    }
  }
  const seen = new Set<number>()
  return {
    is_agency_admin: true,
    agency_workspace_id: agencyWorkspaceId,
    current_workspace_id: currentWorkspaceId,
    current_workspace_name: currentWorkspace.name,
    workspaces: workspaces.filter((workspace) => {
      if (seen.has(workspace.id)) return false
      seen.add(workspace.id)
      return true
    }),
  }
}

export function createCrmAgencyMembership(data: {
  agencyWorkspaceId: number
  memberWorkspaceId: number
  tier?: CrmAgencyMembershipTier
}): CrmAgencyClient {
  const now = agencyNowIso()
  getDb().prepare(`
    INSERT INTO crm_agency_memberships (agency_workspace_id, member_workspace_id, tier, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?)
    ON CONFLICT(agency_workspace_id, member_workspace_id) DO UPDATE SET
      tier = excluded.tier,
      updated_at = excluded.updated_at
  `).run(
    data.agencyWorkspaceId,
    data.memberWorkspaceId,
    normalizeAgencyTier(data.tier),
    now,
    now,
  )
  const created = getCrmAgencyClientByWorkspaceId(data.agencyWorkspaceId, data.memberWorkspaceId)
  if (!created) throw new Error('Failed to create agency membership')
  return created
}

export function listCrmAgencyClients(agencyWorkspaceId: number): CrmAgencyClient[] {
  return getDb().prepare(`
    SELECT
      m.id,
      m.agency_workspace_id,
      m.member_workspace_id,
      m.tier,
      m.created_at,
      m.updated_at,
      w.name AS workspace_name,
      w.public_id AS workspace_public_id,
      w.color AS workspace_color,
      w.owner_id AS workspace_owner_id,
      u.name AS workspace_owner_name,
      u.email AS workspace_owner_email
    FROM crm_agency_memberships m
    JOIN workspaces w ON w.id = m.member_workspace_id
    LEFT JOIN users u ON u.id = w.owner_id
    WHERE m.agency_workspace_id = ?
    ORDER BY w.name COLLATE NOCASE ASC
  `).all(agencyWorkspaceId) as CrmAgencyClient[]
}

export function getCrmAgencyClientByWorkspaceId(agencyWorkspaceId: number, memberWorkspaceId: number): CrmAgencyClient | null {
  const row = getDb().prepare(`
    SELECT
      m.id,
      m.agency_workspace_id,
      m.member_workspace_id,
      m.tier,
      m.created_at,
      m.updated_at,
      w.name AS workspace_name,
      w.public_id AS workspace_public_id,
      w.color AS workspace_color,
      w.owner_id AS workspace_owner_id,
      u.name AS workspace_owner_name,
      u.email AS workspace_owner_email
    FROM crm_agency_memberships m
    JOIN workspaces w ON w.id = m.member_workspace_id
    LEFT JOIN users u ON u.id = w.owner_id
    WHERE m.agency_workspace_id = ? AND m.member_workspace_id = ?
    LIMIT 1
  `).get(agencyWorkspaceId, memberWorkspaceId) as CrmAgencyClient | undefined
  return row ?? null
}

export function createCrmAgencyClientWorkspace(data: {
  agencyWorkspaceId: number
  invitedByUserId: number
  email: string
  name?: string | null
  tier?: CrmAgencyMembershipTier
}): CrmAgencyClient {
  const email = String(data.email || '').trim().toLowerCase()
  if (!email || !email.includes('@')) throw new Error('Valid email required')
  const workspaceName = agencyWorkspaceNameFromEmail(email, data.name)
  const db = getDb()
  const now = Math.floor(Date.now() / 1000)
  const existingUser = db.prepare('SELECT id, role FROM users WHERE LOWER(email) = LOWER(?)').get(email) as { id: number; role: string } | undefined
  let clientUserId = existingUser?.id ?? null
  if (!clientUserId) {
    const created = db.prepare(`
      INSERT INTO users (email, name, password_hash, role, created_at, last_login)
      VALUES (?, ?, NULL, 'client', ?, ?)
    `).run(email, workspaceName, now, now)
    clientUserId = Number(created.lastInsertRowid)
  }
  const workspace = createWorkspace(workspaceName, agencyUniqueWorkspaceSlug(workspaceName))
  updateWorkspace(workspace.id, { owner_id: clientUserId ?? data.invitedByUserId })
  addUserToWorkspace(data.invitedByUserId, workspace.id, 'owner')
  if (clientUserId && clientUserId !== data.invitedByUserId) {
    addUserToWorkspace(clientUserId, workspace.id, 'owner')
  }
  const membership = createCrmAgencyMembership({
    agencyWorkspaceId: data.agencyWorkspaceId,
    memberWorkspaceId: workspace.id,
    tier: normalizeAgencyTier(data.tier),
  })
  try {
    queueAgencyWorkflowTrigger(data.agencyWorkspaceId, 'agency_client_added', String(workspace.id))
  } catch {
    // Keep client creation resilient if trigger queueing fails.
  }
  return membership
}

export function getCrmAgencyClientStats(agencyWorkspaceId: number, memberWorkspaceId: number): CrmAgencyClientStats | null {
  if (!getCrmAgencyClientByWorkspaceId(agencyWorkspaceId, memberWorkspaceId)) return null
  const db = getDb()
  const contactRow = db.prepare('SELECT COUNT(*) AS c FROM crm_contacts WHERE workspace_id = ?').get(memberWorkspaceId) as { c: number }
  const openDealsRow = db.prepare(`
    SELECT COUNT(*) AS c, COALESCE(SUM(value), 0) AS total
    FROM crm_opportunities
    WHERE workspace_id = ? AND status = 'open'
  `).get(memberWorkspaceId) as { c: number; total: number }
  const start = new Date()
  start.setUTCDate(1)
  start.setUTCHours(0, 0, 0, 0)
  const end = new Date(start)
  end.setUTCMonth(end.getUTCMonth() + 1)
  const revenueRow = db.prepare(`
    SELECT COALESCE(SUM(value), 0) AS total
    FROM crm_opportunities
    WHERE workspace_id = ?
      AND status = 'won'
      AND close_date IS NOT NULL
      AND close_date >= ?
      AND close_date < ?
  `).get(memberWorkspaceId, start.toISOString().slice(0, 10), end.toISOString().slice(0, 10)) as { total: number }
  const campaignRow = db.prepare(`
    SELECT
      (SELECT COUNT(*) FROM email_campaigns WHERE workspace_id = ? AND status = 'active') AS campaigns,
      (SELECT COUNT(*) FROM crm_drip_sequences WHERE workspace_id = ? AND is_active = 1) AS drips
  `).get(memberWorkspaceId, memberWorkspaceId) as { campaigns: number; drips: number }
  const workspace = getWorkspaceById(memberWorkspaceId)
  const recentActivity = listAuditLog(memberWorkspaceId, { limit: 5 })
  const lastContact = db.prepare('SELECT MAX(created_at) AS ts FROM crm_contacts WHERE workspace_id = ?').get(memberWorkspaceId) as { ts: number | null }
  const lastAudit = db.prepare('SELECT MAX(created_at) AS ts FROM crm_audit_log WHERE workspace_id = ?').get(memberWorkspaceId) as { ts: number | null }
  const lastOpportunity = db.prepare('SELECT MAX(created_at) AS ts FROM crm_opportunities WHERE workspace_id = ?').get(memberWorkspaceId) as { ts: string | null }
  const lastCall = db.prepare('SELECT MAX(started_at) AS ts FROM crm_call_logs WHERE workspace_id = ?').get(memberWorkspaceId) as { ts: string | null }
  const lastMs = Math.max(
    parseAgencyTimestamp(lastContact?.ts),
    parseAgencyTimestamp(lastAudit?.ts),
    parseAgencyTimestamp(lastOpportunity?.ts),
    parseAgencyTimestamp(lastCall?.ts),
  )

  const trendMap = new Map<string, { day: string; contacts: number; activity: number; revenue: number }>()
  for (let offset = 6; offset >= 0; offset -= 1) {
    const day = new Date()
    day.setUTCHours(0, 0, 0, 0)
    day.setUTCDate(day.getUTCDate() - offset)
    trendMap.set(day.toISOString().slice(0, 10), { day: day.toISOString().slice(0, 10), contacts: 0, activity: 0, revenue: 0 })
  }
  const contactTrend = db.prepare('SELECT created_at FROM crm_contacts WHERE workspace_id = ? AND created_at >= ?').all(memberWorkspaceId, Math.floor((Date.now() - 7 * 86400_000) / 1000)) as Array<{ created_at: number }>
  for (const row of contactTrend) {
    const day = new Date(row.created_at * 1000).toISOString().slice(0, 10)
    const bucket = trendMap.get(day)
    if (bucket) bucket.contacts += 1
  }
  const auditTrend = db.prepare('SELECT created_at FROM crm_audit_log WHERE workspace_id = ? AND created_at >= ?').all(memberWorkspaceId, Math.floor((Date.now() - 7 * 86400_000) / 1000)) as Array<{ created_at: number }>
  for (const row of auditTrend) {
    const day = new Date(row.created_at * 1000).toISOString().slice(0, 10)
    const bucket = trendMap.get(day)
    if (bucket) bucket.activity += 1
  }
  const revenueTrend = db.prepare(`
    SELECT close_date, value
    FROM crm_opportunities
    WHERE workspace_id = ?
      AND status = 'won'
      AND close_date IS NOT NULL
      AND close_date >= ?
  `).all(memberWorkspaceId, new Date(Date.now() - 7 * 86400_000).toISOString().slice(0, 10)) as Array<{ close_date: string; value: number }>
  for (const row of revenueTrend) {
    const day = row.close_date.slice(0, 10)
    const bucket = trendMap.get(day)
    if (bucket) bucket.revenue += Number(row.value || 0)
  }

  return {
    workspace_id: memberWorkspaceId,
    contacts: Number(contactRow?.c || 0),
    open_deals: Number(openDealsRow?.c || 0),
    open_deals_value: Number(openDealsRow?.total || 0),
    revenue_mtd: Number(revenueRow?.total || 0),
    active_campaigns: Number(campaignRow?.campaigns || 0) + Number(campaignRow?.drips || 0),
    ad_spend: null,
    ad_spend_connected: Boolean(workspace?.google_ads_api_token || workspace?.facebook_page_access_tokens),
    last_activity_at: lastMs ? new Date(lastMs).toISOString() : null,
    recent_activity: recentActivity,
    trend: Array.from(trendMap.values()),
  }
}

export function exportCrmAgencySnapshotPayload(sourceWorkspaceId: number): CrmAgencySnapshotPayload {
  const workspace = getWorkspaceById(sourceWorkspaceId)
  if (!workspace) throw new Error('Workspace not found')
  const templates = getCrmMessageTemplates(sourceWorkspaceId)
  const serializeTemplate = (template: CrmMessageTemplate): CrmAgencySnapshotTemplate => ({
    name: template.name,
    subject: template.subject,
    body: template.body,
    category: template.category,
  })
  return {
    version: 1,
    source_workspace_id: sourceWorkspaceId,
    source_workspace_name: workspace.name,
    exported_at: agencyNowIso(),
    workflows: getCrmWorkflows(sourceWorkspaceId).map((workflow) => ({
      name: workflow.name,
      trigger_type: workflow.trigger_type,
      trigger_value: workflow.trigger_value,
      graph: workflow.graph,
      is_active: Boolean(workflow.is_active),
      allow_reentry: Boolean(workflow.allow_reentry),
      business_hours: workflow.business_hours_json
        ? safeJsonParse<CrmWorkflowBusinessHours | null>(workflow.business_hours_json, null)
        : null,
      respect_contact_timezone: Boolean(workflow.respect_contact_timezone),
    })),
    email_templates: templates.filter((template) => template.channel === 'email').map(serializeTemplate),
    sms_templates: templates.filter((template) => template.channel === 'sms').map(serializeTemplate),
    canned_replies: templates.filter((template) => template.channel === 'internal').map(serializeTemplate),
    pipelines: getCrmPipelines(sourceWorkspaceId).map((pipeline) => ({
      name: pipeline.name,
      position: pipeline.position,
      is_default: Boolean(pipeline.is_default),
      stages: getPipelineStages(sourceWorkspaceId, pipeline.id).map((stage) => ({
        name: stage.name,
        color: stage.color,
        position: stage.position,
      })),
    })),
    drip_sequences: listCrmDripSequences(sourceWorkspaceId).map((sequence) => ({
      name: sequence.name,
      description: sequence.description,
      is_active: Boolean(sequence.is_active),
      allow_reentry: Boolean(sequence.allow_reentry),
      steps: listCrmDripSteps(sequence.id, sourceWorkspaceId).map((step) => ({
        position: step.position,
        delay_days: step.delay_days,
        delay_hours: step.delay_hours,
        channel: step.channel,
        subject: step.subject,
        body_html: step.body_html,
        body_blocks: step.body_blocks,
        body_text: step.body_text,
      })),
    })),
  }
}

export function getCrmAgencySnapshotById(id: number, agencyWorkspaceId: number): CrmAgencySnapshotRecord | null {
  const row = getDb().prepare(
    'SELECT * FROM crm_agency_snapshots WHERE id = ? AND agency_workspace_id = ?'
  ).get(id, agencyWorkspaceId) as CrmAgencySnapshot | undefined
  return row ? enrichCrmAgencySnapshot(row) : null
}

export function listCrmAgencySnapshots(agencyWorkspaceId: number): CrmAgencySnapshotRecord[] {
  const rows = getDb().prepare(
    'SELECT * FROM crm_agency_snapshots WHERE agency_workspace_id = ? ORDER BY updated_at DESC, id DESC'
  ).all(agencyWorkspaceId) as CrmAgencySnapshot[]
  return rows.map(enrichCrmAgencySnapshot)
}

export function createCrmAgencySnapshot(data: {
  agencyWorkspaceId: number
  sourceWorkspaceId: number
  name: string
  description?: string | null
}): CrmAgencySnapshotRecord {
  const now = agencyNowIso()
  const info = getDb().prepare(`
    INSERT INTO crm_agency_snapshots (agency_workspace_id, name, description, payload_json, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?)
  `).run(
    data.agencyWorkspaceId,
    data.name.trim(),
    data.description?.trim() || null,
    JSON.stringify(exportCrmAgencySnapshotPayload(data.sourceWorkspaceId)),
    now,
    now,
  )
  const created = getCrmAgencySnapshotById(Number(info.lastInsertRowid), data.agencyWorkspaceId)
  if (!created) throw new Error('Failed to create agency snapshot')
  return created
}

export function updateCrmAgencySnapshot(
  id: number,
  agencyWorkspaceId: number,
  patch: Partial<{ name: string; description: string | null; sourceWorkspaceId: number }>,
): CrmAgencySnapshotRecord | null {
  const existing = getCrmAgencySnapshotById(id, agencyWorkspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number | null> = []
  if (patch.name !== undefined) {
    sets.push('name = ?')
    params.push(patch.name.trim())
  }
  if ('description' in patch) {
    sets.push('description = ?')
    params.push(patch.description?.trim() || null)
  }
  if (patch.sourceWorkspaceId !== undefined) {
    sets.push('payload_json = ?')
    params.push(JSON.stringify(exportCrmAgencySnapshotPayload(patch.sourceWorkspaceId)))
  }
  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(agencyNowIso())
  params.push(id)
  params.push(agencyWorkspaceId)
  getDb().prepare(`UPDATE crm_agency_snapshots SET ${sets.join(', ')} WHERE id = ? AND agency_workspace_id = ?`).run(...params)
  return getCrmAgencySnapshotById(id, agencyWorkspaceId)
}

export function deleteCrmAgencySnapshot(id: number, agencyWorkspaceId: number): boolean {
  return getDb().prepare(
    'DELETE FROM crm_agency_snapshots WHERE id = ? AND agency_workspace_id = ?'
  ).run(id, agencyWorkspaceId).changes > 0
}

export function listCrmAgencySnapshotLoads(agencyWorkspaceId: number, snapshotId?: number): CrmAgencySnapshotLoadRecord[] {
  const clauses = ['s.agency_workspace_id = ?']
  const params: Array<number> = [agencyWorkspaceId]
  if (snapshotId) {
    clauses.push('l.snapshot_id = ?')
    params.push(snapshotId)
  }
  return getDb().prepare(`
    SELECT
      l.id,
      l.snapshot_id,
      l.target_workspace_id,
      l.loaded_by_user_id,
      l.status,
      l.error_message,
      l.created_at,
      l.updated_at,
      s.name AS snapshot_name,
      w.name AS target_workspace_name
    FROM crm_agency_snapshot_loads l
    JOIN crm_agency_snapshots s ON s.id = l.snapshot_id
    JOIN workspaces w ON w.id = l.target_workspace_id
    WHERE ${clauses.join(' AND ')}
    ORDER BY l.created_at DESC, l.id DESC
  `).all(...params) as CrmAgencySnapshotLoadRecord[]
}

export function queueCrmAgencySnapshotLoads(data: {
  agencyWorkspaceId: number
  snapshotId: number
  targetWorkspaceIds: number[]
  loadedByUserId: number
}): CrmAgencySnapshotLoadRecord[] {
  const snapshot = getCrmAgencySnapshotById(data.snapshotId, data.agencyWorkspaceId)
  if (!snapshot) throw new Error('Snapshot not found')
  const allowedTargets = new Set(listCrmAgencyClients(data.agencyWorkspaceId).map((client) => client.member_workspace_id))
  const targetIds = Array.from(new Set(data.targetWorkspaceIds.filter((id) => allowedTargets.has(id))))
  if (!targetIds.length) throw new Error('No target workspaces selected')
  const insert = getDb().prepare(`
    INSERT INTO crm_agency_snapshot_loads (snapshot_id, target_workspace_id, loaded_by_user_id, status, error_message, created_at, updated_at)
    VALUES (?, ?, ?, 'pending', NULL, ?, ?)
  `)
  const now = agencyNowIso()
  for (const workspaceId of targetIds) {
    insert.run(data.snapshotId, workspaceId, data.loadedByUserId, now, now)
  }
  return listCrmAgencySnapshotLoads(data.agencyWorkspaceId, data.snapshotId).filter((row) => targetIds.includes(row.target_workspace_id))
}

function createSnapshotTemplatesForWorkspace(targetWorkspaceId: number, templates: CrmAgencySnapshotTemplate[], channel: CrmMessageTemplateChannel): void {
  for (const template of templates) {
    createCrmMessageTemplate(targetWorkspaceId, {
      name: template.name,
      channel,
      subject: template.subject,
      body: template.body,
      category: template.category,
    })
  }
}

function applyCrmAgencySnapshotPayload(targetWorkspaceId: number, payload: CrmAgencySnapshotPayload): void {
  createSnapshotTemplatesForWorkspace(targetWorkspaceId, payload.email_templates, 'email')
  createSnapshotTemplatesForWorkspace(targetWorkspaceId, payload.sms_templates, 'sms')
  createSnapshotTemplatesForWorkspace(targetWorkspaceId, payload.canned_replies, 'internal')

  for (const pipeline of payload.pipelines) {
    const createdPipeline = createCrmPipeline(targetWorkspaceId, { name: pipeline.name })
    if (pipeline.is_default) updateCrmPipeline(createdPipeline.id, targetWorkspaceId, { is_default: true })
    for (const stage of pipeline.stages) {
      createPipelineStage({
        workspace_id: targetWorkspaceId,
        pipeline_id: createdPipeline.id,
        name: stage.name,
        color: stage.color,
        position: stage.position,
      })
    }
  }

  for (const workflow of payload.workflows) {
    const created = createCrmWorkflow(targetWorkspaceId, {
      name: workflow.name,
      trigger_type: workflow.trigger_type,
      trigger_value: workflow.trigger_value,
      graph: workflow.graph,
      is_active: workflow.is_active,
    })
    updateCrmWorkflow(created.id, targetWorkspaceId, {
      allow_reentry: workflow.allow_reentry,
      business_hours: workflow.business_hours,
      respect_contact_timezone: workflow.respect_contact_timezone,
    })
  }

  for (const sequence of payload.drip_sequences) {
    const created = createCrmDripSequence(targetWorkspaceId, {
      name: sequence.name,
      description: sequence.description,
      is_active: sequence.is_active,
      allow_reentry: sequence.allow_reentry,
    })
    for (const step of sequence.steps) {
      createCrmDripStep(created.id, targetWorkspaceId, {
        position: step.position,
        delay_days: step.delay_days,
        delay_hours: step.delay_hours,
        channel: step.channel,
        subject: step.subject,
        body_html: step.body_html,
        body_blocks: step.body_blocks,
        body_text: step.body_text,
      })
    }
  }
}

export function processPendingCrmAgencySnapshotLoads(limit = 6): { processed: number; completed: number; failed: number } {
  const pending = getDb().prepare(`
    SELECT l.*, s.agency_workspace_id, s.name AS snapshot_name, s.payload_json
    FROM crm_agency_snapshot_loads l
    JOIN crm_agency_snapshots s ON s.id = l.snapshot_id
    WHERE l.status = 'pending'
    ORDER BY l.created_at ASC, l.id ASC
    LIMIT ?
  `).all(limit) as Array<CrmAgencySnapshotLoad & { agency_workspace_id: number; snapshot_name: string; payload_json: string }>
  let completed = 0
  let failed = 0
  const update = getDb().prepare(
    'UPDATE crm_agency_snapshot_loads SET status = ?, error_message = ?, updated_at = ? WHERE id = ?'
  )
  for (const load of pending) {
    update.run('loading', null, agencyNowIso(), load.id)
    try {
      applyCrmAgencySnapshotPayload(load.target_workspace_id, parseCrmAgencySnapshotPayload(load.payload_json))
      update.run('completed', null, agencyNowIso(), load.id)
      const targetWorkspace = getWorkspaceById(load.target_workspace_id)
      writeAuditLog({
        workspaceId: load.agency_workspace_id,
        userId: load.loaded_by_user_id,
        entity: 'agency_snapshot_load',
        entityId: load.id,
        action: 'completed',
        summary: `Loaded snapshot "${load.snapshot_name}" into ${targetWorkspace?.name || `workspace #${load.target_workspace_id}`}`,
      })
      writeAuditLog({
        workspaceId: load.target_workspace_id,
        userId: load.loaded_by_user_id,
        entity: 'agency_snapshot_load',
        entityId: load.id,
        action: 'completed',
        summary: `Applied agency snapshot "${load.snapshot_name}"`,
      })
      queueAgencyWorkflowTrigger(load.agency_workspace_id, 'snapshot_loaded', String(load.target_workspace_id))
      completed += 1
    } catch (error) {
      update.run('failed', error instanceof Error ? error.message : 'Snapshot load failed', agencyNowIso(), load.id)
      failed += 1
    }
  }
  return { processed: pending.length, completed, failed }
}

export function getCrmAgencyWhiteLabel(agencyWorkspaceId: number): CrmAgencyWhiteLabel | null {
  const row = getDb().prepare(
    'SELECT * FROM crm_agency_white_label WHERE agency_workspace_id = ?'
  ).get(agencyWorkspaceId) as CrmAgencyWhiteLabel | undefined
  return row ?? null
}

export function upsertCrmAgencyWhiteLabel(
  agencyWorkspaceId: number,
  patch: Partial<Omit<CrmAgencyWhiteLabel, 'agency_workspace_id' | 'created_at' | 'updated_at'>>,
): CrmAgencyWhiteLabel {
  const existing = getCrmAgencyWhiteLabel(agencyWorkspaceId)
  const now = agencyNowIso()
  const next = {
    brand_name: patch.brand_name !== undefined ? patch.brand_name : existing?.brand_name ?? null,
    logo_url: patch.logo_url !== undefined ? patch.logo_url : existing?.logo_url ?? null,
    favicon_url: patch.favicon_url !== undefined ? patch.favicon_url : existing?.favicon_url ?? null,
    primary_color: patch.primary_color !== undefined ? patch.primary_color : existing?.primary_color ?? getWorkspaceById(agencyWorkspaceId)?.primary_color ?? null,
    support_email: patch.support_email !== undefined ? patch.support_email : existing?.support_email ?? null,
    login_bg_url: patch.login_bg_url !== undefined ? patch.login_bg_url : existing?.login_bg_url ?? null,
    custom_domain_cname: patch.custom_domain_cname !== undefined ? patch.custom_domain_cname : existing?.custom_domain_cname ?? null,
  }
  getDb().prepare(`
    INSERT INTO crm_agency_white_label (
      agency_workspace_id, brand_name, logo_url, favicon_url, primary_color, support_email, login_bg_url, custom_domain_cname, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(agency_workspace_id) DO UPDATE SET
      brand_name = excluded.brand_name,
      logo_url = excluded.logo_url,
      favicon_url = excluded.favicon_url,
      primary_color = excluded.primary_color,
      support_email = excluded.support_email,
      login_bg_url = excluded.login_bg_url,
      custom_domain_cname = excluded.custom_domain_cname,
      updated_at = excluded.updated_at
  `).run(
    agencyWorkspaceId,
    next.brand_name,
    next.logo_url,
    next.favicon_url,
    next.primary_color,
    next.support_email,
    next.login_bg_url,
    next.custom_domain_cname,
    existing?.created_at ?? now,
    now,
  )
  return getCrmAgencyWhiteLabel(agencyWorkspaceId) as CrmAgencyWhiteLabel
}

// ─── Saved views ──────────────────────────────────────────────────────────
// Saved filter/sort presets that the user can flip between on CRM list
// pages. A view is either owned by a specific user (user_id set) or shared
// with the whole workspace (is_shared = 1). list returns the union deduped
// on id so shared views authored by someone else still show up.

export interface CrmSavedView {
  id: number
  workspace_id: number
  user_id: number | null
  name: string
  entity: 'contact' | 'opportunity' | 'company'
  filters_json: string
  sort_key: string | null
  sort_dir: 'asc' | 'desc' | null
  is_shared: number
  position: number
  created_at: number
  updated_at: number
}

export function listCrmSavedViews(
  workspaceId: number,
  entity: CrmSavedView['entity'],
  userId: number,
): CrmSavedView[] {
  const rows = getDb().prepare(
    `SELECT id, workspace_id, user_id, name, entity, filters_json,
            sort_key, sort_dir, is_shared, position, created_at, updated_at
     FROM crm_saved_views
     WHERE workspace_id = ? AND entity = ?
       AND (user_id = ? OR is_shared = 1)
     ORDER BY position ASC, created_at ASC, id ASC`
  ).all(workspaceId, entity, userId) as CrmSavedView[]
  const seen = new Set<number>()
  const out: CrmSavedView[] = []
  for (const row of rows) {
    if (seen.has(row.id)) continue
    seen.add(row.id)
    out.push(row)
  }
  return out
}

export function createCrmSavedView(data: {
  workspaceId: number
  userId: number
  name: string
  entity: CrmSavedView['entity']
  filters_json?: string
  sort_key?: string | null
  sort_dir?: 'asc' | 'desc' | null
  is_shared?: boolean
  position?: number
}): CrmSavedView {
  const db = getDb()
  const info = db.prepare(
    `INSERT INTO crm_saved_views
       (workspace_id, user_id, name, entity, filters_json, sort_key, sort_dir, is_shared, position)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
  ).run(
    data.workspaceId,
    data.userId,
    data.name,
    data.entity,
    data.filters_json ?? '{}',
    data.sort_key ?? null,
    data.sort_dir ?? null,
    data.is_shared ? 1 : 0,
    data.position ?? 0,
  )
  return db.prepare(
    `SELECT id, workspace_id, user_id, name, entity, filters_json,
            sort_key, sort_dir, is_shared, position, created_at, updated_at
     FROM crm_saved_views WHERE id = ?`
  ).get(Number(info.lastInsertRowid)) as CrmSavedView
}

export function updateCrmSavedView(
  id: number,
  workspaceId: number,
  userId: number,
  data: Partial<{
    name: string
    filters_json: string
    sort_key: string | null
    sort_dir: 'asc' | 'desc' | null
    is_shared: boolean
    position: number
  }>,
): CrmSavedView | null {
  const db = getDb()
  const existing = db.prepare(
    `SELECT id, user_id FROM crm_saved_views WHERE id = ? AND workspace_id = ?`
  ).get(id, workspaceId) as { id: number; user_id: number | null } | undefined
  if (!existing) return null
  // Only the owner may mutate their view. Shared views created by other
  // users are read-only to everyone else — a later permissions pass can
  // relax this for workspace admins.
  if (existing.user_id !== userId) return null

  const sets: string[] = []
  const args: (string | number | null)[] = []
  if (typeof data.name === 'string') { sets.push('name = ?'); args.push(data.name) }
  if (typeof data.filters_json === 'string') { sets.push('filters_json = ?'); args.push(data.filters_json) }
  if ('sort_key' in data) { sets.push('sort_key = ?'); args.push(data.sort_key ?? null) }
  if ('sort_dir' in data) { sets.push('sort_dir = ?'); args.push(data.sort_dir ?? null) }
  if (typeof data.is_shared === 'boolean') { sets.push('is_shared = ?'); args.push(data.is_shared ? 1 : 0) }
  if (typeof data.position === 'number') { sets.push('position = ?'); args.push(data.position) }
  if (sets.length === 0) {
    return db.prepare(
      `SELECT id, workspace_id, user_id, name, entity, filters_json,
              sort_key, sort_dir, is_shared, position, created_at, updated_at
       FROM crm_saved_views WHERE id = ?`
    ).get(id) as CrmSavedView
  }
  sets.push(`updated_at = strftime('%s','now')`)
  args.push(id)
  db.prepare(`UPDATE crm_saved_views SET ${sets.join(', ')} WHERE id = ?`).run(...args)
  return db.prepare(
    `SELECT id, workspace_id, user_id, name, entity, filters_json,
            sort_key, sort_dir, is_shared, position, created_at, updated_at
     FROM crm_saved_views WHERE id = ?`
  ).get(id) as CrmSavedView
}

export function deleteCrmSavedView(id: number, workspaceId: number, userId: number): boolean {
  const db = getDb()
  const existing = db.prepare(
    `SELECT user_id FROM crm_saved_views WHERE id = ? AND workspace_id = ?`
  ).get(id, workspaceId) as { user_id: number | null } | undefined
  if (!existing) return false
  if (existing.user_id !== userId) return false
  const info = db.prepare(`DELETE FROM crm_saved_views WHERE id = ?`).run(id)
  return info.changes > 0
}

// ─── Workspace CRM settings ─────────────────────────────────────────────────
// Workspace-level preferences surfaced at /crm/settings/workspace. Today the
// booking-page editor and schedulers default to America/Vancouver — having a
// single row of defaults lets future integrations (calendars, notifications,
// currency formatting) read one place instead of hard-coding the fallback.

export interface CrmWorkspaceSettings {
  id: number
  name: string
  slug: string
  color: string
  timezone: string
  currency: string
  primary_color: string
  business_hours_start: number
  business_hours_end: number
  business_days_mask: number
  notify_new_lead_email: number
  notify_owner_on_inbound: number
  default_reminder_24h: number
  default_reminder_1h: number
  auto_unsubscribe_footer: number
  // Conversation AI auto-reply configuration. See
  // src/lib/conversation-ai-autoreply.ts for the runtime that reads these.
  ai_autoreply_enabled: number
  ai_autoreply_channels: string
  ai_autoreply_confidence_threshold: number
  ai_autoreply_business_hours_only: number
  ai_autoreply_max_per_contact_per_day: number
  ai_autoreply_system_prompt: string | null
  ai_autoreply_handoff_keywords: string
  public_id: string
}

export function getCrmWorkspaceSettings(workspaceId: number): CrmWorkspaceSettings | null {
  const row = getDb().prepare(`
    SELECT id, name, slug, color, timezone, currency, primary_color,
           business_hours_start, business_hours_end, business_days_mask,
           notify_new_lead_email, notify_owner_on_inbound,
           default_reminder_24h, default_reminder_1h, auto_unsubscribe_footer,
           ai_autoreply_enabled, ai_autoreply_channels,
           ai_autoreply_confidence_threshold, ai_autoreply_business_hours_only,
           ai_autoreply_max_per_contact_per_day, ai_autoreply_system_prompt,
           ai_autoreply_handoff_keywords,
           public_id
    FROM workspaces WHERE id = ?
  `).get(workspaceId) as CrmWorkspaceSettings | undefined
  return row || null
}

export function updateCrmWorkspaceSettings(workspaceId: number, data: Partial<Pick<CrmWorkspaceSettings,
  'name' | 'timezone' | 'currency' | 'primary_color' | 'business_hours_start' | 'business_hours_end' | 'business_days_mask' |
  'ai_autoreply_channels' | 'ai_autoreply_confidence_threshold' | 'ai_autoreply_max_per_contact_per_day' |
  'ai_autoreply_system_prompt' | 'ai_autoreply_handoff_keywords'
> & {
  notify_new_lead_email: boolean
  notify_owner_on_inbound: boolean
  default_reminder_24h: boolean
  default_reminder_1h: boolean
  auto_unsubscribe_footer: boolean
  ai_autoreply_enabled: boolean
  ai_autoreply_business_hours_only: boolean
}>): CrmWorkspaceSettings | null {
  const existing = getCrmWorkspaceSettings(workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const params: Array<string | number | null> = []
  if (data.name !== undefined) { sets.push('name = ?'); params.push(data.name.trim()) }
  if (data.timezone !== undefined) { sets.push('timezone = ?'); params.push(data.timezone) }
  if (data.currency !== undefined) { sets.push('currency = ?'); params.push(data.currency) }
  if (data.primary_color !== undefined) { sets.push('primary_color = ?'); params.push(data.primary_color) }
  if (typeof data.business_hours_start === 'number') { sets.push('business_hours_start = ?'); params.push(Math.max(0, Math.min(23, data.business_hours_start))) }
  if (typeof data.business_hours_end === 'number') { sets.push('business_hours_end = ?'); params.push(Math.max(1, Math.min(24, data.business_hours_end))) }
  if (typeof data.business_days_mask === 'number') { sets.push('business_days_mask = ?'); params.push(Math.max(0, Math.min(127, data.business_days_mask))) }
  if (data.notify_new_lead_email !== undefined) { sets.push('notify_new_lead_email = ?'); params.push(data.notify_new_lead_email ? 1 : 0) }
  if (data.notify_owner_on_inbound !== undefined) { sets.push('notify_owner_on_inbound = ?'); params.push(data.notify_owner_on_inbound ? 1 : 0) }
  if (data.default_reminder_24h !== undefined) { sets.push('default_reminder_24h = ?'); params.push(data.default_reminder_24h ? 1 : 0) }
  if (data.default_reminder_1h !== undefined) { sets.push('default_reminder_1h = ?'); params.push(data.default_reminder_1h ? 1 : 0) }
  if (data.auto_unsubscribe_footer !== undefined) { sets.push('auto_unsubscribe_footer = ?'); params.push(data.auto_unsubscribe_footer ? 1 : 0) }
  if (data.ai_autoreply_enabled !== undefined) { sets.push('ai_autoreply_enabled = ?'); params.push(data.ai_autoreply_enabled ? 1 : 0) }
  if (data.ai_autoreply_channels !== undefined) { sets.push('ai_autoreply_channels = ?'); params.push(data.ai_autoreply_channels) }
  if (typeof data.ai_autoreply_confidence_threshold === 'number') { sets.push('ai_autoreply_confidence_threshold = ?'); params.push(Math.max(0, Math.min(100, Math.round(data.ai_autoreply_confidence_threshold)))) }
  if (data.ai_autoreply_business_hours_only !== undefined) { sets.push('ai_autoreply_business_hours_only = ?'); params.push(data.ai_autoreply_business_hours_only ? 1 : 0) }
  if (typeof data.ai_autoreply_max_per_contact_per_day === 'number') { sets.push('ai_autoreply_max_per_contact_per_day = ?'); params.push(Math.max(0, Math.min(1000, Math.round(data.ai_autoreply_max_per_contact_per_day)))) }
  if (data.ai_autoreply_system_prompt !== undefined) { sets.push('ai_autoreply_system_prompt = ?'); params.push(data.ai_autoreply_system_prompt) }
  if (data.ai_autoreply_handoff_keywords !== undefined) { sets.push('ai_autoreply_handoff_keywords = ?'); params.push(data.ai_autoreply_handoff_keywords) }
  if (!sets.length) return existing
  params.push(workspaceId)
  getDb().prepare(`UPDATE workspaces SET ${sets.join(', ')}, updated_at = strftime('%s','now') WHERE id = ?`).run(...params)
  return getCrmWorkspaceSettings(workspaceId)
}

// ─── Conversation AI auto-reply log ────────────────────────────────────────

export type CrmAiAutoReplyOutcome =
  | 'sent'
  | 'skipped_low_confidence'
  | 'skipped_hours'
  | 'skipped_quota'
  | 'skipped_disabled'
  | 'skipped_channel'
  | 'handoff_keyword'
  | 'error'

export type CrmAiAutoReplyChannel = 'sms' | 'email' | 'chat' | 'whatsapp' | 'instagram'

export interface CrmAiAutoReplyLogRow {
  id: number
  workspace_id: number
  contact_id: number
  channel: CrmAiAutoReplyChannel
  inbound_message: string
  outbound_message: string | null
  confidence: number | null
  outcome: CrmAiAutoReplyOutcome
  error_message: string | null
  created_at: string
}

export function logCrmAiAutoReply(data: {
  workspaceId: number
  contactId: number
  channel: CrmAiAutoReplyChannel
  inboundMessage: string
  outboundMessage?: string | null
  confidence?: number | null
  outcome: CrmAiAutoReplyOutcome
  errorMessage?: string | null
}): CrmAiAutoReplyLogRow {
  const result = getDb().prepare(`
    INSERT INTO crm_ai_autoreply_log
      (workspace_id, contact_id, channel, inbound_message, outbound_message, confidence, outcome, error_message)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    data.workspaceId,
    data.contactId,
    data.channel,
    data.inboundMessage.slice(0, 4000),
    data.outboundMessage ?? null,
    typeof data.confidence === 'number' ? Math.max(0, Math.min(100, Math.round(data.confidence))) : null,
    data.outcome,
    data.errorMessage ?? null,
  )
  return getDb().prepare('SELECT * FROM crm_ai_autoreply_log WHERE id = ?').get(Number(result.lastInsertRowid)) as CrmAiAutoReplyLogRow
}

export function getCrmAiAutoReplyLogForContact(contactId: number, workspaceId: number, limit = 50): CrmAiAutoReplyLogRow[] {
  return getDb().prepare(`
    SELECT * FROM crm_ai_autoreply_log
    WHERE contact_id = ? AND workspace_id = ?
    ORDER BY id DESC
    LIMIT ?
  `).all(contactId, workspaceId, Math.max(1, Math.min(500, limit))) as CrmAiAutoReplyLogRow[]
}

/**
 * Count 'sent' rows for a contact today. Used by the auto-reply runtime to
 * enforce the per-contact daily cap. "Today" is the last 24 hours from the
 * current moment rather than a calendar midnight — simpler and still honors
 * the spirit of "don't spam them more than N times a day."
 */
export function countCrmAiAutoReplySentForContactToday(contactId: number, workspaceId: number): number {
  const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString()
  const row = getDb().prepare(`
    SELECT COUNT(*) as c FROM crm_ai_autoreply_log
    WHERE workspace_id = ? AND contact_id = ? AND outcome = 'sent' AND created_at >= ?
  `).get(workspaceId, contactId, since) as { c: number } | undefined
  return row?.c ?? 0
}

/**
 * Has this contact triggered a handoff in the last 24 hours and not yet had
 * a teammate resume auto-reply? The inbox UI surfaces this as a banner so a
 * teammate knows the bot stepped back. A handoff is considered "cleared"
 * when a newer row with outcome='sent' lands (posted by the resume endpoint
 * when a teammate clicks "Resume").
 */
export function getCrmAiAutoReplyRecentHandoff(contactId: number, workspaceId: number): CrmAiAutoReplyLogRow | null {
  const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString()
  const latest = getDb().prepare(`
    SELECT * FROM crm_ai_autoreply_log
    WHERE workspace_id = ? AND contact_id = ? AND created_at >= ?
      AND outcome IN ('handoff_keyword','sent')
    ORDER BY id DESC
    LIMIT 1
  `).get(workspaceId, contactId, since) as CrmAiAutoReplyLogRow | undefined
  if (!latest) return null
  return latest.outcome === 'handoff_keyword' ? latest : null
}

/**
 * Aggregate counts by outcome over a time window (in days). Drives the
 * /crm/reports/ai-autoreply dashboard.
 */
export function getCrmAiAutoReplyStats(workspaceId: number, windowDays: number): {
  window_days: number
  total: number
  by_outcome: Array<{ outcome: CrmAiAutoReplyOutcome; count: number }>
} {
  const days = Math.max(1, Math.min(365, Math.round(windowDays)))
  const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString()
  const rows = getDb().prepare(`
    SELECT outcome, COUNT(*) as count
    FROM crm_ai_autoreply_log
    WHERE workspace_id = ? AND created_at >= ?
    GROUP BY outcome
    ORDER BY count DESC
  `).all(workspaceId, since) as Array<{ outcome: CrmAiAutoReplyOutcome; count: number }>
  const total = rows.reduce((acc, r) => acc + r.count, 0)
  return { window_days: days, total, by_outcome: rows }
}

/**
 * Check if any logged chat message on this contact's thread came from the
 * auto-reply runtime. The inbox UI renders a tiny "AI" chip next to these
 * bubbles. We compare against the per-channel message body since the log is
 * the only place that knows — outbound SMS/chat/email bodies don't otherwise
 * carry a "this was AI" flag.
 */
export function getCrmAiAutoReplySentBodiesForContact(contactId: number, workspaceId: number): Set<string> {
  const rows = getDb().prepare(`
    SELECT outbound_message FROM crm_ai_autoreply_log
    WHERE workspace_id = ? AND contact_id = ? AND outcome = 'sent' AND outbound_message IS NOT NULL
    ORDER BY id DESC
    LIMIT 200
  `).all(workspaceId, contactId) as Array<{ outbound_message: string | null }>
  const set = new Set<string>()
  for (const row of rows) {
    if (row.outbound_message) set.add(row.outbound_message.trim())
  }
  return set
}

// ──────────────────────────────────────────────────────────
// Recurring workflow schedules
// Time-driven enrollment: fires on a daily / weekly / monthly cadence and
// enrolls every member of the bound list into the workflow as a brand-new
// run. `computeNextRunAt` drives the cron math without any outside lib.
// ──────────────────────────────────────────────────────────

export interface CrmWorkflowSchedule {
  id: number
  workspace_id: number
  workflow_id: number
  list_id: number | null
  cadence: 'daily' | 'weekly' | 'monthly'
  hour_of_day: number
  day_of_week: number | null
  day_of_month: number | null
  timezone: string
  is_active: number
  last_run_at: number | null
  next_run_at: number
  created_at: number
  updated_at: number
}

function clampScheduleHour(value: unknown): number {
  const n = Math.floor(Number(value))
  if (!Number.isFinite(n)) return 9
  return Math.max(0, Math.min(23, n))
}

function clampScheduleDayOfWeek(value: unknown): number {
  const n = Math.floor(Number(value))
  if (!Number.isFinite(n)) return 0
  return Math.max(0, Math.min(6, n))
}

function clampScheduleDayOfMonth(value: unknown): number {
  const n = Math.floor(Number(value))
  if (!Number.isFinite(n)) return 1
  // Stay <=28 so we never hit Feb / short-month edge cases
  return Math.max(1, Math.min(28, n))
}

/**
 * Compute the next unix timestamp at which a schedule should fire.
 * Uses host-system timezone math via `Intl.DateTimeFormat` against the
 * target tz — good enough for a first pass, and matches how appointment
 * reminders handle tz elsewhere in this codebase.
 *
 * - daily:   today at hour_of_day if still in the future, else next day
 * - weekly:  next occurrence of day_of_week at hour_of_day
 * - monthly: next occurrence of day_of_month at hour_of_day
 */
export function computeNextRunAt(
  schedule: Pick<CrmWorkflowSchedule, 'cadence' | 'hour_of_day' | 'day_of_week' | 'day_of_month' | 'timezone'>,
  fromSec: number,
): number {
  const timezone = schedule.timezone || 'America/Vancouver'
  const hour = clampScheduleHour(schedule.hour_of_day)
  const fromMs = Math.max(0, Math.floor(fromSec)) * 1000

  // Decompose `ms` into tz-local parts so we can line candidate days
  // up against the user's local calendar + weekday.
  const partsFor = (ms: number) => {
    const parts = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      year: 'numeric', month: 'numeric', day: 'numeric',
      hour: 'numeric', minute: 'numeric', second: 'numeric',
      weekday: 'short', hour12: false,
    }).formatToParts(new Date(ms))
    const get = (t: string) => Number(parts.find((p) => p.type === t)?.value)
    const weekdayStr = parts.find((p) => p.type === 'weekday')?.value || 'Sun'
    const weekdayMap: Record<string, number> = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 }
    return {
      year: get('year'),
      month: get('month'),
      day: get('day'),
      hour: get('hour') === 24 ? 0 : get('hour'),
      weekday: weekdayMap[weekdayStr] ?? 0,
    }
  }

  // Finds the unix-seconds ts that, rendered in `timezone`, reads as
  // (year, month, day, hour:00:00). DST-safe via 3 iterative corrections.
  const buildTs = (year: number, month: number, day: number): number => {
    let guessMs = Date.UTC(year, month - 1, day, hour, 0, 0)
    for (let i = 0; i < 3; i += 1) {
      const p = partsFor(guessMs)
      const targetMs = Date.UTC(p.year, p.month - 1, p.day, p.hour, 0, 0)
      const wantedMs = Date.UTC(year, month - 1, day, hour, 0, 0)
      const delta = wantedMs - targetMs
      if (delta === 0) break
      guessMs += delta
    }
    return Math.floor(guessMs / 1000)
  }

  const addDays = (year: number, month: number, day: number, n: number): { year: number; month: number; day: number } => {
    const d = new Date(Date.UTC(year, month - 1, day))
    d.setUTCDate(d.getUTCDate() + n)
    return { year: d.getUTCFullYear(), month: d.getUTCMonth() + 1, day: d.getUTCDate() }
  }

  const today = partsFor(fromMs)
  const nowSec = Math.floor(fromMs / 1000)

  if (schedule.cadence === 'daily') {
    const todayTs = buildTs(today.year, today.month, today.day)
    if (todayTs > nowSec) return todayTs
    const next = addDays(today.year, today.month, today.day, 1)
    return buildTs(next.year, next.month, next.day)
  }

  if (schedule.cadence === 'weekly') {
    const targetDow = clampScheduleDayOfWeek(schedule.day_of_week ?? 1)
    for (let offset = 0; offset < 14; offset += 1) {
      const d = addDays(today.year, today.month, today.day, offset)
      const p = partsFor(Date.UTC(d.year, d.month - 1, d.day, 12, 0, 0))
      if (p.weekday !== targetDow) continue
      const ts = buildTs(d.year, d.month, d.day)
      if (ts > nowSec) return ts
    }
    const fallback = addDays(today.year, today.month, today.day, 7)
    return buildTs(fallback.year, fallback.month, fallback.day)
  }

  // monthly
  const targetDom = clampScheduleDayOfMonth(schedule.day_of_month ?? 1)
  let candidateYear = today.year
  let candidateMonth = today.month
  for (let i = 0; i < 3; i += 1) {
    const ts = buildTs(candidateYear, candidateMonth, targetDom)
    if (ts > nowSec) return ts
    candidateMonth += 1
    if (candidateMonth > 12) { candidateMonth = 1; candidateYear += 1 }
  }
  return buildTs(candidateYear, candidateMonth, targetDom)
}

export function listCrmWorkflowSchedules(workspaceId: number): CrmWorkflowSchedule[] {
  return getDb().prepare(`
    SELECT * FROM crm_workflow_schedules
    WHERE workspace_id = ?
    ORDER BY id ASC
  `).all(workspaceId) as CrmWorkflowSchedule[]
}

export function listCrmWorkflowSchedulesForWorkflow(workflowId: number, workspaceId: number): CrmWorkflowSchedule[] {
  return getDb().prepare(`
    SELECT * FROM crm_workflow_schedules
    WHERE workspace_id = ? AND workflow_id = ?
    ORDER BY id ASC
  `).all(workspaceId, workflowId) as CrmWorkflowSchedule[]
}

export function getCrmWorkflowScheduleById(id: number, workspaceId: number): CrmWorkflowSchedule | null {
  const row = getDb().prepare(`
    SELECT * FROM crm_workflow_schedules
    WHERE id = ? AND workspace_id = ?
    LIMIT 1
  `).get(id, workspaceId) as CrmWorkflowSchedule | undefined
  return row ?? null
}

export function createCrmWorkflowSchedule(
  workspaceId: number,
  data: {
    workflow_id: number
    list_id?: number | null
    cadence: 'daily' | 'weekly' | 'monthly'
    hour_of_day?: number
    day_of_week?: number | null
    day_of_month?: number | null
    timezone?: string
  },
): CrmWorkflowSchedule {
  const now = Math.floor(Date.now() / 1000)
  const hourOfDay = clampScheduleHour(data.hour_of_day ?? 9)
  const timezone = (data.timezone || 'America/Vancouver').trim() || 'America/Vancouver'
  const dayOfWeek = data.cadence === 'weekly' ? clampScheduleDayOfWeek(data.day_of_week ?? 1) : null
  const dayOfMonth = data.cadence === 'monthly' ? clampScheduleDayOfMonth(data.day_of_month ?? 1) : null

  const nextRunAt = computeNextRunAt({
    cadence: data.cadence,
    hour_of_day: hourOfDay,
    day_of_week: dayOfWeek,
    day_of_month: dayOfMonth,
    timezone,
  }, now)

  const result = getDb().prepare(`
    INSERT INTO crm_workflow_schedules (
      workspace_id, workflow_id, list_id, cadence,
      hour_of_day, day_of_week, day_of_month,
      timezone, is_active, next_run_at, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?, ?)
  `).run(
    workspaceId,
    data.workflow_id,
    data.list_id ?? null,
    data.cadence,
    hourOfDay,
    dayOfWeek,
    dayOfMonth,
    timezone,
    nextRunAt,
    now,
    now,
  )
  return getDb().prepare('SELECT * FROM crm_workflow_schedules WHERE id = ?')
    .get(Number(result.lastInsertRowid)) as CrmWorkflowSchedule
}

export function updateCrmWorkflowSchedule(
  id: number,
  workspaceId: number,
  data: Partial<{
    list_id: number | null
    cadence: 'daily' | 'weekly' | 'monthly'
    hour_of_day: number
    day_of_week: number | null
    day_of_month: number | null
    timezone: string
    is_active: boolean
  }>,
): CrmWorkflowSchedule | null {
  const existing = getCrmWorkflowScheduleById(id, workspaceId)
  if (!existing) return null

  const sets: string[] = []
  const params: Array<string | number | null> = []

  if (data.list_id !== undefined) { sets.push('list_id = ?'); params.push(data.list_id ?? null) }
  if (data.cadence !== undefined) { sets.push('cadence = ?'); params.push(data.cadence) }
  if (data.hour_of_day !== undefined) { sets.push('hour_of_day = ?'); params.push(clampScheduleHour(data.hour_of_day)) }
  if (data.day_of_week !== undefined) { sets.push('day_of_week = ?'); params.push(data.day_of_week === null ? null : clampScheduleDayOfWeek(data.day_of_week)) }
  if (data.day_of_month !== undefined) { sets.push('day_of_month = ?'); params.push(data.day_of_month === null ? null : clampScheduleDayOfMonth(data.day_of_month)) }
  if (data.timezone !== undefined) {
    const tz = (data.timezone || '').trim() || 'America/Vancouver'
    sets.push('timezone = ?'); params.push(tz)
  }
  if (data.is_active !== undefined) { sets.push('is_active = ?'); params.push(data.is_active ? 1 : 0) }

  const timingChanged = (
    data.cadence !== undefined ||
    data.hour_of_day !== undefined ||
    data.day_of_week !== undefined ||
    data.day_of_month !== undefined ||
    data.timezone !== undefined
  )
  if (timingChanged) {
    const merged: Pick<CrmWorkflowSchedule, 'cadence' | 'hour_of_day' | 'day_of_week' | 'day_of_month' | 'timezone'> = {
      cadence: (data.cadence ?? existing.cadence) as CrmWorkflowSchedule['cadence'],
      hour_of_day: data.hour_of_day !== undefined ? clampScheduleHour(data.hour_of_day) : existing.hour_of_day,
      day_of_week: data.day_of_week !== undefined ? (data.day_of_week === null ? null : clampScheduleDayOfWeek(data.day_of_week)) : existing.day_of_week,
      day_of_month: data.day_of_month !== undefined ? (data.day_of_month === null ? null : clampScheduleDayOfMonth(data.day_of_month)) : existing.day_of_month,
      timezone: data.timezone !== undefined ? ((data.timezone || '').trim() || 'America/Vancouver') : existing.timezone,
    }
    sets.push('next_run_at = ?')
    params.push(computeNextRunAt(merged, Math.floor(Date.now() / 1000)))
  }

  if (!sets.length) return existing
  sets.push('updated_at = ?')
  params.push(Math.floor(Date.now() / 1000))
  params.push(id)

  getDb().prepare(`UPDATE crm_workflow_schedules SET ${sets.join(', ')} WHERE id = ?`).run(...params)
  return getCrmWorkflowScheduleById(id, workspaceId)
}

export function deleteCrmWorkflowSchedule(id: number, workspaceId: number): boolean {
  const info = getDb().prepare(
    'DELETE FROM crm_workflow_schedules WHERE id = ? AND workspace_id = ?'
  ).run(id, workspaceId)
  return info.changes > 0
}

export function getDueCrmWorkflowSchedules(nowSec: number): CrmWorkflowSchedule[] {
  return getDb().prepare(`
    SELECT * FROM crm_workflow_schedules
    WHERE is_active = 1 AND next_run_at <= ?
    ORDER BY next_run_at ASC, id ASC
    LIMIT 100
  `).all(Math.floor(nowSec)) as CrmWorkflowSchedule[]
}

export function markCrmWorkflowScheduleRan(id: number, now: number, nextRunAt: number): void {
  getDb().prepare(`
    UPDATE crm_workflow_schedules
    SET last_run_at = ?, next_run_at = ?, updated_at = ?
    WHERE id = ?
  `).run(Math.floor(now), Math.floor(nextRunAt), Math.floor(now), id)
}

// ─── SMS keywords ────────────────────────────────────────────────────────

export type CrmSmsKeywordAction = 'add_tag' | 'remove_tag' | 'add_to_list' | 'opt_in' | 'opt_out' | 'fire_workflow'

export interface CrmSmsKeyword {
  id: number
  workspace_id: number
  keyword: string
  action: CrmSmsKeywordAction
  payload: string | null
  response_message: string | null
  is_active: number
  created_at: string
  updated_at: string
}

function seedBuiltInSmsKeywords(workspaceId: number): void {
  const existing = getDb()
    .prepare('SELECT 1 AS present FROM crm_sms_keywords WHERE workspace_id = ? LIMIT 1')
    .get(workspaceId) as { present: number } | undefined
  if (existing) return
  const workspace = getDb().prepare('SELECT name FROM workspaces WHERE id = ?').get(workspaceId) as { name?: string } | undefined
  const workspaceName = workspace?.name || 'us'
  getDb().prepare(`
    INSERT INTO crm_sms_keywords (workspace_id, keyword, action, payload, response_message, is_active)
    VALUES (?, 'STOP', 'opt_out', NULL, NULL, 1)
  `).run(workspaceId)
  getDb().prepare(`
    INSERT INTO crm_sms_keywords (workspace_id, keyword, action, payload, response_message, is_active)
    VALUES (?, 'HELP', 'add_tag', ?, ?, 1)
  `).run(
    workspaceId,
    JSON.stringify({ tag: 'help_requested' }),
    `For help, reply to this text or visit ${workspaceName}`,
  )
}

export * from './crm-help-db'

export function listCrmSmsKeywords(workspaceId: number): CrmSmsKeyword[] {
  seedBuiltInSmsKeywords(workspaceId)
  return getDb()
    .prepare('SELECT * FROM crm_sms_keywords WHERE workspace_id = ? ORDER BY keyword ASC')
    .all(workspaceId) as CrmSmsKeyword[]
}

export function getCrmSmsKeywordById(id: number, workspaceId: number): CrmSmsKeyword | null {
  const row = getDb()
    .prepare('SELECT * FROM crm_sms_keywords WHERE id = ? AND workspace_id = ?')
    .get(id, workspaceId) as CrmSmsKeyword | undefined
  return row ?? null
}

export function findCrmSmsKeyword(workspaceId: number, rawKeyword: string): CrmSmsKeyword | null {
  seedBuiltInSmsKeywords(workspaceId)
  const key = rawKeyword.trim().toUpperCase()
  if (!key) return null
  const row = getDb()
    .prepare('SELECT * FROM crm_sms_keywords WHERE workspace_id = ? AND is_active = 1 AND UPPER(keyword) = ?')
    .get(workspaceId, key) as CrmSmsKeyword | undefined
  return row ?? null
}

export function createCrmSmsKeyword(workspaceId: number, data: {
  keyword: string
  action: CrmSmsKeywordAction
  payload?: Record<string, unknown> | null
  response_message?: string | null
  is_active?: boolean
}): CrmSmsKeyword {
  const keyword = data.keyword.trim()
  if (!keyword) throw new Error('keyword is required')
  const payloadJson = data.payload ? JSON.stringify(data.payload) : null
  const active = data.is_active === false ? 0 : 1
  const result = getDb().prepare(`
    INSERT INTO crm_sms_keywords (workspace_id, keyword, action, payload, response_message, is_active)
    VALUES (?, ?, ?, ?, ?, ?)
  `).run(workspaceId, keyword, data.action, payloadJson, data.response_message || null, active)
  return getDb()
    .prepare('SELECT * FROM crm_sms_keywords WHERE id = ?')
    .get(Number(result.lastInsertRowid)) as CrmSmsKeyword
}

export function updateCrmSmsKeyword(id: number, workspaceId: number, patch: Partial<{
  keyword: string
  action: CrmSmsKeywordAction
  payload: Record<string, unknown> | null
  response_message: string | null
  is_active: boolean
}>): CrmSmsKeyword | null {
  const existing = getCrmSmsKeywordById(id, workspaceId)
  if (!existing) return null
  const next = {
    keyword: patch.keyword !== undefined ? patch.keyword.trim() : existing.keyword,
    action: patch.action ?? existing.action,
    payload: patch.payload !== undefined ? (patch.payload ? JSON.stringify(patch.payload) : null) : existing.payload,
    response_message: patch.response_message !== undefined ? patch.response_message : existing.response_message,
    is_active: patch.is_active === undefined ? existing.is_active : patch.is_active ? 1 : 0,
  }
  getDb().prepare(`
    UPDATE crm_sms_keywords
    SET keyword = ?, action = ?, payload = ?, response_message = ?, is_active = ?, updated_at = strftime('%Y-%m-%dT%H:%M:%fZ', 'now')
    WHERE id = ? AND workspace_id = ?
  `).run(next.keyword, next.action, next.payload, next.response_message, next.is_active, id, workspaceId)
  return getCrmSmsKeywordById(id, workspaceId)
}

export function deleteCrmSmsKeyword(id: number, workspaceId: number): boolean {
  const info = getDb()
    .prepare('DELETE FROM crm_sms_keywords WHERE id = ? AND workspace_id = ?')
    .run(id, workspaceId)
  return info.changes > 0
}

