export function findCrmTrackingNumberByPhone(phone: string): CrmTrackingNumber | null {
  const needle = normalizeComparablePhoneDigits(phone)
  if (!needle) return null
  const rows = getDb()
    .prepare('SELECT * FROM crm_tracking_numbers WHERE is_active = 1')
    .all() as CrmTrackingNumber[]
  for (const row of rows) {
    const candidate = normalizeComparablePhoneDigits(row.phone_number || '')
    if (!candidate) continue
    if (candidate === needle) return row
    if (candidate.slice(-10) === needle.slice(-10)) return row
  }
  return null
}

export function createCrmTrackingNumber(workspaceId: number, data: {
  twilio_sid: string
  phone_number: string
  source_label: string
  forward_to_number: string
  record_calls?: boolean
  is_active?: boolean
}): CrmTrackingNumber {
  const sid = data.twilio_sid.trim()
  if (!sid.startsWith('PN')) throw new Error('twilio_sid must be a Phone Number SID (starts with PN)')
  const phone = data.phone_number.trim()
  const source = data.source_label.trim()
  const forward = data.forward_to_number.trim()
  if (!phone) throw new Error('phone_number is required')
  if (!source) throw new Error('source_label is required')
  if (!forward) throw new Error('forward_to_number is required')
  const result = getDb().prepare(`
    INSERT INTO crm_tracking_numbers
      (workspace_id, twilio_sid, phone_number, source_label, forward_to_number, record_calls, is_active)
    VALUES (?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId, sid, phone, source, forward,
    data.record_calls === false ? 0 : 1,
    data.is_active === false ? 0 : 1,
  )
  return getDb()
    .prepare('SELECT * FROM crm_tracking_numbers WHERE id = ?')
    .get(Number(result.lastInsertRowid)) as CrmTrackingNumber
}

export function updateCrmTrackingNumber(
  id: number,
  workspaceId: number,
  patch: Partial<{
    twilio_sid: string
    phone_number: string
    source_label: string
    forward_to_number: string
    record_calls: boolean
    is_active: boolean
  }>,
): CrmTrackingNumber | null {
  const existing = getCrmTrackingNumberById(id, workspaceId)
  if (!existing) return null
  const next = {
    twilio_sid: patch.twilio_sid !== undefined ? patch.twilio_sid.trim() : existing.twilio_sid,
    phone_number: patch.phone_number !== undefined ? patch.phone_number.trim() : existing.phone_number,
    source_label: patch.source_label !== undefined ? patch.source_label.trim() : existing.source_label,
    forward_to_number: patch.forward_to_number !== undefined ? patch.forward_to_number.trim() : existing.forward_to_number,
    record_calls: patch.record_calls === undefined ? existing.record_calls : patch.record_calls ? 1 : 0,
    is_active: patch.is_active === undefined ? existing.is_active : patch.is_active ? 1 : 0,
  }
  if (patch.twilio_sid !== undefined && !next.twilio_sid.startsWith('PN')) {
    throw new Error('twilio_sid must be a Phone Number SID (starts with PN)')
  }
  getDb().prepare(`
    UPDATE crm_tracking_numbers
    SET twilio_sid = ?, phone_number = ?, source_label = ?, forward_to_number = ?,
        record_calls = ?, is_active = ?,
        updated_at = strftime('%Y-%m-%dT%H:%M:%fZ', 'now')
    WHERE id = ? AND workspace_id = ?
  `).run(
    next.twilio_sid, next.phone_number, next.source_label, next.forward_to_number,
    next.record_calls, next.is_active, id, workspaceId,
  )
  return getCrmTrackingNumberById(id, workspaceId)
}

export function deleteCrmTrackingNumber(id: number, workspaceId: number): boolean {
  const info = getDb()
    .prepare('DELETE FROM crm_tracking_numbers WHERE id = ? AND workspace_id = ?')
    .run(id, workspaceId)
  return info.changes > 0
}

export function createCrmCallLog(data: {
  workspace_id: number
  tracking_number_id?: number | null
  contact_id?: number | null
  twilio_call_sid?: string | null
  from_number?: string | null
  to_number?: string | null
  direction: CrmCallDirection
  status: CrmCallStatus
  duration_seconds?: number | null
  recording_url?: string | null
  recording_sid?: string | null
  source_label?: string | null
}): CrmCallLog {
  const result = getDb().prepare(`
    INSERT INTO crm_call_logs
      (workspace_id, tracking_number_id, contact_id, twilio_call_sid,
       from_number, to_number, direction, status, duration_seconds,
       recording_url, recording_sid, source_label)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    data.workspace_id,
    data.tracking_number_id ?? null,
    data.contact_id ?? null,
    data.twilio_call_sid ?? null,
    data.from_number ?? null,
    data.to_number ?? null,
    data.direction,
    data.status,
    data.duration_seconds ?? null,
    data.recording_url ?? null,
    data.recording_sid ?? null,
    data.source_label ?? null,
  )
  return getDb()
    .prepare('SELECT * FROM crm_call_logs WHERE id = ?')
    .get(Number(result.lastInsertRowid)) as CrmCallLog
}

export function getCrmCallLogByTwilioSid(sid: string): CrmCallLog | null {
  if (!sid) return null
  const row = getDb()
    .prepare('SELECT * FROM crm_call_logs WHERE twilio_call_sid = ? ORDER BY id DESC LIMIT 1')
    .get(sid) as CrmCallLog | undefined
  return row ?? null
}

export function updateCrmCallLog(
  id: number,
  patch: Partial<{
    status: CrmCallStatus
    duration_seconds: number | null
    recording_url: string | null
    recording_sid: string | null
    completed_at: string | null
    contact_id: number | null
  }>,
): CrmCallLog | null {
  const current = getDb()
    .prepare('SELECT * FROM crm_call_logs WHERE id = ?')
    .get(id) as CrmCallLog | undefined
  if (!current) return null
  const next = {
    status: patch.status ?? current.status,
    duration_seconds: patch.duration_seconds !== undefined ? patch.duration_seconds : current.duration_seconds,
    recording_url: patch.recording_url !== undefined ? patch.recording_url : current.recording_url,
    recording_sid: patch.recording_sid !== undefined ? patch.recording_sid : current.recording_sid,
    completed_at: patch.completed_at !== undefined ? patch.completed_at : current.completed_at,
    contact_id: patch.contact_id !== undefined ? patch.contact_id : current.contact_id,
  }
  getDb().prepare(`
    UPDATE crm_call_logs
    SET status = ?, duration_seconds = ?, recording_url = ?, recording_sid = ?,
        completed_at = ?, contact_id = ?
    WHERE id = ?
  `).run(
    next.status, next.duration_seconds, next.recording_url, next.recording_sid,
    next.completed_at, next.contact_id, id,
  )
  return getDb()
    .prepare('SELECT * FROM crm_call_logs WHERE id = ?')
    .get(id) as CrmCallLog
}

export interface CrmCallsReportRow {
  source_label: string
  total_calls: number
  answered: number
  missed: number
  total_talk_minutes: number
}

export interface CrmCallsReport {
  window_days: number
  totals: {
    total_calls: number
    answered: number
    missed: number
    total_talk_minutes: number
  }
  by_source: CrmCallsReportRow[]
}

export function getCrmCallsReport(workspaceId: number, windowDays: number): CrmCallsReport {
  const days = Math.max(1, Math.min(3650, Math.floor(windowDays)))
  const cutoffMs = Date.now() - days * 86_400_000
  const cutoffIso = new Date(cutoffMs).toISOString()
  const rows = getDb().prepare(`
    SELECT COALESCE(NULLIF(TRIM(source_label), ''), 'Untagged') AS source_label,
           status, duration_seconds
    FROM crm_call_logs
    WHERE workspace_id = ? AND started_at >= ?
  `).all(workspaceId, cutoffIso) as Array<{
    source_label: string
    status: CrmCallStatus
    duration_seconds: number | null
  }>

  const buckets = new Map<string, CrmCallsReportRow>()
  const totals = { total_calls: 0, answered: 0, missed: 0, total_talk_minutes: 0 }

  for (const row of rows) {
    const source = row.source_label
    let bucket = buckets.get(source)
    if (!bucket) {
      bucket = { source_label: source, total_calls: 0, answered: 0, missed: 0, total_talk_minutes: 0 }
      buckets.set(source, bucket)
    }
    bucket.total_calls += 1
    totals.total_calls += 1

    const isAnswered = row.status === 'completed' || row.status === 'in-progress'
    const isMissed = row.status === 'no-answer' || row.status === 'busy' || row.status === 'failed' || row.status === 'canceled'
    if (isAnswered) {
      bucket.answered += 1
      totals.answered += 1
    } else if (isMissed) {
      bucket.missed += 1
      totals.missed += 1
    }

    const durationSec = Number(row.duration_seconds || 0)
    const minutes = durationSec / 60
    bucket.total_talk_minutes += minutes
    totals.total_talk_minutes += minutes
  }

  // Round talk minutes to one decimal once at the boundary.
  for (const bucket of buckets.values()) {
    bucket.total_talk_minutes = Math.round(bucket.total_talk_minutes * 10) / 10
  }
  totals.total_talk_minutes = Math.round(totals.total_talk_minutes * 10) / 10

  const by_source = Array.from(buckets.values())
    .sort((a, b) => b.total_calls - a.total_calls || a.source_label.localeCompare(b.source_label))

  return { window_days: days, totals, by_source }
}

// ─── Appointments report ─────────────────────────────────────────────────

export interface CrmAppointmentsReportBucket {
  booked: number
  showed: number
  no_show: number
  cancelled: number
  rescheduled: number
  conflict: number
}

export interface CrmAppointmentsReportCalendarRow extends CrmAppointmentsReportBucket {
  calendar_id: number
  calendar_name: string
  show_rate: number
}

export interface CrmAppointmentsReportAssigneeRow extends CrmAppointmentsReportBucket {
  user_id: number | null
  user_name: string
  show_rate: number
}

export interface CrmAppointmentsReportDayRow {
  day: string
  booked: number
  showed: number
  no_show: number
}

export interface CrmAppointmentsReport {
  window_days: number
  totals: CrmAppointmentsReportBucket & { show_rate: number; no_show_rate: number }
  by_calendar: CrmAppointmentsReportCalendarRow[]
  by_assignee: CrmAppointmentsReportAssigneeRow[]
  by_day: CrmAppointmentsReportDayRow[]
}

export function getCrmAppointmentsReport(workspaceId: number, windowDays: number): CrmAppointmentsReport {
  const days = Math.max(1, Math.min(3650, Math.floor(windowDays)))
  const cutoff = Math.floor(Date.now() / 1000) - days * 86_400

  // Pull raw rows joined with calendar + assignee names so each bucket has
  // readable labels without a second query pass.
  const rows = getDb().prepare(`
    SELECT a.status AS status,
           a.starts_at AS starts_at,
           a.calendar_id AS calendar_id,
           a.assigned_user_id AS assigned_user_id,
           c.name AS calendar_name,
           u.name AS user_name
    FROM crm_appointments a
    LEFT JOIN crm_calendars c ON c.id = a.calendar_id
    LEFT JOIN users u ON u.id = a.assigned_user_id
    WHERE a.workspace_id = ? AND a.starts_at >= ?
  `).all(workspaceId, cutoff) as Array<{
    status: string
    starts_at: number
    calendar_id: number | null
    assigned_user_id: number | null
    calendar_name: string | null
    user_name: string | null
  }>

  const emptyBucket = (): CrmAppointmentsReportBucket => ({
    booked: 0, showed: 0, no_show: 0, cancelled: 0, rescheduled: 0, conflict: 0,
  })
  const totals = emptyBucket()
  const byCalendar = new Map<number, { name: string; bucket: CrmAppointmentsReportBucket }>()
  const byAssignee = new Map<string, { user_id: number | null; user_name: string; bucket: CrmAppointmentsReportBucket }>()
  const byDay = new Map<string, CrmAppointmentsReportDayRow>()

  function tally(bucket: CrmAppointmentsReportBucket, status: string): void {
    bucket.booked += 1
    if (status === 'showed') bucket.showed += 1
    else if (status === 'no_show') bucket.no_show += 1
    else if (status === 'cancelled') bucket.cancelled += 1
    else if (status === 'rescheduled') bucket.rescheduled += 1
    else if (status === 'conflict_detected') bucket.conflict += 1
  }

  for (const row of rows) {
    tally(totals, row.status)

    if (row.calendar_id !== null) {
      let cal = byCalendar.get(row.calendar_id)
      if (!cal) {
        cal = { name: row.calendar_name || `Calendar #${row.calendar_id}`, bucket: emptyBucket() }
        byCalendar.set(row.calendar_id, cal)
      }
      tally(cal.bucket, row.status)
    }

    const assigneeKey = row.assigned_user_id === null ? 'unassigned' : String(row.assigned_user_id)
    let ass = byAssignee.get(assigneeKey)
    if (!ass) {
      ass = {
        user_id: row.assigned_user_id,
        user_name: row.user_name || (row.assigned_user_id === null ? 'Unassigned' : `User #${row.assigned_user_id}`),
        bucket: emptyBucket(),
      }
      byAssignee.set(assigneeKey, ass)
    }
    tally(ass.bucket, row.status)

    const iso = new Date(row.starts_at * 1000).toISOString().slice(0, 10)
    let day = byDay.get(iso)
    if (!day) {
      day = { day: iso, booked: 0, showed: 0, no_show: 0 }
      byDay.set(iso, day)
    }
    day.booked += 1
    if (row.status === 'showed') day.showed += 1
    else if (row.status === 'no_show') day.no_show += 1
  }

  const decided = (b: CrmAppointmentsReportBucket): number => b.showed + b.no_show
  const showRate = (b: CrmAppointmentsReportBucket): number => decided(b) === 0 ? 0 : b.showed / decided(b)
  const noShowRate = (b: CrmAppointmentsReportBucket): number => decided(b) === 0 ? 0 : b.no_show / decided(b)

  const by_calendar: CrmAppointmentsReportCalendarRow[] = Array.from(byCalendar.entries())
    .map(([id, v]) => ({ calendar_id: id, calendar_name: v.name, ...v.bucket, show_rate: showRate(v.bucket) }))
    .sort((a, b) => b.booked - a.booked || a.calendar_name.localeCompare(b.calendar_name))

  const by_assignee: CrmAppointmentsReportAssigneeRow[] = Array.from(byAssignee.values())
    .map((v) => ({ user_id: v.user_id, user_name: v.user_name, ...v.bucket, show_rate: showRate(v.bucket) }))
    .sort((a, b) => b.booked - a.booked || a.user_name.localeCompare(b.user_name))

  // Fill missing days with zeros so the trend chart is contiguous.
  const by_day: CrmAppointmentsReportDayRow[] = []
  const now = new Date()
  const trendDays = Math.min(days, 90)
  for (let i = trendDays - 1; i >= 0; i -= 1) {
    const dt = new Date(now)
    dt.setUTCDate(dt.getUTCDate() - i)
    const iso = dt.toISOString().slice(0, 10)
    by_day.push(byDay.get(iso) ?? { day: iso, booked: 0, showed: 0, no_show: 0 })
  }

  return {
    window_days: days,
    totals: { ...totals, show_rate: showRate(totals), no_show_rate: noShowRate(totals) },
    by_calendar,
    by_assignee,
    by_day,
  }
}

// ─── Lead ad submissions ──────────────────────────────────────────────────

export type CrmLeadAdSource = 'facebook' | 'google'

export interface CrmLeadAdSubmission {
  id: number
  workspace_id: number
  source: CrmLeadAdSource
  platform_lead_id: string
  ad_id: string | null
  ad_name: string | null
  adset_id: string | null
  adset_name: string | null
  campaign_id: string | null
  campaign_name: string | null
  form_id: string | null
  form_name: string | null
  raw_json: string
  contact_id: number | null
  email: string | null
  phone: string | null
  full_name: string | null
  created_at: string
}

/**
 * Idempotent insert of a lead-ad submission. If a row already exists with the
 * same (source, platform_lead_id) pair, returns { inserted: false } and the
 * existing row — callers can skip contact upsert + trigger firing to avoid
 * double-processing Facebook's retry storm.
 */
export function recordCrmLeadAdSubmission(data: {
  workspaceId: number
  source: CrmLeadAdSource
  platformLeadId: string
  adId?: string | null
  adName?: string | null
  adsetId?: string | null
  adsetName?: string | null
  campaignId?: string | null
  campaignName?: string | null
  formId?: string | null
  formName?: string | null
  rawJson: string
  contactId?: number | null
  email?: string | null
  phone?: string | null
  fullName?: string | null
}): { inserted: boolean; submission: CrmLeadAdSubmission } {
  const existing = getDb()
    .prepare('SELECT * FROM crm_lead_ad_submissions WHERE source = ? AND platform_lead_id = ?')
    .get(data.source, data.platformLeadId) as CrmLeadAdSubmission | undefined
  if (existing) return { inserted: false, submission: existing }

  const info = getDb().prepare(`
    INSERT INTO crm_lead_ad_submissions (
      workspace_id, source, platform_lead_id,
      ad_id, ad_name, adset_id, adset_name,
      campaign_id, campaign_name, form_id, form_name,
      raw_json, contact_id, email, phone, full_name
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    data.workspaceId,
    data.source,
    data.platformLeadId,
    data.adId ?? null,
    data.adName ?? null,
    data.adsetId ?? null,
    data.adsetName ?? null,
    data.campaignId ?? null,
    data.campaignName ?? null,
    data.formId ?? null,
    data.formName ?? null,
    data.rawJson,
    data.contactId ?? null,
    data.email ?? null,
    data.phone ?? null,
    data.fullName ?? null,
  )
  const row = getDb()
    .prepare('SELECT * FROM crm_lead_ad_submissions WHERE id = ?')
    .get(Number(info.lastInsertRowid)) as CrmLeadAdSubmission
  return { inserted: true, submission: row }
}

export interface CrmLeadAdsReportRow {
  id: number
  source: CrmLeadAdSource
  ad_name: string | null
  campaign_name: string | null
  form_name: string | null
  contact_id: number | null
  contact_name: string | null
  full_name: string | null
  email: string | null
  created_at: string
}

export interface CrmLeadAdsReport {
  window_days: number
  totals: {
    total: number
    facebook: number
    google: number
    became_opportunities: number
  }
  recent: CrmLeadAdsReportRow[]
}

export function getCrmLeadAdsReport(workspaceId: number, windowDays: number): CrmLeadAdsReport {
  const days = Math.max(1, Math.min(3650, Math.floor(windowDays)))
  const cutoffIso = new Date(Date.now() - days * 86_400_000).toISOString()

  const totalsRow = getDb().prepare(`
    SELECT
      COUNT(*) AS total,
      SUM(CASE WHEN source = 'facebook' THEN 1 ELSE 0 END) AS facebook,
      SUM(CASE WHEN source = 'google'   THEN 1 ELSE 0 END) AS google
    FROM crm_lead_ad_submissions
    WHERE workspace_id = ? AND created_at >= ?
  `).get(workspaceId, cutoffIso) as { total: number; facebook: number | null; google: number | null } | undefined

  const oppRow = getDb().prepare(`
    SELECT COUNT(DISTINCT s.contact_id) AS became
    FROM crm_lead_ad_submissions s
    INNER JOIN crm_opportunities o ON o.contact_id = s.contact_id AND o.workspace_id = s.workspace_id
    WHERE s.workspace_id = ? AND s.created_at >= ? AND s.contact_id IS NOT NULL
  `).get(workspaceId, cutoffIso) as { became: number | null } | undefined

  const recentRows = getDb().prepare(`
    SELECT s.id, s.source, s.ad_name, s.campaign_name, s.form_name,
           s.contact_id, s.full_name, s.email, s.created_at,
           c.name AS contact_name
    FROM crm_lead_ad_submissions s
    LEFT JOIN crm_contacts c ON c.id = s.contact_id
    WHERE s.workspace_id = ? AND s.created_at >= ?
    ORDER BY s.created_at DESC
    LIMIT 50
  `).all(workspaceId, cutoffIso) as CrmLeadAdsReportRow[]

  return {
    window_days: days,
    totals: {
      total: Number(totalsRow?.total || 0),
      facebook: Number(totalsRow?.facebook || 0),
      google: Number(totalsRow?.google || 0),
      became_opportunities: Number(oppRow?.became || 0),
    },
    recent: recentRows,
  }
}

export interface CrmNewLeadRow {
  submission_id: number
  contact_id: number | null
  name: string | null
  email: string | null
  phone: string | null
  source: CrmLeadAdSource
  form_name: string | null
  created_at: string
}

/**
 * Recent lead-ad submissions for the right-sidebar "new leads" widget.
 * Joins crm_contacts so the widget can render the contact name without
 * a second lookup. Falls back to the submission's own full_name when the
 * contact row is gone (contact_id set null by ON DELETE SET NULL).
 */
export function getRecentCrmNewLeads(workspaceId: number, limit: number): CrmNewLeadRow[] {
  const capped = Math.max(1, Math.min(50, Math.floor(limit)))
  return getDb().prepare(`
    SELECT
      s.id         AS submission_id,
      s.contact_id AS contact_id,
      COALESCE(c.name, s.full_name) AS name,
      COALESCE(c.email, s.email)    AS email,
      COALESCE(c.phone, s.phone)    AS phone,
      s.source     AS source,
      s.form_name  AS form_name,
      s.created_at AS created_at
    FROM crm_lead_ad_submissions s
    LEFT JOIN crm_contacts c ON c.id = s.contact_id
    WHERE s.workspace_id = ?
    ORDER BY s.created_at DESC
    LIMIT ?
  `).all(workspaceId, capped) as CrmNewLeadRow[]
}

// ─── Lead-ad integration settings ─────────────────────────────────────────

export interface CrmLeadAdsIntegrationSettings {
  workspace_public_id: string
  facebook_page_access_tokens: Array<{ page_id: string; access_token: string }>
  facebook_webhook_verify_token: string | null
  google_ads_api_token: string | null
}

export function getCrmLeadAdsIntegrationSettings(workspaceId: number): CrmLeadAdsIntegrationSettings | null {
  const row = getDb().prepare(`
    SELECT public_id, facebook_page_access_tokens, facebook_webhook_verify_token, google_ads_api_token
    FROM workspaces WHERE id = ?
  `).get(workspaceId) as {
    public_id: string
    facebook_page_access_tokens: string | null
    facebook_webhook_verify_token: string | null
    google_ads_api_token: string | null
  } | undefined
  if (!row) return null

  return {
    workspace_public_id: row.public_id,
    facebook_page_access_tokens: parseFacebookPageTokens(row.facebook_page_access_tokens),
    facebook_webhook_verify_token: row.facebook_webhook_verify_token,
    google_ads_api_token: row.google_ads_api_token,
  }
}

export function updateCrmLeadAdsIntegrationSettings(workspaceId: number, patch: {
  facebook_page_access_tokens?: Array<{ page_id: string; access_token: string }>
  facebook_webhook_verify_token?: string | null
  google_ads_api_token?: string | null
}): CrmLeadAdsIntegrationSettings | null {
  const sets: string[] = []
  const args: Array<string | null> = []

  if (patch.facebook_page_access_tokens !== undefined) {
    const clean = patch.facebook_page_access_tokens
      .map((p) => ({ page_id: String(p.page_id || '').trim(), access_token: String(p.access_token || '').trim() }))
      .filter((p) => p.page_id && p.access_token)
    const map: Record<string, string> = {}
    for (const p of clean) map[p.page_id] = p.access_token
    sets.push('facebook_page_access_tokens = ?')
    args.push(clean.length > 0 ? JSON.stringify(map) : null)
  }
  if (patch.facebook_webhook_verify_token !== undefined) {
    const v = (patch.facebook_webhook_verify_token || '').trim()
    sets.push('facebook_webhook_verify_token = ?')
    args.push(v || null)
  }
  if (patch.google_ads_api_token !== undefined) {
    const v = (patch.google_ads_api_token || '').trim()
    sets.push('google_ads_api_token = ?')
    args.push(v || null)
  }
  if (sets.length === 0) return getCrmLeadAdsIntegrationSettings(workspaceId)

  getDb().prepare(`UPDATE workspaces SET ${sets.join(', ')} WHERE id = ?`).run(...args, workspaceId)
  return getCrmLeadAdsIntegrationSettings(workspaceId)
}

/**
 * Looks up the Facebook page access token configured for a workspace's
 * lead-ads integration. Returns null if the workspace has no token map or if
 * the requested pageId is not in the map.
 */
export function getFacebookPageAccessToken(workspaceId: number, pageId: string): string | null {
  const row = getDb()
    .prepare('SELECT facebook_page_access_tokens FROM workspaces WHERE id = ?')
    .get(workspaceId) as { facebook_page_access_tokens: string | null } | undefined
  if (!row?.facebook_page_access_tokens) return null
  const map = parseFacebookPageTokensMap(row.facebook_page_access_tokens)
  return map[pageId] || null
}

function parseFacebookPageTokensMap(raw: string | null): Record<string, string> {
  if (!raw) return {}
  try {
    const parsed = JSON.parse(raw) as unknown
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return {}
    const out: Record<string, string> = {}
    for (const [k, v] of Object.entries(parsed as Record<string, unknown>)) {
      if (typeof v === 'string' && v) out[k] = v
    }
    return out
  } catch {
    return {}
  }
}

function parseFacebookPageTokens(raw: string | null): Array<{ page_id: string; access_token: string }> {
  const map = parseFacebookPageTokensMap(raw)
  return Object.entries(map).map(([page_id, access_token]) => ({ page_id, access_token }))
}

// ─── Pixel tracking ────────────────────────────────────────────────────────

export interface CrmPixelEvent {
  id: number
  workspace_id: number
  contact_id: number | null
  event: string
  url: string | null
  title: string | null
  referrer: string | null
  props_json: string | null
  cid: string | null
  created_at: number
}

export function createCrmPixelEvent(data: {
  workspaceId: number
  contactId?: number | null
  event: string
  url?: string | null
  title?: string | null
  referrer?: string | null
  props?: Record<string, unknown> | null
  cid?: string | null
}): CrmPixelEvent {
  const propsJson = data.props ? JSON.stringify(data.props) : null
  const result = getDb().prepare(`
    INSERT INTO crm_pixel_events (workspace_id, contact_id, event, url, title, referrer, props_json, cid)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    data.workspaceId,
    data.contactId ?? null,
    data.event,
    data.url ?? null,
    data.title ?? null,
    data.referrer ?? null,
    propsJson,
    data.cid ?? null,
  )
  return getDb()
    .prepare('SELECT * FROM crm_pixel_events WHERE id = ?')
    .get(Number(result.lastInsertRowid)) as CrmPixelEvent
}

export function getContactIdForCid(workspaceId: number, cid: string): number | null {
  if (!cid) return null
  const row = getDb()
    .prepare('SELECT contact_id FROM crm_pixel_identities WHERE workspace_id = ? AND cid = ?')
    .get(workspaceId, cid) as { contact_id: number } | undefined
  return row?.contact_id ?? null
}

export function bindPixelIdentity(workspaceId: number, cid: string, contactId: number): void {
  if (!cid || !contactId) return
  getDb().prepare(`
    INSERT INTO crm_pixel_identities (workspace_id, cid, contact_id)
    VALUES (?, ?, ?)
    ON CONFLICT(workspace_id, cid) DO UPDATE SET contact_id = excluded.contact_id
  `).run(workspaceId, cid, contactId)
  // Backfill: any previous pageviews with this cid get stamped with the contact.
  getDb().prepare(`
    UPDATE crm_pixel_events SET contact_id = ?
    WHERE workspace_id = ? AND cid = ? AND contact_id IS NULL
  `).run(contactId, workspaceId, cid)
}

export function listRecentPixelEventsForContact(contactId: number, workspaceId: number, limit = 10): CrmPixelEvent[] {
  const capped = Math.min(100, Math.max(1, Math.floor(limit)))
  return getDb().prepare(`
    SELECT * FROM crm_pixel_events
    WHERE workspace_id = ? AND contact_id = ?
    ORDER BY created_at DESC, id DESC
    LIMIT ?
  `).all(workspaceId, contactId, capped) as CrmPixelEvent[]
}

