function nowIsoText(): string {
  return new Date().toISOString()
}

function getCrmAttributionEncryptionKey(): Buffer {
  const seed = process.env.TOKEN_ENCRYPTION_KEY
    || process.env.INTERNAL_API_SECRET
    || process.env.SUPABASE_SERVICE_ROLE_KEY
    || 'ctrl-motion-attribution-token-key'
  return crypto.createHash('sha256').update(seed).digest().subarray(0, 32)
}

function encryptCrmConversionToken(plaintext: string): string {
  const iv = crypto.randomBytes(12)
  const cipher = crypto.createCipheriv('aes-256-gcm', getCrmAttributionEncryptionKey(), iv)
  const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()])
  const tag = cipher.getAuthTag()
  return `${iv.toString('hex')}:${tag.toString('hex')}:${encrypted.toString('hex')}`
}

function trimOrNull(value: unknown): string | null {
  if (value === null || value === undefined) return null
  const trimmed = String(value).trim()
  return trimmed.length > 0 ? trimmed : null
}

function normalizeTrackingEventName(value: string): string {
  const trimmed = trimOrNull(value)
  if (!trimmed) return 'page_view'
  return trimmed.toLowerCase().replace(/\s+/g, '_')
}

function parseTrackingUrl(url: string | null): {
  utm_source: string | null
  utm_medium: string | null
  utm_campaign: string | null
  utm_content: string | null
  utm_term: string | null
  gclid: string | null
} {
  const empty = {
    utm_source: null,
    utm_medium: null,
    utm_campaign: null,
    utm_content: null,
    utm_term: null,
    gclid: null,
  }
  if (!url) return empty
  try {
    const parsed = new URL(url, 'https://ctrl.local')
    const pick = (key: string) => trimOrNull(parsed.searchParams.get(key))
    return {
      utm_source: pick('utm_source')?.toLowerCase() || null,
      utm_medium: pick('utm_medium')?.toLowerCase() || null,
      utm_campaign: pick('utm_campaign'),
      utm_content: pick('utm_content'),
      utm_term: pick('utm_term'),
      gclid: pick('gclid'),
    }
  } catch {
    return empty
  }
}

