export function createCrmConversionApiEndpoint(workspaceId: number, data: {
  platform: CrmConversionApiPlatform
  access_token: string
  pixel_id_or_dataset: string
  test_event_code?: string | null
  is_active?: boolean
}): CrmConversionApiEndpointSummary {
  const platform = trimOrNull(data.platform)?.toLowerCase() as CrmConversionApiPlatform | null
  if (!platform || !(['meta', 'google_ads', 'tiktok'] as const).includes(platform)) throw new Error('Invalid platform')
  const accessToken = trimOrNull(data.access_token)
  const dataset = trimOrNull(data.pixel_id_or_dataset)
  if (!accessToken) throw new Error('access_token is required')
  if (!dataset) throw new Error('pixel_id_or_dataset is required')
  const now = nowIsoText()
  const result = getDb().prepare(`
    INSERT INTO crm_conversion_api_endpoints (
      workspace_id, platform, access_token_encrypted, pixel_id_or_dataset, test_event_code, is_active, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    platform,
    encryptCrmConversionToken(accessToken),
    dataset,
    trimOrNull(data.test_event_code),
    data.is_active === false ? 0 : 1,
    now,
    now,
  )
  return getCrmConversionApiEndpointSummaryById(Number(result.lastInsertRowid), workspaceId) as CrmConversionApiEndpointSummary
}

export function updateCrmConversionApiEndpoint(id: number, workspaceId: number, patch: Partial<{
  platform: CrmConversionApiPlatform
  access_token: string
  pixel_id_or_dataset: string
  test_event_code: string | null
  is_active: boolean
}>): CrmConversionApiEndpointSummary | null {
  const existing = getCrmConversionApiEndpointRecordById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: Array<string | number | null> = []

  if (patch.platform !== undefined) {
    const platform = trimOrNull(patch.platform)?.toLowerCase() as CrmConversionApiPlatform | null
    if (!platform || !(['meta', 'google_ads', 'tiktok'] as const).includes(platform)) throw new Error('Invalid platform')
    sets.push('platform = ?')
    args.push(platform)
  }
  if (patch.access_token !== undefined) {
    const token = trimOrNull(patch.access_token)
    if (token) {
      sets.push('access_token_encrypted = ?')
      args.push(encryptCrmConversionToken(token))
    }
  }
  if (patch.pixel_id_or_dataset !== undefined) {
    const dataset = trimOrNull(patch.pixel_id_or_dataset)
    if (!dataset) throw new Error('pixel_id_or_dataset is required')
    sets.push('pixel_id_or_dataset = ?')
    args.push(dataset)
  }
  if (patch.test_event_code !== undefined) {
    sets.push('test_event_code = ?')
    args.push(trimOrNull(patch.test_event_code))
  }
  if (patch.is_active !== undefined) {
    sets.push('is_active = ?')
    args.push(patch.is_active ? 1 : 0)
  }
  if (sets.length === 0) return getCrmConversionApiEndpointSummaryById(id, workspaceId)

  sets.push('updated_at = ?')
  args.push(nowIsoText())
  args.push(id, workspaceId)
  getDb().prepare(`
    UPDATE crm_conversion_api_endpoints
    SET ${sets.join(', ')}
    WHERE id = ? AND workspace_id = ?
  `).run(...args)
  return getCrmConversionApiEndpointSummaryById(id, workspaceId)
}

export function deleteCrmConversionApiEndpoint(id: number, workspaceId: number): boolean {
  const info = getDb().prepare(`
    DELETE FROM crm_conversion_api_endpoints
    WHERE id = ? AND workspace_id = ?
  `).run(id, workspaceId)
  return info.changes > 0
}

export function queueCrmConversionForwardsForEvent(data: {
  workspaceId: number
  eventId: number
  endpointId?: number | null
}): { queued: number; endpointIds: number[] } {
  const db = getDb()
  const args: Array<number> = [data.workspaceId]
  const endpointFilter = data.endpointId ? 'AND id = ?' : 'AND is_active = 1'
  if (data.endpointId) args.push(data.endpointId)
  const endpoints = db.prepare(`
    SELECT id
    FROM crm_conversion_api_endpoints
    WHERE workspace_id = ? ${endpointFilter}
    ORDER BY id ASC
  `).all(...args) as Array<{ id: number }>
  if (!endpoints.length) return { queued: 0, endpointIds: [] }

  const insert = db.prepare(`
    INSERT OR IGNORE INTO crm_conversion_forwards (
      endpoint_id, event_id, workspace_id, status, request_json, response_json, created_at, updated_at
    )
    VALUES (?, ?, ?, 'pending', ?, NULL, ?, ?)
  `)
  const now = nowIsoText()
  let queued = 0
  const endpointIds: number[] = []
  db.transaction(() => {
    for (const endpoint of endpoints) {
      const info = insert.run(
        endpoint.id,
        data.eventId,
        data.workspaceId,
        JSON.stringify({ event_id: data.eventId, endpoint_id: endpoint.id, queued_at: now }),
        now,
        now,
      )
      if (info.changes > 0) {
        queued += 1
        endpointIds.push(endpoint.id)
      }
    }
  })()
  return { queued, endpointIds }
}

export function listPendingCrmConversionForwards(limit = 20): PendingCrmConversionForward[] {
  const capped = Math.min(100, Math.max(1, Math.floor(limit)))
  return getDb().prepare(`
    SELECT f.*,
           e.platform AS endpoint_platform,
           e.access_token_encrypted AS endpoint_access_token_encrypted,
           e.pixel_id_or_dataset AS endpoint_pixel_id_or_dataset,
           e.test_event_code AS endpoint_test_event_code,
           e.is_active AS endpoint_is_active,
           ev.event_name,
           ev.url AS event_url,
           ev.event_data_json,
           ev.created_at AS event_created_at,
           ev.contact_id AS event_contact_id,
           s.session_id,
           s.contact_id AS session_contact_id,
           s.first_utm_source,
           s.first_utm_medium,
           s.first_utm_campaign,
           s.first_referrer,
           s.first_landing_url,
           s.last_utm_source,
           s.last_utm_medium,
           s.last_utm_campaign,
           s.last_referrer,
           s.fbp,
           s.fbc,
           s.gclid,
           s.ip_hash,
           s.ua
    FROM crm_conversion_forwards f
    JOIN crm_conversion_api_endpoints e ON e.id = f.endpoint_id
    JOIN crm_tracking_events ev ON ev.id = f.event_id
    JOIN crm_tracking_pixel_sessions s ON s.session_id = ev.session_id
    WHERE f.status = 'pending'
    ORDER BY f.created_at ASC, f.id ASC
    LIMIT ?
  `).all(capped) as PendingCrmConversionForward[]
}

export function updateCrmConversionForward(id: number, patch: {
  status: CrmConversionForwardStatus
  request_json?: string | null
  response_json?: string | null
}): void {
  if (!(['pending', 'sent', 'failed'] as const).includes(patch.status)) throw new Error('Invalid forward status')
  getDb().prepare(`
    UPDATE crm_conversion_forwards
    SET status = ?,
        request_json = COALESCE(?, request_json),
        response_json = COALESCE(?, response_json),
        updated_at = ?
    WHERE id = ?
  `).run(
    patch.status,
    patch.request_json === undefined ? null : patch.request_json,
    patch.response_json === undefined ? null : patch.response_json,
    nowIsoText(),
    id,
  )
}

