// ────────────────────────────────────────────────────────────────────────────
// Voice AI receptionist
// ────────────────────────────────────────────────────────────────────────────

export type CrmVoiceTool =
  | 'lookup_contact'
  | 'check_availability'
  | 'book_appointment'
  | 'take_message'
  | 'transfer_to_human'

export const CRM_VOICE_TOOLS: ReadonlyArray<CrmVoiceTool> = [
  'lookup_contact',
  'check_availability',
  'book_appointment',
  'take_message',
  'transfer_to_human',
]

export interface CrmVoiceAgentRow {
  id: number
  workspace_id: number
  name: string
  vapi_assistant_id: string | null
  vapi_phone_number_id: string | null
  phone_number: string | null
  system_prompt: string
  first_message: string
  voice_id: string
  tools_enabled_json: string
  transfer_to_number: string | null
  is_active: number
  created_at: string
  updated_at: string
}

export interface CrmVoiceAgent extends Omit<CrmVoiceAgentRow, 'tools_enabled_json' | 'is_active'> {
  tools_enabled: CrmVoiceTool[]
  is_active: boolean
}

function enrichCrmVoiceAgent(row: CrmVoiceAgentRow): CrmVoiceAgent {
  let tools: CrmVoiceTool[] = []
  try {
    const parsed = JSON.parse(row.tools_enabled_json)
    if (Array.isArray(parsed)) {
      tools = parsed.filter((v): v is CrmVoiceTool =>
        typeof v === 'string' && (CRM_VOICE_TOOLS as readonly string[]).includes(v),
      )
    }
  } catch { /* default to empty */ }
  return {
    id: row.id,
    workspace_id: row.workspace_id,
    name: row.name,
    vapi_assistant_id: row.vapi_assistant_id,
    vapi_phone_number_id: row.vapi_phone_number_id,
    phone_number: row.phone_number,
    system_prompt: row.system_prompt,
    first_message: row.first_message,
    voice_id: row.voice_id,
    tools_enabled: tools,
    transfer_to_number: row.transfer_to_number,
    is_active: row.is_active === 1,
    created_at: row.created_at,
    updated_at: row.updated_at,
  }
}

