export function createCrmVoiceAgent(workspaceId: number, data: {
  name: string
  vapi_assistant_id?: string | null
  vapi_phone_number_id?: string | null
  phone_number?: string | null
  system_prompt: string
  first_message?: string
  voice_id?: string
  tools_enabled?: CrmVoiceTool[]
  transfer_to_number?: string | null
  is_active?: boolean
}): CrmVoiceAgent {
  const now = new Date().toISOString()
  const tools = normalizeVoiceTools(data.tools_enabled)
  const result = getDb().prepare(`
    INSERT INTO crm_voice_agents (
      workspace_id, name, vapi_assistant_id, vapi_phone_number_id, phone_number,
      system_prompt, first_message, voice_id, tools_enabled_json,
      transfer_to_number, is_active, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    data.name.trim(),
    data.vapi_assistant_id?.trim() || null,
    data.vapi_phone_number_id?.trim() || null,
    data.phone_number?.trim() || null,
    data.system_prompt.trim(),
    (data.first_message?.trim() || 'Hey, thanks for calling. How can I help?'),
    (data.voice_id?.trim() || 'alloy'),
    JSON.stringify(tools),
    data.transfer_to_number?.trim() || null,
    data.is_active === false ? 0 : 1,
    now,
    now,
  )
  return getCrmVoiceAgentById(Number(result.lastInsertRowid), workspaceId) as CrmVoiceAgent
}

export function updateCrmVoiceAgent(id: number, workspaceId: number, patch: Partial<{
  name: string
  vapi_assistant_id: string | null
  vapi_phone_number_id: string | null
  phone_number: string | null
  system_prompt: string
  first_message: string
  voice_id: string
  tools_enabled: CrmVoiceTool[]
  transfer_to_number: string | null
  is_active: boolean
}>): CrmVoiceAgent | null {
  const existing = getCrmVoiceAgentById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number | null)[] = []
  if (typeof patch.name === 'string') { sets.push('name = ?'); args.push(patch.name.trim()) }
  if ('vapi_assistant_id' in patch) { sets.push('vapi_assistant_id = ?'); args.push(patch.vapi_assistant_id?.trim() || null) }
  if ('vapi_phone_number_id' in patch) { sets.push('vapi_phone_number_id = ?'); args.push(patch.vapi_phone_number_id?.trim() || null) }
  if ('phone_number' in patch) { sets.push('phone_number = ?'); args.push(patch.phone_number?.trim() || null) }
  if (typeof patch.system_prompt === 'string') { sets.push('system_prompt = ?'); args.push(patch.system_prompt.trim()) }
  if (typeof patch.first_message === 'string') { sets.push('first_message = ?'); args.push(patch.first_message.trim() || 'Hey, thanks for calling. How can I help?') }
  if (typeof patch.voice_id === 'string') { sets.push('voice_id = ?'); args.push(patch.voice_id.trim() || 'alloy') }
  if (patch.tools_enabled) { sets.push('tools_enabled_json = ?'); args.push(JSON.stringify(normalizeVoiceTools(patch.tools_enabled))) }
  if ('transfer_to_number' in patch) { sets.push('transfer_to_number = ?'); args.push(patch.transfer_to_number?.trim() || null) }
  if (typeof patch.is_active === 'boolean') { sets.push('is_active = ?'); args.push(patch.is_active ? 1 : 0) }
  if (sets.length === 0) return existing
  sets.push('updated_at = ?')
  args.push(new Date().toISOString())
  args.push(id)
  args.push(workspaceId)
  getDb().prepare(`UPDATE crm_voice_agents SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...args)
  return getCrmVoiceAgentById(id, workspaceId)
}

export function deleteCrmVoiceAgent(id: number, workspaceId: number): boolean {
  const result = getDb()
    .prepare('DELETE FROM crm_voice_agents WHERE id = ? AND workspace_id = ?')
    .run(id, workspaceId)
  return result.changes > 0
}

function normalizeVoiceTools(tools?: CrmVoiceTool[]): CrmVoiceTool[] {
  if (!tools) return []
  const seen = new Set<CrmVoiceTool>()
  for (const tool of tools) {
    if ((CRM_VOICE_TOOLS as readonly string[]).includes(tool)) seen.add(tool)
  }
  return Array.from(seen)
}

