function slugifyCourse(value: string): string {
  return String(value || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80) || 'untitled'
}

function ensureUniqueCourseSlug(workspaceId: number, base: string, excludeId?: number): string {
  const d = getDb()
  let candidate = base
  let n = 2
  while (true) {
    const existing = excludeId
      ? d.prepare('SELECT id FROM crm_courses WHERE workspace_id = ? AND slug = ? AND id != ?').get(workspaceId, candidate, excludeId) as { id: number } | undefined
      : d.prepare('SELECT id FROM crm_courses WHERE workspace_id = ? AND slug = ?').get(workspaceId, candidate) as { id: number } | undefined
    if (!existing) return candidate
    candidate = `${base}-${n++}`
    if (n > 500) return `${base}-${Date.now()}`
  }
}

function ensureUniqueMembershipSlug(workspaceId: number, base: string, excludeId?: number): string {
  const d = getDb()
  let candidate = base
  let n = 2
  while (true) {
    const existing = excludeId
      ? d.prepare('SELECT id FROM crm_memberships WHERE workspace_id = ? AND slug = ? AND id != ?').get(workspaceId, candidate, excludeId) as { id: number } | undefined
      : d.prepare('SELECT id FROM crm_memberships WHERE workspace_id = ? AND slug = ?').get(workspaceId, candidate) as { id: number } | undefined
    if (!existing) return candidate
    candidate = `${base}-${n++}`
    if (n > 500) return `${base}-${Date.now()}`
  }
}

function ensureUniqueLessonSlug(courseId: number, base: string, excludeId?: number): string {
  const d = getDb()
  let candidate = base
  let n = 2
  while (true) {
    const existing = excludeId
      ? d.prepare('SELECT id FROM crm_course_lessons WHERE course_id = ? AND slug = ? AND id != ?').get(courseId, candidate, excludeId) as { id: number } | undefined
      : d.prepare('SELECT id FROM crm_course_lessons WHERE course_id = ? AND slug = ?').get(courseId, candidate) as { id: number } | undefined
    if (!existing) return candidate
    candidate = `${base}-${n++}`
    if (n > 500) return `${base}-${Date.now()}`
  }
}

function enrichCourse(row: CrmCourse): CrmCourseRecord {
  const d = getDb()
  const moduleRow = d.prepare('SELECT COUNT(*) as c FROM crm_course_modules WHERE course_id = ?').get(row.id) as { c: number }
  const lessonRow = d.prepare('SELECT COUNT(*) as c FROM crm_course_lessons WHERE course_id = ?').get(row.id) as { c: number }
  const memberRow = d.prepare('SELECT COUNT(*) as c FROM crm_member_course_enrollments WHERE course_id = ?').get(row.id) as { c: number }
  return {
    ...row,
    module_count: moduleRow?.c ?? 0,
    lesson_count: lessonRow?.c ?? 0,
    member_count: memberRow?.c ?? 0,
  }
}

export function listCrmCourses(workspaceId: number): CrmCourseRecord[] {
  const rows = getDb()
    .prepare('SELECT * FROM crm_courses WHERE workspace_id = ? ORDER BY updated_at DESC, id DESC')
    .all(workspaceId) as CrmCourse[]
  return rows.map(enrichCourse)
}

export function getCrmCourseById(id: number, workspaceId: number): CrmCourseRecord | null {
  const row = getDb()
    .prepare('SELECT * FROM crm_courses WHERE id = ? AND workspace_id = ?')
    .get(id, workspaceId) as CrmCourse | undefined
  return row ? enrichCourse(row) : null
}

export function getCrmCourseBySlug(slug: string, workspaceId: number): CrmCourseRecord | null {
  const row = getDb()
    .prepare('SELECT * FROM crm_courses WHERE slug = ? AND workspace_id = ?')
    .get(slug, workspaceId) as CrmCourse | undefined
  return row ? enrichCourse(row) : null
}
export function getCrmCourseBySlugAny(slug: string): CrmCourseRecord | null {
  const row = getDb()
    .prepare("SELECT * FROM crm_courses WHERE slug = ? AND status = 'published' ORDER BY updated_at DESC, id DESC LIMIT 1")
    .get(slug) as CrmCourse | undefined
  return row ? enrichCourse(row) : null
}

export function createCrmCourse(workspaceId: number, userId: number | null, data: {
  title: string
  description?: string | null
  thumbnail_url?: string | null
  status?: CrmCourseStatus
  drip_mode?: CrmCourseDripMode
  slug?: string | null
}): CrmCourseRecord {
  const title = (data.title || '').trim()
  if (!title) throw new Error('title is required')
  const base = slugifyCourse(data.slug?.trim() || title)
  const slug = ensureUniqueCourseSlug(workspaceId, base)
  const now = Math.floor(Date.now() / 1000)
  const status: CrmCourseStatus = data.status ?? 'draft'
  const result = getDb().prepare(`
    INSERT INTO crm_courses
      (workspace_id, title, slug, description, thumbnail_url, status, published_at, drip_mode, created_by_user_id, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    title,
    slug,
    data.description ?? null,
    data.thumbnail_url ?? null,
    status,
    status === 'published' ? now : null,
    data.drip_mode ?? 'none',
    userId,
    now,
    now,
  )
  const row = getCrmCourseById(Number(result.lastInsertRowid), workspaceId)
  if (!row) throw new Error('Course creation failed')
  return row
}

export function updateCrmCourse(id: number, workspaceId: number, patch: Partial<{
  title: string
  slug: string
  description: string | null
  thumbnail_url: string | null
  status: CrmCourseStatus
  drip_mode: CrmCourseDripMode
}>): CrmCourseRecord | null {
  const existing = getCrmCourseById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number | null)[] = []
  if (patch.title !== undefined) { sets.push('title = ?'); args.push(patch.title) }
  if (patch.slug !== undefined) {
    const newSlug = ensureUniqueCourseSlug(workspaceId, slugifyCourse(patch.slug), id)
    sets.push('slug = ?'); args.push(newSlug)
  }
  if (patch.description !== undefined) { sets.push('description = ?'); args.push(patch.description) }
  if (patch.thumbnail_url !== undefined) { sets.push('thumbnail_url = ?'); args.push(patch.thumbnail_url) }
  if (patch.status !== undefined) {
    sets.push('status = ?'); args.push(patch.status)
    if (patch.status === 'published' && !existing.published_at) {
      sets.push('published_at = ?'); args.push(Math.floor(Date.now() / 1000))
    }
  }
  if (patch.drip_mode !== undefined) { sets.push('drip_mode = ?'); args.push(patch.drip_mode) }
  if (sets.length === 0) return existing
  sets.push('updated_at = ?'); args.push(Math.floor(Date.now() / 1000))
  args.push(id, workspaceId)
  getDb().prepare(`UPDATE crm_courses SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...args)
  return getCrmCourseById(id, workspaceId)
}

export function deleteCrmCourse(id: number, workspaceId: number): boolean {
  const r = getDb().prepare('DELETE FROM crm_courses WHERE id = ? AND workspace_id = ?').run(id, workspaceId)
  return r.changes > 0
}

// ─── Modules ─────────────────────────────────────────────────────────────
export function listCrmCourseModules(courseId: number): CrmCourseModule[] {
  return getDb()
    .prepare('SELECT * FROM crm_course_modules WHERE course_id = ? ORDER BY sort_order ASC, id ASC')
    .all(courseId) as CrmCourseModule[]
}

export function createCrmCourseModule(courseId: number, title: string): CrmCourseModule {
  const trimmed = (title || '').trim() || 'Untitled module'
  const max = getDb().prepare('SELECT COALESCE(MAX(sort_order), -1) as m FROM crm_course_modules WHERE course_id = ?').get(courseId) as { m: number }
  const result = getDb().prepare(
    'INSERT INTO crm_course_modules (course_id, title, sort_order) VALUES (?, ?, ?)'
  ).run(courseId, trimmed, (max?.m ?? -1) + 1)
  return getDb().prepare('SELECT * FROM crm_course_modules WHERE id = ?').get(Number(result.lastInsertRowid)) as CrmCourseModule
}

export function updateCrmCourseModule(id: number, courseId: number, patch: { title?: string; sort_order?: number }): CrmCourseModule | null {
  const existing = getDb().prepare('SELECT * FROM crm_course_modules WHERE id = ? AND course_id = ?').get(id, courseId) as CrmCourseModule | undefined
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number)[] = []
  if (patch.title !== undefined) { sets.push('title = ?'); args.push(patch.title) }
  if (patch.sort_order !== undefined) { sets.push('sort_order = ?'); args.push(patch.sort_order) }
  if (sets.length === 0) return existing
  args.push(id)
  getDb().prepare(`UPDATE crm_course_modules SET ${sets.join(', ')} WHERE id = ?`).run(...args)
  return getDb().prepare('SELECT * FROM crm_course_modules WHERE id = ?').get(id) as CrmCourseModule
}

export function deleteCrmCourseModule(id: number, courseId: number): boolean {
  const r = getDb().prepare('DELETE FROM crm_course_modules WHERE id = ? AND course_id = ?').run(id, courseId)
  return r.changes > 0
}

