export function createCrmCourseLesson(courseId: number, data: {
  title: string
  module_id?: number | null
  lesson_type?: CrmCourseLessonType
  video_url?: string | null
  video_provider?: CrmCourseVideoProvider
  article_html?: string | null
  body_markdown?: string | null
  pdf_url?: string | null
  embed_html?: string | null
  assignment_prompt?: string | null
  duration_seconds?: number
  drip_day_offset?: number | null
  drip_release_at?: number | null
  is_free_preview?: boolean
  slug?: string
}): CrmCourseLesson {
  const title = (data.title || '').trim() || 'Untitled lesson'
  const base = slugifyCourse(data.slug?.trim() || title)
  const slug = ensureUniqueLessonSlug(courseId, base)
  const max = getDb().prepare('SELECT COALESCE(MAX(sort_order), -1) as m FROM crm_course_lessons WHERE course_id = ?').get(courseId) as { m: number }
  const now = Math.floor(Date.now() / 1000)
  const result = getDb().prepare(`
    INSERT INTO crm_course_lessons
      (course_id, module_id, title, slug, sort_order, lesson_type, video_url, video_provider, article_html, body_markdown, pdf_url, embed_html, assignment_prompt, duration_seconds, drip_day_offset, drip_release_at, is_free_preview, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    courseId,
    data.module_id ?? null,
    title,
    slug,
    (max?.m ?? -1) + 1,
    data.lesson_type ?? 'video',
    data.video_url ?? null,
    data.video_provider ?? null,
    data.article_html ?? data.body_markdown ?? null,
    data.body_markdown ?? data.article_html ?? null,
    data.pdf_url ?? null,
    data.embed_html ?? null,
    data.assignment_prompt ?? null,
    data.duration_seconds ?? 0,
    data.drip_day_offset ?? null,
    data.drip_release_at ?? null,
    data.is_free_preview ? 1 : 0,
    now,
    now,
  )
  return getDb().prepare('SELECT * FROM crm_course_lessons WHERE id = ?').get(Number(result.lastInsertRowid)) as CrmCourseLesson
}

export function updateCrmCourseLesson(id: number, courseId: number, patch: Partial<{
  title: string
  slug: string
  module_id: number | null
  sort_order: number
  lesson_type: CrmCourseLessonType
  video_url: string | null
  video_provider: CrmCourseVideoProvider
  article_html: string | null
  body_markdown: string | null
  pdf_url: string | null
  embed_html: string | null
  assignment_prompt: string | null
  duration_seconds: number
  drip_day_offset: number | null
  drip_release_at: number | null
  is_free_preview: boolean
}>): CrmCourseLesson | null {
  const existing = getCrmCourseLessonById(id, courseId)
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number | null)[] = []
  if (patch.title !== undefined) { sets.push('title = ?'); args.push(patch.title) }
  if (patch.slug !== undefined) {
    const newSlug = ensureUniqueLessonSlug(courseId, slugifyCourse(patch.slug), id)
    sets.push('slug = ?'); args.push(newSlug)
  }
  if (patch.module_id !== undefined) { sets.push('module_id = ?'); args.push(patch.module_id) }
  if (patch.sort_order !== undefined) { sets.push('sort_order = ?'); args.push(patch.sort_order) }
  if (patch.lesson_type !== undefined) { sets.push('lesson_type = ?'); args.push(patch.lesson_type) }
  if (patch.video_url !== undefined) { sets.push('video_url = ?'); args.push(patch.video_url) }
  if (patch.video_provider !== undefined) { sets.push('video_provider = ?'); args.push(patch.video_provider) }
  if (patch.article_html !== undefined) { sets.push('article_html = ?'); args.push(patch.article_html) }
  if (patch.body_markdown !== undefined) { sets.push('body_markdown = ?'); args.push(patch.body_markdown) }
  if (patch.pdf_url !== undefined) { sets.push('pdf_url = ?'); args.push(patch.pdf_url) }
  if (patch.embed_html !== undefined) { sets.push('embed_html = ?'); args.push(patch.embed_html) }
  if (patch.assignment_prompt !== undefined) { sets.push('assignment_prompt = ?'); args.push(patch.assignment_prompt) }
  if (patch.duration_seconds !== undefined) { sets.push('duration_seconds = ?'); args.push(patch.duration_seconds) }
  if (patch.drip_day_offset !== undefined) { sets.push('drip_day_offset = ?'); args.push(patch.drip_day_offset) }
  if (patch.drip_release_at !== undefined) { sets.push('drip_release_at = ?'); args.push(patch.drip_release_at) }
  if (patch.is_free_preview !== undefined) { sets.push('is_free_preview = ?'); args.push(patch.is_free_preview ? 1 : 0) }
  if (sets.length === 0) return existing
  sets.push('updated_at = ?'); args.push(Math.floor(Date.now() / 1000))
  args.push(id)
  getDb().prepare(`UPDATE crm_course_lessons SET ${sets.join(', ')} WHERE id = ?`).run(...args)
  return getCrmCourseLessonById(id, courseId)
}

