export function reorderCrmCourseContent(
  courseId: number,
  modules: Array<{ id: number; sort_order: number; title?: string }>,
  lessons: Array<{ id: number; sort_order: number; module_id: number | null }>,
): void {
  const d = getDb()
  const mStmt = d.prepare('UPDATE crm_course_modules SET sort_order = ?, title = COALESCE(?, title) WHERE id = ? AND course_id = ?')
  const lStmt = d.prepare('UPDATE crm_course_lessons SET sort_order = ?, module_id = ?, updated_at = strftime(\'%s\',\'now\') WHERE id = ? AND course_id = ?')
  const tx = d.transaction(() => {
    for (const m of modules) mStmt.run(m.sort_order, m.title ?? null, m.id, courseId)
    for (const l of lessons) lStmt.run(l.sort_order, l.module_id, l.id, courseId)
  })
  tx()
}

