export function replaceCrmCourseLessonResources(lessonId: number, resources: Array<{ label: string; url: string }>): void {
  const d = getDb()
  const tx = d.transaction(() => {
    d.prepare('DELETE FROM crm_course_lesson_resources WHERE lesson_id = ?').run(lessonId)
    const stmt = d.prepare('INSERT INTO crm_course_lesson_resources (lesson_id, label, url, sort_order) VALUES (?, ?, ?, ?)')
    resources.forEach((r, i) => stmt.run(lessonId, r.label.trim() || 'Resource', r.url.trim(), i))
  })
  tx()
}

