export function replaceCrmCourseQuizQuestions(
  quizId: number,
  questions: Array<{
    prompt: string
    question_type: 'single' | 'multi' | 'text'
    options: Array<{ label: string; is_correct: boolean }>
  }>,
): void {
  const d = getDb()
  const tx = d.transaction(() => {
    d.prepare('DELETE FROM crm_course_quiz_questions WHERE quiz_id = ?').run(quizId)
    const qStmt = d.prepare('INSERT INTO crm_course_quiz_questions (quiz_id, prompt, question_type, sort_order) VALUES (?, ?, ?, ?)')
    const oStmt = d.prepare('INSERT INTO crm_course_quiz_options (question_id, label, is_correct, sort_order) VALUES (?, ?, ?, ?)')
    questions.forEach((q, i) => {
      const prompt = (q.prompt || '').trim() || 'Question'
      const r = qStmt.run(quizId, prompt, q.question_type, i)
      const qid = Number(r.lastInsertRowid)
      q.options.forEach((o, j) => oStmt.run(qid, (o.label || '').trim() || 'Option', o.is_correct ? 1 : 0, j))
    })
    d.prepare('UPDATE crm_course_quizzes SET question_count = ? WHERE id = ?').run(questions.length, quizId)
  })
  tx()
}

// ─── Memberships ────────────────────────────────────────────────────────
function enrichMembership(row: CrmMembership): CrmMembershipRecord {
  const d = getDb()
  const courseRow = row.access_type === 'all_courses'
    ? d.prepare('SELECT COUNT(*) as c FROM crm_courses WHERE workspace_id = ?').get(row.workspace_id) as { c: number }
    : d.prepare('SELECT COUNT(*) as c FROM crm_membership_course_access WHERE membership_id = ?').get(row.id) as { c: number }
  const memberRow = d.prepare("SELECT COUNT(*) as c FROM crm_members WHERE membership_id = ? AND status = 'active'").get(row.id) as { c: number }
  return {
    ...row,
    course_count: courseRow?.c ?? 0,
    member_count: memberRow?.c ?? 0,
  }
}

export function listCrmMemberships(workspaceId: number): CrmMembershipRecord[] {
  const rows = getDb()
    .prepare('SELECT * FROM crm_memberships WHERE workspace_id = ? ORDER BY updated_at DESC, id DESC')
    .all(workspaceId) as CrmMembership[]
  return rows.map(enrichMembership)
}

