export function createCrmMember(workspaceId: number, data: {
  contact_id: number
  membership_id?: number | null
  status?: CrmMemberStatus
  login_email?: string | null
  password_hash?: string | null
  access_password_hash?: string | null
}): CrmMemberRecord {
  const contact = getDb().prepare('SELECT email FROM crm_contacts WHERE id = ?').get(data.contact_id) as { email: string | null } | undefined
  const loginEmail = (data.login_email ?? contact?.email ?? null)
  const passwordHash = data.password_hash ?? data.access_password_hash ?? null
  const now = Math.floor(Date.now() / 1000)
  const result = getDb().prepare(`
    INSERT INTO crm_members
      (workspace_id, contact_id, membership_id, status, login_email, password_hash, access_password_hash, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    data.contact_id,
    data.membership_id ?? null,
    data.status ?? 'active',
    loginEmail ? String(loginEmail).trim().toLowerCase() : null,
    passwordHash,
    passwordHash,
    now,
    now,
  )
  const row = getCrmMemberById(Number(result.lastInsertRowid), workspaceId)
  if (!row) throw new Error('Member creation failed')
  return row
}

export function updateCrmMember(id: number, workspaceId: number, patch: Partial<{
  membership_id: number | null
  status: CrmMemberStatus
  login_email: string | null
  password_hash: string | null
  login_token: string | null
  access_password_hash: string | null
  last_login: number | null
  last_login_at: number | null
  cancelled_at: number | null
}>): CrmMemberRecord | null {
  const existing = getCrmMemberById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number | null)[] = []
  if (patch.membership_id !== undefined) { sets.push('membership_id = ?'); args.push(patch.membership_id) }
  if (patch.status !== undefined) {
    sets.push('status = ?'); args.push(patch.status)
    if (patch.status === 'cancelled' && !existing.cancelled_at) {
      sets.push('cancelled_at = ?'); args.push(Math.floor(Date.now() / 1000))
    }
  }
  if (patch.login_email !== undefined) { sets.push('login_email = ?'); args.push(patch.login_email ? patch.login_email.trim().toLowerCase() : null) }
  const passwordHash = patch.password_hash !== undefined ? patch.password_hash : patch.access_password_hash
  if (passwordHash !== undefined) {
    sets.push('password_hash = ?'); args.push(passwordHash)
    sets.push('access_password_hash = ?'); args.push(passwordHash)
  }
  if (patch.login_token !== undefined) { sets.push('login_token = ?'); args.push(patch.login_token) }
  const lastLogin = patch.last_login !== undefined ? patch.last_login : patch.last_login_at
  if (lastLogin !== undefined) {
    sets.push('last_login = ?'); args.push(lastLogin)
    sets.push('last_login_at = ?'); args.push(lastLogin)
  }
  if (patch.cancelled_at !== undefined) { sets.push('cancelled_at = ?'); args.push(patch.cancelled_at) }
  if (sets.length === 0) return existing
  sets.push('updated_at = ?'); args.push(Math.floor(Date.now() / 1000))
  args.push(id, workspaceId)
  getDb().prepare(`UPDATE crm_members SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...args)
  return getCrmMemberById(id, workspaceId)
}

export function deleteCrmMember(id: number, workspaceId: number): boolean {
  const r = getDb().prepare('DELETE FROM crm_members WHERE id = ? AND workspace_id = ?').run(id, workspaceId)
  return r.changes > 0
}

