export function listCrmMemberEnrollments(memberId: number): CrmMemberCourseEnrollment[] {
  return getDb()
    .prepare('SELECT * FROM crm_member_course_enrollments WHERE member_id = ? ORDER BY enrolled_at DESC')
    .all(memberId) as CrmMemberCourseEnrollment[]
}

export function getCrmMemberEnrollment(memberId: number, courseId: number): CrmMemberCourseEnrollment | null {
  return (getDb()
    .prepare('SELECT * FROM crm_member_course_enrollments WHERE member_id = ? AND course_id = ?')
    .get(memberId, courseId) as CrmMemberCourseEnrollment | undefined) ?? null
}

/** Idempotent. Returns the row (existing or newly created). */
export function ensureCrmMemberEnrollment(memberId: number, courseId: number): { enrollment: CrmMemberCourseEnrollment; created: boolean } {
  const existing = getCrmMemberEnrollment(memberId, courseId)
  if (existing) return { enrollment: existing, created: false }
  const now = Math.floor(Date.now() / 1000)
  getDb().prepare('INSERT INTO crm_member_course_enrollments (member_id, course_id, enrolled_at, completion_pct) VALUES (?, ?, ?, 0)').run(memberId, courseId, now)
  const created = getCrmMemberEnrollment(memberId, courseId)!
  return { enrollment: created, created: true }
}

export function revokeCrmMemberEnrollment(memberId: number, courseId: number): boolean {
  const r = getDb().prepare('DELETE FROM crm_member_course_enrollments WHERE member_id = ? AND course_id = ?').run(memberId, courseId)
  return r.changes > 0
}

export function listCrmMemberLessonProgress(memberId: number, courseId: number): CrmMemberLessonProgress[] {
  return getDb().prepare(`
    SELECT p.* FROM crm_member_lesson_progress p
    JOIN crm_course_lessons l ON l.id = p.lesson_id
    WHERE p.member_id = ? AND l.course_id = ?
  `).all(memberId, courseId) as CrmMemberLessonProgress[]
}

export function recordCrmLessonProgress(memberId: number, lessonId: number, patch: {
  started?: boolean
  completed?: boolean
  last_position_seconds?: number
  seconds_watched_delta?: number
}): CrmMemberLessonProgress {
  const d = getDb()
  const existing = d.prepare('SELECT * FROM crm_member_lesson_progress WHERE member_id = ? AND lesson_id = ?')
    .get(memberId, lessonId) as CrmMemberLessonProgress | undefined
  const now = Math.floor(Date.now() / 1000)
  if (!existing) {
    d.prepare(`
      INSERT INTO crm_member_lesson_progress
        (member_id, lesson_id, started_at, completed_at, last_position_seconds, seconds_watched)
      VALUES (?, ?, ?, ?, ?, ?)
    `).run(
      memberId,
      lessonId,
      patch.started ? now : null,
      patch.completed ? now : null,
      Math.max(0, Math.floor(patch.last_position_seconds ?? 0)),
      Math.max(0, Math.floor(patch.seconds_watched_delta ?? 0)),
    )
  } else {
    const sets: string[] = []
    const args: (number | null)[] = []
    if (patch.started && !existing.started_at) { sets.push('started_at = ?'); args.push(now) }
    if (patch.completed && !existing.completed_at) { sets.push('completed_at = ?'); args.push(now) }
    if (patch.last_position_seconds !== undefined) {
      sets.push('last_position_seconds = ?'); args.push(Math.max(0, Math.floor(patch.last_position_seconds)))
    }
    if (patch.seconds_watched_delta && patch.seconds_watched_delta > 0) {
      sets.push('seconds_watched = seconds_watched + ?'); args.push(Math.floor(patch.seconds_watched_delta))
    }
    if (sets.length > 0) {
      args.push(memberId, lessonId)
      d.prepare(`UPDATE crm_member_lesson_progress SET ${sets.join(', ')} WHERE member_id = ? AND lesson_id = ?`).run(...args)
    }
  }
  return d.prepare('SELECT * FROM crm_member_lesson_progress WHERE member_id = ? AND lesson_id = ?')
    .get(memberId, lessonId) as CrmMemberLessonProgress
}

/** Recompute completion % for a course enrollment based on lesson progress. */
export function recomputeCrmCourseCompletion(memberId: number, courseId: number): { pct: number; completed: boolean } {
  const d = getDb()
  const lessons = d.prepare('SELECT id FROM crm_course_lessons WHERE course_id = ?').all(courseId) as Array<{ id: number }>
  if (lessons.length === 0) return { pct: 0, completed: false }
  const done = d.prepare(`
    SELECT COUNT(*) as c FROM crm_member_lesson_progress
    WHERE member_id = ? AND completed_at IS NOT NULL AND lesson_id IN (${lessons.map(() => '?').join(',')})
  `).get(memberId, ...lessons.map((l) => l.id)) as { c: number }
  const pct = Math.min(100, Math.floor((done.c / lessons.length) * 100))
  const completed = pct >= 100
  const now = Math.floor(Date.now() / 1000)
  d.prepare(`
    UPDATE crm_member_course_enrollments
    SET completion_pct = ?, completed_at = CASE WHEN ? = 1 AND completed_at IS NULL THEN ? ELSE completed_at END
    WHERE member_id = ? AND course_id = ?
  `).run(pct, completed ? 1 : 0, now, memberId, courseId)
  return { pct, completed }
}

// ─── Quiz attempts ──────────────────────────────────────────────────────
export function recordCrmQuizAttempt(data: {
  memberId: number
  lessonId: number
  scorePct: number
  passed: boolean
  answersJson: string
}): CrmMemberQuizAttempt {
  const r = getDb().prepare(`
    INSERT INTO crm_member_quiz_attempts (member_id, lesson_id, score_pct, passed, submitted_at, answers_json)
    VALUES (?, ?, ?, ?, ?, ?)
  `).run(
    data.memberId,
    data.lessonId,
    Math.max(0, Math.min(100, Math.floor(data.scorePct))),
    data.passed ? 1 : 0,
    Math.floor(Date.now() / 1000),
    data.answersJson,
  )
  return getDb().prepare('SELECT * FROM crm_member_quiz_attempts WHERE id = ?').get(Number(r.lastInsertRowid)) as CrmMemberQuizAttempt
}

// ─── Drip worker: unlock lessons whose drip_release_at has passed ───────
// Returns a list of { memberId, lessonId, workspaceId, contactId } tuples
// that just unlocked, so the workflow runner can fire `lesson_unlocked`.
export function getDueCrmCourseLessonUnlocks(now: number, limit = 50): Array<{
  member_id: number
  lesson_id: number
  course_id: number
  workspace_id: number
  contact_id: number
}> {
  return getDb().prepare(`
    SELECT e.member_id, l.id as lesson_id, l.course_id, m.workspace_id, m.contact_id
    FROM crm_member_course_enrollments e
    JOIN crm_course_lessons l ON l.course_id = e.course_id
    JOIN crm_members m ON m.id = e.member_id
    WHERE (
        (l.drip_release_at IS NOT NULL AND l.drip_release_at <= ?)
        OR (l.drip_day_offset IS NOT NULL AND (e.enrolled_at + (l.drip_day_offset * 86400)) <= ?)
    )
    AND NOT EXISTS (
      SELECT 1 FROM crm_member_lesson_progress p
      WHERE p.member_id = e.member_id AND p.lesson_id = l.id
    )
    ORDER BY l.id ASC
    LIMIT ?
  `).all(now, now, limit) as Array<{
    member_id: number; lesson_id: number; course_id: number; workspace_id: number; contact_id: number;
  }>
}

/** Seed an empty progress row so the unlock doesn't re-fire. */
export function markCrmLessonUnlocked(memberId: number, lessonId: number): void {
  const existing = getDb().prepare('SELECT id FROM crm_member_lesson_progress WHERE member_id = ? AND lesson_id = ?').get(memberId, lessonId)
  if (existing) return
  getDb().prepare(`
    INSERT INTO crm_member_lesson_progress (member_id, lesson_id, last_position_seconds, seconds_watched)
    VALUES (?, ?, 0, 0)
  `).run(memberId, lessonId)
}

// ─── Academy access helpers ─────────────────────────────────────────────
export function listCoursesForMember(member: CrmMember): CrmCourseRecord[] {
  const d = getDb()
  const membership = member.membership_id
    ? d.prepare('SELECT access_type FROM crm_memberships WHERE id = ?').get(member.membership_id) as { access_type: CrmMembershipAccessType } | undefined
    : undefined
  const rows = d.prepare(`
    SELECT DISTINCT c.* FROM crm_courses c
    WHERE c.workspace_id = ?
      AND c.status = 'published'
      AND (
        c.id IN (SELECT course_id FROM crm_member_course_enrollments WHERE member_id = ?)
        OR (
          ? IS NOT NULL AND (
            ? = 'all_courses'
            OR c.id IN (SELECT course_id FROM crm_membership_course_access WHERE membership_id = ?)
          )
        )
      )
    ORDER BY c.updated_at DESC
  `).all(member.workspace_id, member.id, member.membership_id, membership?.access_type ?? null, member.membership_id) as CrmCourse[]
  return rows.map(enrichCourse)
}

export function memberHasCourseAccess(member: CrmMember, courseId: number): boolean {
  const d = getDb()
  const direct = d.prepare('SELECT 1 as x FROM crm_member_course_enrollments WHERE member_id = ? AND course_id = ?').get(member.id, courseId)
  if (direct) return true
  if (!member.membership_id) return false
  const membership = d.prepare('SELECT access_type FROM crm_memberships WHERE id = ?').get(member.membership_id) as { access_type: CrmMembershipAccessType } | undefined
  if (membership?.access_type === 'all_courses') return true
  const viaMembership = d.prepare('SELECT 1 as x FROM crm_membership_course_access WHERE membership_id = ? AND course_id = ?').get(member.membership_id, courseId)
  return Boolean(viaMembership)
}

