const DEFAULT_CRM_PAYMENT_METHODS: CrmPaymentSettingsMethod[] = ['card', 'cash', 'check', 'bank', 'other']

function startOfUtcDay(ts: number = Math.floor(Date.now() / 1000)): number {
  const day = new Date(ts * 1000).toISOString().slice(0, 10)
  return Math.floor(new Date(`${day}T00:00:00.000Z`).getTime() / 1000)
}

function parseCrmPaymentMethods(raw: string | null | undefined): CrmPaymentSettingsMethod[] {
  const parts = String(raw || '')
    .split(',')
    .map((item) => item.trim())
    .filter((item): item is CrmPaymentSettingsMethod => DEFAULT_CRM_PAYMENT_METHODS.includes(item as CrmPaymentSettingsMethod))
  const seen = new Set<CrmPaymentSettingsMethod>()
  for (const item of parts) seen.add(item)
  return seen.size > 0 ? Array.from(seen) : [...DEFAULT_CRM_PAYMENT_METHODS]
}

function serializeCrmPaymentMethods(methods: CrmPaymentSettingsMethod[]): string {
  const cleaned = parseCrmPaymentMethods(methods.join(','))
  return cleaned.join(',')
}

