// ── Products ─────────────────────────────────────────────────────────────

export function listCrmProducts(workspaceId: number, opts?: { includeArchived?: boolean }): CrmProduct[] {
  const d = getDb()
  if (opts?.includeArchived) {
    return d.prepare(`SELECT * FROM crm_products WHERE workspace_id = ? ORDER BY is_archived ASC, name ASC`).all(workspaceId) as CrmProduct[]
  }
  return d.prepare(`SELECT * FROM crm_products WHERE workspace_id = ? AND is_archived = 0 AND active = 1 ORDER BY name ASC`).all(workspaceId) as CrmProduct[]
}

export function getCrmProductById(id: number, workspaceId: number): CrmProduct | null {
  const row = getDb().prepare(`SELECT * FROM crm_products WHERE id = ? AND workspace_id = ?`).get(id, workspaceId) as CrmProduct | undefined
  return row ?? null
}

export function createCrmProduct(workspaceId: number, data: {
  name: string
  description?: string | null
  sku?: string | null
  amount_cents: number
  currency?: string
  kind?: CrmProductKind
  recurring_interval?: CrmRecurringInterval | null
  recurring_interval_count?: number | null
  tax_rate_bps?: number
  active?: boolean | number
  created_by?: number | null
}): CrmProduct {
  const d = getDb()
  const active = data.active === undefined ? 1 : (data.active ? 1 : 0)
  const info = d.prepare(`
    INSERT INTO crm_products (workspace_id, name, description, sku, amount_cents, currency, kind, recurring_interval, recurring_interval_count, tax_rate_bps, active, is_archived, created_by)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    data.name.trim(),
    data.description ?? null,
    data.sku?.trim() || null,
    Math.round(data.amount_cents),
    (data.currency ?? 'USD').toUpperCase(),
    data.kind ?? 'one_time',
    data.recurring_interval ?? null,
    data.recurring_interval_count ?? null,
    data.tax_rate_bps ?? 0,
    active,
    active ? 0 : 1,
    data.created_by ?? null,
  )
  return getCrmProductById(info.lastInsertRowid as number, workspaceId)!
}

export function updateCrmProduct(id: number, workspaceId: number, patch: Partial<Pick<CrmProduct, 'name' | 'description' | 'sku' | 'amount_cents' | 'currency' | 'kind' | 'recurring_interval' | 'recurring_interval_count' | 'tax_rate_bps' | 'active' | 'is_archived'>>): CrmProduct | null {
  const existing = getCrmProductById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number | null)[] = []
  if (patch.name !== undefined) { sets.push('name = ?'); args.push(patch.name.trim()) }
  if (patch.description !== undefined) { sets.push('description = ?'); args.push(patch.description) }
  if (patch.sku !== undefined) { sets.push('sku = ?'); args.push(patch.sku?.trim() || null) }
  if (patch.amount_cents !== undefined) { sets.push('amount_cents = ?'); args.push(Math.round(patch.amount_cents)) }
  if (patch.currency !== undefined) { sets.push('currency = ?'); args.push(patch.currency.toUpperCase()) }
  if (patch.kind !== undefined) { sets.push('kind = ?'); args.push(patch.kind) }
  if (patch.recurring_interval !== undefined) { sets.push('recurring_interval = ?'); args.push(patch.recurring_interval) }
  if (patch.recurring_interval_count !== undefined) { sets.push('recurring_interval_count = ?'); args.push(patch.recurring_interval_count) }
  if (patch.tax_rate_bps !== undefined) { sets.push('tax_rate_bps = ?'); args.push(patch.tax_rate_bps) }
  if (patch.active !== undefined) {
    const active = patch.active ? 1 : 0
    sets.push('active = ?'); args.push(active)
    sets.push('is_archived = ?'); args.push(active ? 0 : 1)
  }
  if (patch.is_archived !== undefined && patch.active === undefined) {
    const archived = patch.is_archived ? 1 : 0
    sets.push('is_archived = ?'); args.push(archived)
    sets.push('active = ?'); args.push(archived ? 0 : 1)
  }
  if (sets.length === 0) return existing
  sets.push(`updated_at = strftime('%s','now')`)
  args.push(id, workspaceId)
  getDb().prepare(`UPDATE crm_products SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...args)
  return getCrmProductById(id, workspaceId)
}

export function deleteCrmProduct(id: number, workspaceId: number): boolean {
  const info = getDb().prepare(`DELETE FROM crm_products WHERE id = ? AND workspace_id = ?`).run(id, workspaceId)
  return info.changes > 0
}

// ── Invoices ────────────────────────────────────────────────────────────

export function nextInvoiceNumber(workspaceId: number): string {
  const d = getDb()
  const yr = new Date().getUTCFullYear()
  const prefix = `INV-${yr}-`
  const row = d.prepare(`SELECT number FROM crm_invoices WHERE workspace_id = ? AND number LIKE ? ORDER BY id DESC LIMIT 1`).get(workspaceId, `${prefix}%`) as { number?: string } | undefined
  let seq = 1
  if (row?.number) {
    const m = row.number.match(/INV-\d{4}-(\d+)/)
    if (m) seq = parseInt(m[1], 10) + 1
  }
  return `${prefix}${String(seq).padStart(4, '0')}`
}

function sumInvoiceLineItems(items: CrmInvoiceLineItemInput[]): { subtotal: number; tax: number; total: number } {
  let subtotal = 0
  let tax = 0
  for (const it of items) {
    const qty = it.quantity ?? 1
    const line = Math.round(it.unit_amount_cents * qty)
    subtotal += line
    const taxBps = it.tax_rate_bps ?? 0
    if (taxBps > 0) tax += Math.round((line * taxBps) / 10000)
  }
  return { subtotal, tax, total: subtotal + tax }
}

export function recomputeInvoiceTotals(invoiceId: number): { subtotal: number; tax: number; total: number; paid: number; due: number } {
  const d = getDb()
  const items = d.prepare(`SELECT quantity, unit_amount_cents, tax_rate_bps FROM crm_invoice_line_items WHERE invoice_id = ?`).all(invoiceId) as { quantity: number; unit_amount_cents: number; tax_rate_bps: number }[]
  const totals = sumInvoiceLineItems(items.map((r) => ({ description: '', quantity: r.quantity, unit_amount_cents: r.unit_amount_cents, tax_rate_bps: r.tax_rate_bps })))
  const invoiceRow = d.prepare(`SELECT discount_cents FROM crm_invoices WHERE id = ?`).get(invoiceId) as { discount_cents?: number } | undefined
  const discount = Math.max(0, invoiceRow?.discount_cents ?? 0)
  const total = Math.max(0, totals.total - discount)
  const paidRow = d.prepare(`SELECT COALESCE(SUM(amount_cents - refunded_amount_cents), 0) AS paid FROM crm_payments WHERE invoice_id = ? AND status IN ('succeeded','partially_refunded')`).get(invoiceId) as { paid: number } | undefined
  const paid = paidRow?.paid ?? 0
  const due = Math.max(0, total - paid)
  d.prepare(`UPDATE crm_invoices SET subtotal_cents = ?, tax_cents = ?, total_cents = ?, amount_paid_cents = ?, amount_due_cents = ?, updated_at = strftime('%s','now') WHERE id = ?`).run(totals.subtotal, totals.tax, total, paid, due, invoiceId)
  return { subtotal: totals.subtotal, tax: totals.tax, total, paid, due }
}

export function recomputeInvoiceStatus(invoiceId: number, now: number = Math.floor(Date.now() / 1000)): CrmInvoiceStatus {
  const d = getDb()
  const row = d.prepare(`SELECT status, total_cents, amount_paid_cents, due_date, voided_at, sent_at, viewed_at, first_viewed_at FROM crm_invoices WHERE id = ?`).get(invoiceId) as {
    status: CrmInvoiceStatus
    total_cents: number
    amount_paid_cents: number
    due_date: number | null
    voided_at: number | null
    sent_at: number | null
    viewed_at: number | null
    first_viewed_at: number | null
  } | undefined
  if (!row) return 'draft'
  if (row.voided_at) return 'void'
  const overdueCutoff = startOfUtcDay(now)
  let status: CrmInvoiceStatus = row.status
  if (row.amount_paid_cents >= row.total_cents && row.total_cents > 0) {
    status = 'paid'
    d.prepare(`UPDATE crm_invoices SET status = 'paid', paid_at = COALESCE(paid_at, ?), amount_due_cents = 0, updated_at = strftime('%s','now') WHERE id = ?`).run(now, invoiceId)
    return status
  }
  if (row.amount_paid_cents > 0 && row.amount_paid_cents < row.total_cents) {
    status = 'partial'
  } else if (row.sent_at && row.due_date && row.due_date < overdueCutoff) {
    status = 'overdue'
  } else if (row.sent_at && (row.viewed_at || row.first_viewed_at)) {
    status = 'viewed'
  } else if (row.sent_at) {
    status = 'sent'
  } else {
    status = 'draft'
  }
  d.prepare(`UPDATE crm_invoices SET status = ?, updated_at = strftime('%s','now') WHERE id = ?`).run(status, invoiceId)
  return status
}

export function enrichInvoice(row: CrmInvoiceRow): CrmInvoice {
  const d = getDb()
  const items = d.prepare(`SELECT * FROM crm_invoice_line_items WHERE invoice_id = ? ORDER BY sort_order ASC, id ASC`).all(row.id) as CrmInvoiceLineItem[]
  let contact_name: string | null = null
  let contact_email: string | null = null
  let contact_phone: string | null = null
  if (row.contact_id) {
    const c = d.prepare(`SELECT name, email, phone FROM crm_contacts WHERE id = ?`).get(row.contact_id) as { name?: string; email?: string; phone?: string } | undefined
    contact_name = c?.name ?? null
    contact_email = c?.email ?? null
    contact_phone = c?.phone ?? null
  }
  const payCount = d.prepare(`SELECT COUNT(*) AS n FROM crm_payments WHERE invoice_id = ?`).get(row.id) as { n: number }
  return { ...row, line_items: items, contact_name, contact_email, contact_phone, payment_count: payCount.n }
}

export function listCrmInvoices(workspaceId: number, opts?: {
  status?: CrmInvoiceStatus | 'all'
  contactId?: number | null
  opportunityId?: number | null
  limit?: number
  offset?: number
}): CrmInvoice[] {
  const d = getDb()
  const clauses: string[] = ['workspace_id = ?']
  const args: (string | number)[] = [workspaceId]
  if (opts?.status && opts.status !== 'all') { clauses.push('status = ?'); args.push(opts.status) }
  if (opts?.contactId) { clauses.push('contact_id = ?'); args.push(opts.contactId) }
  if (opts?.opportunityId) { clauses.push('opportunity_id = ?'); args.push(opts.opportunityId) }
  const limit = Math.min(500, Math.max(1, opts?.limit ?? 100))
  const offset = Math.max(0, opts?.offset ?? 0)
  const rows = d.prepare(`SELECT * FROM crm_invoices WHERE ${clauses.join(' AND ')} ORDER BY id DESC LIMIT ? OFFSET ?`).all(...args, limit, offset) as CrmInvoiceRow[]
  return rows.map((r) => enrichInvoice(r))
}

