export function createCrmInvoice(workspaceId: number, data: {
  contact_id?: number | null
  opportunity_id?: number | null
  currency?: string
  due_date?: number | null
  notes?: string | null
  terms?: string | null
  discount_cents?: number
  line_items: CrmInvoiceLineItemInput[]
  created_by?: number | null
}): CrmInvoice {
  const d = getDb()
  const publicId = generatePublicId()
  const number = nextInvoiceNumber(workspaceId)
  const totals = sumInvoiceLineItems(data.line_items)
  const discountCents = Math.max(0, Math.round(data.discount_cents ?? 0))
  const total = Math.max(0, totals.total - discountCents)
  const info = d.prepare(`
    INSERT INTO crm_invoices (
      workspace_id, public_id, public_token, number, contact_id, opportunity_id, status, currency,
      subtotal_cents, tax_cents, discount_cents, total_cents, amount_paid_cents, amount_due_cents,
      due_date, notes, terms, created_by
    ) VALUES (?, ?, ?, ?, ?, ?, 'draft', ?, ?, ?, ?, ?, 0, ?, ?, ?, ?, ?)
  `).run(
    workspaceId, publicId, publicId, number,
    data.contact_id ?? null, data.opportunity_id ?? null,
    (data.currency ?? 'USD').toUpperCase(),
    totals.subtotal, totals.tax, discountCents, total, total,
    data.due_date ?? null, data.notes ?? null, data.terms ?? null,
    data.created_by ?? null,
  )
  const invoiceId = info.lastInsertRowid as number
  const insertLine = d.prepare(`
    INSERT INTO crm_invoice_line_items (workspace_id, invoice_id, product_id, description, quantity, unit_amount_cents, tax_rate_bps, line_total_cents, position, sort_order)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `)
  data.line_items.forEach((it, idx) => {
    const qty = it.quantity ?? 1
    const unit = Math.round(it.unit_amount_cents)
    insertLine.run(workspaceId, invoiceId, it.product_id ?? null, it.description, qty, unit, it.tax_rate_bps ?? 0, qty * unit, idx, idx)
  })
  return getCrmInvoiceById(invoiceId, workspaceId)!
}

export function updateCrmInvoice(id: number, workspaceId: number, patch: {
  contact_id?: number | null
  opportunity_id?: number | null
  currency?: string
  due_date?: number | null
  issued_at?: number | null
  sent_at?: number | null
  viewed_at?: number | null
  first_viewed_at?: number | null
  paid_at?: number | null
  voided_at?: number | null
  notes?: string | null
  terms?: string | null
  discount_cents?: number
  status?: CrmInvoiceStatus
  provider?: string | null
  provider_invoice_id?: string | null
  hosted_invoice_url?: string | null
  line_items?: CrmInvoiceLineItemInput[]
}): CrmInvoice | null {
  const d = getDb()
  const existing = getCrmInvoiceById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number | null)[] = []
  const assign = <K extends keyof typeof patch>(k: K, col: string, transform?: (v: NonNullable<typeof patch[K]>) => string | number | null) => {
    const v = patch[k]
    if (v === undefined) return
    sets.push(`${col} = ?`)
    args.push(v === null ? null : (transform ? transform(v as NonNullable<typeof patch[K]>) : (v as string | number)))
  }
  assign('contact_id', 'contact_id')
  assign('opportunity_id', 'opportunity_id')
  assign('currency', 'currency', (v) => (v as string).toUpperCase())
  assign('due_date', 'due_date')
  assign('issued_at', 'issued_at')
  assign('sent_at', 'sent_at')
  assign('viewed_at', 'viewed_at')
  assign('first_viewed_at', 'first_viewed_at')
  assign('paid_at', 'paid_at')
  assign('voided_at', 'voided_at')
  assign('notes', 'notes')
  assign('terms', 'terms')
  assign('discount_cents', 'discount_cents', (v) => Math.max(0, Math.round(v as number)))
  assign('status', 'status')
  assign('provider', 'provider')
  assign('provider_invoice_id', 'provider_invoice_id')
  assign('hosted_invoice_url', 'hosted_invoice_url')
  if (sets.length > 0) {
    sets.push(`updated_at = strftime('%s','now')`)
    args.push(id, workspaceId)
    d.prepare(`UPDATE crm_invoices SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...args)
  }
  if (patch.line_items) {
    d.prepare(`DELETE FROM crm_invoice_line_items WHERE invoice_id = ?`).run(id)
    const insertLine = d.prepare(`
      INSERT INTO crm_invoice_line_items (workspace_id, invoice_id, product_id, description, quantity, unit_amount_cents, tax_rate_bps, line_total_cents, position, sort_order)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `)
    patch.line_items.forEach((it, idx) => {
      const qty = it.quantity ?? 1
      const unit = Math.round(it.unit_amount_cents)
      insertLine.run(workspaceId, id, it.product_id ?? null, it.description, qty, unit, it.tax_rate_bps ?? 0, qty * unit, idx, idx)
    })
  }
  recomputeInvoiceTotals(id)
  recomputeInvoiceStatus(id)
  return getCrmInvoiceById(id, workspaceId)
}

export function deleteCrmInvoice(id: number, workspaceId: number): boolean {
  const info = getDb().prepare(`DELETE FROM crm_invoices WHERE id = ? AND workspace_id = ?`).run(id, workspaceId)
  return info.changes > 0
}

export function listOverdueInvoices(cutoff: number = startOfUtcDay()): Array<{ id: number; workspace_id: number; contact_id: number | null; number: string; due_date: number | null }> {
  return getDb().prepare(`
    SELECT id, workspace_id, contact_id, number, due_date
    FROM crm_invoices
    WHERE voided_at IS NULL
      AND paid_at IS NULL
      AND due_date IS NOT NULL
      AND due_date < ?
      AND status IN ('sent','viewed','partial')
  `).all(cutoff) as Array<{ id: number; workspace_id: number; contact_id: number | null; number: string; due_date: number | null }>
}

export function markInvoiceOverdue(id: number): void {
  getDb().prepare(`UPDATE crm_invoices SET status = 'overdue', updated_at = strftime('%s','now') WHERE id = ? AND status IN ('sent','viewed','partial')`).run(id)
}

