export function enrichPayment(row: CrmPaymentRow): CrmPayment {
  const d = getDb()
  let contact_name: string | null = null
  let contact_email: string | null = null
  if (row.contact_id) {
    const c = d.prepare(`SELECT name, email FROM crm_contacts WHERE id = ?`).get(row.contact_id) as { name?: string; email?: string } | undefined
    contact_name = c?.name ?? null
    contact_email = c?.email ?? null
  }
  let invoice_number: string | null = null
  let invoice_public_id: string | null = null
  if (row.invoice_id) {
    const inv = d.prepare(`SELECT number, public_id FROM crm_invoices WHERE id = ?`).get(row.invoice_id) as { number?: string; public_id?: string } | undefined
    invoice_number = inv?.number ?? null
    invoice_public_id = inv?.public_id ?? null
  }
  return { ...row, contact_name, contact_email, invoice_number, invoice_public_id }
}

