  const rows = d.prepare(`SELECT * FROM crm_payments WHERE ${clauses.join(' AND ')} ORDER BY received_at DESC, id DESC LIMIT ? OFFSET ?`).all(...args, limit, offset) as CrmPaymentRow[]
