export function createCrmPayment(workspaceId: number, data: {
  invoice_id?: number | null
  contact_id?: number | null
  amount_cents: number
  currency?: string
  method?: CrmPaymentMethod
  status?: CrmPaymentStatus
  provider?: string | null
  provider_txn_id?: string | null
  external_ref?: string | null
  provider_fee_cents?: number | null
  processor_fee_cents?: number | null
  failure_reason?: string | null
  memo?: string | null
  received_at?: number | null
  created_by?: number | null
}): CrmPayment {
  const d = getDb()
  const txnRef = data.provider_txn_id ?? data.external_ref ?? null
  const externalRef = data.external_ref ?? data.provider_txn_id ?? null
  const info = d.prepare(`
    INSERT INTO crm_payments (
      workspace_id, invoice_id, contact_id, amount_cents, currency, method, status,
      provider, provider_txn_id, external_ref, provider_fee_cents, processor_fee_cents,
      failure_reason, memo, received_at, created_by
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, COALESCE(?, strftime('%s','now')), ?)
  `).run(
    workspaceId,
    data.invoice_id ?? null,
    data.contact_id ?? null,
    Math.round(data.amount_cents),
    (data.currency ?? 'USD').toUpperCase(),
    data.method ?? 'manual',
    data.status ?? 'succeeded',
    data.provider ?? null,
    txnRef,
    externalRef,
    data.provider_fee_cents ?? null,
    data.processor_fee_cents ?? null,
    data.failure_reason ?? null,
    data.memo ?? null,
    data.received_at ?? null,
    data.created_by ?? null,
  )
  const id = info.lastInsertRowid as number
  if (data.invoice_id && (data.status ?? 'succeeded') === 'succeeded') {
    recomputeInvoiceTotals(data.invoice_id)
    recomputeInvoiceStatus(data.invoice_id)
  }
  return getCrmPaymentById(id, workspaceId)!
}

export function updateCrmPaymentStatus(id: number, workspaceId: number, patch: { status?: CrmPaymentStatus; refunded_amount_cents?: number; failure_reason?: string | null }): CrmPayment | null {
  const existing = getCrmPaymentById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number | null)[] = []
  if (patch.status !== undefined) { sets.push('status = ?'); args.push(patch.status) }
  if (patch.refunded_amount_cents !== undefined) { sets.push('refunded_amount_cents = ?'); args.push(Math.round(patch.refunded_amount_cents)) }
  if (patch.failure_reason !== undefined) { sets.push('failure_reason = ?'); args.push(patch.failure_reason) }
  if (sets.length === 0) return existing
  args.push(id, workspaceId)
  getDb().prepare(`UPDATE crm_payments SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...args)
  if (existing.invoice_id) {
    recomputeInvoiceTotals(existing.invoice_id)
    recomputeInvoiceStatus(existing.invoice_id)
  }
  return getCrmPaymentById(id, workspaceId)
}

export function applyPaymentToInvoice(paymentId: number, workspaceId: number, invoiceId: number): CrmPayment | null {
  const p = getCrmPaymentById(paymentId, workspaceId)
  if (!p) return null
  getDb().prepare(`UPDATE crm_payments SET invoice_id = ? WHERE id = ? AND workspace_id = ?`).run(invoiceId, paymentId, workspaceId)
  recomputeInvoiceTotals(invoiceId)
  recomputeInvoiceStatus(invoiceId)
  return getCrmPaymentById(paymentId, workspaceId)
}

