export function upsertCrmPaymentProvider(workspaceId: number, provider: 'stripe' | 'square', data: {
  mode?: 'test' | 'live'
  is_active?: boolean
  display_name?: string | null
  publishable_key?: string | null
  secret_key_enc?: string | null
  webhook_secret_enc?: string | null
  account_id?: string | null
  config_json?: string
  last_tested_at?: number | null
  last_test_ok?: boolean
  last_test_message?: string | null
}): CrmPaymentProvider {
  const d = getDb()
  const existing = getCrmPaymentProvider(workspaceId, provider)
  if (existing) {
    const sets: string[] = []
    const args: (string | number | null)[] = []
    if (data.mode !== undefined) { sets.push('mode = ?'); args.push(data.mode) }
    if (data.is_active !== undefined) { sets.push('is_active = ?'); args.push(data.is_active ? 1 : 0) }
    if (data.display_name !== undefined) { sets.push('display_name = ?'); args.push(data.display_name) }
    if (data.publishable_key !== undefined) { sets.push('publishable_key = ?'); args.push(data.publishable_key) }
    if (data.secret_key_enc !== undefined) { sets.push('secret_key_enc = ?'); args.push(data.secret_key_enc) }
    if (data.webhook_secret_enc !== undefined) { sets.push('webhook_secret_enc = ?'); args.push(data.webhook_secret_enc) }
    if (data.account_id !== undefined) { sets.push('account_id = ?'); args.push(data.account_id) }
    if (data.config_json !== undefined) { sets.push('config_json = ?'); args.push(data.config_json) }
    if (data.last_tested_at !== undefined) { sets.push('last_tested_at = ?'); args.push(data.last_tested_at) }
    if (data.last_test_ok !== undefined) { sets.push('last_test_ok = ?'); args.push(data.last_test_ok ? 1 : 0) }
    if (data.last_test_message !== undefined) { sets.push('last_test_message = ?'); args.push(data.last_test_message) }
    if (sets.length === 0) return existing
    sets.push(`updated_at = strftime('%s','now')`)
    args.push(workspaceId, provider)
    d.prepare(`UPDATE crm_payment_providers SET ${sets.join(', ')} WHERE workspace_id = ? AND provider = ?`).run(...args)
  } else {
    d.prepare(`
      INSERT INTO crm_payment_providers (
        workspace_id, provider, mode, is_active, display_name, publishable_key,
        secret_key_enc, webhook_secret_enc, account_id, config_json,
        last_tested_at, last_test_ok, last_test_message
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      workspaceId,
      provider,
      data.mode ?? 'test',
      data.is_active ? 1 : 0,
      data.display_name ?? null,
      data.publishable_key ?? null,
      data.secret_key_enc ?? null,
      data.webhook_secret_enc ?? null,
      data.account_id ?? null,
      data.config_json ?? '{}',
      data.last_tested_at ?? null,
      data.last_test_ok ? 1 : 0,
      data.last_test_message ?? null,
    )
  }
  return getCrmPaymentProvider(workspaceId, provider)!
}

export function getCrmPaymentSettings(workspaceId: number): CrmPaymentSettings {
  const row = getDb().prepare(`SELECT currency, payment_methods_csv FROM workspaces WHERE id = ?`).get(workspaceId) as { currency?: string; payment_methods_csv?: string | null } | undefined
  return {
    default_currency: (row?.currency || 'USD').toUpperCase(),
    payment_methods: parseCrmPaymentMethods(row?.payment_methods_csv),
    available_methods: [...DEFAULT_CRM_PAYMENT_METHODS],
  }
}

export function updateCrmPaymentSettings(workspaceId: number, patch: {
  default_currency?: string
  payment_methods?: CrmPaymentSettingsMethod[]
}): CrmPaymentSettings {
  const sets: string[] = []
  const args: (string | number)[] = []
  if (patch.default_currency !== undefined) {
    sets.push('currency = ?')
    args.push((patch.default_currency || 'USD').toUpperCase())
  }
  if (patch.payment_methods !== undefined) {
    sets.push('payment_methods_csv = ?')
    args.push(serializeCrmPaymentMethods(patch.payment_methods))
  }
  if (sets.length > 0) {
    args.push(workspaceId)
    getDb().prepare(`UPDATE workspaces SET ${sets.join(', ')} WHERE id = ?`).run(...args)
  }
  return getCrmPaymentSettings(workspaceId)
}

export function listCrmTaxRates(workspaceId: number): CrmTaxRate[] {
  return getDb().prepare(`SELECT * FROM crm_tax_rates WHERE workspace_id = ? ORDER BY is_default DESC, name ASC, id ASC`).all(workspaceId) as CrmTaxRate[]
}

export function getCrmTaxRateById(id: number, workspaceId: number): CrmTaxRate | null {
  const row = getDb().prepare(`SELECT * FROM crm_tax_rates WHERE id = ? AND workspace_id = ?`).get(id, workspaceId) as CrmTaxRate | undefined
  return row ?? null
}

export function createCrmTaxRate(workspaceId: number, data: { name: string; rate_pct: number; is_default?: boolean }): CrmTaxRate {
  const d = getDb()
  const existingCount = d.prepare(`SELECT COUNT(*) AS n FROM crm_tax_rates WHERE workspace_id = ?`).get(workspaceId) as { n: number }
  const makeDefault = data.is_default || existingCount.n === 0
  if (makeDefault) d.prepare(`UPDATE crm_tax_rates SET is_default = 0 WHERE workspace_id = ?`).run(workspaceId)
  const info = d.prepare(`
    INSERT INTO crm_tax_rates (workspace_id, name, rate_pct, is_default, created_at, updated_at)
    VALUES (?, ?, ?, ?, strftime('%s','now'), strftime('%s','now'))
  `).run(workspaceId, data.name.trim(), Number(data.rate_pct) || 0, makeDefault ? 1 : 0)
  return getCrmTaxRateById(Number(info.lastInsertRowid), workspaceId)!
}

export function updateCrmTaxRate(id: number, workspaceId: number, patch: Partial<Pick<CrmTaxRate, 'name' | 'rate_pct' | 'is_default'>>): CrmTaxRate | null {
  const existing = getCrmTaxRateById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: (string | number)[] = []
  if (patch.is_default !== undefined && patch.is_default) {
    getDb().prepare(`UPDATE crm_tax_rates SET is_default = 0 WHERE workspace_id = ? AND id <> ?`).run(workspaceId, id)
  }
  if (patch.name !== undefined) { sets.push('name = ?'); args.push(patch.name.trim()) }
  if (patch.rate_pct !== undefined) { sets.push('rate_pct = ?'); args.push(Number(patch.rate_pct) || 0) }
  if (patch.is_default !== undefined) { sets.push('is_default = ?'); args.push(patch.is_default ? 1 : 0) }
  if (sets.length === 0) return existing
  sets.push(`updated_at = strftime('%s','now')`)
  args.push(id, workspaceId)
  getDb().prepare(`UPDATE crm_tax_rates SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...args)
  return getCrmTaxRateById(id, workspaceId)
}

export function deleteCrmTaxRate(id: number, workspaceId: number): boolean {
  const existing = getCrmTaxRateById(id, workspaceId)
  if (!existing) return false
  const info = getDb().prepare(`DELETE FROM crm_tax_rates WHERE id = ? AND workspace_id = ?`).run(id, workspaceId)
  if (existing.is_default) {
    const replacement = getDb().prepare(`SELECT id FROM crm_tax_rates WHERE workspace_id = ? ORDER BY id ASC LIMIT 1`).get(workspaceId) as { id?: number } | undefined
    if (replacement?.id) {
      getDb().prepare(`UPDATE crm_tax_rates SET is_default = 1, updated_at = strftime('%s','now') WHERE id = ? AND workspace_id = ?`).run(replacement.id, workspaceId)
    }
  }
  return info.changes > 0
}

// ── Subscriptions ──────────────────────────────────────────────────────

export function listCrmSubscriptions(workspaceId: number, opts?: { status?: CrmSubscriptionStatus | 'all'; contactId?: number }): CrmSubscription[] {
  const d = getDb()
  const clauses: string[] = ['workspace_id = ?']
  const args: (string | number)[] = [workspaceId]
  if (opts?.status && opts.status !== 'all') { clauses.push('status = ?'); args.push(opts.status) }
  if (opts?.contactId) { clauses.push('contact_id = ?'); args.push(opts.contactId) }
  return d.prepare(`SELECT * FROM crm_subscriptions WHERE ${clauses.join(' AND ')} ORDER BY id DESC`).all(...args) as CrmSubscription[]
}

export function cancelCrmSubscription(id: number, workspaceId: number, atPeriodEnd = false): CrmSubscription | null {
  const d = getDb()
  const now = Math.floor(Date.now() / 1000)
  if (atPeriodEnd) {
    d.prepare(`UPDATE crm_subscriptions SET cancel_at_period_end = 1, updated_at = strftime('%s','now') WHERE id = ? AND workspace_id = ?`).run(id, workspaceId)
  } else {
    d.prepare(`UPDATE crm_subscriptions SET status = 'canceled', canceled_at = ?, cancel_at_period_end = 0, updated_at = strftime('%s','now') WHERE id = ? AND workspace_id = ?`).run(now, id, workspaceId)
  }
  const row = d.prepare(`SELECT * FROM crm_subscriptions WHERE id = ? AND workspace_id = ?`).get(id, workspaceId) as CrmSubscription | undefined
  return row ?? null
}


// ── Short links (compile-safe WIP support) ───────────────────────────────

export interface CrmShortLink {
  id: number
  workspace_id: number
  slug: string
  long_url: string
  title: string | null
  utm_source: string | null
  utm_medium: string | null
  utm_campaign: string | null
  utm_term: string | null
  utm_content: string | null
  expires_at: number | null
  max_clicks: number | null
  click_count: number
  archived_at: number | null
  created_at: number
  updated_at: number
}

export interface CrmShortLinkClick {
  id: number
  short_link_id: number
  clicked_at: number
  ip_hash: string | null
  device_type: string | null
  os: string | null
  browser: string | null
  country: string | null
  region: string | null
  city: string | null
  referrer: string | null
  user_agent: string | null
}

export function getCrmShortLinkBySlug(slug: string): CrmShortLink | null {
  try {
    return getDb().prepare(`SELECT * FROM crm_short_links WHERE slug = ?`).get(slug) as CrmShortLink | null
  } catch {
    return null
  }
}

const SHORT_LINK_SLUG_ALPHABET = 'abcdefghijkmnpqrstuvwxyz23456789'

function normalizeShortLinkSlug(raw: string | null | undefined): string | null {
  if (!raw) return null
  const cleaned = String(raw).trim().toLowerCase().replace(/[^a-z0-9-]/g, '')
  return cleaned ? cleaned.slice(0, 64) : null
}

function randomShortLinkSlug(length = 7): string {
  let out = ''
  for (let i = 0; i < length; i += 1) {
    out += SHORT_LINK_SLUG_ALPHABET[Math.floor(Math.random() * SHORT_LINK_SLUG_ALPHABET.length)]
  }
  return out
}

function allocateShortLinkSlug(desired: string | null): string {
  const db = getDb()
  const candidate = normalizeShortLinkSlug(desired)
  if (candidate) {
    const clash = db.prepare('SELECT 1 FROM crm_short_links WHERE slug = ? LIMIT 1').get(candidate)
    if (clash) throw new Error(`Slug "${candidate}" already in use`)
    return candidate
  }
  for (let attempt = 0; attempt < 12; attempt += 1) {
    const slug = randomShortLinkSlug(attempt < 6 ? 7 : 10)
    const clash = db.prepare('SELECT 1 FROM crm_short_links WHERE slug = ? LIMIT 1').get(slug)
    if (!clash) return slug
  }
  throw new Error('Could not allocate a unique slug')
}

export function listCrmShortLinks(workspaceId: number): CrmShortLink[] {
  return getDb().prepare(
    `SELECT * FROM crm_short_links
     WHERE workspace_id = ?
     ORDER BY archived_at IS NULL DESC, id DESC`,
  ).all(workspaceId) as CrmShortLink[]
}

export function getCrmShortLinkById(id: number, workspaceId: number): CrmShortLink | null {
  return getDb().prepare(
    `SELECT * FROM crm_short_links WHERE id = ? AND workspace_id = ?`,
  ).get(id, workspaceId) as CrmShortLink | null
}

export function createCrmShortLink(
  workspaceId: number,
  userId: number | null,
  data: {
    long_url: string
    slug?: string | null
    title?: string | null
    utm_source?: string | null
    utm_medium?: string | null
    utm_campaign?: string | null
    utm_term?: string | null
    utm_content?: string | null
    expires_at?: number | null
    max_clicks?: number | null
    password?: string | null
  },
): CrmShortLink {
  const longUrl = String(data.long_url || '').trim()
  if (!longUrl) throw new Error('long_url is required')
  try {
    // eslint-disable-next-line no-new
    new URL(longUrl)
  } catch {
    throw new Error('long_url must be a valid URL')
  }
  const slug = allocateShortLinkSlug(data.slug ?? null)
  const passwordHash = data.password ? String(data.password) : null
  const res = getDb().prepare(`
    INSERT INTO crm_short_links (
      workspace_id, slug, long_url, title,
      utm_source, utm_medium, utm_campaign, utm_term, utm_content,
      expires_at, max_clicks, password_hash, created_by
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    slug,
    longUrl,
    data.title ?? null,
    data.utm_source ?? null,
    data.utm_medium ?? null,
    data.utm_campaign ?? null,
    data.utm_term ?? null,
    data.utm_content ?? null,
    data.expires_at ?? null,
    data.max_clicks ?? null,
    passwordHash,
    userId ?? null,
  )
  const row = getDb().prepare(`SELECT * FROM crm_short_links WHERE id = ?`).get(Number(res.lastInsertRowid)) as CrmShortLink
  return row
}

export function updateCrmShortLink(
  id: number,
  workspaceId: number,
  patch: Partial<{
    long_url: string
    title: string | null
    utm_source: string | null
    utm_medium: string | null
    utm_campaign: string | null
    utm_term: string | null
    utm_content: string | null
    expires_at: number | null
    max_clicks: number | null
    password: string | null
  }>,
): CrmShortLink | null {
  const existing = getCrmShortLinkById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: unknown[] = []
  const push = (col: string, val: unknown) => { sets.push(`${col} = ?`); args.push(val) }
  if (patch.long_url !== undefined) {
    const url = String(patch.long_url || '').trim()
    if (!url) throw new Error('long_url cannot be empty')
    try { new URL(url) } catch { throw new Error('long_url must be a valid URL') }
    push('long_url', url)
  }
  if (patch.title !== undefined) push('title', patch.title)
  if (patch.utm_source !== undefined) push('utm_source', patch.utm_source)
  if (patch.utm_medium !== undefined) push('utm_medium', patch.utm_medium)
  if (patch.utm_campaign !== undefined) push('utm_campaign', patch.utm_campaign)
  if (patch.utm_term !== undefined) push('utm_term', patch.utm_term)
  if (patch.utm_content !== undefined) push('utm_content', patch.utm_content)
  if (patch.expires_at !== undefined) push('expires_at', patch.expires_at)
  if (patch.max_clicks !== undefined) push('max_clicks', patch.max_clicks)
  if (patch.password !== undefined) push('password_hash', patch.password)
  if (!sets.length) return existing
  sets.push(`updated_at = strftime('%s','now')`)
  args.push(id, workspaceId)
  getDb().prepare(
    `UPDATE crm_short_links SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`,
  ).run(...(args as (string | number | null)[]))
  return getCrmShortLinkById(id, workspaceId)
}

export function archiveCrmShortLink(id: number, workspaceId: number): boolean {
  const info = getDb().prepare(
    `UPDATE crm_short_links
     SET archived_at = strftime('%s','now'), updated_at = strftime('%s','now')
     WHERE id = ? AND workspace_id = ? AND archived_at IS NULL`,
  ).run(id, workspaceId)
  return info.changes > 0
}

export function deleteCrmShortLink(id: number, workspaceId: number): boolean {
  const info = getDb().prepare(
    `DELETE FROM crm_short_links WHERE id = ? AND workspace_id = ?`,
  ).run(id, workspaceId)
  return info.changes > 0
}

export function recordCrmShortLinkClick(data: {
  short_link_id: number
  workspace_id: number
  contact_id: number | null
  clicked_at: number
  ip_hash: string | null
  user_agent: string | null
  device_type: string | null
  os: string | null
  browser: string | null
  country?: string | null
  region?: string | null
  city?: string | null
  referrer: string | null
}): void {
  const db = getDb()
  const tx = db.transaction(() => {
    db.prepare(`
      INSERT INTO crm_short_link_clicks (
        short_link_id, workspace_id, contact_id, clicked_at,
        ip_hash, user_agent, device_type, os, browser,
        country, region, city, referrer
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      data.short_link_id,
      data.workspace_id,
      data.contact_id,
      data.clicked_at,
      data.ip_hash,
      data.user_agent,
      data.device_type,
      data.os,
      data.browser,
      data.country ?? null,
      data.region ?? null,
      data.city ?? null,
      data.referrer,
    )
    db.prepare(
      `UPDATE crm_short_links SET click_count = click_count + 1, updated_at = strftime('%s','now') WHERE id = ? AND workspace_id = ?`,
    ).run(data.short_link_id, data.workspace_id)
  })
  tx()
}

export function listCrmShortLinkClicks(
  shortLinkId: number,
  workspaceId: number,
  limit = 200,
): CrmShortLinkClick[] {
  const capped = Math.max(1, Math.min(Math.floor(limit), 1000))
  return getDb().prepare(
    `SELECT * FROM crm_short_link_clicks
     WHERE short_link_id = ? AND workspace_id = ?
     ORDER BY clicked_at DESC
     LIMIT ?`,
  ).all(shortLinkId, workspaceId, capped) as CrmShortLinkClick[]
}

export function crmShortLinkClicksSince(
  shortLinkId: number,
  workspaceId: number,
  sinceEpoch: number,
): Array<{ day: string; count: number }> {
  return getDb().prepare(
    `SELECT date(clicked_at, 'unixepoch') AS day, COUNT(*) AS count
     FROM crm_short_link_clicks
     WHERE short_link_id = ? AND workspace_id = ? AND clicked_at >= ?
     GROUP BY day
     ORDER BY day ASC`,
  ).all(shortLinkId, workspaceId, sinceEpoch) as Array<{ day: string; count: number }>
}

