export interface CrmContractRecord extends CrmContractListRow {
  contact_phone: string | null
  contact_company: string | null
  events: CrmContractEvent[]
}

interface ContractMergeVars {
  contact?: {
    name?: string | null
    email?: string | null
    phone?: string | null
    company?: string | null
  } | null
  opportunity?: {
    name?: string | null
  } | null
  workspace?: {
    name?: string | null
  } | null
  today?: string
}

function contractNowIso(): string {
  return new Date().toISOString()
}

function normalizeContractDate(value: unknown): string | null {
  if (value === null || value === undefined) return null
  if (typeof value === 'number' && Number.isFinite(value)) return new Date(value * 1000).toISOString()
  if (typeof value === 'string') {
    const trimmed = value.trim()
    if (!trimmed) return null
    if (/^\d+$/.test(trimmed)) return new Date(Number(trimmed) * 1000).toISOString()
    const parsed = Date.parse(trimmed)
    return Number.isNaN(parsed) ? trimmed : new Date(parsed).toISOString()
  }
  return null
}

function normalizeContractStatus(value: unknown): CrmContractStatus {
  switch (String(value || '').trim()) {
    case 'sent':
      return 'sent'
    case 'viewed':
    case 'partial':
      return 'viewed'
    case 'signed':
    case 'completed':
      return 'signed'
    case 'declined':
      return 'declined'
    case 'expired':
      return 'expired'
    case 'void':
    case 'voided':
      return 'void'
    default:
      return 'draft'
  }
}

function normalizeContractEventType(value: unknown): CrmContractEventType {
  switch (String(value || '').trim()) {
    case 'viewed':
      return 'viewed'
    case 'signed':
    case 'completed':
      return 'signed'
    case 'declined':
      return 'declined'
    case 'downloaded':
      return 'downloaded'
    case 'void':
    case 'voided':
      return 'void'
    case 'expired':
      return 'expired'
    default:
      return 'sent'
  }
}

function escapeContractHtml(value: string): string {
  return value
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;')
}

function legacyContractBlocksToHtml(source: string): string {
  let parsed: { blocks?: Array<Record<string, unknown>> }
  try {
    parsed = JSON.parse(source)
  } catch {
    return source
  }
  if (!Array.isArray(parsed.blocks) || parsed.blocks.length === 0) return ''

  const out: string[] = []
  for (const block of parsed.blocks) {
    const type = String(block.type || 'paragraph')
    const text = typeof block.text === 'string' ? block.text : ''
    const title = typeof block.title === 'string' ? block.title : text
    switch (type) {
      case 'header':
        out.push(`<h1>${escapeContractHtml(text)}</h1>`)
        break
      case 'section':
        out.push(`<h2>${escapeContractHtml(title)}</h2>`)
        break
      case 'clause':
        out.push(`<p><strong>${escapeContractHtml(title)}</strong></p>`)
        if (text) out.push(`<p>${escapeContractHtml(text).replace(/\n/g, '<br />')}</p>`)
        break
      case 'signature_block': {
        const label = typeof block.label === 'string' ? block.label : 'Signature'
        out.push(`<div data-contract-signature-line="true"><p><strong>${escapeContractHtml(label)}</strong></p><p>______________________________</p></div>`)
        break
      }
      case 'page_break':
        out.push('<hr />')
        break
      case 'date': {
        const label = typeof block.label === 'string' ? block.label : 'Date'
        out.push(`<p><strong>${escapeContractHtml(label)}:</strong> {{today}}</p>`)
        break
      }
      default:
        if (text) out.push(`<p>${escapeContractHtml(text).replace(/\n/g, '<br />')}</p>`)
        break
    }
  }
  return out.join('\n')
}

function resolveContractHtmlInput(bodyHtml: unknown, legacyBodyJson?: unknown): string {
  const direct = typeof bodyHtml === 'string' ? bodyHtml.trim() : ''
  if (direct) {
    if (direct.startsWith('{') || direct.startsWith('[')) return legacyContractBlocksToHtml(direct)
    return bodyHtml as string
  }
  const legacy = typeof legacyBodyJson === 'string' ? legacyBodyJson.trim() : ''
  if (!legacy) return ''
  if (legacy.startsWith('{') || legacy.startsWith('[')) return legacyContractBlocksToHtml(legacy)
  return legacyBodyJson as string
}

function resolveContractVariable(path: string, vars: ContractMergeVars): string {
  const keys = path.split('.').map((key) => key.trim()).filter(Boolean)
  if (keys.length === 0) return ''
  let current: unknown = vars
  for (const key of keys) {
    if (!current || typeof current !== 'object') return ''
    current = (current as Record<string, unknown>)[key]
  }
  if (current === null || current === undefined) return ''
  return String(current)
}

function replaceContractVariables(text: string, vars: ContractMergeVars): string {
  if (!text) return ''
  return text.replace(/\{\{\s*([a-zA-Z0-9_.]+)\s*\}\}/g, (_match, path: string) => {
    return escapeContractHtml(resolveContractVariable(path, vars))
  })
}

function hydrateCrmContractTemplateRow(row: Record<string, unknown>): CrmContractTemplate {
  const createdAt = normalizeContractDate(row.created_at) ?? contractNowIso()
  return {
    id: Number(row.id),
    workspace_id: Number(row.workspace_id),
    name: String(row.name ?? ''),
    category: typeof row.category === 'string' && row.category.trim() ? row.category : null,
    body_html: resolveContractHtmlInput(row.body_html, row.body_json),
    created_by_user_id: row.created_by_user_id === null || row.created_by_user_id === undefined ? null : Number(row.created_by_user_id),
    created_at: createdAt,
    updated_at: normalizeContractDate(row.updated_at) ?? createdAt,
  }
}

function hydrateCrmContractEventRow(row: Record<string, unknown>): CrmContractEvent {
  return {
    id: Number(row.id),
    contract_id: Number(row.contract_id),
    event_type: normalizeContractEventType(row.event_type),
    metadata_json: typeof row.metadata_json === 'string'
      ? row.metadata_json
      : (typeof row.meta_json === 'string' ? row.meta_json : null),
    created_at: normalizeContractDate(row.created_at ?? row.occurred_at) ?? contractNowIso(),
  }
}

function hydrateCrmContractListRow(row: Record<string, unknown>): CrmContractListRow {
  const createdAt = normalizeContractDate(row.created_at) ?? contractNowIso()
  const updatedAt = normalizeContractDate(row.updated_at) ?? createdAt
  return {
    id: Number(row.id),
    workspace_id: Number(row.workspace_id),
    contact_id: row.contact_id === null || row.contact_id === undefined ? null : Number(row.contact_id),
    opportunity_id: row.opportunity_id === null || row.opportunity_id === undefined ? null : Number(row.opportunity_id),
    template_id: row.template_id === null || row.template_id === undefined ? null : Number(row.template_id),
    title: String(row.title ?? ''),
    subject: typeof row.subject === 'string' ? row.subject : null,
    status: normalizeContractStatus(row.status),
    body_html: resolveContractHtmlInput(row.body_html, row.body_json),
    merged_html: typeof row.merged_html === 'string' && row.merged_html.trim() ? row.merged_html : null,
    public_token: typeof row.public_token === 'string' && row.public_token.trim()
      ? row.public_token
      : (typeof row.public_id === 'string' && row.public_id.trim() ? row.public_id : generatePublicId()),
    sent_at: normalizeContractDate(row.sent_at),
    viewed_at: normalizeContractDate(row.viewed_at),
    signed_at: normalizeContractDate(row.signed_at ?? row.completed_at),
    expires_at: normalizeContractDate(row.expires_at),
    signed_name: typeof row.signed_name === 'string' && row.signed_name.trim() ? row.signed_name : null,
    signed_email: typeof row.signed_email === 'string' && row.signed_email.trim() ? row.signed_email : null,
    signed_ip_hash: typeof row.signed_ip_hash === 'string' && row.signed_ip_hash.trim() ? row.signed_ip_hash : null,
    signed_ua: typeof row.signed_ua === 'string' && row.signed_ua.trim() ? row.signed_ua : null,
    signature_png: typeof row.signature_png === 'string' && row.signature_png.trim() ? row.signature_png : null,
    created_by_user_id: row.created_by_user_id === null || row.created_by_user_id === undefined ? null : Number(row.created_by_user_id),
    created_at: createdAt,
    updated_at: updatedAt,
    contact_name: typeof row.contact_name === 'string' && row.contact_name.trim() ? row.contact_name : null,
    contact_email: typeof row.contact_email === 'string' && row.contact_email.trim() ? row.contact_email : null,
    opportunity_name: typeof row.opportunity_name === 'string' && row.opportunity_name.trim() ? row.opportunity_name : null,
    recent_event_type: row.recent_event_type === null || row.recent_event_type === undefined ? null : normalizeContractEventType(row.recent_event_type),
    recent_event_at: normalizeContractDate(row.recent_event_at) ?? updatedAt,
  }
}

function contractSelectSql(where: string): string {
  return `
    SELECT
      c.*,
      contact.name AS contact_name,
      contact.email AS contact_email,
      contact.phone AS contact_phone,
      contact.company AS contact_company,
      opportunity.name AS opportunity_name,
      recent.event_type AS recent_event_type,
      recent.created_at AS recent_event_at
    FROM crm_contracts c
    LEFT JOIN crm_contacts contact ON contact.id = c.contact_id
    LEFT JOIN crm_opportunities opportunity ON opportunity.id = c.opportunity_id
    LEFT JOIN crm_contract_events recent ON recent.id = (
      SELECT e.id
      FROM crm_contract_events e
      WHERE e.contract_id = c.id
      ORDER BY e.created_at DESC, e.id DESC
      LIMIT 1
    )
    WHERE ${where}
  `
}

function loadCrmContractRecord(sql: string, args: Array<string | number>): CrmContractRecord | null {
  const row = getDb().prepare(sql).get(...args) as Record<string, unknown> | undefined
  if (!row) return null
  const base = hydrateCrmContractListRow(row)
  return {
    ...base,
    contact_phone: typeof row.contact_phone === 'string' && row.contact_phone.trim() ? row.contact_phone : null,
    contact_company: typeof row.contact_company === 'string' && row.contact_company.trim() ? row.contact_company : null,
    events: listCrmContractEvents(base.id, base.workspace_id),
  }
}

export function mergeContractBodyToHtml(bodyHtml: string, vars: ContractMergeVars): string {
  const source = resolveContractHtmlInput(bodyHtml, bodyHtml)
  if (!source) return ''
  const mergeVars: ContractMergeVars = {
    ...vars,
    today: vars.today ?? new Date().toISOString().slice(0, 10),
  }
  return replaceContractVariables(source, mergeVars)
}

export function listCrmContractTemplates(workspaceId: number): CrmContractTemplate[] {
  const rows = getDb()
    .prepare('SELECT * FROM crm_contract_templates WHERE workspace_id = ? ORDER BY updated_at DESC, id DESC')
    .all(workspaceId) as Record<string, unknown>[]
  return rows.map(hydrateCrmContractTemplateRow)
}

export function getCrmContractTemplateById(id: number, workspaceId: number): CrmContractTemplate | null {
  const row = getDb()
    .prepare('SELECT * FROM crm_contract_templates WHERE id = ? AND workspace_id = ?')
    .get(id, workspaceId) as Record<string, unknown> | undefined
  return row ? hydrateCrmContractTemplateRow(row) : null
}

export function createCrmContractTemplate(workspaceId: number, userId: number | null, data: {
  name: string
  category?: string | null
  body_html?: unknown
  body_json?: unknown
}): CrmContractTemplate {
  const name = data.name.trim()
  if (!name) throw new Error('name is required')
  const now = contractNowIso()
  const bodyHtml = resolveContractHtmlInput(data.body_html, data.body_json)
  const result = getDb().prepare(`
    INSERT INTO crm_contract_templates (
      workspace_id, name, category, body_html, created_by_user_id, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    name,
    data.category?.trim() || null,
    bodyHtml,
    userId ?? null,
    now,
    now,
  )
  const created = getCrmContractTemplateById(Number(result.lastInsertRowid), workspaceId)
  if (!created) throw new Error('Failed to load template')
  return created
}

export function updateCrmContractTemplate(id: number, workspaceId: number, patch: Partial<{
  name: string
  category: string | null
  body_html: unknown
  body_json: unknown
}>): CrmContractTemplate | null {
  const existing = getCrmContractTemplateById(id, workspaceId)
  if (!existing) return null
  const nextName = patch.name !== undefined ? patch.name.trim() : existing.name
  if (!nextName) throw new Error('name is required')
  const nextCategory = patch.category !== undefined ? (patch.category?.trim() || null) : existing.category
  const nextBodyHtml = patch.body_html !== undefined || patch.body_json !== undefined
    ? resolveContractHtmlInput(patch.body_html, patch.body_json)
    : existing.body_html
  getDb().prepare(`
    UPDATE crm_contract_templates
    SET name = ?, category = ?, body_html = ?, updated_at = ?
    WHERE id = ? AND workspace_id = ?
  `).run(
    nextName,
    nextCategory,
    nextBodyHtml,
    contractNowIso(),
    id,
    workspaceId,
  )
  return getCrmContractTemplateById(id, workspaceId)
}

export function deleteCrmContractTemplate(id: number, workspaceId: number): boolean {
  const info = getDb()
    .prepare('DELETE FROM crm_contract_templates WHERE id = ? AND workspace_id = ?')
    .run(id, workspaceId)
  return info.changes > 0
}

export function listCrmContracts(workspaceId: number, opts?: {
  status?: CrmContractStatus | 'all'
  opportunityId?: number
  contactId?: number
  limit?: number
}): CrmContractListRow[] {
  const clauses: string[] = ['c.workspace_id = ?']
  const args: Array<string | number> = [workspaceId]
  if (opts?.status && opts.status !== 'all') {
    clauses.push('c.status = ?')
    args.push(opts.status)
  }
  if (opts?.opportunityId) {
    clauses.push('c.opportunity_id = ?')
    args.push(opts.opportunityId)
  }
  if (opts?.contactId) {
    clauses.push('c.contact_id = ?')
    args.push(opts.contactId)
  }
  const limit = Math.min(500, Math.max(1, Math.floor(opts?.limit ?? 200)))
  const rows = getDb().prepare(`
    ${contractSelectSql(clauses.join(' AND '))}
    ORDER BY COALESCE(recent.created_at, c.updated_at) DESC, c.id DESC
    LIMIT ${limit}
  `).all(...args) as Record<string, unknown>[]
  return rows.map(hydrateCrmContractListRow)
}

export function getCrmContractById(id: number, workspaceId: number): CrmContractRecord | null {
  return loadCrmContractRecord(`${contractSelectSql('c.id = ? AND c.workspace_id = ?')} LIMIT 1`, [id, workspaceId])
}

export function getCrmContractByPublicToken(publicToken: string): CrmContractRecord | null {
  return loadCrmContractRecord(`${contractSelectSql('c.public_token = ?')} LIMIT 1`, [publicToken])
}

export function createCrmContract(workspaceId: number, userId: number | null, data: {
  title: string
  subject?: string | null
  template_id?: number | null
  body_html?: unknown
  body_json?: unknown
  opportunity_id?: number | null
  contact_id?: number | null
  expires_at?: string | null
}): CrmContractRecord {
  const title = data.title.trim()
  if (!title) throw new Error('title is required')
  const bodyHtml = resolveContractHtmlInput(data.body_html, data.body_json)
  const now = contractNowIso()
  const publicToken = crypto.randomBytes(24).toString('base64url')
  const result = getDb().prepare(`
    INSERT INTO crm_contracts (
      workspace_id, contact_id, opportunity_id, template_id, title, subject, status,
      body_html, merged_html, public_token, expires_at, created_by_user_id, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?, 'draft', ?, NULL, ?, ?, ?, ?, ?)
  `).run(
    workspaceId,
    data.contact_id ?? null,
    data.opportunity_id ?? null,
    data.template_id ?? null,
    title,
    data.subject ?? null,
    bodyHtml,
    publicToken,
    data.expires_at ?? null,
    userId ?? null,
    now,
    now,
  )
  const created = getCrmContractById(Number(result.lastInsertRowid), workspaceId)
  if (!created) throw new Error('Failed to load contract')
  return created
}

export function updateCrmContract(id: number, workspaceId: number, patch: Partial<{
  title: string
  subject: string | null
  body_html: unknown
  body_json: unknown
  merged_html: string | null
  status: CrmContractStatus
  expires_at: string | null
  contact_id: number | null
  opportunity_id: number | null
  sent_at: string | null
  viewed_at: string | null
  signed_at: string | null
  signed_name: string | null
  signed_email: string | null
  signed_ip_hash: string | null
  signed_ua: string | null
  signature_png: string | null
}>): CrmContractRecord | null {
  const existing = getCrmContractById(id, workspaceId)
  if (!existing) return null
  const sets: string[] = []
  const args: Array<string | number | null> = []
  if (patch.title !== undefined) {
    const nextTitle = patch.title.trim()
    if (!nextTitle) throw new Error('title is required')
    sets.push('title = ?')
    args.push(nextTitle)
  }
  if (patch.subject !== undefined) { sets.push('subject = ?'); args.push(patch.subject) }
  if (patch.body_html !== undefined || patch.body_json !== undefined) {
    sets.push('body_html = ?')
    args.push(resolveContractHtmlInput(patch.body_html, patch.body_json))
  }
  if (patch.merged_html !== undefined) { sets.push('merged_html = ?'); args.push(patch.merged_html) }
  if (patch.status !== undefined) { sets.push('status = ?'); args.push(patch.status) }
  if (patch.expires_at !== undefined) { sets.push('expires_at = ?'); args.push(patch.expires_at) }
  if (patch.contact_id !== undefined) { sets.push('contact_id = ?'); args.push(patch.contact_id) }
  if (patch.opportunity_id !== undefined) { sets.push('opportunity_id = ?'); args.push(patch.opportunity_id) }
  if (patch.sent_at !== undefined) { sets.push('sent_at = ?'); args.push(patch.sent_at) }
  if (patch.viewed_at !== undefined) { sets.push('viewed_at = ?'); args.push(patch.viewed_at) }
  if (patch.signed_at !== undefined) { sets.push('signed_at = ?'); args.push(patch.signed_at) }
  if (patch.signed_name !== undefined) { sets.push('signed_name = ?'); args.push(patch.signed_name) }
  if (patch.signed_email !== undefined) { sets.push('signed_email = ?'); args.push(patch.signed_email) }
  if (patch.signed_ip_hash !== undefined) { sets.push('signed_ip_hash = ?'); args.push(patch.signed_ip_hash) }
  if (patch.signed_ua !== undefined) { sets.push('signed_ua = ?'); args.push(patch.signed_ua) }
  if (patch.signature_png !== undefined) { sets.push('signature_png = ?'); args.push(patch.signature_png) }
  if (sets.length === 0) return existing
  sets.push('updated_at = ?')
  args.push(contractNowIso())
  args.push(id)
  args.push(workspaceId)
  getDb().prepare(`UPDATE crm_contracts SET ${sets.join(', ')} WHERE id = ? AND workspace_id = ?`).run(...args)
  return getCrmContractById(id, workspaceId)
}

export function deleteCrmContract(id: number, workspaceId: number): boolean {
  const info = getDb().prepare('DELETE FROM crm_contracts WHERE id = ? AND workspace_id = ?').run(id, workspaceId)
  return info.changes > 0
}

export function recordCrmContractEvent(data: {
  contract_id: number
  event_type: CrmContractEventType
  metadata?: Record<string, unknown> | null
  created_at?: string | null
}): CrmContractEvent {
  const createdAt = data.created_at ?? contractNowIso()
  const result = getDb().prepare(`
    INSERT INTO crm_contract_events (contract_id, event_type, metadata_json, created_at)
    VALUES (?, ?, ?, ?)
  `).run(
    data.contract_id,
    data.event_type,
    data.metadata ? JSON.stringify(data.metadata) : null,
    createdAt,
  )
  const row = getDb().prepare('SELECT * FROM crm_contract_events WHERE id = ?').get(Number(result.lastInsertRowid)) as Record<string, unknown>
  return hydrateCrmContractEventRow(row)
}

export function listCrmContractEvents(contractId: number, workspaceId: number): CrmContractEvent[] {
  const contract = getDb()
    .prepare('SELECT id FROM crm_contracts WHERE id = ? AND workspace_id = ?')
    .get(contractId, workspaceId) as { id: number } | undefined
  if (!contract) return []
  const rows = getDb().prepare(
    'SELECT * FROM crm_contract_events WHERE contract_id = ? ORDER BY created_at ASC, id ASC',
  ).all(contractId) as Record<string, unknown>[]
  return rows.map(hydrateCrmContractEventRow)
}

export function markCrmContractSent(contractId: number, workspaceId: number, opts?: {
  subject?: string | null
  expires_at?: string | null
  merged_html?: string | null
}): CrmContractRecord | null {
  const contract = getCrmContractById(contractId, workspaceId)
  if (!contract) return null
  const now = contractNowIso()
  const publicToken = contract.public_token || crypto.randomBytes(24).toString('base64url')
  getDb().prepare(`
    UPDATE crm_contracts
    SET status = 'sent',
        subject = ?,
        merged_html = ?,
        public_token = ?,
        expires_at = ?,
        sent_at = ?,
        updated_at = ?
    WHERE id = ? AND workspace_id = ?
  `).run(
    opts?.subject !== undefined ? opts.subject : contract.subject,
    opts?.merged_html !== undefined ? opts.merged_html : contract.merged_html,
    publicToken,
    opts?.expires_at !== undefined ? opts.expires_at : contract.expires_at,
    contract.sent_at ?? now,
    now,
    contractId,
    workspaceId,
  )
  recordCrmContractEvent({
    contract_id: contractId,
    event_type: 'sent',
    metadata: {
      subject: opts?.subject !== undefined ? opts.subject : contract.subject,
      expires_at: opts?.expires_at !== undefined ? opts.expires_at : contract.expires_at,
    },
  })
  return getCrmContractById(contractId, workspaceId)
}

export function markCrmContractViewed(contractId: number, workspaceId: number): CrmContractRecord | null {
  const contract = getCrmContractById(contractId, workspaceId)
  if (!contract) return null
  if (contract.viewed_at) return contract
  const now = contractNowIso()
  getDb().prepare(`
    UPDATE crm_contracts
    SET status = CASE WHEN status = 'sent' THEN 'viewed' ELSE status END,
        viewed_at = ?,
        updated_at = ?
    WHERE id = ? AND workspace_id = ?
  `).run(now, now, contractId, workspaceId)
  recordCrmContractEvent({ contract_id: contractId, event_type: 'viewed' })
  return getCrmContractById(contractId, workspaceId)
}

export function markCrmContractSigned(contractId: number, workspaceId: number, data: {
  name: string
  email: string
  signature_png: string
  signed_ip_hash?: string | null
  signed_ua?: string | null
}): CrmContractRecord | null {
  const contract = getCrmContractById(contractId, workspaceId)
  if (!contract) return null
  const now = contractNowIso()
  getDb().prepare(`
    UPDATE crm_contracts
    SET status = 'signed',
        viewed_at = COALESCE(viewed_at, ?),
        signed_at = ?,
        signed_name = ?,
        signed_email = ?,
        signed_ip_hash = ?,
        signed_ua = ?,
        signature_png = ?,
        updated_at = ?
    WHERE id = ? AND workspace_id = ?
  `).run(
    now,
    now,
    data.name,
    data.email,
    data.signed_ip_hash ?? null,
    data.signed_ua ?? null,
    data.signature_png,
    now,
    contractId,
    workspaceId,
  )
  recordCrmContractEvent({
    contract_id: contractId,
    event_type: 'signed',
    metadata: { name: data.name, email: data.email },
  })
  return getCrmContractById(contractId, workspaceId)
}

export function markCrmContractDeclined(contractId: number, workspaceId: number, reason?: string | null): CrmContractRecord | null {
  const contract = getCrmContractById(contractId, workspaceId)
  if (!contract) return null
  const now = contractNowIso()
  getDb().prepare(`
    UPDATE crm_contracts
    SET status = 'declined',
        viewed_at = COALESCE(viewed_at, ?),
        updated_at = ?
    WHERE id = ? AND workspace_id = ?
  `).run(now, now, contractId, workspaceId)
  recordCrmContractEvent({
    contract_id: contractId,
    event_type: 'declined',
    metadata: reason ? { reason } : null,
  })
  return getCrmContractById(contractId, workspaceId)
}

export function markCrmContractVoided(contractId: number, workspaceId: number, reason?: string | null): CrmContractRecord | null {
  const contract = getCrmContractById(contractId, workspaceId)
  if (!contract) return null
  const now = contractNowIso()
  getDb().prepare(`
    UPDATE crm_contracts
    SET status = 'void', updated_at = ?
    WHERE id = ? AND workspace_id = ?
  `).run(now, contractId, workspaceId)
  recordCrmContractEvent({
    contract_id: contractId,
    event_type: 'void',
    metadata: reason ? { reason } : null,
  })
  return getCrmContractById(contractId, workspaceId)
}

export function expireDueCrmContracts(nowIso: string = contractNowIso()): Array<{ id: number; workspace_id: number }> {
  const rows = getDb().prepare(`
    SELECT id, workspace_id
    FROM crm_contracts
    WHERE status IN ('sent','viewed')
      AND expires_at IS NOT NULL
      AND expires_at != ''
      AND expires_at < ?
  `).all(nowIso) as Array<{ id: number; workspace_id: number }>
  if (rows.length === 0) return []
  const update = getDb().prepare("UPDATE crm_contracts SET status = 'expired', updated_at = ? WHERE id = ?")
  for (const row of rows) {
    update.run(nowIso, row.id)
    recordCrmContractEvent({ contract_id: row.id, event_type: 'expired' })
  }
  return rows
}

export function seedDefaultContractTemplates(workspaceId: number): void {
  const existing = getDb().prepare('SELECT COUNT(*) as c FROM crm_contract_templates WHERE workspace_id = ?').get(workspaceId) as { c: number }
  if (existing.c > 0) return
  const now = contractNowIso()
  const insert = getDb().prepare(`
    INSERT INTO crm_contract_templates (
      workspace_id, name, category, body_html, created_at, updated_at
    ) VALUES (?, ?, ?, ?, ?, ?)
  `)
  insert.run(
    workspaceId,
    'Services Agreement',
    'Sales',
    `
      <h1>Services Agreement</h1>
      <p>This Services Agreement is effective on {{today}} between {{workspace.name}} and {{contact.name}}.</p>
      <h2>Scope</h2>
      <p>{{workspace.name}} will provide the services described in the approved scope of work. Changes in scope require written approval from both parties.</p>
      <h2>Fees and payment</h2>
      <p>Invoices are due within fourteen days unless otherwise stated in writing. Late balances may pause active work.</p>
      <h2>Term and termination</h2>
      <p>Either party may end this agreement with fourteen days written notice. Client remains responsible for all completed work through the termination date.</p>
      <h2>Acceptance</h2>
      <p>Signer acknowledges authority to enter this agreement on behalf of {{contact.name}}.</p>
    `.trim(),
    now,
    now,
  )
  insert.run(
    workspaceId,
    'Mutual NDA',
    'Legal',
    `
      <h1>Mutual Non-Disclosure Agreement</h1>
      <p>This agreement is effective on {{today}} between {{workspace.name}} and {{contact.name}}.</p>
      <h2>Confidential information</h2>
      <p>Each party may disclose non-public business, technical, client, or financial information in connection with evaluation or delivery of services.</p>
      <h2>Use and protection</h2>
      <p>The receiving party will only use confidential information for the intended relationship and will protect it with reasonable care.</p>
      <h2>Exclusions</h2>
      <p>Information that is public, independently developed, or rightfully received from a third party is not confidential.</p>
      <h2>Term</h2>
      <p>These obligations continue for two years after disclosure unless a longer period is required by law or contract.</p>
    `.trim(),
    now,
    now,
  )
}

