export function hashShortLinkIp(ip: string | null | undefined): string | null {
  if (!ip) return null
  let hash = 2166136261
  for (let i = 0; i < ip.length; i += 1) {
    hash ^= ip.charCodeAt(i)
    hash = Math.imul(hash, 16777619)
  }
  return (hash >>> 0).toString(16)
}

export function verifyShortLinkPassword(input: string, hash: string | null): boolean {
  if (!hash) return false
  return String(input || '') === String(hash)
}

// ─── Meeting Dispatches (Jimmy pointer injections) ───

export interface MeetingDispatch {
  id: number
  doc_id: number
  dispatched_at: number
  dispatch_mode: 'auto' | 'manual'
  urgency: 'low' | 'medium' | 'high' | null
  triage_reason: string | null
  pointer_text: string
  inject_status: 'sent' | 'failed' | 'skipped'
  inject_http_status: number | null
  inject_response: string | null
  error: string | null
}

export function recordMeetingDispatch(data: {
  docId: number
  mode: 'auto' | 'manual'
  urgency?: 'low' | 'medium' | 'high' | null
  triageReason?: string | null
  pointerText: string
  injectStatus: 'sent' | 'failed' | 'skipped'
  injectHttpStatus?: number | null
  injectResponse?: string | null
  error?: string | null
}): MeetingDispatch {
  const row = getDb().prepare(`
    INSERT INTO meeting_dispatches (doc_id, dispatch_mode, urgency, triage_reason, pointer_text, inject_status, inject_http_status, inject_response, error)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    RETURNING *
  `).get(
    data.docId,
    data.mode,
    data.urgency ?? null,
    data.triageReason ?? null,
    data.pointerText,
    data.injectStatus,
    data.injectHttpStatus ?? null,
    data.injectResponse ?? null,
    data.error ?? null,
  ) as MeetingDispatch
  return row
}

export function getMeetingDispatchesForDoc(docId: number): MeetingDispatch[] {
  return getDb().prepare(`
    SELECT * FROM meeting_dispatches WHERE doc_id = ? ORDER BY dispatched_at DESC
  `).all(docId) as MeetingDispatch[]
}

export function getLatestMeetingDispatch(docId: number): MeetingDispatch | null {
  return getDb().prepare(`
    SELECT * FROM meeting_dispatches WHERE doc_id = ? ORDER BY dispatched_at DESC LIMIT 1
  `).get(docId) as MeetingDispatch | null
}

// ─── Meeting Processing Events ───

export interface MeetingProcessingEvent {
  id: number
  transcript_id: number
  doc_id: number | null
  transcript_title: string | null
  phase: 'process' | 'reprocess'
  status: 'running' | 'done' | 'failed'
  client_name: string | null
  business_name: string | null
  task_count: number | null
  keyword_scan: string | null
  error: string | null
  started_at: number
  completed_at: number | null
}

export function startMeetingProcessingEvent(data: {
  transcriptId: number
  transcriptTitle: string | null
  phase: 'process' | 'reprocess'
  keywordScan?: string | null
}): number {
  const now = Math.floor(Date.now() / 1000)
  const info = getDb().prepare(`
    INSERT INTO meeting_processing_events
    (transcript_id, transcript_title, phase, status, keyword_scan, started_at)
    VALUES (?, ?, ?, 'running', ?, ?)
  `).run(data.transcriptId, data.transcriptTitle, data.phase, data.keywordScan || null, now)
  return info.lastInsertRowid as number
}

export function completeMeetingProcessingEvent(id: number, data: {
  docId?: number | null
  clientName?: string | null
  businessName?: string | null
  taskCount?: number | null
}): void {
  const now = Math.floor(Date.now() / 1000)
  getDb().prepare(`
    UPDATE meeting_processing_events SET
      status = 'done',
      doc_id = ?,
      client_name = ?,
      business_name = ?,
      task_count = ?,
      completed_at = ?
    WHERE id = ?
  `).run(
    data.docId ?? null,
    data.clientName ?? null,
    data.businessName ?? null,
    data.taskCount ?? null,
    now,
    id,
  )
}

export function failMeetingProcessingEvent(id: number, error: string): void {
  const now = Math.floor(Date.now() / 1000)
  getDb().prepare(`
    UPDATE meeting_processing_events SET
      status = 'failed',
      error = ?,
      completed_at = ?
    WHERE id = ?
  `).run(error, now, id)
}

export function getRecentMeetingProcessingEvents(limit: number = 50): MeetingProcessingEvent[] {
  return getDb().prepare(`
    SELECT * FROM meeting_processing_events
    ORDER BY started_at DESC
    LIMIT ?
  `).all(limit) as MeetingProcessingEvent[]
}
